import java.time.LocalDate;
import java.time.format.TextStyle;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ThreadLocalRandom;
import java.util.concurrent.atomic.AtomicLong;

/**
 * Drives bot auto-chat with realistic human-like behaviour.
 *
 * <h3>Realism features</h3>
 * <ul>
 *   <li><b>Typing delay</b> вҖ” optional 0вҖ“2.5 s pause before each message fires.</li>
 *   <li><b>Burst messages</b> вҖ” configurable chance of sending a short follow-up
 *       message 2вҖ“5 s after the first, mimicking multi-line real chat.</li>
 *   <li><b>Mention replies</b> вҖ” when a real player says a bot's name in chat
 *       the bot has a configurable chance (default 65 %) of replying after a
 *       short delay вҖ” see {@code fake-chat.mention-reply-chance}.</li>
 *   <li><b>Stagger interval</b> вҖ” minimum gap (default 3 s) between any two bots
 *       chatting prevents message floods.</li>
 *   <li><b>Activity variation</b> вҖ” each bot is randomly assigned a quiet /
 *       normal / active / very-active tier that scales its chat interval.</li>
 *   <li><b>Per-bot tier override</b> вҖ” {@link FakePlayer#setChatTier(String)} locks a
 *       bot to a specific activity tier; changeable via {@code /fpp chat <bot> tier}.</li>
 *   <li><b>Per-bot mute</b> вҖ” {@link FakePlayer#setChatEnabled(boolean)} silences
 *       individual bots; changeable via {@code /fpp chat <bot> on|off}.</li>
 *   <li><b>History window</b> вҖ” per-bot Deque keeps the last N messages so the
 *       same line is never repeated back-to-back.</li>
 *   <li><b>Event-triggered chat</b> вҖ” bots react to player joins and deaths.</li>
 *   <li><b>Keyword reactions</b> вҖ” bots reply when players say configured keywords.</li>
 *   <li><b>Rich placeholders</b> вҖ” {@code {name}}, {@code {random_player}},
 *       {@code {online}}, {@code {world}}, {@code {time}}, {@code {biome}}.</li>
 * </ul>
 *
 * <p>All config values are re-read on every fire so {@code /fpp reload} and
 * {@code /fpp chat on|off} take effect immediately.
 */
public final class BotChatAI implements Listener {

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;

    /**
     * Thread-local flag marking whether the current broadcast is a remote echo
     * received from another server. When true we must NOT re-forward the message
     * via plugin messaging to prevent infinite loops.
     */
    private static final ThreadLocal<Boolean> isRemoteBroadcast = ThreadLocal.withInitial(() -> false);

    /** Per-bot rolling message history вҖ” avoids repeating recent messages. */
    private final Map<UUID, Deque<String>> messageHistory = new ConcurrentHashMap<>();
    /** Task IDs for each bot's main scheduler loop so we can cancel on removal. */
    private final Map<UUID, Integer> taskIds = new ConcurrentHashMap<>();
    /**
     * Per-bot activity multiplier applied to the base chat interval.
     * Assigned once when the bot's loop starts; preserved until the bot is removed.
     * Can be overridden by {@link #setActivityTier(UUID, String)}.
     */
    private final Map<UUID, Double> activityMultipliers = new ConcurrentHashMap<>();
    /** Pending mention-reply task per bot вҖ” only one reply queued at a time. */
    private final Map<UUID, Integer> pendingReplyTasks = new ConcurrentHashMap<>();
    /** Pending event-trigger task per bot вҖ” only one at a time. */
    private final Map<UUID, Integer> pendingEventTasks = new ConcurrentHashMap<>();
    /**
     * Timed-mute expiry tasks вҖ” when active, the bot is silenced until the task fires
     * and re-enables chat. Key = bot UUID, value = scheduler task ID.
     */
    private final Map<UUID, Integer> muteTaskIds = new ConcurrentHashMap<>();

    /**
     * Timestamp (ms) of the last time any bot actually sent a chat message.
     * Used by the stagger logic to space out bot messages across the server.
     */
    private final AtomicLong lastAnyChatMs = new AtomicLong(0L);

    public BotChatAI(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
        // 1-second watcher: start loops for new bots, clean up removed ones.
        Bukkit.getScheduler().runTaskTimer(plugin, this::syncBotLoops, 20L, 20L);
        // Register chat event listeners.
        Bukkit.getPluginManager().registerEvents(this, plugin);
    }

    // в”Җв”Җ Loop management в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private void syncBotLoops() {
        for (FakePlayer fp : manager.getActivePlayers()) {
            if (!taskIds.containsKey(fp.getUuid())) {
                assignActivityMultiplier(fp.getUuid());
                scheduleNext(fp.getUuid());
            }
        }
        taskIds.entrySet().removeIf(e -> {
            if (manager.getByUuid(e.getKey()) == null) {
                Bukkit.getScheduler().cancelTask(e.getValue());
                messageHistory.remove(e.getKey());
                activityMultipliers.remove(e.getKey());
                cancelPendingReply(e.getKey());
                cancelPendingEvent(e.getKey());
                cancelMuteTask(e.getKey());
                return true;
            }
            return false;
        });
    }

    /**
     * Assigns a random activity tier to a newly-discovered bot.
     * If the bot has a {@link FakePlayer#getChatTier()} override, that tier is used.
     * <ul>
     *   <li>15 % вҖ” quiet    (2.0Г— interval вҶ’ chats ~half as often)</li>
     *   <li>25 % вҖ” passive  (1.4Г— interval)</li>
     *   <li>30 % вҖ” normal   (1.0Г— interval)</li>
     *   <li>18 % вҖ” active   (0.7Г— interval)</li>
     *   <li>12 % вҖ” chatty   (0.5Г— interval вҶ’ chats ~twice as often)</li>
     * </ul>
     */
    private void assignActivityMultiplier(UUID botUuid) {
        // Check for a per-bot tier override
        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp != null && fp.getChatTier() != null) {
            activityMultipliers.put(botUuid, tierToMultiplier(fp.getChatTier()));
            return;
        }
        if (!Config.fakeChatActivityVariation()) {
            activityMultipliers.put(botUuid, 1.0);
            return;
        }
        double r = ThreadLocalRandom.current().nextDouble();
        double mult;
        if      (r < 0.15) mult = 2.0;   // quiet
        else if (r < 0.40) mult = 1.4;   // passive
        else if (r < 0.70) mult = 1.0;   // normal
        else if (r < 0.88) mult = 0.7;   // active
        else               mult = 0.5;   // chatty
        activityMultipliers.put(botUuid, mult);
    }

    /**
     * Converts a tier name to its activity multiplier.
     * Unknown values fall back to {@code 1.0} (normal).
     */
    private static double tierToMultiplier(String tier) {
        return switch (tier.toLowerCase(Locale.ROOT)) {
            case "quiet"   -> 2.0;
            case "passive" -> 1.4;
            case "active"  -> 0.7;
            case "chatty"  -> 0.5;
            default        -> 1.0; // "normal" and unrecognised
        };
    }

    /**
     * Overrides the activity tier for a specific bot and resets its multiplier immediately.
     * Pass {@code null} to return to random assignment.
     *
     * @param botUuid UUID of the bot
     * @param tier    one of {@code "quiet"}, {@code "passive"}, {@code "normal"},
     *                {@code "active"}, {@code "chatty"}, or {@code null}
     */
    public void setActivityTier(UUID botUuid, String tier) {
        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) return;
        fp.setChatTier(tier);
        if (tier == null) {
            // Re-roll randomly
            activityMultipliers.remove(botUuid);
            assignActivityMultiplier(botUuid);
        } else {
            activityMultipliers.put(botUuid, tierToMultiplier(tier));
        }
        Config.debugChat("Activity tier for " + fp.getName() + " set to "
                + (tier != null ? tier : "random") + " (mult="
                + activityMultipliers.getOrDefault(botUuid, 1.0) + ")");
    }

    private void scheduleNext(UUID botUuid) {
        if (!Config.fakeChatEnabled()) {
            // Chat disabled вҖ” cancel any pending reply/event/burst tasks for this bot
            // so they don't fire after the admin ran /fpp chat off.
            cancelPendingReply(botUuid);
            cancelPendingEvent(botUuid);
            // Cancel the OLD long-delay main task so it can't fire a duplicate loop.
            Integer oldTask = taskIds.remove(botUuid);
            if (oldTask != null) Bukkit.getScheduler().cancelTask(oldTask);
            // Re-check in 2 s вҖ” picks up quickly when chat is re-enabled via /fpp reload
            int id = Bukkit.getScheduler().runTaskLater(plugin,
                    () -> scheduleNext(botUuid), 40L).getTaskId();
            taskIds.put(botUuid, id);
            return;
        }

        double mult = activityMultipliers.getOrDefault(botUuid, 1.0);
        int minTicks = Math.max(20, (int)(Config.fakeChatIntervalMin() * 20 * mult));
        int maxTicks = Math.max(minTicks, (int)(Config.fakeChatIntervalMax() * 20 * mult));

        long delay = minTicks == maxTicks
                ? minTicks
                : minTicks + ThreadLocalRandom.current().nextInt(maxTicks - minTicks + 1);

        int id = Bukkit.getScheduler().runTaskLater(plugin, () -> {
            fireChat(botUuid);
            if (manager.getByUuid(botUuid) != null) {
                scheduleNext(botUuid);
            } else {
                taskIds.remove(botUuid);
                messageHistory.remove(botUuid);
                activityMultipliers.remove(botUuid);
            }
        }, delay).getTaskId();

        taskIds.put(botUuid, id);
    }

    // в”Җв”Җ Fire в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private void fireChat(UUID botUuid) {
        if (!Config.fakeChatEnabled()) return;

        FakePlayer bot = manager.getByUuid(botUuid);
        if (bot == null) return;

        // Per-bot mute check
        if (!bot.isChatEnabled()) return;

        if (Config.fakeChatRequirePlayer() && !hasRealPlayerOnline()) return;

        // Chance roll вҖ” skip silently if unlucky
        if (ThreadLocalRandom.current().nextDouble() > Config.fakeChatChance()) return;

        List<String> messages = Config.fakeChatMessages();
        if (messages.isEmpty()) return;

        String message = pickMessage(botUuid, messages, bot);

        // в”Җв”Җ Stagger + typing delay в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        int delayTicks = computePreSendDelay();
        if (delayTicks > 0) {
            Bukkit.getScheduler().runTaskLater(plugin,
                    () -> sendMessage(bot, message, true), delayTicks);
        } else {
            sendMessage(bot, message, true);
        }
    }

    /**
     * Picks the next message for {@code botUuid}, resolves all placeholders,
     * and updates the history deque.
     *
     * <p>Supported placeholders:
     * <ul>
 *   <li>{@code {name}}          вҖ” the bot's own name</li>
 *   <li>{@code {random_player}} вҖ” a random real player's name</li>
 *   <li>{@code {online}}        вҖ” number of real (non-bot) players online</li>
 *   <li>{@code {world}}         вҖ” the bot's current world name</li>
 *   <li>{@code {time}}          вҖ” {@code "day"} or {@code "night"} based on world time</li>
 *   <li>{@code {biome}}         вҖ” the bot's current biome name (human-readable)</li>
 *   <li>{@code {x}}/{@code {y}}/{@code {z}} вҖ” the bot's current block coordinates</li>
 *   <li>{@code {server}}        вҖ” the server ID from config ({@code database.server-id})</li>
 *   <li>{@code {date}}          вҖ” today's date (e.g. {@code 2026-04-05})</li>
 *   <li>{@code {day}}           вҖ” full day of week (e.g. {@code Sunday})</li>
 * </ul>
     */
    private String pickMessage(UUID botUuid, List<String> pool, FakePlayer bot) {
        Deque<String> history = messageHistory.computeIfAbsent(botUuid, k -> new ArrayDeque<>());
        int historySize = Math.max(1, Config.fakeChatHistorySize());

        // Exclude recently-sent messages so the bot doesn't repeat itself
        List<String> available = new ArrayList<>(pool);
        available.removeAll(history);
        if (available.isEmpty()) available = new ArrayList<>(pool); // reset if pool exhausted

        String raw = available.get(ThreadLocalRandom.current().nextInt(available.size()));

        // Roll history window
        history.addLast(raw);
        while (history.size() > historySize) history.pollFirst();

        return resolvePlaceholders(raw, bot);
    }

    /**
     * Resolves all chat placeholders in the given raw message string.
     */
    private String resolvePlaceholders(String raw, FakePlayer bot) {
        String s = raw
                .replace("{name}", bot.getName())
                .replace("{random_player}", resolveRandomPlayer(bot));

        // {online} вҖ” real player count
        if (s.contains("{online}")) {
            int realCount = 0;
            for (Player p : Bukkit.getOnlinePlayers()) {
                if (manager.getByUuid(p.getUniqueId()) == null) realCount++;
            }
            s = s.replace("{online}", String.valueOf(realCount));
        }

        // {server} вҖ” server ID from config
        if (s.contains("{server}")) {
            s = s.replace("{server}", Config.serverId());
        }

        // {date} / {day} вҖ” real-world date
        if (s.contains("{date}") || s.contains("{day}")) {
            LocalDate today = LocalDate.now();
            if (s.contains("{date}")) s = s.replace("{date}", today.toString());
            if (s.contains("{day}"))  s = s.replace("{day}",  today.getDayOfWeek()
                    .getDisplayName(TextStyle.FULL, Locale.ROOT));
        }

        // Location-based placeholders вҖ” only resolved when the bot has a valid entity
        if (s.contains("{world}") || s.contains("{time}") || s.contains("{biome}")
                || s.contains("{x}") || s.contains("{y}") || s.contains("{z}")) {
            Location loc = bot.getLiveLocation();
            if (loc != null && loc.getWorld() != null) {
                if (s.contains("{world}")) {
                    s = s.replace("{world}", loc.getWorld().getName());
                }
                if (s.contains("{time}")) {
                    long worldTime = loc.getWorld().getTime();
                    // Day: 0вҖ“12000, Night: 12000вҖ“24000 (approx)
                    String timeLabel = (worldTime >= 0 && worldTime < 12300) ? "day" : "night";
                    s = s.replace("{time}", timeLabel);
                }
                if (s.contains("{biome}")) {
                    try {
                        String biome = loc.getBlock().getBiome().name()
                                .toLowerCase(Locale.ROOT).replace('_', ' ');
                        s = s.replace("{biome}", biome);
                    } catch (Throwable t) {
                        s = s.replace("{biome}", "unknown");
                    }
                }
                // {x}, {y}, {z} вҖ” block coordinates
                if (s.contains("{x}")) s = s.replace("{x}", String.valueOf((int) loc.getX()));
                if (s.contains("{y}")) s = s.replace("{y}", String.valueOf((int) loc.getY()));
                if (s.contains("{z}")) s = s.replace("{z}", String.valueOf((int) loc.getZ()));
            } else {
                s = s.replace("{world}", "unknown")
                      .replace("{time}", "day")
                      .replace("{biome}", "unknown")
                      .replace("{x}", "?")
                      .replace("{y}", "?")
                      .replace("{z}", "?");
            }
        }
        return s;
    }

    /**
     * Calculates extra pre-send delay ticks combining stagger enforcement and
     * an optional simulated typing pause.
     *
     * <p>Stagger: if another bot sent a message less than {@code stagger-interval}
     * seconds ago, we push this message past that gap.  The projected send time
     * is written atomically so the next caller sees it immediately.
     */
    private int computePreSendDelay() {
        int staggerTicks = 0;
        int staggerSec = Config.fakeChatStaggerInterval();
        if (staggerSec > 0) {
            long now       = System.currentTimeMillis();
            long minGapMs  = staggerSec * 1000L;
            long nextSend;
            // CAS loop so concurrent callers (shouldn't happen on main thread, but be safe)
            while (true) {
                long last = lastAnyChatMs.get();
                nextSend  = Math.max(now, last + minGapMs);
                if (lastAnyChatMs.compareAndSet(last, nextSend)) break;
            }
            long extraMs = nextSend - now;
            if (extraMs > 0) {
                staggerTicks = (int)(extraMs / 50L) + 1; // 50 ms per tick
            }
        }

        int typingTicks = 0;
        if (Config.fakeChatTypingDelay()) {
            // Random pause 0вҖ“2.5 s converted to ticks
            typingTicks = ThreadLocalRandom.current().nextInt(50);
        }

        return staggerTicks + typingTicks;
    }

    /**
     * Delivers a resolved message for {@code bot} through the appropriate path
     * and optionally schedules a burst follow-up.
     * Respects both the global {@code fake-chat.enabled} flag and the per-bot mute.
     * In-flight typing-delay tasks check this before sending.
     */
    private void sendMessage(FakePlayer bot, String message, boolean allowBurst) {
        if (manager.getByUuid(bot.getUuid()) == null) return; // bot removed while waiting
        // Re-check both global and per-bot flags here so any in-flight typing-delay
        // or burst tasks that were already queued BEFORE a /fpp chat off command
        // respect the new state immediately.
        if (!Config.fakeChatEnabled()) return;
        if (!bot.isChatEnabled()) return;
        sendMessageForced(bot, message, allowBurst);
    }

    /**
     * Same as {@link #sendMessage} but bypasses the global {@code fake-chat.enabled}
     * and per-bot mute checks. Used by admin force-send commands so the message
     * always goes through regardless of chat state.
     */
    private void sendMessageForced(FakePlayer bot, String message, boolean allowBurst) {
        if (manager.getByUuid(bot.getUuid()) == null) return;

        Player playerEntity = bot.getPlayer();
        if (playerEntity != null && playerEntity.isOnline() && !bot.isBodyless()) {
            // Local bot with a body: fire through the real chat pipeline
            dispatchChat(playerEntity, message);
        } else {
            // Bodyless / entity-less bot: broadcast using the configurable remote format
            broadcastFormatted(bot.getDisplayName(), message);
        }
        Config.debugChat(bot.getName() + " said: " + message);

        // в”Җв”Җ Cross-server sync via plugin messaging в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        var vc = plugin.getVelocityChannel();
        if (vc != null) {
            vc.sendChatToNetwork(bot.getName(), bot.getDisplayName(), message, "", "");
            Config.debugChat("Forwarded to other servers via plugin messaging.");
        }

        // в”Җв”Җ Burst follow-up в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (allowBurst) {
            double burstChance = Config.fakeChatBurstChance();
            if (burstChance > 0 && ThreadLocalRandom.current().nextDouble() < burstChance) {
                scheduleBurst(bot);
            }
        }
    }

    /**
     * Broadcasts a message using the configurable remote-format template.
     * Used for bodyless bots and remote-bot echoes.
     */
    private static void broadcastFormatted(String displayName, String message) {
        try {
            String format = Config.fakeChatRemoteFormat()
                    .replace("{name}", displayName)
                    .replace("{message}", message);
            Component chatLine = MiniMessage.miniMessage().deserialize(format);
            Bukkit.getServer().broadcast(chatLine);
        } catch (Throwable t) {
            // Fallback to plain format if MiniMessage fails
            Component chatLine = Component.text("<")
                    .append(TextUtil.colorize(displayName))
                    .append(Component.text("> "))
                    .append(Component.text(message));
            Bukkit.getServer().broadcast(chatLine);
        }
    }

    /** Schedules a short burst follow-up message for {@code bot}. */
    private void scheduleBurst(FakePlayer bot) {
        List<String> pool = Config.chatBurstMessages();
        if (pool.isEmpty()) return;

        int minTicks = Math.max(20, Config.fakeChatBurstDelayMin() * 20);
        int maxTicks = Math.max(minTicks, Config.fakeChatBurstDelayMax() * 20);
        long delay = minTicks == maxTicks
                ? minTicks
                : minTicks + ThreadLocalRandom.current().nextInt(maxTicks - minTicks + 1);

        String raw = pool.get(ThreadLocalRandom.current().nextInt(pool.size()));
        String msg = resolvePlaceholders(raw, bot);

        Bukkit.getScheduler().runTaskLater(plugin,
                () -> sendMessage(bot, msg, false), delay);
    }

    // в”Җв”Җ Mention detection (AsyncChatEvent listener) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Listens for real player chat messages, schedules a reply for any bot
     * whose name appears in the message text, and fires keyword-triggered
     * reactions when configured.
     */
    @EventHandler(priority = EventPriority.MONITOR, ignoreCancelled = true)
    public void onPlayerChat(AsyncChatEvent event) {
        if (!Config.fakeChatEnabled()) return;

        // Skip messages sent by bots to prevent infinite loops
        if (manager.getByUuid(event.getPlayer().getUniqueId()) != null) return;

        // Extract plain text (thread-safe read on the Adventure Component)
        final String plainText;
        try {
            plainText = PlainTextComponentSerializer.plainText()
                    .serialize(event.message()).toLowerCase(Locale.ROOT);
        } catch (Throwable t) {
            return;
        }

        // в”Җв”Җ Mention replies в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.fakeChatReplyToMentions()) {
            List<UUID> candidates = new ArrayList<>();
            for (FakePlayer fp : manager.getActivePlayers()) {
                if (fp.isChatEnabled()
                        && plainText.contains(fp.getName().toLowerCase(Locale.ROOT))) {
                    candidates.add(fp.getUuid());
                }
            }
            if (!candidates.isEmpty()) {
                Bukkit.getScheduler().runTask(plugin, () -> {
                    for (UUID uuid : candidates) {
                        if (!pendingReplyTasks.containsKey(uuid)) {
                            scheduleMentionReply(uuid);
                        }
                    }
                });
            }
        }

        // в”Җв”Җ Keyword reactions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.fakeChatKeywordReactionsEnabled()) {
            Map<String, String> keywordMap = Config.fakeChatKeywordMap();
            if (!keywordMap.isEmpty()) {
                // Find all matching keywords (collect; react to at most one per message)
                List<String> matchedPools = new ArrayList<>();
                for (Map.Entry<String, String> entry : keywordMap.entrySet()) {
                    if (plainText.contains(entry.getKey())) {
                        matchedPools.add(entry.getValue());
                    }
                }
                if (!matchedPools.isEmpty()) {
                    String poolKey = matchedPools.get(
                            ThreadLocalRandom.current().nextInt(matchedPools.size()));
                    Bukkit.getScheduler().runTask(plugin,
                            () -> scheduleKeywordReaction(poolKey));
                }
            }
        }
    }

    /** Schedules a mention-reply for {@code botUuid} (configurable chance of actually firing). */
    private void scheduleMentionReply(UUID botUuid) {
        FakePlayer bot = manager.getByUuid(botUuid);
        if (bot == null || !bot.isChatEnabled()) return;

        // Configurable chance вҖ” bot may ignore the mention
        if (ThreadLocalRandom.current().nextDouble() > Config.fakeChatMentionReplyChance()) return;

        int minTicks = Math.max(20, Config.fakeChatReplyDelayMin() * 20);
        int maxTicks = Math.max(minTicks, Config.fakeChatReplyDelayMax() * 20);
        long delay = minTicks == maxTicks
                ? minTicks
                : minTicks + ThreadLocalRandom.current().nextInt(maxTicks - minTicks + 1);

        int taskId = Bukkit.getScheduler().runTaskLater(plugin, () -> {
            pendingReplyTasks.remove(botUuid);
            FakePlayer b = manager.getByUuid(botUuid);
            if (b == null || !b.isChatEnabled() || !hasRealPlayerOnline()) return;

            // Prefer the dedicated reply pool; fall back to general messages
            List<String> pool = Config.chatReplyMessages();
            if (pool.isEmpty()) pool = Config.fakeChatMessages();
            if (pool.isEmpty()) return;

            String raw = pool.get(ThreadLocalRandom.current().nextInt(pool.size()));
            String reply = resolvePlaceholders(raw, b);

            sendMessage(b, reply, false);
            Config.debugChat(b.getName() + " replied to a mention вҶ’ " + reply);
        }, delay).getTaskId();

        pendingReplyTasks.put(botUuid, taskId);
    }

    /**
     * Picks a random chat-enabled bot and schedules a keyword-reaction message
     * drawn from {@code bot-messages.yml} under {@code keyword-reactions.<poolKey>}.
     */
    private void scheduleKeywordReaction(String poolKey) {
        if (!Config.fakeChatEnabled()) return;
        List<String> pool = Config.chatKeywordReactionMessages(poolKey);
        if (pool.isEmpty()) return;

        // Pick a random chat-enabled bot
        List<FakePlayer> eligible = manager.getActivePlayers().stream()
                .filter(FakePlayer::isChatEnabled)
                .toList();
        if (eligible.isEmpty()) return;
        if (Config.fakeChatRequirePlayer() && !hasRealPlayerOnline()) return;

        FakePlayer bot = eligible.get(ThreadLocalRandom.current().nextInt(eligible.size()));

        // Small random delay (0вҖ“3 s) so reaction feels natural
        int delayTicks = ThreadLocalRandom.current().nextInt(60) + 20;
        Bukkit.getScheduler().runTaskLater(plugin, () -> {
            FakePlayer b = manager.getByUuid(bot.getUuid());
            if (b == null || !b.isChatEnabled()) return;
            String raw = pool.get(ThreadLocalRandom.current().nextInt(pool.size()));
            String msg = resolvePlaceholders(raw, b);
            sendMessage(b, msg, false);
            Config.debugChat(b.getName() + " keyword-reaction [" + poolKey + "]: " + msg);
        }, delayTicks);
    }

    private void cancelPendingReply(UUID botUuid) {
        Integer taskId = pendingReplyTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);
    }

    private void cancelPendingEvent(UUID botUuid) {
        Integer taskId = pendingEventTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);
    }

    private void cancelMuteTask(UUID botUuid) {
        Integer taskId = muteTaskIds.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);
    }

    // в”Җв”Җ Event-triggered chat в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Reacts to a real player joining the server.
     * Picks a random chat-enabled bot and has it send a join-reaction message.
     */
    @EventHandler(priority = EventPriority.MONITOR)
    public void onPlayerJoin(PlayerJoinEvent event) {
        if (!Config.fakeChatEnabled()) return;
        if (!Config.fakeChatEventTriggersEnabled()) return;
        if (!Config.fakeChatOnJoinEnabled()) return;

        // Ignore bots joining
        if (manager.getByUuid(event.getPlayer().getUniqueId()) != null) return;

        // Chance roll
        if (ThreadLocalRandom.current().nextDouble() > Config.fakeChatOnJoinChance()) return;

        List<String> pool = Config.chatJoinReactionMessages();
        if (pool.isEmpty()) return;

        List<FakePlayer> eligible = manager.getActivePlayers().stream()
                .filter(FakePlayer::isChatEnabled)
                .toList();
        if (eligible.isEmpty()) return;

        FakePlayer bot = eligible.get(ThreadLocalRandom.current().nextInt(eligible.size()));
        final String joinerName = event.getPlayer().getName();

        int minTicks = Math.max(20, Config.fakeChatOnJoinDelayMin() * 20);
        int maxTicks = Math.max(minTicks, Config.fakeChatOnJoinDelayMax() * 20);
        long delay   = minTicks + ThreadLocalRandom.current().nextInt(Math.max(1, maxTicks - minTicks + 1));

        int taskId = Bukkit.getScheduler().runTaskLater(plugin, () -> {
            pendingEventTasks.remove(bot.getUuid());
            FakePlayer b = manager.getByUuid(bot.getUuid());
            if (b == null || !b.isChatEnabled()) return;
            if (Config.fakeChatRequirePlayer() && !hasRealPlayerOnline()) return;

            String raw = pool.get(ThreadLocalRandom.current().nextInt(pool.size()));
            // Allow {random_player} to resolve to the joiner for natural-looking reactions
            String msg = resolvePlaceholders(
                    raw.replace("{random_player}", joinerName), b);
            sendMessage(b, msg, false);
            Config.debugChat(b.getName() + " join-reaction for " + joinerName + ": " + msg);
        }, delay).getTaskId();

        pendingEventTasks.put(bot.getUuid(), taskId);
    }

    /**
     * Reacts to any entity death (players and other bots).
     * Has a configurable chance of picking a bot to send a death-reaction message.
     * When {@code fake-chat.event-triggers.on-death.players-only} is {@code true},
     * only reactions to real player deaths fire (mobs and animals are ignored).
     */
    @EventHandler(priority = EventPriority.MONITOR, ignoreCancelled = true)
    public void onEntityDeath(EntityDeathEvent event) {
        if (!Config.fakeChatEnabled()) return;
        if (!Config.fakeChatEventTriggersEnabled()) return;
        if (!Config.fakeChatOnDeathEnabled()) return;

        Entity deceased = event.getEntity();

        // Optional player-only filter
        if (Config.fakeChatOnDeathPlayersOnly() && !(deceased instanceof Player)) return;

        if (ThreadLocalRandom.current().nextDouble() > Config.fakeChatOnDeathChance()) return;

        List<String> pool = Config.chatDeathReactionMessages();
        if (pool.isEmpty()) return;


        // Prefer bots not already queued for another event
        List<FakePlayer> eligible = manager.getActivePlayers().stream()
                .filter(FakePlayer::isChatEnabled)
                .filter(fp -> !pendingEventTasks.containsKey(fp.getUuid()))
                .toList();
        if (eligible.isEmpty()) return;
        if (Config.fakeChatRequirePlayer() && !hasRealPlayerOnline()) return;

        FakePlayer bot = eligible.get(ThreadLocalRandom.current().nextInt(eligible.size()));
        final String deceasedName = deceased.getName();

        int minTicks = Math.max(20, Config.fakeChatOnDeathDelayMin() * 20);
        int maxTicks = Math.max(minTicks, Config.fakeChatOnDeathDelayMax() * 20);
        long delay   = minTicks + ThreadLocalRandom.current().nextInt(Math.max(1, maxTicks - minTicks + 1));

        int taskId = Bukkit.getScheduler().runTaskLater(plugin, () -> {
            pendingEventTasks.remove(bot.getUuid());
            FakePlayer b = manager.getByUuid(bot.getUuid());
            if (b == null || !b.isChatEnabled()) return;

            String raw = pool.get(ThreadLocalRandom.current().nextInt(pool.size()));
            String msg = resolvePlaceholders(
                    raw.replace("{random_player}", deceasedName), b);
            sendMessage(b, msg, false);
            Config.debugChat(b.getName() + " death-reaction for " + deceasedName + ": " + msg);
        }, delay).getTaskId();

        pendingEventTasks.put(bot.getUuid(), taskId);
    }

    /**
     * Reacts to a real player leaving the server.
     * Picks a random chat-enabled bot and has it send a leave-reaction message.
     */
    @EventHandler(priority = EventPriority.MONITOR)
    public void onPlayerQuit(PlayerQuitEvent event) {
        if (!Config.fakeChatEnabled()) return;
        if (!Config.fakeChatEventTriggersEnabled()) return;
        if (!Config.fakeChatOnLeaveEnabled()) return;

        // Ignore bots disconnecting
        if (manager.getByUuid(event.getPlayer().getUniqueId()) != null) return;

        // Chance roll
        if (ThreadLocalRandom.current().nextDouble() > Config.fakeChatOnLeaveChance()) return;

        List<String> pool = Config.chatLeaveReactionMessages();
        if (pool.isEmpty()) return;

        List<FakePlayer> eligible = manager.getActivePlayers().stream()
                .filter(FakePlayer::isChatEnabled)
                .toList();
        if (eligible.isEmpty()) return;

        FakePlayer bot = eligible.get(ThreadLocalRandom.current().nextInt(eligible.size()));
        final String leaverName = event.getPlayer().getName();

        int minTicks = Math.max(20, Config.fakeChatOnLeaveDelayMin() * 20);
        int maxTicks = Math.max(minTicks, Config.fakeChatOnLeaveDelayMax() * 20);
        long delay   = minTicks + ThreadLocalRandom.current().nextInt(Math.max(1, maxTicks - minTicks + 1));

        int taskId = Bukkit.getScheduler().runTaskLater(plugin, () -> {
            pendingEventTasks.remove(bot.getUuid());
            FakePlayer b = manager.getByUuid(bot.getUuid());
            if (b == null || !b.isChatEnabled()) return;
            if (Config.fakeChatRequirePlayer() && !hasRealPlayerOnline()) return;

            String raw = pool.get(ThreadLocalRandom.current().nextInt(pool.size()));
            // Allow {random_player} to resolve to the player who left
            String msg = resolvePlaceholders(
                    raw.replace("{random_player}", leaverName), b);
            sendMessage(b, msg, false);
            Config.debugChat(b.getName() + " leave-reaction for " + leaverName + ": " + msg);
        }, delay).getTaskId();

        pendingEventTasks.put(bot.getUuid(), taskId);
    }

    /**
     * Cancels all current main-loop tasks and immediately reschedules every active bot
     * using fresh interval, chance, and stagger values read from config.
     *
     * <p>Call this after {@code /fpp reload} so changes to
     * {@code fake-chat.interval}, {@code fake-chat.chance}, and
     * {@code fake-chat.stagger-interval} take effect instantly instead of waiting
     * for each bot's old long-delay task to naturally expire.
     *
     * <p>Per-bot tier overrides ({@code /fpp chat <bot> tier}) and per-bot mute
     * states are preserved across the restart.
     */
    public void restartLoops() {
        // Cancel every queued main-loop delayed task so bots don't fire on the old delay
        taskIds.values().forEach(Bukkit.getScheduler()::cancelTask);
        taskIds.clear();
        // Re-read activity multipliers (picks up activity-variation config changes;
        // honours per-bot tier overrides set via /fpp chat <bot> tier)
        for (FakePlayer fp : manager.getActivePlayers()) {
            assignActivityMultiplier(fp.getUuid());
            scheduleNext(fp.getUuid());
        }
        Config.debugChat("BotChatAI loops restarted вҖ” new interval "
                + Config.fakeChatIntervalMin() + "вҖ“" + Config.fakeChatIntervalMax() + "s,"
                + " stagger " + Config.fakeChatStaggerInterval() + "s");
    }

    /** Cancels all pending tasks. Call this on plugin shutdown / disable. */
    public void cancelAll() {
        taskIds.values().forEach(Bukkit.getScheduler()::cancelTask);
        pendingReplyTasks.values().forEach(Bukkit.getScheduler()::cancelTask);
        pendingEventTasks.values().forEach(Bukkit.getScheduler()::cancelTask);
        muteTaskIds.values().forEach(Bukkit.getScheduler()::cancelTask);
        taskIds.clear();
        messageHistory.clear();
        activityMultipliers.clear();
        pendingReplyTasks.clear();
        pendingEventTasks.clear();
        muteTaskIds.clear();
    }

    /**
     * Immediately cancels all pending chat tasks (main loop, replies, events, bursts)
     * and restarts each bot's loop in the "chat disabled" polling mode (re-checks
     * every 2 s so it picks up immediately when chat is re-enabled).
     *
     * <p>Call this from {@code /fpp chat off} so in-flight typing-delay and event
     * tasks are killed right away rather than waiting until the current long delay fires.
     */
    public void stopAllLoopsNow() {
        // Cancel every tracked task immediately
        taskIds.values().forEach(Bukkit.getScheduler()::cancelTask);
        pendingReplyTasks.values().forEach(Bukkit.getScheduler()::cancelTask);
        pendingEventTasks.values().forEach(Bukkit.getScheduler()::cancelTask);
        taskIds.clear();
        pendingReplyTasks.clear();
        pendingEventTasks.clear();
        // Do NOT clear activityMultipliers / messageHistory вҖ” preserve tier overrides
        // and history so they're still active when chat is re-enabled.
        // Restart each bot's loop in disabled-polling mode (scheduleNext will see
        // fakeChatEnabled() == false and create a 2-s re-check task).
        for (FakePlayer fp : manager.getActivePlayers()) {
            scheduleNext(fp.getUuid());
        }
    }

    // в”Җв”Җ Public API в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Forces a specific bot to immediately send {@code message} through the
     * appropriate chat path. Does not trigger a burst follow-up.
     * The message is delivered even when global fake-chat is disabled.
     *
     * @param bot     the bot that should speak
     * @param message fully resolved message text (placeholders NOT re-expanded)
     */
    public void forceSendMessage(FakePlayer bot, String message) {
        if (manager.getByUuid(bot.getUuid()) == null) return;
        // Bypass global enabled check вҖ” force-send is explicitly requested by admin
        sendMessageForced(bot, message, false);
    }    /**
     * Forces a specific bot to immediately send {@code message}, first expanding
     * all supported chat placeholders ({@code {name}}, {@code {random_player}},
     * {@code {online}}, {@code {world}}, {@code {time}}, {@code {biome}},
     * {@code {x}}, {@code {y}}, {@code {z}}, {@code {server}}, {@code {date}},
     * {@code {day}}).
     *
     * <p>Use this variant when the message string comes directly from a command
     * argument so admin-supplied placeholders are properly resolved.
     *
     * @param bot     the bot that should speak
     * @param message message template with optional placeholder tokens
     */
    public void forceSendMessageResolved(FakePlayer bot, String message) {
        if (manager.getByUuid(bot.getUuid()) == null) return;
        String resolved = resolvePlaceholders(message, bot);
        // Bypass global enabled check вҖ” force-send is explicitly requested by admin
        sendMessageForced(bot, resolved, false);
    }

    /**
     * Returns the current activity multiplier for the given bot.
     * A multiplier &lt; 1.0 means the bot chats more frequently than the base
     * interval; &gt; 1.0 means less frequently; 1.0 = normal.
     *
     * @param botUuid bot's UUID
     * @return the multiplier, or {@code 1.0} if not yet assigned
     */
    public double getActivityMultiplier(UUID botUuid) {
        return activityMultipliers.getOrDefault(botUuid, 1.0);
    }

    /**
     * Silences a bot for {@code seconds} seconds, then automatically re-enables it.
     *
     * <p>Any existing timed mute for the bot is cancelled and replaced.
     * Passing {@code 0} or a negative value permanently silences the bot
     * (same as {@link FakePlayer#setChatEnabled(boolean) setChatEnabled(false)}).
     *
     * @param botUuid bot's UUID
     * @param seconds duration of the mute; 0 = permanent
     */
    public void timedMute(UUID botUuid, int seconds) {
        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) return;

        // Cancel any previous timed mute
        Integer prev = muteTaskIds.remove(botUuid);
        if (prev != null) Bukkit.getScheduler().cancelTask(prev);

        fp.setChatEnabled(false);
        Config.debugChat(fp.getName() + " muted" + (seconds > 0 ? " for " + seconds + "s" : " permanently"));

        if (seconds > 0) {
            int taskId = Bukkit.getScheduler().runTaskLater(plugin, () -> {
                muteTaskIds.remove(botUuid);
                FakePlayer b = manager.getByUuid(botUuid);
                if (b != null) {
                    b.setChatEnabled(true);
                    Config.debugChat(b.getName() + " mute expired вҖ” chat re-enabled");
                }
            }, (long) seconds * 20L).getTaskId();
            muteTaskIds.put(botUuid, taskId);
        }
    }

    // в”Җв”Җ Public static dispatch API в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Dispatches a bot chat message through the server's real chat pipeline
     * <b>without</b> the {@code [Not Secure]} label that {@link Player#chat(String)}
     * appends in Paper 1.19+ for unsigned messages.
     *
     * <p>Fires {@link AsyncChatEvent} with {@code async=false} (safe from the main
     * thread) so chat-formatting plugins (EssentialsChat, VentureChat, etc.) receive
     * and process the event normally.  Broadcasting is handled directly via
     * {@link Audience#sendMessage}, bypassing the NMS {@code broadcastChatMessage()}
     * path that writes {@code [Not Secure]} to the console log.
     *
     * <p>Falls back to {@link Player#chat(String)} if Paper API is unavailable.
     *
     * @param player     the bot's live {@link Player} entity
     * @param rawMessage resolved message text (placeholders already substituted)
     */
    public static void dispatchChat(Player player, String rawMessage) {
        try {
            // Initial viewer set: all online players + console.
            Set<Audience> viewers = new LinkedHashSet<>(Bukkit.getOnlinePlayers());
            viewers.add(Bukkit.getConsoleSender());

            Component message = Component.text(rawMessage);

            @SuppressWarnings("UnstableApiUsage")
            AsyncChatEvent event = new AsyncChatEvent(
                    false, player, viewers,
                    ChatRenderer.defaultRenderer(),
                    message, message, null);

            Bukkit.getPluginManager().callEvent(event);

            if (!event.isCancelled()) {
                Component displayName = player.displayName();
                for (Audience viewer : event.viewers()) {
                    viewer.sendMessage(
                            event.renderer().render(player, displayName, event.message(), viewer));
                }
            }
        } catch (Throwable t) {
            Config.debugChat("AsyncChatEvent dispatch failed (" + t.getMessage()
                    + ") вҖ” falling back to player.chat()");
            player.chat(rawMessage);
        }
    }

    /**
     * Broadcasts a bot chat message received from another server via plugin messaging.
     *
     * <p>Uses the configurable {@code fake-chat.remote-format} template.
     *
     * <p><b>Loop prevention:</b> sets {@link #isRemoteBroadcast} so the message is
     * NOT re-forwarded via plugin messaging.
     *
     * @param botName        internal bot name
     * @param botDisplayName display name with prefix / formatting
     * @param message        the resolved message text
     * @param prefix         unused вҖ” kept for wire-format compatibility
     * @param suffix         unused вҖ” kept for wire-format compatibility
     */
    public static void broadcastRemote(String botName, String botDisplayName,
                                       String message, String prefix, String suffix) {
        if (!Config.fakeChatEnabled()) {
            Config.debugChat("Remote message dropped (bot chat disabled).");
            return;
        }
        isRemoteBroadcast.set(true);
        try {
            broadcastFormatted(botDisplayName, message);
            Config.debugChat("Broadcast remote message from bot '" + botName + "'.");
        } finally {
            isRemoteBroadcast.remove();
        }
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Returns {@code true} when at least one non-bot player is currently online.
     */
    private boolean hasRealPlayerOnline() {
        for (Player p : Bukkit.getOnlinePlayers()) {
            if (manager.getByUuid(p.getUniqueId()) == null) return true;
        }
        return false;
    }

    /**
     * Resolves the {@code {random_player}} placeholder.
     * Prefers real (non-bot) players; falls back to other bots, then the bot itself.
     */
    private String resolveRandomPlayer(FakePlayer self) {
        List<String> real = new ArrayList<>();
        for (Player p : Bukkit.getOnlinePlayers()) {
            if (manager.getByUuid(p.getUniqueId()) == null) real.add(p.getName());
        }
        if (!real.isEmpty())
            return real.get(ThreadLocalRandom.current().nextInt(real.size()));

        List<FakePlayer> others = new ArrayList<>(manager.getActivePlayers());
        others.removeIf(fp -> fp.getUuid().equals(self.getUuid()));
        if (!others.isEmpty())
            return others.get(ThreadLocalRandom.current().nextInt(others.size())).getName();

        return self.getName();
    }
}

package me.bill.fakePlayerPlugin.listener;

import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.EventPriority;
import org.bukkit.event.Listener;
import org.bukkit.event.player.PlayerCommandPreprocessEvent;
import org.bukkit.persistence.PersistentDataType;

/**
 * Prevents fake player bots from executing any commands.
 *
 * <p>Bots are NMS ServerPlayer entities and may trigger command events
 * if external plugins or mods attempt to force-run commands on them.
 * This listener blocks all command attempts by bots at the highest priority
 * to ensure they cannot execute commands under any circumstances.
 */
public class BotCommandBlocker implements Listener {

    @EventHandler(priority = EventPriority.LOWEST)
    public void onBotCommand(PlayerCommandPreprocessEvent event) {
        Player player = event.getPlayer();

        // Check if this is a bot by looking for the FPP PDC marker
        if (FakePlayerManager.FAKE_PLAYER_KEY == null) return;

        String marker = player.getPersistentDataContainer()
                .get(FakePlayerManager.FAKE_PLAYER_KEY, PersistentDataType.STRING);

        // If this player is marked as an FPP bot, cancel the command
        if (marker != null && marker.startsWith("fpp-visual:")) {
            event.setCancelled(true);
        }
    }
}

package me.bill.fakePlayerPlugin.listener;

import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.EventPriority;
import org.bukkit.event.Listener;
import org.bukkit.event.player.PlayerCommandPreprocessEvent;
import org.bukkit.event.player.PlayerCommandSendEvent;
import org.bukkit.persistence.PersistentDataType;

/**
 * Prevents fake player bots from executing any commands.
 * 
 * <p>Bots are NMS ServerPlayer entities and may trigger command events
 * if external plugins or mods attempt to force-run commands on them.
 * This listener blocks ALL command execution paths including:
 * <ul>
 *   <li>Direct command typing</li>
 *   <li>Commands executed via {@code Player.performCommand()}</li>
 *   <li>Commands executed via {@code Bukkit.dispatchCommand()}</li>
 *   <li>Auto-command plugins (first join, scheduled commands, etc.)</li>
 *   <li>Command suggestions and tab-completion</li>
 * </ul>
 * 
 * <p>Uses multiple event priorities and {@code ignoreCancelled = false}
 * to ensure bots cannot execute commands under any circumstances.
 */
public class BotCommandBlocker implements Listener {

    /**
     * Blocks command execution at the earliest possible stage.
     * Uses LOWEST priority and ignoreCancelled = false to catch commands
     * before any other plugin can process them, including auto-command plugins.
     */
    @EventHandler(priority = EventPriority.LOWEST, ignoreCancelled = false)
    public void onBotCommandEarly(PlayerCommandPreprocessEvent event) {
        if (isFppBot(event.getPlayer())) {
            event.setCancelled(true);
            Config.debugNms("BotCommandBlocker: blocked command (LOWEST) for " 
                    + event.getPlayer().getName() + ": " + event.getMessage());
        }
    }

    /**
     * Blocks command execution at the highest priority as a safety net.
     * Catches any commands that somehow bypassed the LOWEST priority handler.
     */
    @EventHandler(priority = EventPriority.HIGHEST, ignoreCancelled = false)
    public void onBotCommandLate(PlayerCommandPreprocessEvent event) {
        if (isFppBot(event.getPlayer())) {
            event.setCancelled(true);
            Config.debugNms("BotCommandBlocker: blocked command (HIGHEST) for " 
                    + event.getPlayer().getName() + ": " + event.getMessage());
        }
    }

    /**
     * Blocks command execution at MONITOR priority as final safeguard.
     * This ensures bots cannot execute commands even if another plugin
     * un-cancels the event at a lower priority.
     */
    @EventHandler(priority = EventPriority.MONITOR, ignoreCancelled = false)
    public void onBotCommandMonitor(PlayerCommandPreprocessEvent event) {
        if (isFppBot(event.getPlayer())) {
            if (!event.isCancelled()) {
                event.setCancelled(true);
                Config.debugNms("BotCommandBlocker: blocked command (MONITOR) for " 
                        + event.getPlayer().getName() + ": " + event.getMessage());
            }
        }
    }

    /**
     * Prevents bots from receiving command suggestions and tab-completion.
     * This clears the command list so auto-command plugins cannot discover
     * or suggest commands to bots.
     */
    @EventHandler(priority = EventPriority.LOWEST)
    public void onBotCommandSend(PlayerCommandSendEvent event) {
        if (isFppBot(event.getPlayer())) {
            event.getCommands().clear();
            Config.debugNms("BotCommandBlocker: cleared command suggestions for " 
                    + event.getPlayer().getName());
        }
    }

    /**
     * Checks if the given player is an FPP bot by looking for the PDC marker.
     */
    private static boolean isFppBot(Player player) {
        if (FakePlayerManager.FAKE_PLAYER_KEY == null) return false;
        String marker = player.getPersistentDataContainer()
                .get(FakePlayerManager.FAKE_PLAYER_KEY, PersistentDataType.STRING);
        return marker != null && marker.startsWith("fpp-visual:");
    }
}

package me.bill.fakePlayerPlugin.fakeplayer;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.database.DatabaseManager;
import me.bill.fakePlayerPlugin.util.FppLogger;
import org.bukkit.configuration.file.YamlConfiguration;

import java.io.File;
import java.io.IOException;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Persistent identity registry that maps a bot name (scoped to this server) to a
 * stable UUID.
 *
 * <p>When a bot with a given name is first spawned, a random UUID is generated and
 * stored.  On every subsequent spawn with the same name on the same server, the same
 * UUID is returned.  This keeps LuckPerms group assignments, inventory data, and
 * database session history all linked to one consistent identity вҖ” bots never look
 * like "new players" on server restart.
 *
 * <h3>Storage priority</h3>
 * <ol>
 *   <li><b>In-memory cache</b> вҖ” populated at startup and on every first-use; always
 *       consulted first so lookups are O(1) and non-blocking.</li>
 *   <li><b>Database table {@code fpp_bot_identities}</b> вҖ” primary persistent store
 *       when the database is enabled.  Synchronous reads are used only during spawns,
 *       which are infrequent enough that the latency is negligible.</li>
 *   <li><b>YAML file {@code data/bot-identities.yml}</b> вҖ” fallback when the database
 *       is disabled; auto-created on first use and updated whenever a new mapping is
 *       created.</li>
 * </ol>
 *
 * <h3>Identity scope</h3>
 * Each mapping is scoped to the current {@code database.server-id} (read from
 * {@link Config#serverId()}).  The same bot name on two different servers produces
 * two independent UUIDs вҖ” correct behaviour for proxy setups.  The YAML fallback is
 * per-installation (one file per server folder) so it is naturally scoped.
 *
 * <h3>Thread safety</h3>
 * The in-memory cache is a {@link ConcurrentHashMap}.  The YAML file is written only
 * from the main thread.  Database reads are synchronous main-thread calls; writes are
 * enqueued to the DB write thread via {@link DatabaseManager#registerBotUuid}.
 */
public final class BotIdentityCache {

    private static final String YAML_FILE = "bot-identities.yml";

    private final DatabaseManager  db;         // may be null
    private final File             yamlFile;

    /**
     * In-memory cache keyed by lower-case bot name.
     * Server scope is implicit вҖ” one cache instance per running server.
     */
    private final Map<String, UUID> cache = new ConcurrentHashMap<>();

    /** Lazily-loaded YAML config used when {@link #db} is {@code null}. */
    private YamlConfiguration yamlConfig = null;

    // в”Җв”Җ Lifecycle в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * @param plugin the FPP plugin instance
     * @param db     the active {@link DatabaseManager}, or {@code null} if the
     *               database is disabled вҖ” the YAML fallback will be used instead
     */
    public BotIdentityCache(FakePlayerPlugin plugin, DatabaseManager db) {
        this.db       = db;
        this.yamlFile = new File(new File(plugin.getDataFolder(), "data"), YAML_FILE);

        if (db == null) {
            // Pre-load the YAML now so lookups don't require disk I/O later
            loadYaml();
        }
    }

    // в”Җв”Җ Public API в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Returns the stored UUID for {@code botName} on the current server.
     * If no mapping exists yet, a new random UUID is generated, persisted, and returned.
     *
     * <p><b>Must be called on the main thread</b> вҖ” the DB read path is synchronous.
     *
     * @param botName the bot's Minecraft username (exact case as used in the
     *                {@link com.destroystokyo.paper.profile.PlayerProfile})
     * @return the stable UUID for this bot name + server combination
     */
    public UUID lookupOrCreate(String botName) {
        String key = botName.toLowerCase();

        // 1. Hot path вҖ” in-memory cache
        UUID cached = cache.get(key);
        if (cached != null) return cached;

        // 2. Persistent store
        UUID resolved;
        if (db != null) {
            resolved = lookupOrCreateDb(botName, key);
        } else {
            resolved = lookupOrCreateYaml(botName, key);
        }

        cache.put(key, resolved);
        return resolved;
    }

    /**
     * Pre-populates the in-memory cache with a known mapping.
     *
     * <p>Called from {@link FakePlayerManager#spawnRestored} so that bots restored
     * from persistence (which already have a stored UUID) are remembered for the
     * lifetime of this session without hitting the DB a second time.
     * Also called when a fresh spawn registers a new UUID so that subsequent
     * lookups for the same name are instant.
     *
     * @param botName the bot's exact Minecraft username
     * @param uuid    the UUID to associate with that name on this server
     */
    public void prime(String botName, UUID uuid) {
        if (botName == null || uuid == null) return;
        cache.put(botName.toLowerCase(), uuid);
    }

    // в”Җв”Җ Database path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private UUID lookupOrCreateDb(String botName, String cacheKey) {
        String serverId = Config.serverId();

        // Synchronous DB read вҖ” fast primary-key lookup, safe on main thread for spawns
        UUID fromDb = db.lookupBotUuid(botName, serverId);
        if (fromDb != null) {
            Config.debugDatabase("BotIdentityCache: DB hit for '" + botName + "' вҶ’ " + fromDb);
            return fromDb;
        }

        // Not found вҖ” create, persist, return
        UUID fresh = UUID.randomUUID();
        db.registerBotUuid(botName, fresh, serverId);
        Config.debugDatabase("BotIdentityCache: new identity for '" + botName + "' вҶ’ " + fresh);
        return fresh;
    }

    // в”Җв”Җ YAML fallback path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Loads {@code data/bot-identities.yml} into memory.
     * Called once at construction time when the DB is disabled.
     */
    private void loadYaml() {
        if (!yamlFile.exists()) {
            yamlConfig = new YamlConfiguration();
            Config.debugDatabase("BotIdentityCache: no YAML file yet вҖ” will create on first spawn.");
            return;
        }
        yamlConfig = YamlConfiguration.loadConfiguration(yamlFile);
        int loaded = 0;
        for (String key : yamlConfig.getKeys(false)) {
            String val = yamlConfig.getString(key);
            if (val == null || val.isBlank()) continue;
            try {
                cache.put(key, UUID.fromString(val));
                loaded++;
            } catch (IllegalArgumentException e) {
                FppLogger.warn("BotIdentityCache: skipping malformed entry '" + key + "': " + val);
            }
        }
        if (loaded > 0) {
            FppLogger.info("BotIdentityCache: loaded " + loaded + " nameвҶ’UUID mapping(s) from "
                    + YAML_FILE + ".");
        }
    }

    private UUID lookupOrCreateYaml(String botName, String cacheKey) {
        if (yamlConfig == null) yamlConfig = new YamlConfiguration();

        String stored = yamlConfig.getString(cacheKey);
        if (stored != null && !stored.isBlank()) {
            try {
                UUID fromYaml = UUID.fromString(stored);
                Config.debugDatabase("BotIdentityCache: YAML hit for '" + botName + "' вҶ’ " + fromYaml);
                return fromYaml;
            } catch (IllegalArgumentException e) {
                FppLogger.warn("BotIdentityCache: malformed YAML entry for '" + botName + "' вҖ” regenerating UUID.");
            }
        }

        UUID fresh = UUID.randomUUID();
        yamlConfig.set(cacheKey, fresh.toString());
        saveYaml();
        Config.debugDatabase("BotIdentityCache: new YAML identity for '" + botName + "' вҶ’ " + fresh);
        return fresh;
    }

    private void saveYaml() {
        try {
            // Ensure parent directory exists
            File parent = yamlFile.getParentFile();
            if (parent != null && !parent.exists()) parent.mkdirs();
            yamlConfig.save(yamlFile);
        } catch (IOException e) {
            FppLogger.warn("BotIdentityCache: failed to save " + YAML_FILE + ": " + e.getMessage());
        }
    }
}

package me.bill.fakePlayerPlugin.fakeplayer;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.database.DatabaseManager;
import me.bill.fakePlayerPlugin.util.FppLogger;
import org.bukkit.configuration.file.YamlConfiguration;

import java.io.File;
import java.io.IOException;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Persistent identity registry that maps a bot name (scoped to this server) to a
 * stable UUID.
 *
 * <p>When a bot with a given name is first spawned, a random UUID is generated and
 * stored.  On every subsequent spawn with the same name on the same server, the same
 * UUID is returned.  This keeps LuckPerms group assignments, inventory data, and
 * database session history all linked to one consistent identity вҖ” bots never look
 * like "new players" on server restart.
 *
 * <h3>Storage priority</h3>
 * <ol>
 *   <li><b>In-memory cache</b> вҖ” populated at startup and on every first-use; always
 *       consulted first so lookups are O(1) and non-blocking.</li>
 *   <li><b>Database table {@code fpp_bot_identities}</b> вҖ” primary persistent store
 *       when the database is enabled.  Synchronous reads are used only during spawns,
 *       which are infrequent enough that the latency is negligible.</li>
 *   <li><b>YAML file {@code data/bot-identities.yml}</b> вҖ” fallback when the database
 *       is disabled; auto-created on first use and updated whenever a new mapping is
 *       created.</li>
 * </ol>
 *
 * <h3>Identity scope</h3>
 * Each mapping is scoped to the current {@code database.server-id} (read from
 * {@link Config#serverId()}).  The same bot name on two different servers produces
 * two independent UUIDs вҖ” correct behaviour for proxy setups.  The YAML fallback is
 * per-installation (one file per server folder) so it is naturally scoped.
 *
 * <h3>Thread safety</h3>
 * The in-memory cache is a {@link ConcurrentHashMap}.  The YAML file is written only
 * from the main thread.  Database reads are synchronous main-thread calls; writes are
 * enqueued to the DB write thread via {@link DatabaseManager#registerBotUuid}.
 */
public final class BotIdentityCache {

    private static final String YAML_FILE = "bot-identities.yml";

    private final DatabaseManager  db;         // may be null
    private final File             yamlFile;

    /**
     * In-memory cache keyed by lower-case bot name.
     * Server scope is implicit вҖ” one cache instance per running server.
     */
    private final Map<String, UUID> cache = new ConcurrentHashMap<>();

    /** Lazily-loaded YAML config used when {@link #db} is {@code null}. */
    private YamlConfiguration yamlConfig = null;

    // в”Җв”Җ Lifecycle в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * @param plugin the FPP plugin instance
     * @param db     the active {@link DatabaseManager}, or {@code null} if the
     *               database is disabled вҖ” the YAML fallback will be used instead
     */
    public BotIdentityCache(FakePlayerPlugin plugin, DatabaseManager db) {
        this.db       = db;
        this.yamlFile = new File(new File(plugin.getDataFolder(), "data"), YAML_FILE);

        if (db == null) {
            // Pre-load the YAML now so lookups don't require disk I/O later
            loadYaml();
        }
    }

    // в”Җв”Җ Public API в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Returns the stored UUID for {@code botName} on the current server.
     * If no mapping exists yet, a new random UUID is generated, persisted, and returned.
     *
     * <p><b>Must be called on the main thread</b> вҖ” the DB read path is synchronous.
     *
     * @param botName the bot's Minecraft username (exact case as used in the
     *                {@link com.destroystokyo.paper.profile.PlayerProfile})
     * @return the stable UUID for this bot name + server combination
     */
    public UUID lookupOrCreate(String botName) {
        String key = botName.toLowerCase();

        // 1. Hot path вҖ” in-memory cache
        UUID cached = cache.get(key);
        if (cached != null) return cached;

        // 2. Persistent store
        UUID resolved;
        if (db != null) {
            resolved = lookupOrCreateDb(botName);
        } else {
            resolved = lookupOrCreateYaml(botName, key);
        }

        cache.put(key, resolved);
        return resolved;
    }

    /**
     * Pre-populates the in-memory cache with a known mapping.
     *
     * <p>Called from {@link FakePlayerManager#spawnRestored} so that bots restored
     * from persistence (which already have a stored UUID) are remembered for the
     * lifetime of this session without hitting the DB a second time.
     * Also called when a fresh spawn registers a new UUID so that subsequent
     * lookups for the same name are instant.
     *
     * @param botName the bot's exact Minecraft username
     * @param uuid    the UUID to associate with that name on this server
     */
    public void prime(String botName, UUID uuid) {
        if (botName == null || uuid == null) return;
        cache.put(botName.toLowerCase(), uuid);
    }

    // в”Җв”Җ Database path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private UUID lookupOrCreateDb(String botName, String cacheKey) {
        String serverId = Config.serverId();

        // Synchronous DB read вҖ” fast primary-key lookup, safe on main thread for spawns
        UUID fromDb = db.lookupBotUuid(botName, serverId);
        if (fromDb != null) {
            Config.debugDatabase("BotIdentityCache: DB hit for '" + botName + "' вҶ’ " + fromDb);
            return fromDb;
        }

        // Not found вҖ” create, persist, return
        UUID fresh = UUID.randomUUID();
        db.registerBotUuid(botName, fresh, serverId);
        Config.debugDatabase("BotIdentityCache: new identity for '" + botName + "' вҶ’ " + fresh);
        return fresh;
    }

    // в”Җв”Җ YAML fallback path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Loads {@code data/bot-identities.yml} into memory.
     * Called once at construction time when the DB is disabled.
     */
    private void loadYaml() {
        if (!yamlFile.exists()) {
            yamlConfig = new YamlConfiguration();
            Config.debugDatabase("BotIdentityCache: no YAML file yet вҖ” will create on first spawn.");
            return;
        }
        yamlConfig = YamlConfiguration.loadConfiguration(yamlFile);
        int loaded = 0;
        for (String key : yamlConfig.getKeys(false)) {
            String val = yamlConfig.getString(key);
            if (val == null || val.isBlank()) continue;
            try {
                cache.put(key, UUID.fromString(val));
                loaded++;
            } catch (IllegalArgumentException e) {
                FppLogger.warn("BotIdentityCache: skipping malformed entry '" + key + "': " + val);
            }
        }
        if (loaded > 0) {
            FppLogger.info("BotIdentityCache: loaded " + loaded + " nameвҶ’UUID mapping(s) from "
                    + YAML_FILE + ".");
        }
    }

    private UUID lookupOrCreateYaml(String botName, String cacheKey) {
        if (yamlConfig == null) yamlConfig = new YamlConfiguration();

        String stored = yamlConfig.getString(cacheKey);
        if (stored != null && !stored.isBlank()) {
            try {
                UUID fromYaml = UUID.fromString(stored);
                Config.debugDatabase("BotIdentityCache: YAML hit for '" + botName + "' вҶ’ " + fromYaml);
                return fromYaml;
            } catch (IllegalArgumentException e) {
                FppLogger.warn("BotIdentityCache: malformed YAML entry for '" + botName + "' вҖ” regenerating UUID.");
            }
        }

        UUID fresh = UUID.randomUUID();
        yamlConfig.set(cacheKey, fresh.toString());
        saveYaml();
        Config.debugDatabase("BotIdentityCache: new YAML identity for '" + botName + "' вҶ’ " + fresh);
        return fresh;
    }

    private void saveYaml() {
        try {
            // Ensure parent directory exists
            File parent = yamlFile.getParentFile();
            if (parent != null && !parent.exists()) parent.mkdirs();
            yamlConfig.save(yamlFile);
        } catch (IOException e) {
            FppLogger.warn("BotIdentityCache: failed to save " + YAML_FILE + ": " + e.getMessage());
        }
    }
}

package me.bill.fakePlayerPlugin.fakeplayer;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.util.FppLogger;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.NamespacedKey;
import org.bukkit.World;
import org.bukkit.configuration.file.YamlConfiguration;
import org.bukkit.persistence.PersistentDataType;

import java.io.File;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

/**
 * Saves the list of active fake players to disk on shutdown and reloads
 * them on the next startup, so bots persist across server restarts.
 *
 * <p>Storage: {@code plugins/FakePlayerPlugin/data/active-bots.yml}
 *
 * <p>Each entry stores:
 * <ul>
 *   <li>Bot name</li>
 *   <li>Spawn world + coordinates + yaw/pitch</li>
 *   <li>Who originally spawned it</li>
 *   <li>The bot's UUID (reused on restore so DB records stay linked)</li>
 * </ul>
 */
public final class BotPersistence {

    private static final String FILE_NAME = "active-bots.yml";

    private final File           dataFile;
    private final FakePlayerPlugin plugin;

    public BotPersistence(FakePlayerPlugin plugin) {
        this.plugin   = plugin;
        File dataDir  = new File(plugin.getDataFolder(), "data");
        if (!dataDir.exists() && !dataDir.mkdirs()) {
            FppLogger.warn("BotPersistence: could not create data directory: " + dataDir.getAbsolutePath());
        }
        this.dataFile = new File(dataDir, FILE_NAME);
    }

    // в”Җв”Җ Save в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Writes all currently active fake players to {@code active-bots.yml}.
     * Called from {@code onDisable} before entities are removed.
     */
    public void save(Iterable<FakePlayer> players) {
        saveInternal(players);
    }

    /**
     * Saves the active bot list asynchronously so it can be called after every
     * spawn/remove without stalling the main thread. This ensures the file is
     * always up-to-date even if the server crashes.
     */
    public void saveAsync(Iterable<FakePlayer> players) {
        // Snapshot locations on the main thread first (entity access is not thread-safe)
        List<Object> list = buildList(players);
        Bukkit.getScheduler().runTaskAsynchronously(plugin, () -> {
            YamlConfiguration yaml = new YamlConfiguration();
            yaml.set("bots", list);
            try {
                yaml.save(dataFile);
            } catch (IOException e) {
                FppLogger.error("Failed to auto-save active bots: " + e.getMessage());
            }
        });
    }

    private void saveInternal(Iterable<FakePlayer> players) {
        YamlConfiguration yaml = new YamlConfiguration();
        yaml.set("bots", buildList(players));
        try {
            yaml.save(dataFile);
            FppLogger.info("Saved bot list to " + FILE_NAME + ".");
        } catch (IOException e) {
            FppLogger.error("Failed to save active bots: " + e.getMessage());
        }
    }

    private List<Object> buildList(Iterable<FakePlayer> players) {
        List<Object> list = new ArrayList<>();
        for (FakePlayer fp : players) {
            org.bukkit.entity.Entity body = fp.getPhysicsEntity();
            Location loc = (body != null && body.isValid())
                    ? body.getLocation()
                    : fp.getSpawnLocation();
            if (loc == null || loc.getWorld() == null) continue;

            var section = new java.util.LinkedHashMap<String, Object>();
            section.put("name",            fp.getName());
            section.put("uuid",            fp.getUuid().toString());
            section.put("display-name",    fp.getDisplayName());
            section.put("spawned-by",      fp.getSpawnedBy());
            section.put("spawned-by-uuid", fp.getSpawnedByUuid().toString());
            section.put("world",           loc.getWorld().getName());
            section.put("x",               loc.getX());
            section.put("y",               loc.getY());
            section.put("z",               loc.getZ());
            section.put("yaw",             (double) loc.getYaw());
            section.put("pitch",           (double) loc.getPitch());
            list.add(section);
        }
        return list;
    }

    // в”Җв”Җ Restore в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Reads {@code active-bots.yml} and schedules a staggered restore of all
     * saved bots. The file is deleted after loading so bots only restore once.
     *
     * <p>Called from {@code onEnable} вҖ” deferred by 40 ticks (2 seconds) to
     * ensure the world is fully loaded before spawning entities.
     */
    public void restore(FakePlayerManager manager) {
        if (!Config.persistOnRestart()) {
            deleteFile(dataFile);
            FppLogger.info("Bot persistence is disabled вҖ” skipping restore.");
            return;
        }

        // Set flag to indicate restoration is in progress вҖ” players joining during this window
        // will defer tab-list syncing until the post-restore prefix refresh completes.
        manager.setRestorationInProgress(true);

        // в”Җв”Җ Primary: restore from database fpp_active_bots в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        me.bill.fakePlayerPlugin.database.DatabaseManager db =
                plugin.getDatabaseManager();
        if (db != null) {
            // ----------------------------------------------------------------
            // DESIGN RULE вҖ” Bots are per-server only.
            // The database may be shared across multiple servers (NETWORK mode),
            // but Minecraft entities (NMS ServerPlayers, PlayerProfiles)
            // are strictly local to the server that originally spawned them.
            // We therefore ALWAYS restore only rows whose server_id matches
            // Config.serverId(), regardless of the database mode.
            // Never attempt to spawn another server's bots on this instance.
            // ----------------------------------------------------------------
            List<me.bill.fakePlayerPlugin.database.DatabaseManager.ActiveBotRow> rows =
                    db.getActiveBotsForThisServer();
            if (!rows.isEmpty()) {
                FppLogger.info("Restoring " + rows.size() + " bot(s) from database (server='"
                        + me.bill.fakePlayerPlugin.config.Config.serverId() + "')...");
                // Clear only this server's rows immediately вҖ” bots are now being restored.
                // Other servers' rows in a shared DB are left untouched.
                db.clearActiveBots();
                // Also discard the YAML file so we don't double-restore
                deleteFile(dataFile);

                List<SavedBot> saved = new ArrayList<>();
                for (var row : rows) {
                    try {
                        saved.add(new SavedBot(
                                row.botName(),
                                UUID.fromString(row.botUuid()),
                                row.botDisplay(),
                                row.spawnedBy(),
                                UUID.fromString(row.spawnedByUuid()),
                                row.world(),
                                row.x(), row.y(), row.z(),
                                row.yaw(), row.pitch(),
                                null   // No LP group from DB - LP handles natively now
                        ));
                    } catch (Exception e) {
                        FppLogger.warn("Skipping malformed DB active-bot row: " + e.getMessage());
                    }
                }
                if (!saved.isEmpty()) {
                    Bukkit.getScheduler().runTaskLater(plugin,
                            () -> restoreChain(manager, saved, 0), 40L);
                }
                return;
            }
        }

        // в”Җв”Җ Fallback: restore from YAML file (no DB or empty active_bots) в”Җв”Җв”Җв”Җ
        if (!dataFile.exists()) return;

        YamlConfiguration yaml = YamlConfiguration.loadConfiguration(dataFile);
        List<?> raw = yaml.getList("bots");
        if (raw == null || raw.isEmpty()) { deleteFile(dataFile); return; }

        List<SavedBot> saved = new ArrayList<>();
        for (Object obj : raw) {
            if (!(obj instanceof java.util.Map<?, ?> map)) continue;
            try {
                String name          = (String) map.get("name");
                UUID   uuid          = UUID.fromString((String) map.get("uuid"));
                String displayName   = (String) map.get("display-name");  // Load saved display name
                Object sbRaw         = map.get("spawned-by");
                String spawnedBy     = sbRaw instanceof String s ? s : "SERVER";
                Object sbuRaw        = map.get("spawned-by-uuid");
                UUID   spawnedByUuid = sbuRaw instanceof String str
                        ? UUID.fromString(str) : new UUID(0, 0);
                String worldName     = (String) map.get("world");
                double x             = toDouble(map.get("x"));
                double y             = toDouble(map.get("y"));
                double z             = toDouble(map.get("z"));
                float  yaw           = (float) toDouble(map.get("yaw"));
                float  pitch         = (float) toDouble(map.get("pitch"));
                if (name == null || worldName == null) continue;
                saved.add(new SavedBot(name, uuid, displayName, spawnedBy, spawnedByUuid,
                        worldName, x, y, z, yaw, pitch, null)); // No LP group from YAML
            } catch (Exception e) {
                FppLogger.warn("Skipping malformed bot entry in " + FILE_NAME + ": " + e.getMessage());
            }
        }
        deleteFile(dataFile);
        if (saved.isEmpty()) return;

        FppLogger.info("Restoring " + saved.size() + " bot(s) from YAML fallback...");
        Bukkit.getScheduler().runTaskLater(plugin,
                () -> restoreChain(manager, saved, 0), 40L);
    }

    /** Spawns one saved bot and schedules the next with a random join-delay. */
    private void restoreChain(FakePlayerManager manager, List<SavedBot> saved, int index) {
        if (index >= saved.size()) {
            // All bots have been queued вҖ” signal that restoration is complete.
            manager.setRestorationInProgress(false);
            FppLogger.info("Bot restoration complete: " + saved.size() + " bot(s) restored.");
            return;
        }

        SavedBot sb = saved.get(index);

        World world = Bukkit.getWorld(sb.worldName);
        if (world == null) {
            FppLogger.warn("Cannot restore bot '" + sb.name
                    + "' вҖ” world '" + sb.worldName + "' not found. Skipping.");
            restoreChain(manager, saved, index + 1);
            return;
        }

        Location loc = new Location(world, sb.x, sb.y, sb.z, sb.yaw, sb.pitch);

        // Spawn with restored UUID, display name, and LP group override
        manager.spawnRestored(sb.name, sb.uuid, sb.displayName, sb.spawnedBy, sb.spawnedByUuid, loc, sb.luckpermsGroup);

        // Stagger: use the configured join-delay range вҖ” values are TICKS (20 = 1 second)
        int delayMinTicks = Config.joinDelayMin();
        int delayMaxTicks = Math.max(delayMinTicks, Config.joinDelayMax());
        long delayTicks;
        if (delayMaxTicks <= 0) {
            delayTicks = 1L; // at least 1 tick so world updates propagate
        } else {
            int spread = delayMaxTicks - delayMinTicks;
            int t = delayMinTicks + (spread > 0
                    ? java.util.concurrent.ThreadLocalRandom.current().nextInt(spread + 1)
                    : 0);
            delayTicks = Math.max(1L, (long) t);
        }

        Bukkit.getScheduler().runTaskLater(plugin,
                () -> restoreChain(manager, saved, index + 1), delayTicks);
    }

    // в”Җв”Җ Purge + Restore в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Entry point called from {@code onEnable}.
     * <ol>
     *   <li>Sweeps every loaded world for NMS ServerPlayer entities tagged with
     *       {@link FakePlayerManager#FAKE_PLAYER_KEY} and removes them.
     *       This cleans up bodies left by a crash before restoration runs.</li>
     *   <li>Then calls {@link #restore(FakePlayerManager)} to spawn bots from
     *       the persistence file.</li>
     * </ol>
     */
    public void purgeOrphanedBodiesAndRestore(FakePlayerManager manager) {
        // Defer so worlds are fully loaded (same as restore)
        Bukkit.getScheduler().runTaskLater(plugin, () -> {
            purgeOrphanedBodies();
            // Restore after a further tick so the purge entity removal is flushed
            Bukkit.getScheduler().runTaskLater(plugin, () ->
                    restore(manager), 5L);
        }, 40L);
    }

    /**
     * Removes every NMS ServerPlayer in all loaded worlds that carries the FPP PDC tag
     * but is not registered in the active bot map (i.e. a crash remnant).
     */
    private void purgeOrphanedBodies() {
        NamespacedKey key = FakePlayerManager.FAKE_PLAYER_KEY;
        if (key == null) return;

        int removed = 0;
        for (org.bukkit.World world : org.bukkit.Bukkit.getWorlds()) {
            for (org.bukkit.entity.Entity entity : world.getEntities()) {
                if (!entity.getPersistentDataContainer().has(key, PersistentDataType.STRING)) continue;
                String val = entity.getPersistentDataContainer().get(key, PersistentDataType.STRING);
                // Matches NMS ServerPlayer bodies
                if (val != null) {
                    entity.remove();
                    removed++;
                    Config.debug("Purged orphaned entity: " + val);
                }
            }
        }
        if (removed > 0) {
            FppLogger.info("Purged " + removed + " orphaned bot entity/entities from previous session.");
        }
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static double toDouble(Object o) {
        if (o instanceof Number n) return n.doubleValue();
        return 0.0;
    }

    /** Deletes a file, logging a warning if it fails. */
    private static void deleteFile(File f) {
        if (f.exists() && !f.delete()) {
            FppLogger.warn("BotPersistence: could not delete " + f.getName());
        }
    }

    // в”Җв”Җ Inner record в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private record SavedBot(
            String name, UUID uuid,
            String displayName,  // Saved display name (with prefix) for restoration
            String spawnedBy, UUID spawnedByUuid,
            String worldName,
            double x, double y, double z,
            float yaw, float pitch,
            String luckpermsGroup  // LP group override, null for default
    ) {}
}

package me.bill.fakePlayerPlugin.fakeplayer;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.util.FppLogger;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.NamespacedKey;
import org.bukkit.World;
import org.bukkit.configuration.file.YamlConfiguration;
import org.bukkit.persistence.PersistentDataType;

import java.io.File;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

/**
 * Saves the list of active fake players to disk on shutdown and reloads
 * them on the next startup, so bots persist across server restarts.
 *
 * <p>Storage: {@code plugins/FakePlayerPlugin/data/active-bots.yml}
 *
 * <p>Each entry stores:
 * <ul>
 *   <li>Bot name</li>
 *   <li>Spawn world + coordinates + yaw/pitch</li>
 *   <li>Who originally spawned it</li>
 *   <li>The bot's UUID (reused on restore so DB records stay linked)</li>
 * </ul>
 */
public final class BotPersistence {

    private static final String FILE_NAME = "active-bots.yml";

    private final File           dataFile;
    private final FakePlayerPlugin plugin;

    public BotPersistence(FakePlayerPlugin plugin) {
        this.plugin   = plugin;
        File dataDir  = new File(plugin.getDataFolder(), "data");
        if (!dataDir.exists() && !dataDir.mkdirs()) {
            FppLogger.warn("BotPersistence: could not create data directory: " + dataDir.getAbsolutePath());
        }
        this.dataFile = new File(dataDir, FILE_NAME);
    }

    // в”Җв”Җ Save в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Writes all currently active fake players to {@code active-bots.yml}.
     * Called from {@code onDisable} before entities are removed.
     */
    public void save(Iterable<FakePlayer> players) {
        saveInternal(players);
    }

    /**
     * Saves the active bot list asynchronously so it can be called after every
     * spawn/remove without stalling the main thread. This ensures the file is
     * always up-to-date even if the server crashes.
     */
    public void saveAsync(Iterable<FakePlayer> players) {
        // Snapshot locations on the main thread first (entity access is not thread-safe)
        List<Object> list = buildList(players);
        Bukkit.getScheduler().runTaskAsynchronously(plugin, () -> {
            YamlConfiguration yaml = new YamlConfiguration();
            yaml.set("bots", list);
            try {
                yaml.save(dataFile);
            } catch (IOException e) {
                FppLogger.error("Failed to auto-save active bots: " + e.getMessage());
            }
        });
    }

    private void saveInternal(Iterable<FakePlayer> players) {
        YamlConfiguration yaml = new YamlConfiguration();
        yaml.set("bots", buildList(players));
        try {
            yaml.save(dataFile);
            FppLogger.info("Saved bot list to " + FILE_NAME + ".");
        } catch (IOException e) {
            FppLogger.error("Failed to save active bots: " + e.getMessage());
        }
    }

    private List<Object> buildList(Iterable<FakePlayer> players) {
        List<Object> list = new ArrayList<>();
        for (FakePlayer fp : players) {
            org.bukkit.entity.Entity body = fp.getPhysicsEntity();
            Location loc = (body != null && body.isValid())
                    ? body.getLocation()
                    : fp.getSpawnLocation();
            if (loc == null || loc.getWorld() == null) continue;

            var section = new java.util.LinkedHashMap<String, Object>();
            section.put("name",            fp.getName());
            section.put("uuid",            fp.getUuid().toString());
            section.put("display-name",    fp.getDisplayName());
            section.put("spawned-by",      fp.getSpawnedBy());
            section.put("spawned-by-uuid", fp.getSpawnedByUuid().toString());
            section.put("world",           loc.getWorld().getName());
            section.put("x",               loc.getX());
            section.put("y",               loc.getY());
            section.put("z",               loc.getZ());
            section.put("yaw",             (double) loc.getYaw());
            section.put("pitch",           (double) loc.getPitch());
            list.add(section);
        }
        return list;
    }

    // в”Җв”Җ Restore в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Reads {@code active-bots.yml} and schedules a staggered restore of all
     * saved bots. The file is deleted after loading so bots only restore once.
     *
     * <p>Called from {@code onEnable} вҖ” deferred by 40 ticks (2 seconds) to
     * ensure the world is fully loaded before spawning entities.
     */
    public void restore(FakePlayerManager manager) {
        if (!Config.persistOnRestart()) {
            deleteFile(dataFile);
            FppLogger.info("Bot persistence is disabled вҖ” skipping restore.");
            return;
        }

        // Set flag to indicate restoration is in progress вҖ” players joining during this window
        // will defer tab-list syncing until the post-restore prefix refresh completes.
        manager.setRestorationInProgress(true);

        // в”Җв”Җ Primary: restore from database fpp_active_bots в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        me.bill.fakePlayerPlugin.database.DatabaseManager db =
                plugin.getDatabaseManager();
        if (db != null) {
            // ----------------------------------------------------------------
            // DESIGN RULE вҖ” Bots are per-server only.
            // The database may be shared across multiple servers (NETWORK mode),
            // but Minecraft entities (NMS ServerPlayers, PlayerProfiles)
            // are strictly local to the server that originally spawned them.
            // We therefore ALWAYS restore only rows whose server_id matches
            // Config.serverId(), regardless of the database mode.
            // Never attempt to spawn another server's bots on this instance.
            // ----------------------------------------------------------------
            List<me.bill.fakePlayerPlugin.database.DatabaseManager.ActiveBotRow> rows =
                    db.getActiveBotsForThisServer();
            if (!rows.isEmpty()) {
                FppLogger.info("Restoring " + rows.size() + " bot(s) from database (server='"
                        + me.bill.fakePlayerPlugin.config.Config.serverId() + "')...");
                // Clear only this server's rows immediately вҖ” bots are now being restored.
                // Other servers' rows in a shared DB are left untouched.
                db.clearActiveBots();
                // Also discard the YAML file so we don't double-restore
                deleteFile(dataFile);

                List<SavedBot> saved = new ArrayList<>();
                for (var row : rows) {
                    try {
                        saved.add(new SavedBot(
                                row.botName(),
                                UUID.fromString(row.botUuid()),
                                row.botDisplay(),
                                row.spawnedBy(),
                                UUID.fromString(row.spawnedByUuid()),
                                row.world(),
                                row.x(), row.y(), row.z(),
                                row.yaw(), row.pitch(),
                                null   // No LP group from DB - LP handles natively now
                        ));
                    } catch (Exception e) {
                        FppLogger.warn("Skipping malformed DB active-bot row: " + e.getMessage());
                    }
                }
                if (!saved.isEmpty()) {
                    Bukkit.getScheduler().runTaskLater(plugin,
                            () -> restoreChain(manager, saved, 0), 40L);
                }
                return;
            }
        }

        // в”Җв”Җ Fallback: restore from YAML file (no DB or empty active_bots) в”Җв”Җв”Җв”Җ
        if (!dataFile.exists()) return;

        YamlConfiguration yaml = YamlConfiguration.loadConfiguration(dataFile);
        List<?> raw = yaml.getList("bots");
        if (raw == null || raw.isEmpty()) { deleteFile(dataFile); return; }

        List<SavedBot> saved = new ArrayList<>();
        for (Object obj : raw) {
            if (!(obj instanceof java.util.Map<?, ?> map)) continue;
            try {
                String name          = (String) map.get("name");
                UUID   uuid          = UUID.fromString((String) map.get("uuid"));
                String displayName   = (String) map.get("display-name");  // Load saved display name
                Object sbRaw         = map.get("spawned-by");
                String spawnedBy     = sbRaw instanceof String s ? s : "SERVER";
                Object sbuRaw        = map.get("spawned-by-uuid");
                UUID   spawnedByUuid = sbuRaw instanceof String str
                        ? UUID.fromString(str) : new UUID(0, 0);
                String worldName     = (String) map.get("world");
                double x             = toDouble(map.get("x"));
                double y             = toDouble(map.get("y"));
                double z             = toDouble(map.get("z"));
                float  yaw           = (float) toDouble(map.get("yaw"));
                float  pitch         = (float) toDouble(map.get("pitch"));
                if (name == null || worldName == null) continue;
                saved.add(new SavedBot(name, uuid, displayName, spawnedBy, spawnedByUuid,
                        worldName, x, y, z, yaw, pitch, null)); // No LP group from YAML
            } catch (Exception e) {
                FppLogger.warn("Skipping malformed bot entry in " + FILE_NAME + ": " + e.getMessage());
            }
        }
        deleteFile(dataFile);
        if (saved.isEmpty()) return;

        FppLogger.info("Restoring " + saved.size() + " bot(s) from YAML fallback...");
        Bukkit.getScheduler().runTaskLater(plugin,
                () -> restoreChain(manager, saved, 0), 40L);
    }

    /** Spawns one saved bot and schedules the next with a random join-delay. */
    private void restoreChain(FakePlayerManager manager, List<SavedBot> saved, int index) {
        if (index >= saved.size()) {
            // All bots have been queued вҖ” signal that restoration is complete.
            manager.setRestorationInProgress(false);
            FppLogger.info("Bot restoration complete: " + saved.size() + " bot(s) restored.");
            return;
        }

        SavedBot sb = saved.get(index);

        World world = Bukkit.getWorld(sb.worldName);
        if (world == null) {
            FppLogger.warn("Cannot restore bot '" + sb.name
                    + "' вҖ” world '" + sb.worldName + "' not found. Skipping.");
            restoreChain(manager, saved, index + 1);
            return;
        }

        Location loc = new Location(world, sb.x, sb.y, sb.z, sb.yaw, sb.pitch);

        // Spawn with restored UUID and display name
        manager.spawnRestored(sb.name, sb.uuid, sb.displayName, sb.spawnedBy, sb.spawnedByUuid, loc);

        // Stagger: use the configured join-delay range вҖ” values are TICKS (20 = 1 second)
        int delayMinTicks = Config.joinDelayMin();
        int delayMaxTicks = Math.max(delayMinTicks, Config.joinDelayMax());
        long delayTicks;
        if (delayMaxTicks <= 0) {
            delayTicks = 1L; // at least 1 tick so world updates propagate
        } else {
            int spread = delayMaxTicks - delayMinTicks;
            int t = delayMinTicks + (spread > 0
                    ? java.util.concurrent.ThreadLocalRandom.current().nextInt(spread + 1)
                    : 0);
            delayTicks = Math.max(1L, (long) t);
        }

        Bukkit.getScheduler().runTaskLater(plugin,
                () -> restoreChain(manager, saved, index + 1), delayTicks);
    }

    // в”Җв”Җ Purge + Restore в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Entry point called from {@code onEnable}.
     * <ol>
     *   <li>Sweeps every loaded world for NMS ServerPlayer entities tagged with
     *       {@link FakePlayerManager#FAKE_PLAYER_KEY} and removes them.
     *       This cleans up bodies left by a crash before restoration runs.</li>
     *   <li>Then calls {@link #restore(FakePlayerManager)} to spawn bots from
     *       the persistence file.</li>
     * </ol>
     */
    public void purgeOrphanedBodiesAndRestore(FakePlayerManager manager) {
        // Defer so worlds are fully loaded (same as restore)
        Bukkit.getScheduler().runTaskLater(plugin, () -> {
            purgeOrphanedBodies();
            // Restore after a further tick so the purge entity removal is flushed
            Bukkit.getScheduler().runTaskLater(plugin, () ->
                    restore(manager), 5L);
        }, 40L);
    }

    /**
     * Removes every NMS ServerPlayer in all loaded worlds that carries the FPP PDC tag
     * but is not registered in the active bot map (i.e. a crash remnant).
     */
    private void purgeOrphanedBodies() {
        NamespacedKey key = FakePlayerManager.FAKE_PLAYER_KEY;
        if (key == null) return;

        int removed = 0;
        for (org.bukkit.World world : org.bukkit.Bukkit.getWorlds()) {
            for (org.bukkit.entity.Entity entity : world.getEntities()) {
                if (!entity.getPersistentDataContainer().has(key, PersistentDataType.STRING)) continue;
                String val = entity.getPersistentDataContainer().get(key, PersistentDataType.STRING);
                // Matches NMS ServerPlayer bodies
                if (val != null) {
                    entity.remove();
                    removed++;
                    Config.debug("Purged orphaned entity: " + val);
                }
            }
        }
        if (removed > 0) {
            FppLogger.info("Purged " + removed + " orphaned bot entity/entities from previous session.");
        }
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static double toDouble(Object o) {
        if (o instanceof Number n) return n.doubleValue();
        return 0.0;
    }

    /** Deletes a file, logging a warning if it fails. */
    private static void deleteFile(File f) {
        if (f.exists() && !f.delete()) {
            FppLogger.warn("BotPersistence: could not delete " + f.getName());
        }
    }

    // в”Җв”Җ Inner record в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private record SavedBot(
            String name, UUID uuid,
            String displayName,  // Saved display name (with prefix) for restoration
            String spawnedBy, UUID spawnedByUuid,
            String worldName,
            double x, double y, double z,
            float yaw, float pitch,
            String luckpermsGroup  // LP group override, null for default
    ) {}
}

package me.bill.fakePlayerPlugin.fakeplayer;

import org.bukkit.Bukkit;
