        return cfg.getBoolean("peak-hours.enabled", false);
    }

    /**
     * Java {@link java.time.ZoneId} string used to interpret schedule times.
     * Defaults to {@code "UTC"}.  Maps to {@code peak-hours.timezone}.
     */
