     * Map of keyword вҶ’ pool-key for keyword-triggered reactions.
     * Config path: {@code fake-chat.keyword-reactions.keywords}.
     * Example: {@code pvp: "pvp-reactions"}, {@code trade: "trade-reactions"}.
     */
    @SuppressWarnings("unchecked")
    public static java.util.Map<String, String> fakeChatKeywordMap() {
        Object raw = cfg.get("fake-chat.keyword-reactions.keywords");
        if (raw instanceof java.util.Map<?, ?> m) {
            java.util.Map<String, String> result = new java.util.LinkedHashMap<>();
            for (java.util.Map.Entry<?, ?> e : m.entrySet()) {
                if (e.getKey() instanceof String k && e.getValue() instanceof String v) {
                    result.put(k.toLowerCase(), v);
                }
            }
            return result;
        }
        return java.util.Map.of();
    }

    // в”Җв”Җ Database  (database.*) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Use MySQL instead of the built-in SQLite. */
    public static boolean mysqlEnabled()      { return cfg.getBoolean("database.mysql-enabled", false); }
    /** Master toggle to disable database I/O entirely. When false, persistence and DB stats are off. */
    public static boolean databaseEnabled()   { return cfg.getBoolean("database.enabled", true); }

    /**
     * Database mode: {@code "LOCAL"} (default, single-server) or {@code "NETWORK"}
     * (shared database across multiple servers, rows tagged by {@link #serverId()}).
     * Any value other than {@code "NETWORK"} (case-insensitive) is treated as {@code "LOCAL"}.
     */
    public static String databaseMode() {
        String raw = cfg.getString("database.mode", "LOCAL");
        return raw.trim().equalsIgnoreCase("NETWORK") ? "NETWORK" : "LOCAL";
    }

    /**
     * {@code true} when the database is enabled and {@link #databaseMode()} is {@code "NETWORK"}.
     * Use this to enable cross-server features such as per-server row filtering.
     */
    public static boolean isNetworkMode() {
        return databaseEnabled() && databaseMode().equalsIgnoreCase("NETWORK");
    }

    /**
     * Config sync mode: {@code "DISABLED"} (default), {@code "MANUAL"}, {@code "AUTO_PULL"}, or {@code "AUTO_PUSH"}.
     * Controls how config files are synchronized across network servers.
     * Valid values:
     * <ul>
     *   <li>{@code DISABLED} вҖ” No syncing (default for LOCAL mode)</li>
     *   <li>{@code MANUAL} вҖ” Only sync via /fpp sync commands</li>
     *   <li>{@code AUTO_PULL} вҖ” Pull latest on startup/reload</li>
     *   <li>{@code AUTO_PUSH} вҖ” Push changes automatically</li>
     * </ul>
     */
    public static String configSyncMode() {
        String raw = cfg.getString("config-sync.mode", "DISABLED");
        return raw.trim().toUpperCase();
    }

    public static String  mysqlHost()         { return cfg.getString("database.mysql.host", "localhost"); }
    public static int     mysqlPort()         { return cfg.getInt("database.mysql.port", 3306); }
    public static String  mysqlDatabase()     { return cfg.getString("database.mysql.database", "fpp"); }
    public static String  mysqlUsername()     { return cfg.getString("database.mysql.username", "root"); }
    public static String  mysqlPassword()     { return cfg.getString("database.mysql.password", ""); }
    public static boolean mysqlUseSSL()       { return cfg.getBoolean("database.mysql.use-ssl", false); }
    public static int     mysqlPoolSize()     { return cfg.getInt("database.mysql.pool-size", 5); }
    public static int     mysqlConnTimeout()  { return cfg.getInt("database.mysql.connection-timeout", 30000); }

    /** Seconds between batch location flushes to DB. */
    public static int dbLocationFlushInterval() { return cfg.getInt("database.location-flush-interval", 30); }

    /** Max rows returned per DB history query. */
    public static int dbMaxHistoryRows() { return cfg.getInt("database.session-history.max-rows", 20); }

    // в”Җв”Җ Server identity  (database.server-id) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Unique server identifier stamped on database rows when
     * {@link #isNetworkMode()} is {@code true}.
     *
     * <p>Reads {@code database.server-id} (current path since config v31).
     * Falls back to the legacy {@code server.id} path for configs that have
     * not yet been migrated, so the value is never lost on the first reload
     * after an upgrade.  Blank / null values fall back to {@code "default"}.
     */
    public static String serverId() {
        // New path (v31+)
        String id = cfg.getString("database.server-id", null);
        // Legacy fallback (v29-v30 configs not yet migrated)
        if (id == null || id.isBlank()) {
            id = cfg.getString("server.id", "default");
        }
        return (id == null || id.isBlank()) ? "default" : id.trim();
    }

    // в”Җв”Җ Utility в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    // в”Җв”Җ Performance  (performance.*) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Maximum distance (in blocks) at which a moving bot sends position-sync packets
     * to a real player.  Players farther than this value will not receive per-tick
     * movement updates вҖ” they cannot render the bot anyway beyond their view distance.
     *
     * <p>Set to {@code 0} to disable distance culling (legacy behaviour вҖ” sends to all
     * online players regardless of distance).  The recommended value is {@code 128},
     * which covers the standard Minecraft player-entity tracking range.</p>
     *
     * Maps to {@code performance.position-sync-distance}.
     */
    public static double positionSyncDistance() {
        return cfg.getDouble("performance.position-sync-distance", 128.0);
    }

    /** Log a message to console only when the legacy global debug mode is on. */
    public static void debug(String message) { FppLogger.debug(message); }

    public static void debugStartup(String message)    { FppLogger.debug("STARTUP", debugStartup(), message); }
    public static void debugNms(String message)        { FppLogger.debug("NMS", debugNms(), message); }
    public static void debugPackets(String message)    { FppLogger.debug("PACKETS", debugPackets(), message); }
    public static void debugLuckPerms(String message)  { FppLogger.debug("LP", debugLuckPerms(), message); }
    public static void debugNetwork(String message)    { FppLogger.debug("NETWORK", debugNetwork(), message); }
    public static void debugConfigSync(String message) { FppLogger.debug("CONFIG_SYNC", debugConfigSync(), message); }
    public static void debugSkin(String message)       { FppLogger.debug("SKIN", debugSkin(), message); }
    public static void debugDatabase(String message)   { FppLogger.debug("DATABASE", debugDatabase(), message); }
    public static void debugChat(String message)       { FppLogger.debug("CHAT", debugChat(), message); }
    public static void debugSwap(String message)      { FppLogger.debug("SWAP", debugSwap(), message); }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import org.bukkit.configuration.file.YamlConfiguration;

import java.io.*;
import java.util.Arrays;

/**
 * Handles automatic, non-destructive upgrades of {@code config.yml} from any
 * previous plugin version to the current one.
 *
 * <h3>How it works</h3>
 * <ol>
 *   <li>On every startup, {@link #migrateIfNeeded(FakePlayerPlugin)} is called
 *       <em>before</em> {@code Config.init()} so migrations run on the raw YAML.</li>
 *   <li>The key {@code config-version} in {@code config.yml} records which
 *       format version was last written. If it is missing the config is treated
 *       as version&nbsp;0 (very old / first run without this system).</li>
 *   <li>Each numbered migration step is applied in sequence вҖ” keys are added,
 *       renamed, or restructured as needed while existing user values are
 *       preserved.</li>
 *   <li>A full backup is created via {@link BackupManager} before any changes
 *       are written to disk.</li>
 *   <li>After all steps run the file is saved and {@code config-version} is
 *       set to {@link #CURRENT_VERSION}.</li>
 *   <li>Bukkit's own {@code copyDefaults} mechanism fills in any remaining
 *       missing keys when {@code Config.init()} runs immediately afterwards.</li>
 * </ol>
 *
 * <h3>Adding a new migration</h3>
 * <ol>
 *   <li>Increment {@link #CURRENT_VERSION}.</li>
 *   <li>Add a new {@code migrateVnToVm()} private method.</li>
 *   <li>Add a call to it in {@link #migrateIfNeeded} inside the version chain.</li>
 *   <li>Update {@code config.yml} in resources with the new keys / comments.</li>
 * </ol>
 */
public final class ConfigMigrator {

    /**
     * The config-version value written by this build.
     * <b>Increment this whenever config.yml structure changes.</b>
     */
    public static final int CURRENT_VERSION = 50;

    /**
     * Mirrors the {@code debug} flag read directly from the raw YAML during migration.
     * Used by {@link #log} so it never touches {@code Config.cfg} (which is null
     * during migration вҖ” {@code Config.init()} runs after {@code migrateIfNeeded}).
     */
    private static boolean rawDebug = false;

    private ConfigMigrator() {}

    // в”Җв”Җ Public API в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Runs the full migration chain if the stored {@code config-version} is
     * below {@link #CURRENT_VERSION}.
     *
     * @param plugin Plugin instance (used to locate the data folder).
     * @return {@code true} if at least one migration step was applied and the
     *         file was saved; {@code false} if the config was already current.
     */
    public static boolean migrateIfNeeded(FakePlayerPlugin plugin) {
        File configFile = new File(plugin.getDataFolder(), "config.yml");

        // First run вҖ” Bukkit hasn't saved defaults yet; nothing to migrate.
        if (!configFile.exists()) {
            return false;
        }

        YamlConfiguration cfg = YamlConfiguration.loadConfiguration(configFile);

        // Read debug flag directly from raw YAML вҖ” Config.cfg is still null at this point.
        rawDebug = cfg.getBoolean("debug", false)
                || cfg.getBoolean("logging.debug.startup", false);

        int stored = cfg.getInt("config-version", 0);

        if (stored >= CURRENT_VERSION) {
            log("config is current (v" + stored + "). No migration needed.");
            return false;
        }

        // в”Җв”Җ Pre-migration backup в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        String fromLabel = stored == 0 ? "legacy" : "v" + stored;
        if (rawDebug) {
            FppLogger.section("Config Migration");
            FppLogger.info("Upgrading config from " + fromLabel + " вҶ’ v" + CURRENT_VERSION + "вҖҰ");
            FppLogger.info("A backup will be created before any changes are written.");
        }
        BackupManager.createFullBackup(plugin, "pre-migration-" + fromLabel, rawDebug);

        // в”Җв”Җ Apply migrations in order в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        boolean anyChange = false;
        if (stored < 2)  anyChange |= v1to2(cfg);
        if (stored < 3)  anyChange |= v2to3(cfg);
        if (stored < 4)  anyChange |= v3to4(cfg);
        if (stored < 5)  anyChange |= v4to5(cfg);
        if (stored < 6)  anyChange |= v5to6(cfg);
        if (stored < 7)  anyChange |= v6to7(cfg);
        if (stored < 8)  anyChange |= v7to8(cfg);
        if (stored < 9)  anyChange |= v8to9(cfg);
        if (stored < 10) anyChange |= v9to10(cfg);
        if (stored < 11) anyChange |= v10to11(cfg);
        if (stored < 12) anyChange |= v11to12(cfg);
        if (stored < 13) anyChange |= v12to13(cfg);
        if (stored < 14) anyChange |= v13to14(cfg);
        if (stored < 15) anyChange |= v14to15(cfg);
        if (stored < 16) anyChange |= v15to16(cfg);
        if (stored < 17) anyChange |= v16to17(cfg);
        if (stored < 18) anyChange |= v17to18(cfg);
        if (stored < 19) anyChange |= v18to19(cfg);
        if (stored < 20) anyChange |= v19to20(cfg);
        if (stored < 22) anyChange |= v21to22(cfg);
        if (stored < 23) anyChange |= v22to23(cfg);
        if (stored < 24) anyChange |= v23to24(cfg);
        if (stored < 25) anyChange |= v24to25(cfg);
        if (stored < 26) anyChange |= v25to26(cfg);
        if (stored < 27) anyChange |= v26to27(cfg);
        if (stored < 28) anyChange |= v27to28(cfg);
        if (stored < 30) anyChange |= v29to30(cfg);
        if (stored < 31) anyChange |= v30to31(cfg);
        if (stored < 32) anyChange |= v31to32(cfg);
        if (stored < 33) anyChange |= v32to33(cfg);
        if (stored < 34) anyChange |= v33to34(cfg);
        if (stored < 35) anyChange |= v34to35(cfg);
        if (stored < 36) anyChange |= v35to36(cfg);
        if (stored < 37) anyChange |= v36to37(cfg);
        if (stored < 38) anyChange |= v37to38(cfg);
        if (stored < 39) anyChange |= v38to39(cfg);
        if (stored < 40) anyChange |= v39to40(cfg);
        if (stored < 41) anyChange |= v40to41(cfg);
        if (stored < 42) anyChange |= v41to42(cfg);
        if (stored < 43) anyChange |= v42to43(cfg);
        if (stored < 44) anyChange |= v43to44(cfg);
        if (stored < 46) anyChange |= v45to46(cfg);
        if (stored < 47) anyChange |= v46to47(cfg);
        if (stored < 48) anyChange |= v47to48(cfg);
        if (stored < 49) anyChange |= v48to49(cfg);

        // в”Җв”Җ Fill any remaining missing keys from jar defaults в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        fillDefaults(plugin, cfg);

        // в”Җв”Җ Stamp the version and save в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        cfg.set("config-version", CURRENT_VERSION);

        try {
            cfg.save(configFile);
            if (anyChange) {
                if (rawDebug) {
                    FppLogger.success("Config migrated to v" + CURRENT_VERSION + " successfully.");
                } else {
                    FppLogger.info("Config migration applied (v" + fromLabel + " вҶ’ v" + CURRENT_VERSION + ").");
                }
            } else {
                if (rawDebug) {
                    FppLogger.success("Config stamped as v" + CURRENT_VERSION
                            + " (no structural changes needed; defaults filled).");
                }
            }
        } catch (IOException e) {
            FppLogger.error("ConfigMigrator: failed to save migrated config: " + e.getMessage());
            return false;
        }

        return true;
    }

    /**
     * Forces a re-run of the migration chain from version 0, regardless of the
     * stored version. Also fills any missing keys from the jar defaults.
     * Useful as part of {@code /fpp migrate config}.
     */
    public static void forceMigrate(FakePlayerPlugin plugin) {
        File configFile = new File(plugin.getDataFolder(), "config.yml");
        if (!configFile.exists()) return;

        YamlConfiguration cfg = YamlConfiguration.loadConfiguration(configFile);
        cfg.set("config-version", 0);   // reset so the chain runs fully
        try { cfg.save(configFile); } catch (IOException ignored) {}

        migrateIfNeeded(plugin);
    }

    public static int getCurrentVersion() { return CURRENT_VERSION; }

    // в”Җв”Җ Migration steps в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // Each method returns true if it changed anything.

    /** v1 вҶ’ v2: Added update-checker section. */
    private static boolean v1to2(YamlConfiguration cfg) {
        if (cfg.contains("update-checker")) return false;
        cfg.set("update-checker.enabled", true);
        log("v1вҶ’v2", "added update-checker section");
        return true;
    }

    /** v2 вҶ’ v3: Added luckperms section. */
    private static boolean v2to3(YamlConfiguration cfg) {
        if (cfg.contains("luckperms")) return false;
        cfg.set("luckperms.use-prefix", true);
        log("v2вҶ’v3", "added luckperms section");
        return true;
    }

    /**
     * v3 вҶ’ v4: Skin system overhaul.
     * <ul>
     *   <li>{@code skin-enabled} (boolean) вҶ’ {@code skin.mode} (string)</li>
     *   <li>{@code skin.enabled} (boolean) вҶ’ {@code skin.mode} (string)</li>
     *   <li>{@code skin.custom.pool}    вҶ’ {@code skin.pool}</li>
     *   <li>{@code skin.custom.by-name} вҶ’ {@code skin.overrides}</li>
     * </ul>
     */
    private static boolean v3to4(YamlConfiguration cfg) {
        boolean changed = false;

        // Top-level boolean flag (very old format)
        if (cfg.contains("skin-enabled")) {
            boolean was = cfg.getBoolean("skin-enabled", true);
            cfg.set("skin.mode", was ? "auto" : "off");
            cfg.set("skin-enabled", null);
            log("v3вҶ’v4", "skin-enabled вҶ’ skin.mode=" + (was ? "auto" : "off"));
            changed = true;
        }

        // skin.enabled (intermediate format)
        if (cfg.contains("skin.enabled")) {
            boolean was = cfg.getBoolean("skin.enabled", true);
            if (!cfg.contains("skin.mode")) cfg.set("skin.mode", was ? "auto" : "off");
            cfg.set("skin.enabled", null);
            log("v3вҶ’v4", "skin.enabled вҶ’ skin.mode");
            changed = true;
        }

        // Ensure skin.mode always exists
        if (!cfg.contains("skin.mode")) {
            cfg.set("skin.mode", "auto");
            changed = true;
        }

        // skin.custom.pool вҶ’ skin.pool
        if (cfg.contains("skin.custom.pool") && !cfg.contains("skin.pool")) {
            cfg.set("skin.pool", cfg.get("skin.custom.pool"));
            log("v3вҶ’v4", "skin.custom.pool вҶ’ skin.pool");
            changed = true;
        }

        // skin.custom.by-name вҶ’ skin.overrides
        if (cfg.contains("skin.custom.by-name") && !cfg.contains("skin.overrides")) {
            cfg.set("skin.overrides", cfg.get("skin.custom.by-name"));
            log("v3вҶ’v4", "skin.custom.by-name вҶ’ skin.overrides");
            changed = true;
        }

        // Remove deprecated nested section if now empty
        if (!cfg.contains("skin.custom.pool") && !cfg.contains("skin.custom.by-name")) {
            cfg.set("skin.custom", null);
        }

        return changed;
    }

    /** v4 вҶ’ v5: Added body section (replaces top-level {@code spawn-body}). */
    private static boolean v4to5(YamlConfiguration cfg) {
        if (cfg.contains("body")) return false;
        boolean prev = cfg.getBoolean("spawn-body", true);
        cfg.set("body.enabled", prev);
        cfg.set("spawn-body", null);
        log("v4вҶ’v5", "spawn-body вҶ’ body.enabled");
        return true;
    }

    /** v5 вҶ’ v6: Added chunk-loading section. */
    private static boolean v5to6(YamlConfiguration cfg) {
        if (cfg.contains("chunk-loading")) return false;
        cfg.set("chunk-loading.enabled", true);
        cfg.set("chunk-loading.radius", 6);
        cfg.set("chunk-loading.update-interval", 20);
        log("v5вҶ’v6", "added chunk-loading section");
        return true;
    }

    /** v6 вҶ’ v7: Added head-ai section. */
    private static boolean v6to7(YamlConfiguration cfg) {
        if (cfg.contains("head-ai")) return false;
        cfg.set("head-ai.look-range", 8.0);
        cfg.set("head-ai.turn-speed", 0.3);
        log("v6вҶ’v7", "added head-ai section");
        return true;
    }

    /** v7 вҶ’ v8: Added collision / push section. */
    private static boolean v7to8(YamlConfiguration cfg) {
        if (cfg.contains("collision")) return false;
        cfg.set("collision.walk-radius", 0.85);
        cfg.set("collision.walk-strength", 0.22);
        cfg.set("collision.max-horizontal-speed", 0.30);
        cfg.set("collision.hit-strength", 0.45);
        cfg.set("collision.bot-radius", 0.90);
        cfg.set("collision.bot-strength", 0.14);
        log("v7вҶ’v8", "added collision section");
        return true;
    }

    /** v8 вҶ’ v9: Added swap and fake-chat sections. */
    private static boolean v8to9(YamlConfiguration cfg) {
        boolean changed = false;

        if (!cfg.contains("swap")) {
            cfg.set("swap.enabled",           false);
            cfg.set("swap.session-min",        120);
            cfg.set("swap.session-max",        600);
            cfg.set("swap.rejoin-delay-min",   5);
            cfg.set("swap.rejoin-delay-max",   45);
            cfg.set("swap.jitter",             30);
