    /**
     * v35 вҶ’ v36: Comprehensive orphaned-key cleanup pass.
     * <ul>
     *   <li>Removes any surviving old LuckPerms keys that should have been cleaned
     *       by v31вҶ’v32 but may remain on certain upgrade paths:
     *       {@code weight-offset}, {@code weight-ordering-enabled}, {@code use-prefix},
     *       {@code packet-prefix-char}, {@code bot-group}.</li>
     *   <li>Removes the deprecated {@code skin.custom} sub-section left over from
     *       pre-v4 installations (should have been removed by v3вҶ’v4).</li>
     *   <li>Removes the orphaned top-level {@code server} section that should have
     *       been migrated to {@code database.server-id} by v30вҶ’v31.</li>
     * </ul>
     */
    private static boolean v35to36(YamlConfiguration cfg) {
        boolean changed = false;

        // в”Җв”Җ Orphaned LuckPerms keys в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        for (String deadKey : new String[]{
                "luckperms.weight-offset",
                "luckperms.weight-ordering-enabled",
                "luckperms.use-prefix",
                "luckperms.packet-prefix-char",
                "luckperms.bot-group"}) {
            if (cfg.contains(deadKey)) {
                cfg.set(deadKey, null);
                log("v35вҶ’v36", "removed orphaned key: " + deadKey);
                changed = true;
            }
        }

        // в”Җв”Җ Leftover skin.custom section (pre-v4 installations) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (cfg.contains("skin.custom")) {
            cfg.set("skin.custom", null);
            log("v35вҶ’v36", "removed leftover skin.custom section");
            changed = true;
        }

        // в”Җв”Җ Removed skin fallback-pool and fallback-name (simplified in v1.5.4) в”Җв”Җ
        // skin.guaranteed-skin default changed to false вҖ” no Mojang API fallback pool needed.
        if (cfg.contains("skin.fallback-pool")) {
            cfg.set("skin.fallback-pool", null);
            log("v35вҶ’v36", "removed skin.fallback-pool (fallback is now Steve/Alex by default)");
            changed = true;
        }
        if (cfg.contains("skin.fallback-name")) {
            cfg.set("skin.fallback-name", null);
            log("v35вҶ’v36", "removed skin.fallback-name (fallback is now Steve/Alex by default)");
            changed = true;
        }
        // Reset guaranteed-skin to false if it was explicitly true (old default was true)
        if (cfg.contains("skin.guaranteed-skin") && cfg.getBoolean("skin.guaranteed-skin", false)) {
            cfg.set("skin.guaranteed-skin", false);
            log("v35вҶ’v36", "reset skin.guaranteed-skin to false (new default: Steve/Alex fallback)");
            changed = true;
        }

        // в”Җв”Җ Orphaned top-level server: section (should have moved to database.server-id in v30вҶ’v31) в”Җв”Җ
        if (cfg.contains("server") && cfg.contains("database.server-id")) {
            cfg.set("server", null);
            log("v35вҶ’v36", "removed leftover server: section (already in database.server-id)");
            changed = true;
        }

        return changed;
    }

