    /**
     * Logs a migration step message.
     * Uses {@link #rawDebug} read from the raw YAML вҖ” never touches {@code Config.cfg}
     * because this runs before {@code Config.init()}
     */
    private static void log(String step, String message) {
        if (rawDebug) {
            FppLogger.info("[ConfigMigrator][" + step + "] " + message);
        }
    }

    /** Single-arg variant used for non-step messages (e.g. "config is current"). */
    private static void log(String message) {
        if (rawDebug) {
            FppLogger.info("[ConfigMigrator] " + message);
        }
    }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.config.Config;
import org.bukkit.Bukkit;
import org.bukkit.Material;

/**
 * Validates {@code config.yml} values on startup and reload.
 *
 * <p>Emits {@link FppLogger#warn} for bad values but never throws вҖ”
 * the plugin always continues to run; admins see the warnings in console.
 *
 * <p>Checks performed:
 * <ul>
 *   <li>Join/leave delay: min вүӨ max</li>
 *   <li>Skin fallback name not blank</li>
 *   <li>Chunk radius вүӨ server view-distance</li>
 *   <li>Fake-chat interval: min вүӨ max</li>
 *   <li>Swap session: min вүӨ max</li>
 *   <li>Swap rejoin delay: min вүӨ max</li>
 *   <li>Max-bots вүҘ 0</li>
 *   <li>User bot limit вүҘ 1</li>
 *   <li>Spawn cooldown вүҘ 0</li>
 *   <li>Collision max-horizontal-speed > 0</li>
 *   <li>Head AI look range > 0</li>
 *   <li>Head AI turn speed in (0, 1]</li>
 *   <li>Max health > 0</li>
 *   <li>Peak-hours: enabled requires swap enabled</li>
 *   <li>Peak-hours: stagger-seconds > 0</li>
 *   <li>Peak-hours: timezone is a valid ZoneId</li>
 * </ul>
 */
public final class ConfigValidator {

    private ConfigValidator() {}

    /**
     * Run all validation checks. Warnings go to the FPP console log.
     * Returns the number of issues found (0 = config is clean).
     */
    public static int validate() {
        int issues = 0;

        // в”Җв”Җ Join / leave delays в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.joinDelayMin() > Config.joinDelayMax()) {
            FppLogger.warn("[Config] join-delay.min (" + Config.joinDelayMin() + ") > "
                    + "join-delay.max (" + Config.joinDelayMax() + ") вҖ” swapping values in memory.");
            issues++;
        }
        if (Config.leaveDelayMin() > Config.leaveDelayMax()) {
            FppLogger.warn("[Config] leave-delay.min (" + Config.leaveDelayMin() + ") > "
                    + "leave-delay.max (" + Config.leaveDelayMax() + ") вҖ” swapping values in memory.");
            issues++;
        }

        // в”Җв”Җ Skin в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.skinGuaranteed() && Config.skinFallbackName().isBlank()) {
            FppLogger.warn("[Config] skin.fallback-name is blank but skin.guaranteed-skin is true вҖ” "
                    + "last-resort fallback will not work.");
            issues++;
        }

        // в”Җв”Җ Chunk loading в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.chunkLoadingEnabled()) {
            int radius    = Config.chunkLoadingRadius();
            int viewDist  = Bukkit.getSimulationDistance();
            if (radius > viewDist) {
                FppLogger.warn("[Config] chunk-loading.radius (" + radius + ") exceeds "
                        + "server simulation-distance (" + viewDist + "). "
                        + "Tickets beyond simulation distance have no effect.");
                issues++;
            }
        }

        // в”Җв”Җ Fake chat в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.fakeChatIntervalMin() > Config.fakeChatIntervalMax()) {
            FppLogger.warn("[Config] fake-chat.interval.min > fake-chat.interval.max вҖ” "
                    + "set min вүӨ max for correct behaviour.");
            issues++;
        }


        // в”Җв”Җ Limits в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.maxBots() < 0) {
            FppLogger.warn("[Config] limits.max-bots is negative вҖ” treating as 0 (unlimited).");
            issues++;
        }
        if (Config.userBotLimit() < 1) {
            FppLogger.warn("[Config] limits.user-bot-limit is < 1 вҖ” users will never be able to spawn.");
            issues++;
        }

        // в”Җв”Җ Spawn cooldown в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.spawnCooldown() < 0) {
            FppLogger.warn("[Config] spawn-cooldown is negative вҖ” treating as 0 (no cooldown).");
            issues++;
        }

        // в”Җв”Җ Combat в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.maxHealth() <= 0) {
            FppLogger.warn("[Config] combat.max-health must be > 0. Defaulting to 20.");
            issues++;
        }

        // в”Җв”Җ Head AI в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.headAiLookRange() <= 0) {
            FppLogger.warn("[Config] head-ai.look-range must be > 0.");
            issues++;
        }
        float turnSpeed = Config.headAiTurnSpeed();
        if (turnSpeed <= 0 || turnSpeed > 1) {
            FppLogger.warn("[Config] head-ai.turn-speed should be between 0.0 and 1.0 (got " + turnSpeed + ").");
            issues++;
        }

        // в”Җв”Җ Collision в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.collisionMaxHoriz() <= 0) {
            FppLogger.warn("[Config] collision.max-horizontal-speed must be > 0.");
            issues++;
        }
        if (Config.collisionHitStrength() < 0) {
            FppLogger.warn("[Config] collision.hit-strength must be >= 0.");
            issues++;
        }
        if (Config.collisionHitMaxHoriz() <= 0) {
            FppLogger.warn("[Config] collision.hit-max-horizontal-speed must be > 0.");
            issues++;
        }
        if (Config.collisionWalkRadius() <= 0) {
            FppLogger.warn("[Config] collision.walk-radius must be > 0.");
            issues++;
        }
        if (Config.collisionBotRadius() <= 0) {
            FppLogger.warn("[Config] collision.bot-radius must be > 0.");
            issues++;
        }
        if (Config.collisionWalkStrength() < 0) {
            FppLogger.warn("[Config] collision.walk-strength must be >= 0.");
            issues++;
        }
        if (Config.collisionBotStrength() < 0) {
            FppLogger.warn("[Config] collision.bot-strength must be >= 0.");
            issues++;
        }

        // в”Җв”Җ Peak hours в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.peakHoursEnabled() && !Config.swapEnabled()) {
            FppLogger.warn("[Config] peak-hours.enabled is true but swap.enabled is false вҖ” "
                    + "peak-hours will not run until swap is enabled (/fpp swap on).");
            issues++;
        }
        if (Config.peakHoursStaggerSeconds() <= 0) {
            FppLogger.warn("[Config] peak-hours.stagger-seconds must be > 0 (got "
                    + Config.peakHoursStaggerSeconds() + ").");
            issues++;
        }
        String phTz = Config.peakHoursTimezone();
        try {
            var ignored = java.time.ZoneId.of(phTz);
        } catch (java.time.DateTimeException e) {
            FppLogger.warn("[Config] peak-hours.timezone \"" + phTz + "\" is not a valid ZoneId "
                    + "(e.g. \"UTC\", \"America/New_York\") вҖ” falling back to UTC at runtime.");
            issues++;
        }

        // в”Җв”Җ Database mode в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        org.bukkit.plugin.Plugin fpp = Bukkit.getPluginManager().getPlugin("FakePlayerPlugin");
        if (fpp != null) {
            String rawMode = fpp.getConfig().getString("database.mode", "LOCAL");
            if (!rawMode.trim().equalsIgnoreCase("LOCAL")
                    && !rawMode.trim().equalsIgnoreCase("NETWORK")) {
                FppLogger.warn("[Config] database.mode \"" + rawMode.trim() + "\" is not valid "
                        + "(accepted: LOCAL, NETWORK) вҖ” falling back to LOCAL.");
                issues++;
            }
        }

        if (issues == 0) {
            FppLogger.debug("[Config] All values passed validation.");
        } else {
            FppLogger.warn("[Config] " + issues + " config issue(s) detected вҖ” review warnings above.");
        }

        return issues;
    }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.config.Config;
import org.bukkit.Bukkit;
import org.bukkit.Material;

/**
 * Validates {@code config.yml} values on startup and reload.
 *
 * <p>Emits {@link FppLogger#warn} for bad values but never throws вҖ”
 * the plugin always continues to run; admins see the warnings in console.
 *
 * <p>Checks performed:
 * <ul>
 *   <li>Join/leave delay: min вүӨ max</li>
 *   <li>Skin fallback name not blank</li>
 *   <li>Chunk radius вүӨ server view-distance</li>
 *   <li>Fake-chat interval: min вүӨ max</li>
 *   <li>Swap session: min вүӨ max</li>
 *   <li>Swap rejoin delay: min вүӨ max</li>
 *   <li>Max-bots вүҘ 0</li>
 *   <li>User bot limit вүҘ 1</li>
 *   <li>Spawn cooldown вүҘ 0</li>
 *   <li>Collision max-horizontal-speed > 0</li>
 *   <li>Head AI look range > 0</li>
 *   <li>Head AI turn speed in (0, 1]</li>
 *   <li>Max health > 0</li>
 *   <li>Peak-hours: enabled requires swap enabled</li>
 *   <li>Peak-hours: stagger-seconds > 0</li>
 *   <li>Peak-hours: timezone is a valid ZoneId</li>
 * </ul>
 */
public final class ConfigValidator {

    private ConfigValidator() {}

    /**
     * Run all validation checks. Warnings go to the FPP console log.
     * Returns the number of issues found (0 = config is clean).
     */
    public static int validate() {
        int issues = 0;

        // в”Җв”Җ Join / leave delays в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.joinDelayMin() > Config.joinDelayMax()) {
            FppLogger.warn("[Config] join-delay.min (" + Config.joinDelayMin() + ") > "
                    + "join-delay.max (" + Config.joinDelayMax() + ") вҖ” swapping values in memory.");
            issues++;
        }
        if (Config.leaveDelayMin() > Config.leaveDelayMax()) {
            FppLogger.warn("[Config] leave-delay.min (" + Config.leaveDelayMin() + ") > "
                    + "leave-delay.max (" + Config.leaveDelayMax() + ") вҖ” swapping values in memory.");
            issues++;
        }

        // в”Җв”Җ Skin в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.skinGuaranteed() && Config.skinFallbackName().isBlank()) {
            FppLogger.warn("[Config] skin.fallback-name is blank but skin.guaranteed-skin is true вҖ” "
                    + "last-resort fallback will not work.");
            issues++;
        }

        // в”Җв”Җ Chunk loading в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.chunkLoadingEnabled()) {
            int radius    = Config.chunkLoadingRadius();
            int viewDist  = Bukkit.getSimulationDistance();
            if (radius > viewDist) {
                FppLogger.warn("[Config] chunk-loading.radius (" + radius + ") exceeds "
                        + "server simulation-distance (" + viewDist + "). "
                        + "Tickets beyond simulation distance have no effect.");
                issues++;
            }
        }

        // в”Җв”Җ Fake chat в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.fakeChatIntervalMin() > Config.fakeChatIntervalMax()) {
            FppLogger.warn("[Config] fake-chat.interval.min > fake-chat.interval.max вҖ” "
                    + "set min вүӨ max for correct behaviour.");
            issues++;
        }


        // в”Җв”Җ Limits в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.maxBots() < 0) {
            FppLogger.warn("[Config] limits.max-bots is negative вҖ” treating as 0 (unlimited).");
            issues++;
        }
        if (Config.userBotLimit() < 1) {
            FppLogger.warn("[Config] limits.user-bot-limit is < 1 вҖ” users will never be able to spawn.");
            issues++;
        }

        // в”Җв”Җ Spawn cooldown в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.spawnCooldown() < 0) {
            FppLogger.warn("[Config] spawn-cooldown is negative вҖ” treating as 0 (no cooldown).");
            issues++;
        }

        // в”Җв”Җ Combat в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.maxHealth() <= 0) {
            FppLogger.warn("[Config] combat.max-health must be > 0. Defaulting to 20.");
            issues++;
        }

        // в”Җв”Җ Head AI в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.headAiLookRange() <= 0) {
            FppLogger.warn("[Config] head-ai.look-range must be > 0.");
            issues++;
        }
        float turnSpeed = Config.headAiTurnSpeed();
        if (turnSpeed <= 0 || turnSpeed > 1) {
            FppLogger.warn("[Config] head-ai.turn-speed should be between 0.0 and 1.0 (got " + turnSpeed + ").");
            issues++;
        }

        // в”Җв”Җ Collision в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.collisionMaxHoriz() <= 0) {
            FppLogger.warn("[Config] collision.max-horizontal-speed must be > 0.");
            issues++;
        }
        if (Config.collisionHitStrength() < 0) {
            FppLogger.warn("[Config] collision.hit-strength must be >= 0.");
            issues++;
        }
        if (Config.collisionHitMaxHoriz() <= 0) {
            FppLogger.warn("[Config] collision.hit-max-horizontal-speed must be > 0.");
            issues++;
        }
        if (Config.collisionWalkRadius() <= 0) {
            FppLogger.warn("[Config] collision.walk-radius must be > 0.");
            issues++;
        }
        if (Config.collisionBotRadius() <= 0) {
            FppLogger.warn("[Config] collision.bot-radius must be > 0.");
            issues++;
        }
        if (Config.collisionWalkStrength() < 0) {
            FppLogger.warn("[Config] collision.walk-strength must be >= 0.");
            issues++;
        }
        if (Config.collisionBotStrength() < 0) {
            FppLogger.warn("[Config] collision.bot-strength must be >= 0.");
            issues++;
        }

        // в”Җв”Җ Peak hours в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.peakHoursEnabled() && !Config.swapEnabled()) {
            FppLogger.warn("[Config] peak-hours.enabled is true but swap.enabled is false вҖ” "
                    + "peak-hours will not run until swap is enabled (/fpp swap on).");
            issues++;
        }
        if (Config.peakHoursStaggerSeconds() <= 0) {
            FppLogger.warn("[Config] peak-hours.stagger-seconds must be > 0 (got "
                    + Config.peakHoursStaggerSeconds() + ").");
            issues++;
        }
        String phTz = Config.peakHoursTimezone();
        try {
            var ignored = java.time.ZoneId.of(phTz);
        } catch (java.time.DateTimeException e) {
            FppLogger.warn("[Config] peak-hours.timezone \"" + phTz + "\" is not a valid ZoneId "
                    + "(e.g. \"UTC\", \"America/New_York\") вҖ” falling back to UTC at runtime.");
            issues++;
        }

        // в”Җв”Җ Database mode в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        org.bukkit.plugin.Plugin fpp = Bukkit.getPluginManager().getPlugin("FakePlayerPlugin");
        if (fpp != null) {
            String rawMode = fpp.getConfig().getString("database.mode", "LOCAL");
            if (!rawMode.trim().equalsIgnoreCase("LOCAL")
                    && !rawMode.trim().equalsIgnoreCase("NETWORK")) {
                FppLogger.warn("[Config] database.mode \"" + rawMode.trim() + "\" is not valid "
                        + "(accepted: LOCAL, NETWORK) вҖ” falling back to LOCAL.");
                issues++;
            }
        }

        // в”Җв”Җ Pathfinding в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (Config.pathfindingPlaceBlocks()) {
            String matName = Config.pathfindingPlaceMaterial();
            Material mat = Material.matchMaterial(matName.toUpperCase());
            if (mat == null || !mat.isBlock() || !mat.isSolid()) {
                FppLogger.warn("[Config] pathfinding.place-material \"" + matName + "\" is not a valid "
                        + "solid block вҖ” falling back to DIRT.");
                issues++;
            }
        }

        if (issues == 0) {
            FppLogger.debug("[Config] All values passed validation.");
        } else {
            FppLogger.warn("[Config] " + issues + " config issue(s) detected вҖ” review warnings above.");
        }

        return issues;
    }
}

package me.bill.fakePlayerPlugin.database;

import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.util.FppLogger;

import java.io.File;
import java.sql.*;
import java.time.Instant;
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;

/**
 * Handles all database I/O for FakePlayerPlugin.
 *
 * <h3>Backends</h3>
 * <ol>
 *   <li><b>MySQL</b>  вҖ” when {@code database.mysql.enabled: true}</li>
 *   <li><b>SQLite</b> вҖ” automatic local fallback; WAL mode for crash-safety</li>
 * </ol>
 *
 * <h3>Key features</h3>
 * <ul>
 *   <li>Write queue вҖ” all writes are serialised on a dedicated thread.</li>
 *   <li>Batch location flush вҖ” position updates are deduplicated and sent in one
 *       batch statement instead of one UPDATE per bot per tick.</li>
 *   <li>Auto-reconnect health check вҖ” silently reconnects on connection loss.</li>
 *   <li>{@code fpp_active_bots} table вҖ” authoritative source for restart
 *       persistence; always reflects live bot state, even after a crash.</li>
 *   <li>Yaw/pitch tracked in last location вҖ” bots face the correct direction
 *       after a restart.</li>
 *   <li>Schema version table вҖ” safe incremental migrations.</li>
 *   <li>Indices on hot query columns вҖ” bot_name, spawned_by, removed_at.</li>
 *   <li>Display name stored alongside internal name for audit trail.</li>
 *   <li>Stats API вҖ” total sessions, unique bots, top spawners, uptime.</li>
 * </ul>
 */
public class DatabaseManager {

    // в”Җв”Җ Schema version в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private static final int SCHEMA_VERSION = 7;

    /** Returns the latest DB schema version this build requires. */
    public static int getCurrentSchemaVersion() { return SCHEMA_VERSION; }

    // в”Җв”Җ DDL вҖ” session history в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private static final String CREATE_SESSIONS_SQLITE =
            "CREATE TABLE IF NOT EXISTS fpp_bot_sessions (" +
            "  id              INTEGER PRIMARY KEY AUTOINCREMENT," +
            "  bot_name        VARCHAR(16)  NOT NULL," +
            "  bot_display     VARCHAR(128) DEFAULT NULL," +
            "  bot_uuid        VARCHAR(36)  NOT NULL," +
            "  spawned_by      VARCHAR(16)  NOT NULL," +
            "  spawned_by_uuid VARCHAR(36)  NOT NULL," +
            "  world_name      VARCHAR(64)  NOT NULL," +
            "  spawn_x         DOUBLE NOT NULL," +
            "  spawn_y         DOUBLE NOT NULL," +
            "  spawn_z         DOUBLE NOT NULL," +
            "  spawn_yaw       FLOAT  NOT NULL DEFAULT 0," +
            "  spawn_pitch     FLOAT  NOT NULL DEFAULT 0," +
            "  last_world      VARCHAR(64)," +
            "  last_x          DOUBLE," +
            "  last_y          DOUBLE," +
            "  last_z          DOUBLE," +
            "  last_yaw        FLOAT," +
            "  last_pitch      FLOAT," +
            "  entity_type     VARCHAR(32)  NOT NULL DEFAULT 'MANNEQUIN'," +
            "  spawned_at      BIGINT NOT NULL," +
            "  removed_at      BIGINT," +
            "  remove_reason   VARCHAR(32)," +
            "  server_id       VARCHAR(64)  NOT NULL DEFAULT 'default'" +
            ")";

    private static final String CREATE_SESSIONS_MYSQL =
            "CREATE TABLE IF NOT EXISTS fpp_bot_sessions (" +
            "  id              BIGINT NOT NULL AUTO_INCREMENT PRIMARY KEY," +
            "  bot_name        VARCHAR(16)  NOT NULL," +
            "  bot_display     VARCHAR(128) DEFAULT NULL," +
            "  bot_uuid        VARCHAR(36)  NOT NULL," +
            "  spawned_by      VARCHAR(16)  NOT NULL," +
            "  spawned_by_uuid VARCHAR(36)  NOT NULL," +
            "  world_name      VARCHAR(64)  NOT NULL," +
            "  spawn_x         DOUBLE NOT NULL," +
            "  spawn_y         DOUBLE NOT NULL," +
            "  spawn_z         DOUBLE NOT NULL," +
            "  spawn_yaw       FLOAT  NOT NULL DEFAULT 0," +
            "  spawn_pitch     FLOAT  NOT NULL DEFAULT 0," +
            "  last_world      VARCHAR(64)," +
            "  last_x          DOUBLE," +
            "  last_y          DOUBLE," +
            "  last_z          DOUBLE," +
            "  last_yaw        FLOAT," +
            "  last_pitch      FLOAT," +
            "  entity_type     VARCHAR(32)  NOT NULL DEFAULT 'MANNEQUIN'," +
            "  spawned_at      BIGINT NOT NULL," +
            "  removed_at      BIGINT," +
            "  remove_reason   VARCHAR(32)," +
            "  server_id       VARCHAR(64)  NOT NULL DEFAULT 'default'" +
