    /**
     * Updates display names and tab-list entries for all active bots.
     * Called automatically when LuckPerms group data changes.
     * @return number of bots updated
     */
    /**
     * Moves the physics body of {@code fp} to {@code destination} immediately.
     * Used by the tph / tp commands.
     */
    public boolean teleportBot(FakePlayer fp, org.bukkit.Location destination) {
        Player body = fp.getPlayer();
        if (body == null || !body.isValid()) return false;
        body.teleport(destination);
        fp.setSpawnLocation(destination.clone());
        return true;
    }

    // в”Җв”Җ Display name в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Builds the final display name for a bot.
     *
     * <p>Bots are now real NMS ServerPlayer entities вҖ” LuckPerms applies their
     * prefix and suffix natively in chat and the tab list. This method
     * sanitizes and PAPI-expands the raw name to produce the FPP-side custom
     * name shown via the name packet.
     *
     * @param rawName base name resolved from admin/user format
     * @param botName internal bot name used for sanitize-log context
     */
    private String finalizeDisplayName(String rawName, String botName) {
        String display = rawName;

        // Expand PlaceholderAPI placeholders (server-wide, null player context)
        if (display.contains("%")) {
            try {
                if (org.bukkit.Bukkit.getPluginManager().getPlugin("PlaceholderAPI") != null) {
                    display = me.clip.placeholderapi.PlaceholderAPI.setPlaceholders(null, display);
                }
            } catch (Exception ignored) {}
        }

        return sanitizeDisplayName(display, botName);
    }

    /**
     * Re-reads the bot's LuckPerms prefix and suffix from LP's in-memory meta cache
     * and rebuilds its display name.
     *
     * <p>Call this after a LP group assignment completes so the prefix/suffix appear
     * correctly in the tab list and nametag. Must be called on the main server thread.
     *
     * <p>No-op when LP is unavailable or the bot is no longer active.
     *
     * @param fp the bot whose display name should be refreshed
     */
    public void refreshLpDisplayName(FakePlayer fp) {
        if (!activePlayers.containsKey(fp.getUuid())) return;
        if (!plugin.isLuckPermsAvailable()) return;


        // Use the raw display content stored at spawn/restore time
        String rawContent = fp.getRawDisplayName();
        if (rawContent == null || rawContent.isBlank()) rawContent = fp.getName();

        String display = rawContent;

        // PAPI expansion
        if (display.contains("%")) {
            try {
                if (org.bukkit.Bukkit.getPluginManager().getPlugin("PlaceholderAPI") != null) {
                    display = me.clip.placeholderapi.PlaceholderAPI.setPlaceholders(null, display);
                }
            } catch (Exception ignored) {}
        }

        display = sanitizeDisplayName(display, fp.getName());
        fp.setDisplayName(display);

        // Update the entity's display name for death messages and chat
        Player body = fp.getPlayer();
        if (body != null && body.isValid()) {
            try {
                // Use raw display name to preserve color intent, then strip for vanilla compatibility
                String plainName = rawContent.replaceAll("В§[0-9a-fk-or]", "")
                        .replaceAll("<[^>]+>", "")  // Remove MiniMessage tags
                        .replaceAll("\\{#[0-9A-Fa-f]{6}[><]\\}", "");  // Remove LP gradient tags
                body.displayName(Component.text(plainName));
            } catch (Exception ignored) {}
        }

        // Resend tab-list display name to all online players
        if (Config.tabListEnabled()) {
            List<Player> online = new ArrayList<>(Bukkit.getOnlinePlayers());
            for (Player p : online) PacketHelper.sendTabListDisplayNameUpdate(p, fp);
        }

        // Notify remote servers so their RemoteBotCache and tab-list entries update too
        if (Config.isNetworkMode()) {
            var vc = plugin.getVelocityChannel();
            if (vc != null) vc.broadcastBotDisplayNameUpdate(fp);
        }

        Config.debug("[LP] Refreshed display name for '" + fp.getName() + "': '" + display + "'");
    }

    /**
     * Refreshes LP display name with retry logic. If the prefix is still empty after the
     * first attempt, forces LP to refresh cached metadata and retries after a delay.
     * This handles the race condition where LP hasn't finished calculating metadata yet.
     *
     * @param fp the bot whose display name should be refreshed
     * @param attempt current retry attempt (0-indexed, max 2 retries)
     */
    private void refreshLpDisplayNameWithRetry(FakePlayer fp, int attempt) {
        if (!activePlayers.containsKey(fp.getUuid())) return;
        if (!plugin.isLuckPermsAvailable()) return;

        String prefix = me.bill.fakePlayerPlugin.util.LuckPermsHelper.getResolvedPrefix(fp.getUuid());
        String suffix = me.bill.fakePlayerPlugin.util.LuckPermsHelper.getResolvedSuffix(fp.getUuid());

        // If we still have no prefix/suffix after initial delay and haven't exceeded retry limit,
        // force LP to refresh cached data and retry
        if (prefix.isEmpty() && suffix.isEmpty() && attempt < 2) {
            Config.debug("[LP] No prefix/suffix for '" + fp.getName() + "' on attempt " + (attempt + 1) 
                    + ", forcing LP refresh...");
            me.bill.fakePlayerPlugin.util.LuckPermsHelper.refreshUserCache(fp.getUuid());

            UUID botUuid = fp.getUuid();
            Bukkit.getScheduler().runTaskLater(plugin, () -> {
                if (!activePlayers.containsKey(botUuid)) return;
                refreshLpDisplayNameWithRetry(fp, attempt + 1);
            }, 10L); // Wait 10 more ticks after forcing refresh
            return;
        }

        // Apply the display name (even if prefix/suffix are empty on final attempt)
        refreshLpDisplayName(fp);
    }

    /**
     * Compiled pattern that matches unreplaced {@code {placeholder}} tokens in
     * display-name strings. Excludes LuckPerms gradient shorthand
     * ({@code {#rrggbb>}text{#rrggbb<}}) by requiring the first char to be a
     * letter or underscore (not {@code #}).
     */
    private static final java.util.regex.Pattern PLACEHOLDER_PATTERN =
            java.util.regex.Pattern.compile("\\{[a-zA-Z_][a-zA-Z0-9_]*\\}");

    /**
     * Replaces any unreplaced {@code {placeholder}} patterns with a fallback name.
     */
    private String sanitizeDisplayName(String displayName, String context) {
        if (displayName == null || !displayName.contains("{")) return displayName;
        java.util.regex.Matcher m = PLACEHOLDER_PATTERN.matcher(displayName);
        if (!m.find()) return displayName;
        String fallback  = pickRandomSkinName();
        String sanitized = PLACEHOLDER_PATTERN.matcher(displayName).replaceAll(fallback);
        FppLogger.warn("Unreplaced placeholder(s) in display name for '"
                + context + "': '" + displayName + "' вҖ” replaced with '" + fallback
                + "'. Check bot-name.user-format / bot-name.admin-format in config.yml.");
        return sanitized;
    }

    // в”Җв”Җ Name generation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Picks a random name from the bot-names pool for skin lookup.
     */
    private String pickRandomSkinName() {
        List<String> pool = Config.namePool();
        if (pool.isEmpty()) return "Steve";
        return pool.get(ThreadLocalRandom.current().nextInt(pool.size()));
    }

    // в”Җв”Җ UUID resolution в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Returns the stable UUID for {@code botName} on this server.
     *
     * <p>Delegates to {@link BotIdentityCache#lookupOrCreate(String)} when the cache
     * is available; falls back to {@link UUID#randomUUID()} when the cache has not yet
     * been injected (should not happen in normal usage, but guards against ordering issues
     * during tests or incomplete initialisation).
     *
     * <p>This replaces every bare {@code UUID.randomUUID()} call at spawn sites so bots
     * always reconnect with the same UUID they had on previous sessions.
     */
    private UUID resolveUuid(String botName) {
        if (identityCache != null) return identityCache.lookupOrCreate(botName);
        return UUID.randomUUID();
    }

    private String generateName() {
        List<String> pool = Config.namePool();
        if (pool.isEmpty()) return fallbackName();

        String chosen = null;
        int    count  = 0;
        for (String n : pool) {
            if (n == null || n.isEmpty() || n.length() > 16
                    || !n.matches("[a-zA-Z0-9_]+")) continue;
            if (usedNames.contains(n) || Bukkit.getPlayerExact(n) != null) continue;
            count++;
            if (ThreadLocalRandom.current().nextInt(count) == 0) chosen = n;
        }
        if (chosen != null) {
            usedNames.add(chosen);
            return chosen;
        }
        return fallbackName();
    }

    /**
     * Generates a PvP-bot MC username from the name pool, prefixed with {@code pvp_}.
     * The prefix occupies 4 characters, so pool names longer than 12 chars are
     * truncated to ensure the result is a valid Minecraft name (вүӨ 16 chars).
     * Falls back to {@code pvp_Bot<random>} if the pool is exhausted.
     */
    private String generatePvpName() {
        List<String> pool = Config.namePool();
        if (!pool.isEmpty()) {
            String chosen = null;
            int count = 0;
            for (String n : pool) {
                if (n == null || n.isEmpty() || !n.matches("[a-zA-Z0-9_]+")) continue;
                // Truncate base name to 12 chars so pvp_ prefix fits in 16
                String base = n.length() > 12 ? n.substring(0, 12) : n;
                String candidate = "pvp_" + base;
                if (usedNames.contains(candidate) || Bukkit.getPlayerExact(candidate) != null) continue;
                count++;
                if (ThreadLocalRandom.current().nextInt(count) == 0) chosen = candidate;
            }
            if (chosen != null) {
                usedNames.add(chosen);
                return chosen;
            }
        }
        // Fallback: pvp_Bot<1000-9998>
        String generated;
        int attempts = 0;
        do {
            generated = "pvp_Bot" + ThreadLocalRandom.current().nextInt(1000, 9999);
            if (generated.length() > 16) generated = generated.substring(0, 16);
            if (++attempts > 200) return null;
        } while (usedNames.contains(generated) || Bukkit.getPlayerExact(generated) != null);
        usedNames.add(generated);
        return generated;
    }

    private String fallbackName() {
        String generated;
        int attempts = 0;
        do {
            generated = "Bot" + ThreadLocalRandom.current().nextInt(1000, 9999);
            if (++attempts > 200) return null;
        } while (usedNames.contains(generated) || Bukkit.getPlayerExact(generated) != null);
        usedNames.add(generated);
        return generated;
    }

    // в”Җв”Җ User-bot naming в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Result holder for a generated user-bot name pair.
     *
     * @param internalName valid Minecraft identifier used for the GameProfile
     * @param displayName  display text shown in nametag and tab list
     */
    public record UserBotName(String internalName, String displayName) {}

    /**
     * Generates a valid internal Minecraft name and a display name for a user-tier bot.
     *
     * <p>Internal name format: {@code ubot_<spawner>_<N>} (max 16 chars).
     *
     * @param spawnerName   the spawning player's Minecraft name
     * @param existingCount bots this player already owns
     */
    public UserBotName generateUserBotName(String spawnerName, int existingCount) {
        String suffix    = String.valueOf(existingCount + 1);
        final String PREFIX = "ubot_";
        final String SEP    = "_";
        int maxSpawnerLen = 16 - PREFIX.length() - SEP.length() - suffix.length();
        String truncated  = spawnerName.length() > maxSpawnerLen
                ? spawnerName.substring(0, Math.max(1, maxSpawnerLen))
                : spawnerName;
        String internal   = PREFIX + truncated + SEP + suffix;
        if (internal.length() > 16) internal = internal.substring(0, 16);
        usedNames.add(internal);

        String display = sanitizeDisplayName(
                Config.userBotNameFormat()
                        .replace("{spawner}", spawnerName)
                        .replace("{num}",     suffix)
                        .replace("{bot_name}", internal),
                internal);
        return new UserBotName(internal, display);
    }

    /**
     * Legacy compatibility method for updating bot prefixes.
     * Since bots are now real NMS ServerPlayer entities, LuckPerms applies
     * prefixes/suffixes natively without manual intervention.
     */
    public void updateAllBotPrefixes() {
        // No-op - LP handles prefix updates natively for real players
        Config.debug("updateAllBotPrefixes: skipped (bots are real players, LP handles natively)");
    }

    // в”Җв”Җ Head-AI helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Like {@link Player#hasLineOfSight} but treats glass and other visually
     * transparent blocks as if they were air.  Non-solid blocks (flowers,
     * torches, etc.) are always ignored.  Falls back to the vanilla method on
     * any unexpected error.
     *
     * <p>Covered by {@link #isGlassLike}: any {@link Material} whose name
     * contains {@code "GLASS"} (plain glass, stained glass, glass panes,
     * tinted glass, etc.).
     */
    private static boolean hasLineOfSightIgnoringGlass(Player from, Player to) {
        Location start = from.getEyeLocation();
        Location end   = to.getEyeLocation();
        if (start.getWorld() == null || !start.getWorld().equals(end.getWorld())) return false;

        org.bukkit.util.Vector dir = end.toVector().subtract(start.toVector());
        double distance = dir.length();
        if (distance < 1e-6) return true;
        dir.normalize();

        try {
            BlockIterator iter = new BlockIterator(
                    start.getWorld(), start.toVector(), dir, 0.0, (int) Math.ceil(distance) + 1);
            while (iter.hasNext()) {
                org.bukkit.block.Block block = iter.next();
                Material type = block.getType();
                if (!type.isSolid()) continue;        // air, flowers, carpet, etc.
                if (isGlassLike(type)) continue;      // glass is transparent to head-AI
                // Opaque solid вҖ” only counts if it is actually between the two points.
                double blockDistSq = block.getLocation().add(0.5, 0.5, 0.5).distanceSquared(start);
                if (blockDistSq < distance * distance) return false;
            }
        } catch (Exception e) {
            return from.hasLineOfSight(to); // safe fallback
        }
        return true;
    }

    /**
     * Returns {@code true} when the material is glass-like and should be
     * treated as transparent for bot line-of-sight checks.
     * Matches: {@code GLASS}, {@code STAINED_GLASS}, {@code GLASS_PANE},
     * {@code STAINED_GLASS_PANE}, {@code TINTED_GLASS}, and any future
     * glass-variant added by Mojang whose name contains {@code "GLASS"}.
     */
    private static boolean isGlassLike(Material mat) {
        return mat.name().contains("GLASS");
    }

    /**
     * Linearly interpolates between two angles in degrees, always taking the
     * shortest arc across the 360В°/вҲ’180В° boundary.
     *
     * @param from  current angle in degrees
     * @param to    target angle in degrees
     * @param t     blend factor вҖ“ 0 = stay, 1 = snap immediately
     * @return interpolated angle
     */
    private static float lerpAngle(float from, float to, float t) {
        float diff = to - from;
        while (diff >  180f) diff -= 360f;
        while (diff < -180f) diff += 360f;
        return from + diff * t;
    }

}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import org.bukkit.Bukkit;

import java.io.*;
import java.lang.reflect.Method;
import java.net.URL;
import java.net.URLClassLoader;
import java.util.concurrent.Callable;

/**
 * FastStats anonymous usage metrics вҖ” developer-only, not user-configurable.
 *
 * <p>FastStats is loaded at runtime via a dedicated {@link URLClassLoader} pointing
 * to jars bundled inside the plugin jar as resources (src/main/resources/faststats/).
 * This sidesteps all Maven shade-plugin relocation issues: the shade plugin does NOT
 * update references in the project's own class files, causing NoClassDefFoundError.
 * With URLClassLoader the classes are found directly вҖ” no relocation needed.
 *
 * <p>No personal data, player names, or server addresses are ever collected.
 */
public final class FppMetrics {

    // в”Җв”Җ Developer constant вҖ” NOT in config.yml в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private static final String TOKEN = "376511af6c97b56954ff2abed24dfaea";

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private URLClassLoader fsLoader;   // isolated classloader for FastStats jars
    private Object         metrics;    // dev.faststats.bukkit.BukkitMetrics (held as Object)
    private boolean        initialised = false;

    // в”Җв”Җ Lifecycle в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    public void init(FakePlayerPlugin plugin, FakePlayerManager botManager) {
        if (TOKEN.isBlank()) {
            FppLogger.warn("Metrics: TOKEN is blank вҖ” FastStats disabled.");
            return;
        }

        FppLogger.info("Metrics: Initialising FastStats (token=" + TOKEN.substring(0, 8) + "...)");

        ClassLoader prevCtx = Thread.currentThread().getContextClassLoader();
        try {
            // в”Җв”Җ 1. Extract FastStats jars from plugin resources в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            File libsDir = new File(plugin.getDataFolder(), ".faststats-libs");
            libsDir.mkdirs();

            File coreJar   = extractResource(plugin, "faststats/faststats-core.jar",   libsDir);
            File bukkitJar = extractResource(plugin, "faststats/faststats-bukkit.jar",  libsDir);

            // в”Җв”Җ 2. Dedicated URLClassLoader в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            // Parent = plugin's own classloader so FastStats can see Paper API,
            // java.util.concurrent.Callable, org.bukkit.plugin.Plugin, etc.
            fsLoader = new URLClassLoader(
                    new URL[]{ coreJar.toURI().toURL(), bukkitJar.toURI().toURL() },
                    plugin.getClass().getClassLoader()
            );
            // Give FastStats's SPI/ServiceLoader its own loader as context
            Thread.currentThread().setContextClassLoader(fsLoader);

            // в”Җв”Җ 3. ErrorTracker в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            FppLogger.info("Metrics: [1/3] Creating ErrorTracker...");
            Class<?> etClass      = fsLoader.loadClass("dev.faststats.core.ErrorTracker");
            Object   errorTracker = etClass.getMethod("contextAware").invoke(null);
            FppLogger.info("Metrics:       ErrorTracker вң”");

            // в”Җв”Җ 4. BukkitMetrics fluent factory в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            FppLogger.info("Metrics: [2/3] Building BukkitMetrics...");
            Class<?> bmClass = fsLoader.loadClass("dev.faststats.bukkit.BukkitMetrics");
            Class<?> mClass  = fsLoader.loadClass("dev.faststats.core.data.Metric");

            Method numberMethod = findMethod(mClass, "number", 2);
            Method stringMethod = findMethod(mClass, "string", 2);

            Object factory = bmClass.getMethod("factory").invoke(null);
            factory = chain(factory, "token",        TOKEN);

            factory = addMetric(factory, numberMethod.invoke(null, "active_bots",
                    (Callable<Long>) () -> (long) (botManager == null ? 0 : botManager.getCount())));
            factory = addMetric(factory, numberMethod.invoke(null, "online_players",
                    (Callable<Long>) () -> (long) Bukkit.getOnlinePlayers().size()));
            factory = addMetric(factory, stringMethod.invoke(null, "skin_mode",
                    (Callable<String>) Config::skinMode));
            factory = addMetric(factory, numberMethod.invoke(null, "persistence_enabled",
                    (Callable<Long>) () -> Config.persistOnRestart() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "body_enabled",
                    (Callable<Long>) () -> Config.spawnBody() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "fake_chat_enabled",
                    (Callable<Long>) () -> Config.fakeChatEnabled() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "swap_enabled",
                    (Callable<Long>) () -> Config.swapEnabled() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "chunk_loading_enabled",
                    (Callable<Long>) () -> Config.chunkLoadingEnabled() ? 1L : 0L));
            factory = addMetric(factory, stringMethod.invoke(null, "database_type",
                    (Callable<String>) () -> Config.mysqlEnabled() ? "mysql" : "sqlite"));
            factory = addMetric(factory, numberMethod.invoke(null, "luckperms_prefix_enabled",
                    (Callable<Long>) () -> (Bukkit.getPluginManager().getPlugin("LuckPerms") != null
                            && Config.luckpermsUsePrefix()) ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "max_bots_config",
                    (Callable<Long>) () -> (long) Config.maxBots()));

            factory = chain(factory, "errorTracker", errorTracker);
            factory = chain(factory, "debug",        false);
            FppLogger.info("Metrics:       BukkitMetrics built вң”");

            // в”Җв”Җ 5. Create and arm в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            FppLogger.info("Metrics: [3/3] Calling ready()...");
            metrics = chain(factory, "create", plugin);
            findMethod(metrics.getClass(), "ready", 0).invoke(metrics);
            initialised = true;
            FppLogger.success("Metrics: FastStats connected and reporting вң”");

        } catch (Throwable t) {
            FppLogger.error("в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ");
            FppLogger.error("в•‘  Metrics: FastStats init FAILED");
            FppLogger.error("в•‘  " + t.getClass().getName() + ": " + t.getMessage());
            Throwable c = t; int d = 0;
            while (c.getCause() != null && d++ < 6) {
                c = c.getCause();
                FppLogger.error("в•‘  Caused by: " + c.getClass().getName() + ": " + c.getMessage());
            }
            FppLogger.error("в•‘  Stack (top 10):");
            StackTraceElement[] st = t.getStackTrace();
            for (int i = 0; i < Math.min(10, st.length); i++) FppLogger.error("в•‘    at " + st[i]);
            FppLogger.error("в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ");
            metrics = null;
            closeLoader();
        } finally {
            Thread.currentThread().setContextClassLoader(prevCtx);
        }
    }

    public void shutdown() {
        if (metrics != null && initialised) {
            try { findMethod(metrics.getClass(), "shutdown", 0).invoke(metrics); } catch (Throwable ignored) {}
            metrics = null;
        }
        initialised = false;
        closeLoader();
    }

    public boolean isActive() { return initialised && metrics != null; }

    // в”Җв”Җ Reflection helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Invoke the first method named {@code name} with {@code args.length} params on {@code obj}. */
    private static Object chain(Object obj, String name, Object... args) throws ReflectiveOperationException {
        for (Method m : obj.getClass().getMethods()) {
            if (m.getName().equals(name) && m.getParameterCount() == args.length) {
                try { return m.invoke(obj, args); } catch (IllegalArgumentException ignored) {}
            }
        }
        throw new NoSuchMethodException(obj.getClass().getSimpleName() + "." + name + "/" + args.length);
    }

    /** Find the first public method named {@code name} with exactly {@code paramCount} params. */
    private static Method findMethod(Class<?> cls, String name, int paramCount) throws NoSuchMethodException {
        for (Method m : cls.getMethods()) {
            if (m.getName().equals(name) && m.getParameterCount() == paramCount) return m;
        }
        throw new NoSuchMethodException(cls.getSimpleName() + "." + name + "/" + paramCount);
    }

    /** Call {@code addMetric(metric)} on the factory and return the updated factory. */
    private static Object addMetric(Object factory, Object metric) throws ReflectiveOperationException {
        for (Method m : factory.getClass().getMethods()) {
            if (m.getName().equals("addMetric") && m.getParameterCount() == 1) {
                try { return m.invoke(factory, metric); } catch (IllegalArgumentException ignored) {}
            }
        }
        throw new NoSuchMethodException("addMetric");
    }

    // в”Җв”Җ Resource extraction в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static File extractResource(FakePlayerPlugin plugin, String resourcePath, File destDir)
            throws IOException {
        String fileName = resourcePath.substring(resourcePath.lastIndexOf('/') + 1);
        File   dest     = new File(destDir, fileName);
        try (InputStream in = plugin.getResource(resourcePath)) {
            if (in == null) throw new IOException("Bundled resource not found: " + resourcePath);
            byte[] data = in.readAllBytes();
            if (!dest.exists() || dest.length() != data.length) {
                try (OutputStream out = new FileOutputStream(dest)) { out.write(data); }
                FppLogger.info("Metrics: extracted " + fileName + " (" + data.length / 1024 + " KB)");
            }
        }
        return dest;
    }

    private void closeLoader() {
        if (fsLoader != null) {
            try { fsLoader.close(); } catch (IOException ignored) {}
            fsLoader = null;
        }
    }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import org.bukkit.Bukkit;

import java.io.*;
import java.lang.reflect.Method;
import java.net.URL;
import java.net.URLClassLoader;
import java.util.concurrent.Callable;

/**
 * FastStats anonymous usage metrics вҖ” developer-only, not user-configurable.
 *
 * <p>FastStats is loaded at runtime via a dedicated {@link URLClassLoader} pointing
 * to jars bundled inside the plugin jar as resources (src/main/resources/faststats/).
 * This sidesteps all Maven shade-plugin relocation issues: the shade plugin does NOT
 * update references in the project's own class files, causing NoClassDefFoundError.
 * With URLClassLoader the classes are found directly вҖ” no relocation needed.
 *
 * <p>No personal data, player names, or server addresses are ever collected.
 */
public final class FppMetrics {

    // в”Җв”Җ Developer constant вҖ” NOT in config.yml в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private static final String TOKEN = "376511af6c97b56954ff2abed24dfaea";

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private URLClassLoader fsLoader;   // isolated classloader for FastStats jars
    private Object         metrics;    // dev.faststats.bukkit.BukkitMetrics (held as Object)
    private boolean        initialised = false;

    // в”Җв”Җ Lifecycle в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    public void init(FakePlayerPlugin plugin, FakePlayerManager botManager) {
        if (TOKEN.isBlank()) {
            FppLogger.warn("Metrics: TOKEN is blank вҖ” FastStats disabled.");
            return;
        }

        FppLogger.info("Metrics: Initialising FastStats (token=" + TOKEN.substring(0, 8) + "...)");

        ClassLoader prevCtx = Thread.currentThread().getContextClassLoader();
        try {
            // в”Җв”Җ 1. Extract FastStats jars from plugin resources в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            File libsDir = new File(plugin.getDataFolder(), ".faststats-libs");
            libsDir.mkdirs();

            File coreJar   = extractResource(plugin, "faststats/faststats-core.jar",   libsDir);
            File bukkitJar = extractResource(plugin, "faststats/faststats-bukkit.jar",  libsDir);

            // в”Җв”Җ 2. Dedicated URLClassLoader в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            // Parent = plugin's own classloader so FastStats can see Paper API,
            // java.util.concurrent.Callable, org.bukkit.plugin.Plugin, etc.
            fsLoader = new URLClassLoader(
                    new URL[]{ coreJar.toURI().toURL(), bukkitJar.toURI().toURL() },
                    plugin.getClass().getClassLoader()
            );
            // Give FastStats's SPI/ServiceLoader its own loader as context
            Thread.currentThread().setContextClassLoader(fsLoader);

            // в”Җв”Җ 3. ErrorTracker в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            FppLogger.info("Metrics: [1/3] Creating ErrorTracker...");
            Class<?> etClass      = fsLoader.loadClass("dev.faststats.core.ErrorTracker");
            Object   errorTracker = etClass.getMethod("contextAware").invoke(null);
            FppLogger.info("Metrics:       ErrorTracker вң”");

            // в”Җв”Җ 4. BukkitMetrics fluent factory в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            FppLogger.info("Metrics: [2/3] Building BukkitMetrics...");
            Class<?> bmClass = fsLoader.loadClass("dev.faststats.bukkit.BukkitMetrics");
            Class<?> mClass  = fsLoader.loadClass("dev.faststats.core.data.Metric");

            Method numberMethod = findMethod(mClass, "number", 2);
            Method stringMethod = findMethod(mClass, "string", 2);

            Object factory = bmClass.getMethod("factory").invoke(null);
            factory = chain(factory, "token",        TOKEN);

            factory = addMetric(factory, numberMethod.invoke(null, "active_bots",
                    (Callable<Long>) () -> (long) (botManager == null ? 0 : botManager.getCount())));
            factory = addMetric(factory, numberMethod.invoke(null, "online_players",
                    (Callable<Long>) () -> (long) Bukkit.getOnlinePlayers().size()));
            factory = addMetric(factory, stringMethod.invoke(null, "skin_mode",
                    (Callable<String>) Config::skinMode));
            factory = addMetric(factory, numberMethod.invoke(null, "persistence_enabled",
                    (Callable<Long>) () -> Config.persistOnRestart() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "body_enabled",
                    (Callable<Long>) () -> Config.spawnBody() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "fake_chat_enabled",
                    (Callable<Long>) () -> Config.fakeChatEnabled() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "swap_enabled",
                    (Callable<Long>) () -> Config.swapEnabled() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "chunk_loading_enabled",
                    (Callable<Long>) () -> Config.chunkLoadingEnabled() ? 1L : 0L));
            factory = addMetric(factory, stringMethod.invoke(null, "database_type",
                    (Callable<String>) () -> Config.mysqlEnabled() ? "mysql" : "sqlite"));
            factory = addMetric(factory, numberMethod.invoke(null, "luckperms_prefix_enabled",
                    (Callable<Long>) () -> (Bukkit.getPluginManager().getPlugin("LuckPerms") != null
                            && Config.luckpermsUsePrefix()) ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "max_bots_config",
                    (Callable<Long>) () -> (long) Config.maxBots()));

            factory = chain(factory, "errorTracker", errorTracker);
            factory = chain(factory, "debug",        false);
            FppLogger.info("Metrics:       BukkitMetrics built вң”");

            // в”Җв”Җ 5. Create and arm в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            FppLogger.info("Metrics: [3/3] Calling ready()...");
            metrics = chain(factory, "create", plugin);
            findMethod(metrics.getClass(), "ready", 0).invoke(metrics);
            initialised = true;
            FppLogger.success("Metrics: FastStats connected and reporting вң”");

        } catch (Throwable t) {
            FppLogger.error("в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ");
            FppLogger.error("в•‘  Metrics: FastStats init FAILED");
            FppLogger.error("в•‘  " + t.getClass().getName() + ": " + t.getMessage());
            Throwable c = t; int d = 0;
            while (c.getCause() != null && d++ < 6) {
                c = c.getCause();
                FppLogger.error("в•‘  Caused by: " + c.getClass().getName() + ": " + c.getMessage());
            }
            FppLogger.error("в•‘  Stack (top 10):");
            StackTraceElement[] st = t.getStackTrace();
            for (int i = 0; i < Math.min(10, st.length); i++) FppLogger.error("в•‘    at " + st[i]);
            FppLogger.error("в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ");
            metrics = null;
            closeLoader();
        } finally {
            Thread.currentThread().setContextClassLoader(prevCtx);
        }
    }

    public void shutdown() {
        if (metrics != null && initialised) {
            try { findMethod(metrics.getClass(), "shutdown", 0).invoke(metrics); } catch (Throwable ignored) {}
            metrics = null;
        }
        initialised = false;
        closeLoader();
    }

    public boolean isActive() { return initialised && metrics != null; }

    // в”Җв”Җ Reflection helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Invoke the first method named {@code name} with {@code args.length} params on {@code obj}.
     *  Walks the full class/interface hierarchy and calls setAccessible(true) to avoid
     *  IllegalAccessException when the impl class (e.g. BukkitMetricsImpl$Factory) is loaded
     *  from a foreign URLClassLoader. */
    private static Object chain(Object obj, String name, Object... args) throws ReflectiveOperationException {
        Method found = null;
        // Walk declared methods up the hierarchy (handles impl inner classes)
        Class<?> cls = obj.getClass();
        outer:
        while (cls != null) {
            for (Method m : cls.getDeclaredMethods()) {
                if (m.getName().equals(name) && m.getParameterCount() == args.length) {
                    found = m; break outer;
                }
            }
            for (Class<?> iface : cls.getInterfaces()) {
                for (Method m : iface.getDeclaredMethods()) {
                    if (m.getName().equals(name) && m.getParameterCount() == args.length) {
                        found = m; break outer;
                    }
                }
            }
            cls = cls.getSuperclass();
        }
        // Last resort: getMethods()
        if (found == null) {
            for (Method m : obj.getClass().getMethods()) {
                if (m.getName().equals(name) && m.getParameterCount() == args.length) { found = m; break; }
            }
        }
        if (found == null)
            throw new NoSuchMethodException(obj.getClass().getSimpleName() + "." + name + "/" + args.length);
        found.setAccessible(true);
        return found.invoke(obj, args);
    }

    /** Find the first method named {@code name} with exactly {@code paramCount} params.
     *  Calls setAccessible(true) before returning. */
    private static Method findMethod(Class<?> cls, String name, int paramCount) throws NoSuchMethodException {
        Class<?> c = cls;
        while (c != null) {
            for (Method m : c.getDeclaredMethods()) {
                if (m.getName().equals(name) && m.getParameterCount() == paramCount) {
                    m.setAccessible(true);
                    return m;
                }
            }
            c = c.getSuperclass();
        }
        for (Method m : cls.getMethods()) {
            if (m.getName().equals(name) && m.getParameterCount() == paramCount) {
                m.setAccessible(true);
                return m;
            }
        }
        throw new NoSuchMethodException(cls.getSimpleName() + "." + name + "/" + paramCount);
    }

    /** Call {@code addMetric(metric)} on the factory and return the updated factory. */
    private static Object addMetric(Object factory, Object metric) throws ReflectiveOperationException {
        Class<?> cls = factory.getClass();
        while (cls != null) {
            for (Method m : cls.getDeclaredMethods()) {
                if (m.getName().equals("addMetric") && m.getParameterCount() == 1) {
                    m.setAccessible(true);
                    try { return m.invoke(factory, metric); } catch (IllegalArgumentException ignored) {}
                }
            }
            cls = cls.getSuperclass();
        }
        for (Method m : factory.getClass().getMethods()) {
            if (m.getName().equals("addMetric") && m.getParameterCount() == 1) {
                m.setAccessible(true);
                try { return m.invoke(factory, metric); } catch (IllegalArgumentException ignored) {}
            }
        }
        throw new NoSuchMethodException("addMetric");
    }

    // в”Җв”Җ Resource extraction в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static File extractResource(FakePlayerPlugin plugin, String resourcePath, File destDir)
            throws IOException {
        String fileName = resourcePath.substring(resourcePath.lastIndexOf('/') + 1);
        File   dest     = new File(destDir, fileName);
        try (InputStream in = plugin.getResource(resourcePath)) {
            if (in == null) throw new IOException("Bundled resource not found: " + resourcePath);
            byte[] data = in.readAllBytes();
            if (!dest.exists() || dest.length() != data.length) {
                try (OutputStream out = new FileOutputStream(dest)) { out.write(data); }
                FppLogger.info("Metrics: extracted " + fileName + " (" + data.length / 1024 + " KB)");
            }
        }
        return dest;
    }

    private void closeLoader() {
        if (fsLoader != null) {
            try { fsLoader.close(); } catch (IOException ignored) {}
            fsLoader = null;
        }
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.gui.HelpGui;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import me.bill.fakePlayerPlugin.util.TextUtil;
import net.kyori.adventure.text.Component;
import net.kyori.adventure.text.event.ClickEvent;
import net.kyori.adventure.text.event.HoverEvent;
import net.kyori.adventure.text.format.NamedTextColor;
import net.kyori.adventure.text.format.TextColor;
import net.kyori.adventure.text.format.TextDecoration;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;

import java.util.List;

/**
 * Handles {@code /fpp help [page]}.
 *
 * <p>For in-game players: opens the {@link HelpGui} double-chest GUI.
 * For console / non-player senders: falls back to the original paginated text output.
 *
 * <p>The command list is read live from the {@link CommandManager} so new commands
 * appear automatically without any manual wiring.
 */
public class HelpCommand implements FppCommand {

    private static final int PAGE_SIZE = 6;
    private static final TextColor ACCENT = TextColor.fromHexString("#0079FF");

    private final CommandManager manager;

    /** Injected after onEnable creates the GUI. {@code null} until then вҶ’ text fallback. */
    private volatile HelpGui helpGui = null;

    public HelpCommand(CommandManager manager) {
        this.manager = manager;
    }

    /** Called by {@link CommandManager#setHelpGui(HelpGui)} once the GUI is ready. */
    public void setHelpGui(HelpGui gui) {
        this.helpGui = gui;
    }

    // в”Җв”Җ FppCommand impl в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override public String getName()        { return "help"; }
    @Override public String getUsage()       { return "[page]"; }
    @Override public String getDescription() { return "Shows the command help menu."; }
    @Override public String getPermission()  { return Perm.HELP; }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        // в”Җв”Җ GUI for players в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (sender instanceof Player player && helpGui != null) {
            helpGui.open(player);
            return true;
        }

        // в”Җв”Җ Text fallback for console / pre-GUI init в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        List<FppCommand> visible = manager.getCommands().stream()
                .filter(cmd -> cmd.canUse(sender))
                .toList();

        int totalPages = Math.max(1, (int) Math.ceil(visible.size() / (double) PAGE_SIZE));

        int page = 1;
        if (args.length > 0) {
            try { page = Integer.parseInt(args[0]); } catch (NumberFormatException ignored) {}
        }
        page = Math.min(Math.max(page, 1), totalPages);

        // в”Җв”Җ Header в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        sender.sendMessage(Lang.get("help-header"));
        sender.sendMessage(Component.empty());

        // в”Җв”Җ Entries в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        int from = (page - 1) * PAGE_SIZE;
        int to   = Math.min(from + PAGE_SIZE, visible.size());

        for (FppCommand cmd : visible.subList(from, to)) {
            String usage = cmd.getUsage().isEmpty() ? "" : " " + cmd.getUsage();
            String raw = Lang.raw("help-entry",
                    "cmd",  "fpp " + cmd.getName(),
                    "args", usage,
                    "desc", cmd.getDescription());
            sender.sendMessage(TextUtil.colorize(raw));
        }

        // в”Җв”Җ Clickable pagination bar (below entries) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        sender.sendMessage(Component.empty());
        sender.sendMessage(buildPaginationBar(page, totalPages));
        sender.sendMessage(Lang.get("help-footer"));
        return true;
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Builds the clickable В« page/total В» pagination bar.
     * Prev/next arrows are greyed out and non-clickable when on the first/last page.
     */
    private Component buildPaginationBar(int page, int totalPages) {
        // В« prev
        Component prev;
        if (page > 1) {
            prev = Component.text("В« бҙҳКҖбҙҮбҙ ")
                    .color(ACCENT)
                    .decoration(TextDecoration.BOLD, true)
                    .clickEvent(ClickEvent.runCommand("/fpp help " + (page - 1)))
                    .hoverEvent(HoverEvent.showText(
                            Component.text("Go to page " + (page - 1)).color(NamedTextColor.GRAY)));
        } else {
            prev = Component.text("В« бҙҳКҖбҙҮбҙ ")
                    .color(NamedTextColor.DARK_GRAY)
                    .decoration(TextDecoration.BOLD, true);
        }

        // page / total (centre)
        Component pageInfo = Component.text("  " + page + " / " + totalPages + "  ")
                .color(NamedTextColor.WHITE);

        // next В»
        Component next;
        if (page < totalPages) {
            next = Component.text("ЙҙбҙҮxбҙӣ В»")
                    .color(ACCENT)
                    .decoration(TextDecoration.BOLD, true)
                    .clickEvent(ClickEvent.runCommand("/fpp help " + (page + 1)))
                    .hoverEvent(HoverEvent.showText(
                            Component.text("Go to page " + (page + 1)).color(NamedTextColor.GRAY)));
        } else {
            next = Component.text("ЙҙбҙҮxбҙӣ В»")
                    .color(NamedTextColor.DARK_GRAY)
                    .decoration(TextDecoration.BOLD, true);
        }

        return Component.text(" ").append(prev).append(pageInfo).append(next);
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.gui.HelpGui;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import me.bill.fakePlayerPlugin.util.TextUtil;
import net.kyori.adventure.text.Component;
import net.kyori.adventure.text.event.ClickEvent;
import net.kyori.adventure.text.event.HoverEvent;
import net.kyori.adventure.text.format.NamedTextColor;
import net.kyori.adventure.text.format.TextColor;
import net.kyori.adventure.text.format.TextDecoration;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;

import java.util.List;

/**
 * Handles {@code /fpp help [page]}.
 *
 * <p>For in-game players: opens the {@link HelpGui} double-chest GUI.
 * For console / non-player senders: falls back to the original paginated text output.
 *
 * <p>The command list is read live from the {@link CommandManager} so new commands
 * appear automatically without any manual wiring.
 */
public class HelpCommand implements FppCommand {

    private static final int PAGE_SIZE = 6;
    private static final TextColor ACCENT = TextColor.fromHexString("#0079FF");

    private final CommandManager manager;

    /** Injected after onEnable creates the GUI. {@code null} until then вҶ’ text fallback. */
    private volatile HelpGui helpGui = null;

    public HelpCommand(CommandManager manager) {
        this.manager = manager;
    }

    /** Called by CommandManager once the GUI is ready. */
    public void setHelpGui(HelpGui gui) {
        this.helpGui = gui;
    }

    // в”Җв”Җ FppCommand impl в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override public String getName()        { return "help"; }
    @Override public String getUsage()       { return "[page]"; }
    @Override public String getDescription() { return "Shows the command help menu."; }
    @Override public String getPermission()  { return Perm.HELP; }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        // в”Җв”Җ GUI for players в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (sender instanceof Player player && helpGui != null) {
            helpGui.open(player);
            return true;
        }

        // в”Җв”Җ Text fallback for console / pre-GUI init в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        List<FppCommand> visible = manager.getCommands().stream()
                .filter(cmd -> cmd.canUse(sender))
                .toList();

        int totalPages = Math.max(1, (int) Math.ceil(visible.size() / (double) PAGE_SIZE));

        int page = 1;
        if (args.length > 0) {
            try { page = Integer.parseInt(args[0]); } catch (NumberFormatException ignored) {}
        }
        page = Math.min(Math.max(page, 1), totalPages);

        // в”Җв”Җ Header в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        sender.sendMessage(Lang.get("help-header"));
        sender.sendMessage(Component.empty());

        // в”Җв”Җ Entries в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        int from = (page - 1) * PAGE_SIZE;
        int to   = Math.min(from + PAGE_SIZE, visible.size());

        for (FppCommand cmd : visible.subList(from, to)) {
            String usage = cmd.getUsage().isEmpty() ? "" : " " + cmd.getUsage();
            String raw = Lang.raw("help-entry",
                    "cmd",  "fpp " + cmd.getName(),
                    "args", usage,
                    "desc", cmd.getDescription());
            sender.sendMessage(TextUtil.colorize(raw));
        }

        // в”Җв”Җ Clickable pagination bar (below entries) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        sender.sendMessage(Component.empty());
        sender.sendMessage(buildPaginationBar(page, totalPages));
        sender.sendMessage(Lang.get("help-footer"));
        return true;
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Builds the clickable В« page/total В» pagination bar.
     * Prev/next arrows are greyed out and non-clickable when on the first/last page.
     */
    private Component buildPaginationBar(int page, int totalPages) {
        // В« prev
        Component prev;
        if (page > 1) {
            prev = Component.text("В« бҙҳКҖбҙҮбҙ ")
                    .color(ACCENT)
                    .decoration(TextDecoration.BOLD, true)
                    .clickEvent(ClickEvent.runCommand("/fpp help " + (page - 1)))
                    .hoverEvent(HoverEvent.showText(
                            Component.text("Go to page " + (page - 1)).color(NamedTextColor.GRAY)));
        } else {
            prev = Component.text("В« бҙҳКҖбҙҮбҙ ")
                    .color(NamedTextColor.DARK_GRAY)
                    .decoration(TextDecoration.BOLD, true);
        }

        // page / total (centre)
        Component pageInfo = Component.text("  " + page + " / " + totalPages + "  ")
                .color(NamedTextColor.WHITE);

        // next В»
        Component next;
        if (page < totalPages) {
            next = Component.text("ЙҙбҙҮxбҙӣ В»")
                    .color(ACCENT)
                    .decoration(TextDecoration.BOLD, true)
                    .clickEvent(ClickEvent.runCommand("/fpp help " + (page + 1)))
                    .hoverEvent(HoverEvent.showText(
                            Component.text("Go to page " + (page + 1)).color(NamedTextColor.GRAY)));
        } else {
            next = Component.text("ЙҙбҙҮxбҙӣ В»")
                    .color(NamedTextColor.DARK_GRAY)
                    .decoration(TextDecoration.BOLD, true);
        }

        return Component.text(" ").append(prev).append(pageInfo).append(next);
    }
}

package me.bill.fakePlayerPlugin.gui;

import me.bill.fakePlayerPlugin.command.CommandManager;
import me.bill.fakePlayerPlugin.command.FppCommand;
import net.kyori.adventure.text.Component;
import net.kyori.adventure.text.format.NamedTextColor;
import net.kyori.adventure.text.format.TextColor;
import net.kyori.adventure.text.format.TextDecoration;
import org.bukkit.Bukkit;
import org.bukkit.Material;
import org.bukkit.Sound;
import org.bukkit.SoundCategory;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.inventory.InventoryClickEvent;
import org.bukkit.event.inventory.InventoryCloseEvent;
import org.bukkit.event.player.PlayerQuitEvent;
import org.bukkit.inventory.Inventory;
import org.bukkit.inventory.InventoryHolder;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.meta.ItemMeta;
import org.bukkit.plugin.Plugin;

import java.util.*;

/**
 * Double-chest GUI for {@code /fpp help}.
 *
 * <h3>Layout (54 slots)</h3>
 * <pre>
 *  Rows 0-4  [slots 0-44]  вҖ” one command item per slot (up to 45 per page)
 *  Row  5    [slots 45-53] вҖ” [filler][в—Җ prev][filler][filler][page #][filler][filler][в–¶ next][вң• close]
 * </pre>
 *
 * <p>Each command item shows the command name, usage, description, and
 * permission node in its lore. The icon uses a semantically meaningful
 * {@link Material} chosen per-command. The list is filtered live via
 * {@link FppCommand#canUse(org.bukkit.command.CommandSender)} so players
 * only see commands they have access to.
 *
 * <p>Console senders fall back to the original text-based help output in
 * {@link me.bill.fakePlayerPlugin.command.HelpCommand}.
 */
public final class HelpGui implements Listener {

    // в”Җв”Җ Colour palette (mirrors SettingGui / InventoryCommand) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private static final TextColor ACCENT    = TextColor.fromHexString("#0079FF");
    private static final TextColor ON_GREEN  = TextColor.fromHexString("#66CC66");
    private static final TextColor ORANGE    = TextColor.fromHexString("#FFA500");
    private static final TextColor DARK_GRAY = NamedTextColor.DARK_GRAY;
    private static final TextColor GRAY      = NamedTextColor.GRAY;
    private static final TextColor WHITE     = NamedTextColor.WHITE;
    private static final TextColor OFF_RED   = NamedTextColor.RED;
    private static final TextColor YELLOW    = NamedTextColor.YELLOW;

    // в”Җв”Җ Geometry в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private static final int SIZE          = 54;
    private static final int CMDS_PER_PAGE = 45;   // rows 0-4, all 9 cols
    private static final int SLOT_PREV     = 46;
    private static final int SLOT_PAGE     = 49;
    private static final int SLOT_NEXT     = 52;
    private static final int SLOT_CLOSE    = 53;

    private final Plugin         plugin;
    private final CommandManager commandManager;

    /** Per-player session: UUID вҶ’ current page index (0-based). */
    private final Map<UUID, Integer> sessions = new HashMap<>();

    public HelpGui(Plugin plugin, CommandManager commandManager) {
        this.plugin         = plugin;
        this.commandManager = commandManager;
    }

    // в”Җв”Җ Public API в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Opens the help GUI for {@code player} at page 0. */
    public void open(Player player) {
        sessions.put(player.getUniqueId(), 0);
        build(player);
    }

    // в”Җв”Җ Events в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @EventHandler
    public void onInventoryClick(InventoryClickEvent event) {
        if (!(event.getInventory().getHolder() instanceof Holder holder)) return;
        event.setCancelled(true);
        if (!(event.getWhoClicked() instanceof Player player)) return;
        if (event.getClickedInventory() == null) return;
        if (!event.getClickedInventory().equals(event.getInventory())) return;

        Integer page = sessions.get(holder.uuid);
        if (page == null) return;

        int slot = event.getSlot();
        int totalPages = totalPages(player);

        if (slot == SLOT_PREV && page > 0) {
            sessions.put(holder.uuid, page - 1);
            playClick(player, 1.0f);
            build(player);
            return;
        }
        if (slot == SLOT_NEXT && page < totalPages - 1) {
            sessions.put(holder.uuid, page + 1);
            playClick(player, 1.0f);
            build(player);
            return;
        }
        if (slot == SLOT_CLOSE) {
            playClick(player, 0.8f);
            player.closeInventory();
            return;
        }
        // Clicking a command entry вҖ” play a soft tick for tactile feedback.
        if (slot < CMDS_PER_PAGE) {
            int idx = page * CMDS_PER_PAGE + slot;
            if (idx < visibleCommands(player).size()) playClick(player, 1.3f);
        }
    }

    @EventHandler
    public void onInventoryClose(InventoryCloseEvent event) {
        if (!(event.getInventory().getHolder() instanceof Holder)) return;
        sessions.remove(event.getPlayer().getUniqueId());
    }

    @EventHandler
    public void onPlayerQuit(PlayerQuitEvent event) {
        sessions.remove(event.getPlayer().getUniqueId());
    }

    // в”Җв”Җ Build в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private void build(Player player) {
        Integer raw = sessions.get(player.getUniqueId());
        if (raw == null) return;

        List<FppCommand> visible = visibleCommands(player);
        int totalPages = Math.max(1, (int) Math.ceil(visible.size() / (double) CMDS_PER_PAGE));
        int page = Math.min(raw, totalPages - 1);
        sessions.put(player.getUniqueId(), page);

        Holder    holder = new Holder(player.getUniqueId());
        Component title  = Component.empty()
                .decoration(TextDecoration.ITALIC, false)
                .append(Component.text("[").color(DARK_GRAY))
                .append(Component.text("кң°бҙҳбҙҳ").color(ACCENT))
                .append(Component.text("]  ").color(DARK_GRAY))
                .append(Component.text("бҙ„бҙҸбҙҚбҙҚбҙҖЙҙбҙ…кңұ").color(WHITE).decoration(TextDecoration.BOLD, true));

        Inventory inv = Bukkit.createInventory(holder, SIZE, title);

        // в”Җв”Җ Command items (slots 0-44) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        int start = page * CMDS_PER_PAGE;
        int end   = Math.min(start + CMDS_PER_PAGE, visible.size());
        for (int i = start; i < end; i++) {
            inv.setItem(i - start, buildCommandItem(visible.get(i)));
        }

        // в”Җв”Җ Bottom row (slots 45-53) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        ItemStack filler = glassFiller();
        for (int s = 45; s <= 53; s++) inv.setItem(s, filler);

        inv.setItem(SLOT_PREV,  page > 0              ? buildArrow(false) : filler);
        inv.setItem(SLOT_PAGE,  buildPageItem(page + 1, totalPages));
        inv.setItem(SLOT_NEXT,  page < totalPages - 1 ? buildArrow(true)  : filler);
        inv.setItem(SLOT_CLOSE, buildCloseButton());

        player.openInventory(inv);
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private List<FppCommand> visibleCommands(Player player) {
        return commandManager.getCommands().stream()
                .filter(cmd -> cmd.canUse(player))
                .toList();
    }

    private int totalPages(Player player) {
        return Math.max(1, (int) Math.ceil(visibleCommands(player).size() / (double) CMDS_PER_PAGE));
    }

    // в”Җв”Җ Item builders в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static ItemStack buildCommandItem(FppCommand cmd) {
        ItemStack item = new ItemStack(iconFor(cmd.getName()));
        ItemMeta  meta = item.getItemMeta();

        meta.displayName(Component.empty()
                .decoration(TextDecoration.ITALIC, false)
                .append(Component.text("/fpp " + cmd.getName())
                        .color(ACCENT)
                        .decoration(TextDecoration.BOLD, true)));

        List<Component> lore = new ArrayList<>();
        lore.add(Component.empty());

        // Usage
        String usage = cmd.getUsage();
        if (usage != null && !usage.isBlank()) {
            lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                    .append(Component.text("бҙңкңұбҙҖЙўбҙҮ  ").color(DARK_GRAY))
                    .append(Component.text("/fpp " + cmd.getName() + " " + usage).color(WHITE)));
            lore.add(Component.empty());
        }

        // Description вҖ” wrap at ~40 chars per line for readability
        String desc = cmd.getDescription();
        if (desc != null && !desc.isBlank()) {
            for (String line : wrapText(desc, 42)) {
                lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(line).color(GRAY)));
            }
        }

        // Permission node
        String perm = cmd.getPermission();
        if (perm != null && !perm.isBlank()) {
            lore.add(Component.empty());
            lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                    .append(Component.text("бҙҳбҙҮКҖбҙҚ  ").color(DARK_GRAY))
                    .append(Component.text(perm).color(YELLOW)));
        }

        lore.add(Component.empty());
        meta.lore(lore);
        item.setItemMeta(meta);
        return item;
    }

    private static Material iconFor(String name) {
        return switch (name.toLowerCase()) {
            case "spawn"               -> Material.PLAYER_HEAD;
            case "despawn", "delete"   -> Material.BONE;
            case "list"                -> Material.BOOK;
            case "help"                -> Material.KNOWLEDGE_BOOK;
            case "info"                -> Material.MAP;
            case "chat"                -> Material.PAPER;
            case "reload"              -> Material.NETHER_STAR;
            case "freeze"              -> Material.PACKED_ICE;
            case "stats"               -> Material.CLOCK;
            case "tp"                  -> Material.ENDER_PEARL;
            case "tph"                 -> Material.ENDER_EYE;
            case "rank"                -> Material.GOLDEN_CHESTPLATE;
            case "lpinfo"              -> Material.GOLDEN_HELMET;
            case "move"                -> Material.COMPASS;
            case "inventory", "inv"    -> Material.CHEST;
            case "cmd"                 -> Material.COMMAND_BLOCK;
            case "swap"                -> Material.RECOVERY_COMPASS;
            case "peaks"               -> Material.SUNFLOWER;
            case "settings"            -> Material.COMPARATOR;
            case "migrate"             -> Material.ANVIL;
            case "sync"                -> Material.OBSERVER;
            case "alert"               -> Material.BELL;
            case "xp"                  -> Material.EXPERIENCE_BOTTLE;
            default                    -> Material.PAPER;
        };
    }

    private static ItemStack buildArrow(boolean next) {
        Material  mat  = next ? Material.LIME_STAINED_GLASS_PANE : Material.MAGENTA_STAINED_GLASS_PANE;
        String    lbl  = next ? "в–¶  ЙҙбҙҮxбҙӣ бҙҳбҙҖЙўбҙҮ" : "в—Җ  бҙҳКҖбҙҮбҙ  бҙҳбҙҖЙўбҙҮ";
        TextColor col  = next ? ON_GREEN : ORANGE;
        ItemStack item = new ItemStack(mat);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text(lbl).color(col).decoration(TextDecoration.BOLD, true)));
        item.setItemMeta(meta);
        return item;
    }

    private static ItemStack buildPageItem(int page, int total) {
        ItemStack item = new ItemStack(Material.LIGHT_BLUE_STAINED_GLASS_PANE);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("бҙҳбҙҖЙўбҙҮ  ").color(DARK_GRAY))
                .append(Component.text(page + " / " + total).color(WHITE).decoration(TextDecoration.BOLD, true)));
        item.setItemMeta(meta);
        return item;
    }

    private static ItemStack buildCloseButton() {
        ItemStack item = new ItemStack(Material.BARRIER);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("вң•  бҙ„КҹбҙҸкңұбҙҮ").color(OFF_RED).decoration(TextDecoration.BOLD, true)));
        meta.lore(List.of(Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("бҙ„КҹбҙҸкңұбҙҮ бҙӣКңбҙҮ КңбҙҮКҹбҙҳ бҙҚбҙҮЙҙбҙң.").color(DARK_GRAY))));
        item.setItemMeta(meta);
        return item;
    }

    private static ItemStack glassFiller() {
        ItemStack item = new ItemStack(Material.GRAY_STAINED_GLASS_PANE);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(Component.text(" ").decoration(TextDecoration.ITALIC, false));
        item.setItemMeta(meta);
        return item;
    }

    private static void playClick(Player player, float pitch) {
        player.playSound(player.getLocation(), Sound.UI_BUTTON_CLICK, SoundCategory.MASTER, 0.5f, pitch);
    }

    /**
     * Very simple word-wrap: splits {@code text} into lines no longer than
     * {@code maxLen} characters, breaking at spaces where possible.
     */
    private static List<String> wrapText(String text, int maxLen) {
        if (text.length() <= maxLen) return List.of(text);
        List<String> lines = new ArrayList<>();
        String[] words = text.split(" ");
        StringBuilder sb = new StringBuilder();
        for (String word : words) {
            if (!sb.isEmpty() && sb.length() + 1 + word.length() > maxLen) {
                lines.add(sb.toString());
                sb.setLength(0);
            }
            if (!sb.isEmpty()) sb.append(' ');
            sb.append(word);
        }
        if (!sb.isEmpty()) lines.add(sb.toString());
        return lines;
    }

    // в”Җв”Җ Inner InventoryHolder в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Uniquely identifies a HelpGui inventory instance. */
    public static final class Holder implements InventoryHolder {
        public final UUID uuid;
        Holder(UUID uuid) { this.uuid = uuid; }
        @Override public Inventory getInventory() { return null; }
    }
}

package me.bill.fakePlayerPlugin.gui;

import me.bill.fakePlayerPlugin.command.CommandManager;
import me.bill.fakePlayerPlugin.command.FppCommand;
import net.kyori.adventure.text.Component;
import net.kyori.adventure.text.format.NamedTextColor;
import net.kyori.adventure.text.format.TextColor;
import net.kyori.adventure.text.format.TextDecoration;
import org.bukkit.Bukkit;
import org.bukkit.Material;
import org.bukkit.Sound;
import org.bukkit.SoundCategory;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.inventory.InventoryClickEvent;
import org.bukkit.event.inventory.InventoryCloseEvent;
import org.bukkit.event.player.PlayerQuitEvent;
import org.bukkit.inventory.Inventory;
import org.bukkit.inventory.InventoryHolder;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.meta.ItemMeta;
import org.bukkit.plugin.Plugin;

import java.util.*;

/**
 * Double-chest GUI for {@code /fpp help}.
 *
 * <h3>Layout (54 slots)</h3>
 * <pre>
 *  Rows 0-4  [slots 0-44]  вҖ” one command item per slot (up to 45 per page)
 *  Row  5    [slots 45-53] вҖ” [filler][в—Җ prev][filler][filler][page #][filler][filler][в–¶ next][вң• close]
 * </pre>
 *
 * <p>Each command item shows the command name, usage, description, and
 * permission node in its lore. The icon uses a semantically meaningful
 * {@link Material} chosen per-command. The list is filtered live via
 * {@link FppCommand#canUse(org.bukkit.command.CommandSender)} so players
 * only see commands they have access to.
 *
 * <p>Console senders fall back to the original text-based help output in
 * {@link me.bill.fakePlayerPlugin.command.HelpCommand}.
 */
public final class HelpGui implements Listener {

    // в”Җв”Җ Colour palette (mirrors SettingGui / InventoryCommand) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private static final TextColor ACCENT    = TextColor.fromHexString("#0079FF");
    private static final TextColor ON_GREEN  = TextColor.fromHexString("#66CC66");
    private static final TextColor ORANGE    = TextColor.fromHexString("#FFA500");
    private static final TextColor DARK_GRAY = NamedTextColor.DARK_GRAY;
    private static final TextColor GRAY      = NamedTextColor.GRAY;
    private static final TextColor WHITE     = NamedTextColor.WHITE;
    private static final TextColor OFF_RED   = NamedTextColor.RED;
    private static final TextColor YELLOW    = NamedTextColor.YELLOW;

    // в”Җв”Җ Geometry в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private static final int SIZE          = 54;
    private static final int CMDS_PER_PAGE = 45;   // rows 0-4, all 9 cols
    private static final int SLOT_PREV     = 46;
    private static final int SLOT_PAGE     = 49;
    private static final int SLOT_NEXT     = 52;
    private static final int SLOT_CLOSE    = 53;

    private final Plugin         plugin;
    private final CommandManager commandManager;

    /** Per-player session: UUID вҶ’ current page index (0-based). */
    private final Map<UUID, Integer> sessions = new HashMap<>();

    public HelpGui(Plugin plugin, CommandManager commandManager) {
        this.plugin         = plugin;
        this.commandManager = commandManager;
    }

    // в”Җв”Җ Public API в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Opens the help GUI for {@code player} at page 0. */
    public void open(Player player) {
        sessions.put(player.getUniqueId(), 0);
        build(player);
    }

    // в”Җв”Җ Events в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @EventHandler
    public void onInventoryClick(InventoryClickEvent event) {
        if (!(event.getInventory().getHolder() instanceof Holder holder)) return;
        event.setCancelled(true);
        if (!(event.getWhoClicked() instanceof Player player)) return;
        if (event.getClickedInventory() == null) return;
        if (!event.getClickedInventory().equals(event.getInventory())) return;

        Integer page = sessions.get(holder.uuid);
        if (page == null) return;

        int slot = event.getSlot();
        int totalPages = totalPages(player);

        if (slot == SLOT_PREV && page > 0) {
            sessions.put(holder.uuid, page - 1);
            playClick(player, 1.0f);
            build(player);
            return;
        }
        if (slot == SLOT_NEXT && page < totalPages - 1) {
            sessions.put(holder.uuid, page + 1);
            playClick(player, 1.0f);
            build(player);
            return;
        }
        if (slot == SLOT_CLOSE) {
            playClick(player, 0.8f);
            player.closeInventory();
            return;
        }
        // Clicking a command entry вҖ” play a soft tick for tactile feedback.
        if (slot < CMDS_PER_PAGE) {
            int idx = page * CMDS_PER_PAGE + slot;
            if (idx < visibleCommands(player).size()) playClick(player, 1.3f);
        }
    }

    @EventHandler
    public void onInventoryClose(InventoryCloseEvent event) {
        if (!(event.getInventory().getHolder() instanceof Holder)) return;
        sessions.remove(event.getPlayer().getUniqueId());
    }

    @EventHandler
    public void onPlayerQuit(PlayerQuitEvent event) {
        sessions.remove(event.getPlayer().getUniqueId());
    }

    // в”Җв”Җ Build в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private void build(Player player) {
        Integer raw = sessions.get(player.getUniqueId());
        if (raw == null) return;

        List<FppCommand> visible = visibleCommands(player);
        int totalPages = Math.max(1, (int) Math.ceil(visible.size() / (double) CMDS_PER_PAGE));
        int page = Math.min(raw, totalPages - 1);
        sessions.put(player.getUniqueId(), page);

        Holder    holder = new Holder(player.getUniqueId());
        Component title  = Component.empty()
                .decoration(TextDecoration.ITALIC, false)
                .append(Component.text("[").color(DARK_GRAY))
                .append(Component.text("кң°бҙҳбҙҳ").color(ACCENT))
                .append(Component.text("]  ").color(DARK_GRAY))
                .append(Component.text("бҙ„бҙҸбҙҚбҙҚбҙҖЙҙбҙ…кңұ").color(WHITE).decoration(TextDecoration.BOLD, true));

        Inventory inv = Bukkit.createInventory(holder, SIZE, title);

        // в”Җв”Җ Command items (slots 0-44) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        int start = page * CMDS_PER_PAGE;
        int end   = Math.min(start + CMDS_PER_PAGE, visible.size());
        for (int i = start; i < end; i++) {
            inv.setItem(i - start, buildCommandItem(visible.get(i)));
        }

        // в”Җв”Җ Bottom row (slots 45-53) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        ItemStack filler = glassFiller();
        for (int s = 45; s <= 53; s++) inv.setItem(s, filler);

        inv.setItem(SLOT_PREV,  page > 0              ? buildArrow(false) : filler);
        inv.setItem(SLOT_PAGE,  buildPageItem(page + 1, totalPages));
        inv.setItem(SLOT_NEXT,  page < totalPages - 1 ? buildArrow(true)  : filler);
        inv.setItem(SLOT_CLOSE, buildCloseButton());

        player.openInventory(inv);
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private List<FppCommand> visibleCommands(Player player) {
        return commandManager.getCommands().stream()
                .filter(cmd -> cmd.canUse(player))
                .toList();
    }

    private int totalPages(Player player) {
        return Math.max(1, (int) Math.ceil(visibleCommands(player).size() / (double) CMDS_PER_PAGE));
    }

    // в”Җв”Җ Item builders в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static ItemStack buildCommandItem(FppCommand cmd) {
        ItemStack item = new ItemStack(iconFor(cmd.getName()));
        ItemMeta  meta = item.getItemMeta();

        meta.displayName(Component.empty()
                .decoration(TextDecoration.ITALIC, false)
                .append(Component.text("/fpp " + cmd.getName())
                        .color(ACCENT)
                        .decoration(TextDecoration.BOLD, true)));

        List<Component> lore = new ArrayList<>();
        lore.add(Component.empty());

        // Usage
        String usage = cmd.getUsage();
        if (usage != null && !usage.isBlank()) {
            lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                    .append(Component.text("бҙңкңұбҙҖЙўбҙҮ  ").color(DARK_GRAY))
                    .append(Component.text("/fpp " + cmd.getName() + " " + usage).color(WHITE)));
            lore.add(Component.empty());
        }

        // Description вҖ” wrap at ~40 chars per line for readability
        String desc = cmd.getDescription();
        if (desc != null && !desc.isBlank()) {
            for (String line : wrapText(desc, 42)) {
                lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(line).color(GRAY)));
            }
        }

        // Permission node
        String perm = cmd.getPermission();
        if (perm != null && !perm.isBlank()) {
            lore.add(Component.empty());
            lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                    .append(Component.text("бҙҳбҙҮКҖбҙҚ  ").color(DARK_GRAY))
                    .append(Component.text(perm).color(YELLOW)));
        }

        lore.add(Component.empty());
        meta.lore(lore);
        item.setItemMeta(meta);
        return item;
    }

    private static Material iconFor(String name) {
        return switch (name.toLowerCase()) {
            case "spawn"               -> Material.PLAYER_HEAD;
            case "despawn", "delete"   -> Material.BONE;
            case "list"                -> Material.BOOK;
            case "help"                -> Material.KNOWLEDGE_BOOK;
            case "info"                -> Material.MAP;
            case "chat"                -> Material.PAPER;
            case "reload"              -> Material.NETHER_STAR;
            case "freeze"              -> Material.PACKED_ICE;
            case "stats"               -> Material.CLOCK;
            case "tp"                  -> Material.ENDER_PEARL;
            case "tph"                 -> Material.ENDER_EYE;
            case "rank"                -> Material.GOLDEN_CHESTPLATE;
            case "lpinfo"              -> Material.GOLDEN_HELMET;
            case "move"                -> Material.COMPASS;
            case "inventory", "inv"    -> Material.CHEST;
            case "cmd"                 -> Material.COMMAND_BLOCK;
            case "swap"                -> Material.RECOVERY_COMPASS;
            case "peaks"               -> Material.SUNFLOWER;
            case "settings"            -> Material.COMPARATOR;
            case "migrate"             -> Material.ANVIL;
            case "sync"                -> Material.OBSERVER;
            case "alert"               -> Material.BELL;
            case "xp"                  -> Material.EXPERIENCE_BOTTLE;
            default                    -> Material.PAPER;
        };
    }

    private static ItemStack buildArrow(boolean next) {
        Material  mat  = next ? Material.LIME_STAINED_GLASS_PANE : Material.MAGENTA_STAINED_GLASS_PANE;
        String    lbl  = next ? "в–¶  ЙҙбҙҮxбҙӣ бҙҳбҙҖЙўбҙҮ" : "в—Җ  бҙҳКҖбҙҮбҙ  бҙҳбҙҖЙўбҙҮ";
        TextColor col  = next ? ON_GREEN : ORANGE;
        ItemStack item = new ItemStack(mat);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text(lbl).color(col).decoration(TextDecoration.BOLD, true)));
        item.setItemMeta(meta);
        return item;
    }

    private static ItemStack buildPageItem(int page, int total) {
        ItemStack item = new ItemStack(Material.LIGHT_BLUE_STAINED_GLASS_PANE);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("бҙҳбҙҖЙўбҙҮ  ").color(DARK_GRAY))
                .append(Component.text(page + " / " + total).color(WHITE).decoration(TextDecoration.BOLD, true)));
        item.setItemMeta(meta);
        return item;
    }

    private static ItemStack buildCloseButton() {
        ItemStack item = new ItemStack(Material.BARRIER);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("вң•  бҙ„КҹбҙҸкңұбҙҮ").color(OFF_RED).decoration(TextDecoration.BOLD, true)));
        meta.lore(List.of(Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("бҙ„КҹбҙҸкңұбҙҮ бҙӣКңбҙҮ КңбҙҮКҹбҙҳ бҙҚбҙҮЙҙбҙң.").color(DARK_GRAY))));
        item.setItemMeta(meta);
        return item;
    }

    private static ItemStack glassFiller() {
        ItemStack item = new ItemStack(Material.GRAY_STAINED_GLASS_PANE);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(Component.text(" ").decoration(TextDecoration.ITALIC, false));
        item.setItemMeta(meta);
        return item;
    }

    private static void playClick(Player player, float pitch) {
        player.playSound(player.getLocation(), Sound.UI_BUTTON_CLICK, SoundCategory.MASTER, 0.5f, pitch);
    }

    /**
     * Very simple word-wrap: splits {@code text} into lines no longer than
     * {@code maxLen} characters, breaking at spaces where possible.
     */
    private static List<String> wrapText(String text, int maxLen) {
        if (text.length() <= maxLen) return List.of(text);
        List<String> lines = new ArrayList<>();
        String[] words = text.split(" ");
        StringBuilder sb = new StringBuilder();
        for (String word : words) {
            if (!sb.isEmpty() && sb.length() + 1 + word.length() > maxLen) {
                lines.add(sb.toString());
                sb.setLength(0);
            }
            if (!sb.isEmpty()) sb.append(' ');
            sb.append(word);
        }
        if (!sb.isEmpty()) lines.add(sb.toString());
        return lines;
    }

    // в”Җв”Җ Inner InventoryHolder в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Uniquely identifies a HelpGui inventory instance. */
    public static final class Holder implements InventoryHolder {
        public final UUID uuid;
        Holder(UUID uuid) { this.uuid = uuid; }
        @SuppressWarnings("NullableProblems")  // Bukkit API contract вҖ” never actually called
        @Override public Inventory getInventory() { return null; }
    }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import net.luckperms.api.LuckPerms;
import net.luckperms.api.LuckPermsProvider;
import net.luckperms.api.event.EventSubscription;
import net.luckperms.api.event.user.UserDataRecalculateEvent;
import net.luckperms.api.model.group.Group;
import net.luckperms.api.model.user.User;
import net.luckperms.api.node.NodeType;
import net.luckperms.api.node.types.InheritanceNode;
import org.bukkit.Bukkit;
import org.bukkit.plugin.Plugin;

import java.util.*;
import java.util.concurrent.CompletableFuture;

/**
 * LuckPerms integration helper for FakePlayerPlugin.
 *
 * <h3>Architecture</h3>
 * <p>Bots are real NMS {@code ServerPlayer} entities. LP detects them as genuine
 * online players automatically. This class:
 * <ul>
 *   <li>Pre-assigns a group in LP storage <em>before</em> the NMS body spawns so
 *       that {@code PlayerJoinEvent} listeners (TAB, LP itself) see the correct group
 *       immediately at join time.</li>
 *   <li>Preserves a bot's previously-assigned group across restarts вҖ” restored bots
 *       keep their {@code /fpp rank} group without being reset to the default.</li>
 *   <li>Subscribes to LP's {@code UserDataRecalculateEvent} so display names update
 *       automatically when an admin changes a bot's group via LP commands.</li>
 *   <li>Reads resolved prefix/suffix from LP's in-memory {@code CachedMetaData} for
 *       tab-list display name rebuilding.</li>
 * </ul>
 */
public final class LuckPermsHelper {

    /** Active LP event subscription вҖ” closed in {@link #unsubscribeLpEvents()}. */
    private static EventSubscription<UserDataRecalculateEvent> eventSub;

    private LuckPermsHelper() {}

    // в”Җв”Җ Availability в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** @return {@code true} when LuckPerms is installed and enabled on this server. */
    public static boolean isAvailable() {
        Plugin p = Bukkit.getPluginManager().getPlugin("LuckPerms");
        return p != null && p.isEnabled();
    }

    /** Safe LP API accessor вҖ” returns {@code null} when LP is not available. */
    private static LuckPerms lp() {
        if (!isAvailable()) return null;
        try { return LuckPermsProvider.get(); }
        catch (IllegalStateException e) { return null; }
    }

    // в”Җв”Җ Event bus в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Subscribes to LP's {@code UserDataRecalculateEvent} so that whenever a bot's
     * LP permissions are recalculated (group change via LP command, API, etc.) the
     * plugin automatically rebuilds its tab-list display name with the new prefix.
     *
     * <p>Must be called on the main thread after both LP and {@link FakePlayerManager}
     * are initialised.
     *
     * @param plugin  plugin instance (used to schedule Bukkit tasks)
     * @param manager fake-player manager (used to look up and refresh bots)
     */
    public static void subscribeLpEvents(FakePlayerPlugin plugin, FakePlayerManager manager) {
        LuckPerms api = lp();
        if (api == null) return;
        // Prevent double-subscription (e.g. on reload)
        if (eventSub != null) {
            eventSub.close();
            eventSub = null;
        }
        try {
            eventSub = api.getEventBus().subscribe(
                    plugin,
                    UserDataRecalculateEvent.class,
                    event -> {
                        UUID uuid = event.getUser().getUniqueId();
                        FakePlayer fp = manager.getByUuid(uuid);
                        if (fp == null) return; // not one of our bots
                        // Sync the group field and refresh display on main thread
                        String newGroup = event.getUser().getPrimaryGroup();
                        fp.setLuckpermsGroup(newGroup);
                        Bukkit.getScheduler().runTask(plugin,
                                () -> manager.refreshLpDisplayName(fp));
                        Config.debugLuckPerms("UserDataRecalculate for bot '" + fp.getName()
                                + "' вҖ” new group='" + newGroup + "', refreshing display name.");
                    });
            Config.debugLuckPerms("Subscribed to UserDataRecalculateEvent вҖ” bot display names will auto-update when LP groups change.");
        } catch (Exception e) {
            FppLogger.warn("[LP] Failed to subscribe to LP events: " + e.getMessage());
        }
    }

    /**
     * Unsubscribes from LP events. Call in {@code onDisable} to prevent memory leaks.
     */
    public static void unsubscribeLpEvents() {
        if (eventSub != null) {
            try { eventSub.close(); } catch (Exception ignored) {}
            eventSub = null;
        }
    }

    // в”Җв”Җ Pre-spawn group setup в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Ensures the bot has the correct LP group in storage <em>before</em> their NMS
     * body is spawned. Called from {@code finishSpawn} to guarantee that LP and
     * tab-list plugins (e.g. TAB) see the correct group when {@code PlayerJoinEvent}
     * fires.
     *
     * <h3>Resolution logic</h3>
     * <ol>
     *   <li>Load the bot's LP user from storage (async).</li>
     *   <li>If the bot already has a non-{@code default} primary group (i.e. a group
     *       explicitly assigned by a previous {@code /fpp rank}) <em>and</em> no
     *       {@code luckperms.default-group} is configured in FPP config, keep the
     *       existing group вҖ” this preserves rank across server restarts.</li>
     *   <li>Otherwise assign the configured {@code configGroup}, or {@code "default"}
     *       if the config is blank, and call {@link User#setPrimaryGroup(String)} so
     *       LP reports the correct primary group immediately at join time.</li>
     * </ol>
     *
     * @param botUuid     UUID of the bot
     * @param configGroup value of {@code Config.luckpermsDefaultGroup()} (may be blank)
     * @return future that resolves with the group name that was applied or kept
     */
    public static CompletableFuture<String> ensureGroupBeforeSpawn(UUID botUuid, String configGroup) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture("default");

        // Fallback target: use the configured group or "default" as baseline
        String targetGroup = (configGroup != null && !configGroup.trim().isEmpty())
                ? configGroup.trim() : "default";

        return api.getUserManager().loadUser(botUuid)
                .thenCompose(user -> {
                    if (user == null) return CompletableFuture.completedFuture(targetGroup);

                    String storedPrimary = user.getPrimaryGroup();
                    // A bot "has a real group" when LP already has an explicit, non-default
                    // primary group recorded (set by a previous /fpp rank assignment).
                    boolean hasExplicitGroup = storedPrimary != null
                            && !storedPrimary.equalsIgnoreCase("default")
                            && !storedPrimary.isBlank();
                    boolean configForcesGroup = configGroup != null && !configGroup.trim().isEmpty();

                    if (hasExplicitGroup && !configForcesGroup) {
                        // Restore path: keep the previously-assigned rank
                        Config.debugLuckPerms("ensureGroupBeforeSpawn: keeping stored group '"
                                + storedPrimary + "' for " + botUuid);
                        return CompletableFuture.completedFuture(storedPrimary);
                    }

                    // New bot path (or config override): assign targetGroup
                    user.data().clear(NodeType.INHERITANCE::matches);
                    user.data().add(InheritanceNode.builder(targetGroup).build());
                    user.setPrimaryGroup(targetGroup);

                    // Force LP to recalculate cached metadata immediately
                    user.getCachedData().invalidate();

                    return api.getUserManager().saveUser(user)
                            .thenApply(v -> {
                                Config.debugLuckPerms("ensureGroupBeforeSpawn: set group '"
                                        + targetGroup + "' for " + botUuid);
                                // Invalidate again after save to ensure fresh calculation
                                user.getCachedData().invalidate();
                                return targetGroup;
                            });
                })
                .exceptionally(ex -> {
                    FppLogger.warn("[LP] ensureGroupBeforeSpawn error for " + botUuid
                            + ": " + ex.getMessage());
                    return targetGroup;
                });
    }


    // в”Җв”Җ Runtime group changes в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Applies an LP group to an <em>online</em> bot by writing directly to the live
     * {@link User} instance that LuckPerms loaded at {@code PlayerJoinEvent}, then
     * calling {@code saveUser()}.
     *
     * <p>This is the key fix for prefix not showing on first spawn. LP keeps one
     * authoritative {@code User} object per online player. {@code saveUser()} on that
     * object fires {@code UserDataRecalculateEvent}, which our event subscriber
     * already handles to rebuild the tab-list display name.</p>
     *
     * <p>Falls back to {@link #setPlayerGroup(UUID, String)} when the user isn't
     * loaded yet (shouldn't happen 5 ticks after spawn, but safe).</p>
     *
     * @param botUuid   the bot's UUID
     * @param groupName LP group to apply
     * @return future that completes after the save (or immediately on fallback)
     */
    public static CompletableFuture<Void> applyGroupToOnlineUser(UUID botUuid, String groupName) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture(null);

        // getUser() returns the LIVE online User instance LP loaded at PlayerJoinEvent.
        // Modifying it and calling saveUser() fires UserDataRecalculateEvent.
        User onlineUser = api.getUserManager().getUser(botUuid);
        if (onlineUser != null) {
            onlineUser.data().clear(NodeType.INHERITANCE::matches);
            onlineUser.data().add(InheritanceNode.builder(groupName).build());
            onlineUser.setPrimaryGroup(groupName);
            Config.debugLuckPerms("applyGroupToOnlineUser: applying '" + groupName + "' to online user " + botUuid);
            // saveUser() on an online User triggers UserDataRecalculateEvent вҶ’ prefix updates
            return api.getUserManager().saveUser(onlineUser);
        }

        // Fallback: user not in online cache yet вҖ” load from storage and set
        Config.debugLuckPerms("applyGroupToOnlineUser: user not online yet, falling back to setPlayerGroup for " + botUuid);
        return setPlayerGroup(botUuid, groupName);
    }

    /**
     * Sets a bot's LP group at runtime (used by {@code /fpp rank}).
     * Prefers the live online {@link User} instance so the save fires
     * {@code UserDataRecalculateEvent} immediately. Falls back to {@code loadUser()}
     * for offline users.
     *
     * @param playerUuid   the bot's UUID
     * @param newGroupName the LP group name to assign
     * @return future that completes when the assignment is saved
     */
    public static CompletableFuture<Void> setPlayerGroup(UUID playerUuid, String newGroupName) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.failedFuture(
                new IllegalStateException("LuckPerms not available"));

        // Prefer the live online instance вҖ” saveUser() on it fires UserDataRecalculateEvent
        User onlineUser = api.getUserManager().getUser(playerUuid);
        if (onlineUser != null) {
            onlineUser.data().clear(NodeType.INHERITANCE::matches);
            onlineUser.data().add(InheritanceNode.builder(newGroupName).build());
            onlineUser.setPrimaryGroup(newGroupName);
            return api.getUserManager().saveUser(onlineUser).thenRun(() ->
                    Config.debugLuckPerms("setPlayerGroup (online): " + playerUuid + " вҶ’ '" + newGroupName + "'"));
        }

        // User not online вҖ” fall back to loadUser (offline / pre-spawn use)
        return api.getUserManager().loadUser(playerUuid).thenCompose(user -> {
            if (user == null) return CompletableFuture.failedFuture(
                    new IllegalStateException("LP user not found for " + playerUuid));
            user.data().clear(NodeType.INHERITANCE::matches);
            user.data().add(InheritanceNode.builder(newGroupName).build());
            user.setPrimaryGroup(newGroupName);
            return api.getUserManager().saveUser(user).thenRun(() ->
                    Config.debugLuckPerms("setPlayerGroup (offline): " + playerUuid + " вҶ’ '" + newGroupName + "'"));
        });
    }

    // в”Җв”Җ Meta / prefix resolution в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Synchronously reads the resolved prefix for a bot from LP's in-memory meta
     * cache. Only works when the bot is online (LP has their {@code User} loaded).
     *
     * @param botUuid the bot's UUID
     * @return resolved prefix string, or {@code ""} if LP unavailable / no prefix
     */
    public static String getResolvedPrefix(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "";
            String prefix = user.getCachedData().getMetaData().getPrefix();
            return prefix != null ? prefix : "";
        } catch (Exception e) {
            Config.debugLuckPerms("getResolvedPrefix error for " + botUuid + ": " + e.getMessage());
            return "";
        }
    }

    /**
     * Synchronously reads the resolved suffix for a bot from LP's in-memory meta
     * cache. Only works when the bot is online (LP has their {@code User} loaded).
     *
     * @param botUuid the bot's UUID
     * @return resolved suffix string, or {@code ""} if LP unavailable / no suffix
     */
    public static String getResolvedSuffix(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "";
            String suffix = user.getCachedData().getMetaData().getSuffix();
            return suffix != null ? suffix : "";
        } catch (Exception e) {
            Config.debugLuckPerms("getResolvedSuffix error for " + botUuid + ": " + e.getMessage());
            return "";
        }
    }

    /**
     * Forces LuckPerms to refresh the cached metadata for a user.
     * Useful when LP hasn't finished calculating metadata after a group assignment.
     *
     * @param uuid the UUID of the user to refresh
     */
    public static void refreshUserCache(UUID uuid) {
        LuckPerms api = lp();
        if (api == null) return;
        try {
            User user = api.getUserManager().getUser(uuid);
            if (user == null) {
                // User not loaded yet, try loading them first
                api.getUserManager().loadUser(uuid).thenAccept(loadedUser -> {
                    if (loadedUser != null) {
                        loadedUser.getCachedData().invalidate();
                        Config.debugLuckPerms("Forced cache refresh for " + uuid + " (loaded first)");
                    }
                });
            } else {
                // User already loaded, just invalidate their cache
                user.getCachedData().invalidate();
                Config.debugLuckPerms("Forced cache refresh for " + uuid);
            }
        } catch (Exception e) {
            Config.debugLuckPerms("refreshUserCache error for " + uuid + ": " + e.getMessage());
        }
    }

    /**
     * Synchronously reads the primary group for a bot from LP's in-memory cache.
     * Only works when the bot is online.
     *
     * @param botUuid the bot's UUID
     * @return primary group name, or {@code "default"} as fallback
     */
    public static String getPrimaryGroup(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "default";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "default";
            return user.getPrimaryGroup();
        } catch (Exception e) {
            return "default";
        }
    }

    /**
     * Asynchronously reads the primary group for a player UUID from LP storage.
     * Works even when the player is offline. Used by diagnostics and {@code /fpp rank list}.
     *
     * @param playerUuid the UUID to query
     * @return future containing the primary group name, or {@code "default"} on failure
     */
    public static CompletableFuture<String> getStoredPrimaryGroup(UUID playerUuid) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture("default");
        return api.getUserManager().loadUser(playerUuid)
                .thenApply(user -> user != null ? user.getPrimaryGroup() : "default")
                .exceptionally(ex -> "default");
    }


    // в”Җв”Җ Group info / queries в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Checks if the specified LP group exists (case-insensitive).
     *
     * @param name group name to check
     * @return {@code true} when LP is available and the group is loaded
     */
    public static boolean groupExists(String name) {
        LuckPerms api = lp();
        if (api == null || name == null || name.isBlank()) return false;
        return api.getGroupManager().getGroup(name.toLowerCase()) != null;
    }

    /**
     * Returns a sorted list of all LP group names currently loaded in memory.
     * Used for tab completion in {@code /fpp rank}.
     */
    public static List<String> getAllGroupNames() {
        LuckPerms api = lp();
        if (api == null) return Collections.emptyList();
        return api.getGroupManager().getLoadedGroups()
                .stream()
                .map(Group::getName)
                .sorted()
                .toList();
    }

    /**
     * Returns a human-readable summary of loaded LP groups and their weights.
     * Format: {@code name(w=N), ...} вҖ” used by {@code /fpp lpinfo}.
     */
    public static String buildGroupSummary() {
        LuckPerms api = lp();
        if (api == null) return "(LP unavailable)";
        try {
            StringBuilder sb = new StringBuilder();
            api.getGroupManager().getLoadedGroups().stream()
                    .sorted(Comparator.comparing(Group::getName))
                    .forEach(g -> {
                        int w = g.getWeight().orElse(0);
                        if (!sb.isEmpty()) sb.append(", ");
                        sb.append(g.getName()).append("(w=").append(w).append(')');
                    });
            return sb.isEmpty() ? "(none)" : sb.toString();
        } catch (Exception e) {
            return "(error: " + e.getMessage() + ")";
        }
    }

    // в”Җв”Җ Deprecated aliases for backwards compatibility в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** @deprecated No-op вҖ” LP handles caching natively for NMS ServerPlayer entities. */
    @Deprecated
    public static void invalidateCache() {}

    /** @deprecated Use {@link #setPlayerGroup(UUID, String)} instead. */
    @Deprecated
    public static CompletableFuture<Void> addPlayerToGroup(UUID playerUuid, String groupName) {
        return setPlayerGroup(playerUuid, groupName);
    }

    /** @deprecated Use {@link #setPlayerGroup(UUID, String)} with "default" instead. */
    @Deprecated
    public static CompletableFuture<Void> cleanupBotUser(UUID playerUuid) {
        return setPlayerGroup(playerUuid, "default");
    }

    /** @deprecated Use {@link #getStoredPrimaryGroup(UUID)} instead. */
    @Deprecated
    public static CompletableFuture<String> getPlayerPrimaryGroup(UUID playerUuid) {
        return getStoredPrimaryGroup(playerUuid);
    }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import net.luckperms.api.LuckPerms;
import net.luckperms.api.LuckPermsProvider;
import net.luckperms.api.event.EventSubscription;
import net.luckperms.api.event.user.UserDataRecalculateEvent;
import net.luckperms.api.model.group.Group;
import net.luckperms.api.model.user.User;
import net.luckperms.api.node.NodeType;
import net.luckperms.api.node.types.InheritanceNode;
import org.bukkit.Bukkit;
import org.bukkit.plugin.Plugin;

import java.util.*;
import java.util.concurrent.CompletableFuture;

/**
 * LuckPerms integration helper for FakePlayerPlugin.
 *
 * <h3>Architecture</h3>
 * <p>Bots are real NMS {@code ServerPlayer} entities. LP detects them as genuine
 * online players automatically. This class:
 * <ul>
 *   <li>Pre-assigns a group in LP storage <em>before</em> the NMS body spawns so
 *       that {@code PlayerJoinEvent} listeners (TAB, LP itself) see the correct group
 *       immediately at join time.</li>
 *   <li>Preserves a bot's previously-assigned group across restarts вҖ” restored bots
 *       keep their {@code /fpp rank} group without being reset to the default.</li>
 *   <li>Subscribes to LP's {@code UserDataRecalculateEvent} so display names update
 *       automatically when an admin changes a bot's group via LP commands.</li>
 *   <li>Reads resolved prefix/suffix from LP's in-memory {@code CachedMetaData} for
 *       tab-list display name rebuilding.</li>
 * </ul>
 */
public final class LuckPermsHelper {

    /** Active LP event subscription вҖ” closed in {@link #unsubscribeLpEvents()}. */
    private static EventSubscription<UserDataRecalculateEvent> eventSub;

    private LuckPermsHelper() {}

    // в”Җв”Җ Availability в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** @return {@code true} when LuckPerms is installed and enabled on this server. */
    public static boolean isAvailable() {
        Plugin p = Bukkit.getPluginManager().getPlugin("LuckPerms");
        return p != null && p.isEnabled();
    }

    /** Safe LP API accessor вҖ” returns {@code null} when LP is not available. */
    private static LuckPerms lp() {
        if (!isAvailable()) return null;
        try { return LuckPermsProvider.get(); }
        catch (IllegalStateException e) { return null; }
    }

    // в”Җв”Җ Event bus в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Subscribes to LP's {@code UserDataRecalculateEvent} so that whenever a bot's
     * LP permissions are recalculated (group change via LP command, API, etc.) the
     * plugin automatically rebuilds its tab-list display name with the new prefix.
     *
     * <p>Must be called on the main thread after both LP and {@link FakePlayerManager}
     * are initialised.
     *
     * @param plugin  plugin instance (used to schedule Bukkit tasks)
     * @param manager fake-player manager (used to look up and refresh bots)
     */
    public static void subscribeLpEvents(FakePlayerPlugin plugin, FakePlayerManager manager) {
        LuckPerms api = lp();
        if (api == null) return;
        // Prevent double-subscription (e.g. on reload)
        if (eventSub != null) {
            eventSub.close();
            eventSub = null;
        }
        try {
            eventSub = api.getEventBus().subscribe(
                    plugin,
                    UserDataRecalculateEvent.class,
                    event -> {
                        UUID uuid = event.getUser().getUniqueId();
                        FakePlayer fp = manager.getByUuid(uuid);
                        if (fp == null) return; // not one of our bots
                        // getPrimaryGroup() throws NPE internally when LP hasn't assigned
                        // a primary group yet (brand-new user with no nodes).
                        String newGroup;
                        try {
                            newGroup = event.getUser().getPrimaryGroup();
                        } catch (NullPointerException ignored) {
                            newGroup = null;
                        }
                        if (newGroup == null) newGroup = "default";
                        fp.setLuckpermsGroup(newGroup);
                        Bukkit.getScheduler().runTask(plugin,
                                () -> manager.refreshLpDisplayName(fp));
                        Config.debugLuckPerms("UserDataRecalculate for bot '" + fp.getName()
                                + "' вҖ” new group='" + newGroup + "', refreshing display name.");
                    });
            Config.debugLuckPerms("Subscribed to UserDataRecalculateEvent вҖ” bot display names will auto-update when LP groups change.");
        } catch (Exception e) {
            FppLogger.warn("[LP] Failed to subscribe to LP events: " + e.getMessage());
        }
    }

    /**
     * Unsubscribes from LP events. Call in {@code onDisable} to prevent memory leaks.
     */
    public static void unsubscribeLpEvents() {
        if (eventSub != null) {
            try { eventSub.close(); } catch (Exception ignored) {}
            eventSub = null;
        }
    }

    // в”Җв”Җ Pre-spawn group setup в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Ensures the bot has the correct LP group in storage <em>before</em> their NMS
     * body is spawned. Called from {@code finishSpawn} to guarantee that LP and
     * tab-list plugins (e.g. TAB) see the correct group when {@code PlayerJoinEvent}
     * fires.
     *
     * <h3>Resolution logic</h3>
     * <ol>
     *   <li>Load the bot's LP user from storage (async).</li>
     *   <li>If the bot already has a non-{@code default} primary group (i.e. a group
     *       explicitly assigned by a previous {@code /fpp rank}) <em>and</em> no
     *       {@code luckperms.default-group} is configured in FPP config, keep the
     *       existing group вҖ” this preserves rank across server restarts.</li>
     *   <li>Otherwise assign the configured {@code configGroup}, or {@code "default"}
     *       if the config is blank, and call {@link User#setPrimaryGroup(String)} so
     *       LP reports the correct primary group immediately at join time.</li>
     * </ol>
     *
     * @param botUuid     UUID of the bot
     * @param configGroup value of {@code Config.luckpermsDefaultGroup()} (may be blank)
     * @return future that resolves with the group name that was applied or kept
     */
    public static CompletableFuture<String> ensureGroupBeforeSpawn(UUID botUuid, String configGroup) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture("default");

        // Fallback target: use the configured group or "default" as baseline
        String targetGroup = (configGroup != null && !configGroup.trim().isEmpty())
                ? configGroup.trim() : "default";

        return api.getUserManager().loadUser(botUuid)
                .thenCompose(user -> {
                    if (user == null) return CompletableFuture.completedFuture(targetGroup);

                    String storedPrimary = user.getPrimaryGroup();
                    // A bot "has a real group" when LP already has an explicit, non-default
                    // primary group recorded (set by a previous /fpp rank assignment).
                    boolean hasExplicitGroup = storedPrimary != null
                            && !storedPrimary.equalsIgnoreCase("default")
                            && !storedPrimary.isBlank();
                    boolean configForcesGroup = configGroup != null && !configGroup.trim().isEmpty();

                    if (hasExplicitGroup && !configForcesGroup) {
                        // Restore path: keep the previously-assigned rank
                        Config.debugLuckPerms("ensureGroupBeforeSpawn: keeping stored group '"
                                + storedPrimary + "' for " + botUuid);
                        return CompletableFuture.completedFuture(storedPrimary);
                    }

                    // New bot path (or config override): assign targetGroup
                    user.data().clear(NodeType.INHERITANCE::matches);
                    user.data().add(InheritanceNode.builder(targetGroup).build());
                    user.setPrimaryGroup(targetGroup);
                    
                    // Force LP to recalculate cached metadata immediately
                    user.getCachedData().invalidate();
                    
                    return api.getUserManager().saveUser(user)
                            .thenApply(v -> {
                                Config.debugLuckPerms("ensureGroupBeforeSpawn: set group '"
                                        + targetGroup + "' for " + botUuid);
                                // Invalidate again after save to ensure fresh calculation
                                user.getCachedData().invalidate();
                                return targetGroup;
                            });
                })
                .exceptionally(ex -> {
                    FppLogger.warn("[LP] ensureGroupBeforeSpawn error for " + botUuid
                            + ": " + ex.getMessage());
                    return targetGroup;
                });
    }


    // в”Җв”Җ Runtime group changes в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Applies an LP group to an <em>online</em> bot by writing directly to the live
     * {@link User} instance that LuckPerms loaded at {@code PlayerJoinEvent}, then
     * calling {@code saveUser()}.
     *
     * <p>This is the key fix for prefix not showing on first spawn. LP keeps one
     * authoritative {@code User} object per online player. {@code saveUser()} on that
     * object fires {@code UserDataRecalculateEvent}, which our event subscriber
     * already handles to rebuild the tab-list display name.</p>
     *
     * <p>Falls back to {@link #setPlayerGroup(UUID, String)} when the user isn't
     * loaded yet (shouldn't happen 5 ticks after spawn, but safe).</p>
     *
     * @param botUuid   the bot's UUID
     * @param groupName LP group to apply
     * @return future that completes after the save (or immediately on fallback)
     */
    public static CompletableFuture<Void> applyGroupToOnlineUser(UUID botUuid, String groupName) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture(null);

        // getUser() returns the LIVE online User instance LP loaded at PlayerJoinEvent.
        // Modifying it and calling saveUser() fires UserDataRecalculateEvent.
        User onlineUser = api.getUserManager().getUser(botUuid);
        if (onlineUser != null) {
            onlineUser.data().clear(NodeType.INHERITANCE::matches);
            onlineUser.data().add(InheritanceNode.builder(groupName).build());
            onlineUser.setPrimaryGroup(groupName);
            Config.debugLuckPerms("applyGroupToOnlineUser: applying '" + groupName + "' to online user " + botUuid);
            // saveUser() on an online User triggers UserDataRecalculateEvent вҶ’ prefix updates
            return api.getUserManager().saveUser(onlineUser);
        }

        // Fallback: user not in online cache yet вҖ” load from storage and set
        Config.debugLuckPerms("applyGroupToOnlineUser: user not online yet, falling back to setPlayerGroup for " + botUuid);
        return setPlayerGroup(botUuid, groupName);
    }

    /**
     * Sets a bot's LP group at runtime (used by {@code /fpp rank}).
     * Prefers the live online {@link User} instance so the save fires
     * {@code UserDataRecalculateEvent} immediately. Falls back to {@code loadUser()}
     * for offline users.
     *
     * @param playerUuid   the bot's UUID
     * @param newGroupName the LP group name to assign
     * @return future that completes when the assignment is saved
     */
    public static CompletableFuture<Void> setPlayerGroup(UUID playerUuid, String newGroupName) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.failedFuture(
                new IllegalStateException("LuckPerms not available"));

        // Prefer the live online instance вҖ” saveUser() on it fires UserDataRecalculateEvent
        User onlineUser = api.getUserManager().getUser(playerUuid);
        if (onlineUser != null) {
            onlineUser.data().clear(NodeType.INHERITANCE::matches);
            onlineUser.data().add(InheritanceNode.builder(newGroupName).build());
            onlineUser.setPrimaryGroup(newGroupName);
            return api.getUserManager().saveUser(onlineUser).thenRun(() ->
                    Config.debugLuckPerms("setPlayerGroup (online): " + playerUuid + " вҶ’ '" + newGroupName + "'"));
        }

        // User not online вҖ” fall back to loadUser (offline / pre-spawn use)
        return api.getUserManager().loadUser(playerUuid).thenCompose(user -> {
            if (user == null) return CompletableFuture.failedFuture(
                    new IllegalStateException("LP user not found for " + playerUuid));
            user.data().clear(NodeType.INHERITANCE::matches);
            user.data().add(InheritanceNode.builder(newGroupName).build());
            user.setPrimaryGroup(newGroupName);
            return api.getUserManager().saveUser(user).thenRun(() ->
                    Config.debugLuckPerms("setPlayerGroup (offline): " + playerUuid + " вҶ’ '" + newGroupName + "'"));
        });
    }

    // в”Җв”Җ Meta / prefix resolution в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Synchronously reads the resolved prefix for a bot from LP's in-memory meta
     * cache. Only works when the bot is online (LP has their {@code User} loaded).
     *
     * @param botUuid the bot's UUID
     * @return resolved prefix string, or {@code ""} if LP unavailable / no prefix
     */
    public static String getResolvedPrefix(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "";
            String prefix = user.getCachedData().getMetaData().getPrefix();
            return prefix != null ? prefix : "";
        } catch (Exception e) {
            Config.debugLuckPerms("getResolvedPrefix error for " + botUuid + ": " + e.getMessage());
            return "";
        }
    }

    /**
     * Synchronously reads the resolved suffix for a bot from LP's in-memory meta
     * cache. Only works when the bot is online (LP has their {@code User} loaded).
     *
     * @param botUuid the bot's UUID
     * @return resolved suffix string, or {@code ""} if LP unavailable / no suffix
     */
    public static String getResolvedSuffix(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "";
            String suffix = user.getCachedData().getMetaData().getSuffix();
            return suffix != null ? suffix : "";
        } catch (Exception e) {
            Config.debugLuckPerms("getResolvedSuffix error for " + botUuid + ": " + e.getMessage());
            return "";
        }
    }

    /**
     * Forces LuckPerms to refresh the cached metadata for a user.
     * Useful when LP hasn't finished calculating metadata after a group assignment.
     *
     * @param uuid the UUID of the user to refresh
     */
    public static void refreshUserCache(UUID uuid) {
        LuckPerms api = lp();
        if (api == null) return;
        try {
            User user = api.getUserManager().getUser(uuid);
            if (user == null) {
                // User not loaded yet, try loading them first
                api.getUserManager().loadUser(uuid).thenAccept(loadedUser -> {
                    if (loadedUser != null) {
                        loadedUser.getCachedData().invalidate();
                        Config.debugLuckPerms("Forced cache refresh for " + uuid + " (loaded first)");
                    }
                });
            } else {
                // User already loaded, just invalidate their cache
                user.getCachedData().invalidate();
                Config.debugLuckPerms("Forced cache refresh for " + uuid);
            }
        } catch (Exception e) {
            Config.debugLuckPerms("refreshUserCache error for " + uuid + ": " + e.getMessage());
        }
    }

    /**
     * Synchronously reads the primary group for a bot from LP's in-memory cache.
     * Only works when the bot is online.
     *
     * @param botUuid the bot's UUID
     * @return primary group name, or {@code "default"} as fallback
     */
    public static String getPrimaryGroup(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "default";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "default";
            return user.getPrimaryGroup();
        } catch (Exception e) {
            return "default";
        }
    }

    /**
     * Asynchronously reads the primary group for a player UUID from LP storage.
     * Works even when the player is offline. Used by diagnostics and {@code /fpp rank list}.
     *
     * @param playerUuid the UUID to query
     * @return future containing the primary group name, or {@code "default"} on failure
     */
    public static CompletableFuture<String> getStoredPrimaryGroup(UUID playerUuid) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture("default");
        return api.getUserManager().loadUser(playerUuid)
                .thenApply(user -> user != null ? user.getPrimaryGroup() : "default")
                .exceptionally(ex -> "default");
    }


    // в”Җв”Җ Group info / queries в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Checks if the specified LP group exists (case-insensitive).
     *
     * @param name group name to check
     * @return {@code true} when LP is available and the group is loaded
     */
    public static boolean groupExists(String name) {
        LuckPerms api = lp();
        if (api == null || name == null || name.isBlank()) return false;
        return api.getGroupManager().getGroup(name.toLowerCase()) != null;
    }

    /**
     * Returns a sorted list of all LP group names currently loaded in memory.
     * Used for tab completion in {@code /fpp rank}.
     */
    public static List<String> getAllGroupNames() {
        LuckPerms api = lp();
        if (api == null) return Collections.emptyList();
        return api.getGroupManager().getLoadedGroups()
                .stream()
                .map(Group::getName)
                .sorted()
                .toList();
    }

    /**
     * Returns a human-readable summary of loaded LP groups and their weights.
     * Format: {@code name(w=N), ...} вҖ” used by {@code /fpp lpinfo}.
     */
    public static String buildGroupSummary() {
        LuckPerms api = lp();
        if (api == null) return "(LP unavailable)";
        try {
            StringBuilder sb = new StringBuilder();
            api.getGroupManager().getLoadedGroups().stream()
                    .sorted(Comparator.comparing(Group::getName))
                    .forEach(g -> {
                        int w = g.getWeight().orElse(0);
                        if (!sb.isEmpty()) sb.append(", ");
                        sb.append(g.getName()).append("(w=").append(w).append(')');
                    });
            return sb.isEmpty() ? "(none)" : sb.toString();
        } catch (Exception e) {
            return "(error: " + e.getMessage() + ")";
        }
    }

    // в”Җв”Җ Deprecated aliases for backwards compatibility в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** @deprecated No-op вҖ” LP handles caching natively for NMS ServerPlayer entities. */
    @Deprecated
    public static void invalidateCache() {}

    /** @deprecated Use {@link #setPlayerGroup(UUID, String)} instead. */
    @Deprecated
    public static CompletableFuture<Void> addPlayerToGroup(UUID playerUuid, String groupName) {
        return setPlayerGroup(playerUuid, groupName);
    }

    /** @deprecated Use {@link #setPlayerGroup(UUID, String)} with "default" instead. */
    @Deprecated
    public static CompletableFuture<Void> cleanupBotUser(UUID playerUuid) {
        return setPlayerGroup(playerUuid, "default");
    }

    /** @deprecated Use {@link #getStoredPrimaryGroup(UUID)} instead. */
    @Deprecated
    public static CompletableFuture<String> getPlayerPrimaryGroup(UUID playerUuid) {
        return getStoredPrimaryGroup(playerUuid);
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotPathfinder;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.fakeplayer.NmsPlayerSpawner;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.Material;
import org.bukkit.block.Block;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;
import org.bukkit.scheduler.BukkitRunnable;
import org.bukkit.scheduler.BukkitTask;
import org.jetbrains.annotations.NotNull;
import org.jetbrains.annotations.Nullable;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Navigates a bot to an online player using an A* grid pathfinder,
 * OR patrols a bot through a user-defined list of waypoints in a loop.
 *
 * <h3>Player-follow mode</h3>
 * {@code /fpp move <bot> <player>} вҖ” navigates continuously toward the player.
 * Recalculates path when target moves &gt;{@value #RECALC_DIST} blocks or every
 * {@value #RECALC_INTERVAL} ticks.
 *
 * <h3>Waypoint patrol mode</h3>
 * <ol>
 *   <li>Create a named route with {@code /fpp wp add <route>} (run multiple times
 *       to build a list of positions).</li>
 *   <li>{@code /fpp move <bot> --wp <route>} вҖ” start the patrol loop (bot visits
 *       position 1 вҶ’ 2 вҶ’ вҖҰ вҶ’ N вҶ’ 1 вҶ’ вҖҰ, forever).</li>
 *   <li>{@code /fpp move <bot> --stop} вҖ” stop navigation.</li>
 * </ol>
 *
 * <h3>Navigation loop (1-tick interval)</h3>
 * <ol>
 *   <li>Handles WALK/ASCEND/DESCEND normally (face + forward + conditional jump).</li>
 *   <li>Handles PARKOUR: sprint + request jump when 1вҖ“3.5 blocks from landing.</li>
 *   <li>Handles BREAK: stop, face block, wait {@value #BREAK_TICKS} ticks, break it.</li>
 *   <li>Handles PLACE: stop, wait {@value #PLACE_TICKS} ticks, place bridge block.</li>
 *   <li>Stuck detection ({@value #STUCK_TICKS} ticks) forces jump + recalc.
 *       Suppressed while breaking or placing.</li>
 *   <li>Falls back to direct face-and-walk when no path is found.</li>
 * </ol>
 */
public final class MoveCommand implements FppCommand {

    // в”Җв”Җ Tuning constants в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static final double ARRIVAL_DIST        = 2.0;
    /** Radius within which the bot considers itself "at" a patrol waypoint. */
    private static final double PATROL_ARRIVE_DIST  = 1.5;
    private static final double SPRINT_DIST         = 8.0;
    private static final double WP_ARRIVE_XZ        = 0.65;
    private static final double RECALC_DIST         = 3.5;
    private static final int    RECALC_INTERVAL     = 60;
    private static final int    STUCK_TICKS         = 8;
    private static final double STUCK_THRESHOLD     = 0.04;

    /**
     * Ticks a bot spends "mining" a blocking block before it disappears.
     * This is a fixed bot-behaviour wait (not physics-accurate hardness),
     * chosen so that navigation feels snappy (~0.75 s) without being jarring.
     */
    private static final int BREAK_TICKS = 15;

    /**
     * Ticks a bot waits before placing a bridge block.
     * Short pause to animate the "look-down-and-place" gesture.
     */
    private static final int PLACE_TICKS = 5;

    // в”Җв”Җ Fields в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;
    private final Map<UUID, BukkitTask> navTasks     = new ConcurrentHashMap<>();
    /**
     * Global named waypoint route registry.  Injected via {@link #setWaypointStore(WaypointStore)}.
     * Used by the {@code --wp <name>} flag.
     */
    private WaypointStore waypointStore;

    public MoveCommand(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
    }

    /** Injects the global waypoint store so {@code --wp <name>} can look up destinations. */
    public void setWaypointStore(WaypointStore store) {
        this.waypointStore = store;
    }

    // в”Җв”Җ FppCommand в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override public String getName()        { return "move"; }
    @Override public String getUsage()       { return "<bot> <player>  |  <bot> --wp <route>  |  <bot> --stop"; }
    @Override public String getDescription() { return "Navigate a bot to a player or patrol a named waypoint route in a loop."; }
    @Override public String getPermission()  { return Perm.MOVE; }
    @Override public boolean canUse(CommandSender sender) { return Perm.has(sender, Perm.MOVE); }

    // в”Җв”Җ execute в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(Lang.get("move-usage"));
            return true;
        }

        FakePlayer fp = manager.getByName(args[0]);
        if (fp == null) {
            sender.sendMessage(Lang.get("move-bot-not-found", "name", args[0]));
            return true;
        }

        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("move-bot-not-online", "name", args[0]));
            return true;
        }

        // в”Җв”Җ Flag sub-commands (--wp / --stop) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (args.length >= 2 && args[1].startsWith("--")) {
            String flag = args[1].toLowerCase();

            if (flag.equals("--stop")) {
                if (!navTasks.containsKey(bot.getUniqueId())) {
                    sender.sendMessage(Lang.get("move-not-navigating", "name", fp.getDisplayName()));
                } else {
                    cancelNavigation(bot.getUniqueId()); // releases lock, clears jump, stops movement
                    sender.sendMessage(Lang.get("move-stopped", "name", fp.getDisplayName()));
                }
                return true;
            }

            if (flag.equals("--wp")) {
                if (waypointStore == null || args.length < 3) {
                    sender.sendMessage(Lang.get("move-wp-usage"));
                    return true;
                }
                String wpName = args[2];
                List<Location> route = waypointStore.getRoute(wpName);
                if (route == null || route.isEmpty()) {
                    sender.sendMessage(Lang.get("move-wp-not-found", "name", wpName));
                    return true;
                }
                // Verify at least the first waypoint is in the same world
                Location first = route.get(0);
                if (first.getWorld() == null || !first.getWorld().equals(bot.getWorld())) {
                    sender.sendMessage(Lang.get("move-wp-different-world",
                            "name", fp.getDisplayName(), "waypoint", wpName));
                    return true;
                }
                cancelNavigation(bot.getUniqueId());
                startPatrol(bot, route);
                sender.sendMessage(Lang.get("move-wp-started",
                        "name", fp.getDisplayName(), "waypoint", wpName,
                        "count", String.valueOf(route.size())));
                return true;
            }

            // Unknown flag вҖ” fall through to usage
            sender.sendMessage(Lang.get("move-usage"));
            return true;
        }

        // в”Җв”Җ Player-follow mode: /fpp move <bot> <player> в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (args.length >= 2) {
            Player target = Bukkit.getPlayer(args[1]);  // Case-insensitive lookup
            if (target == null) {
                sender.sendMessage(Lang.get("player-not-found", "player", args[1]));
                return true;
            }

            if (!bot.getWorld().equals(target.getWorld())) {
                sender.sendMessage(Lang.get("move-different-world",
                        "name", fp.getDisplayName(), "player", target.getName()));
                return true;
            }

            cancelNavigation(bot.getUniqueId());
            startNavigation(bot, target);

            sender.sendMessage(Lang.get("move-navigating",
                    "name", fp.getDisplayName(), "player", target.getName()));
            return true;
        }

        // в”Җв”Җ No second arg вҖ” show usage в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        sender.sendMessage(Lang.get("move-usage"));
        return true;
    }

    // в”Җв”Җ Navigation state machine в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @SuppressWarnings("unchecked")
    private void startNavigation(@NotNull Player bot, @NotNull Player target) {
        final UUID botUuid    = bot.getUniqueId();
        final UUID targetUuid = target.getUniqueId();

        // Lock bot for navigation вҖ” disables head-AI so it doesn't look at players
        manager.lockForNavigation(botUuid);

        // в”Җв”Җ Mutable navigation state в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final List<BotPathfinder.Move>[] pathRef  = new List[]{null};
        final int[]      wpIdx     = {0};
        final Location[] lastCalc  = {target.getLocation().clone()};
        final int[]      recalcIn  = {0};
        final int[]      stuckFor  = {0};
        final double[]   prevX     = {bot.getLocation().getX()};
        final double[]   prevZ     = {bot.getLocation().getZ()};

        // в”Җв”Җ Action state: BREAK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final boolean[]  isBreaking  = {false};
        final int[]      breakLeft   = {0};
        final Location[] breakLoc    = {null};

        // в”Җв”Җ Action state: PLACE в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final boolean[]  isPlacing   = {false};
        final int[]      placeLeft   = {0};

        BukkitTask task = new BukkitRunnable() {
            @Override
            public void run() {
                Player botPlayer    = Bukkit.getPlayer(botUuid);
                Player targetPlayer = Bukkit.getPlayer(targetUuid);

                if (botPlayer == null || !botPlayer.isOnline()) { cleanup(null); return; }
                if (targetPlayer == null || !targetPlayer.isOnline()) { cleanup(botPlayer); return; }

                Location botLoc    = botPlayer.getLocation();
                Location targetLoc = targetPlayer.getLocation();

                if (!botLoc.getWorld().equals(targetLoc.getWorld())) { cleanup(botPlayer); return; }

                // в”Җв”Җ Final arrival в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double distToTarget = xzDist(botLoc, targetLoc);
                if (distToTarget <= ARRIVAL_DIST) { cleanup(botPlayer); return; }

                // в”Җв”Җ Path recalculation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                boolean targetMoved   = lastCalc[0].distanceSquared(targetLoc) > RECALC_DIST * RECALC_DIST;
                boolean pathExhausted = (pathRef[0] == null || wpIdx[0] >= pathRef[0].size());
                boolean heartbeat     = (--recalcIn[0] <= 0);

                if (targetMoved || pathExhausted || heartbeat) {
                    recalcIn[0] = RECALC_INTERVAL;
                    lastCalc[0] = targetLoc.clone();

                    // Reset action states when a new path is computed
                    isBreaking[0] = false; breakLoc[0] = null;
                    isPlacing[0]  = false;

                    BotPathfinder.PathOptions opts = new BotPathfinder.PathOptions(
                            Config.pathfindingParkour(),
                            Config.pathfindingBreakBlocks(),
                            Config.pathfindingPlaceBlocks());

                    List<BotPathfinder.Move> newPath = BotPathfinder.findPathMoves(
                            botLoc.getWorld(),
                            botLoc.getBlockX(), botLoc.getBlockY(), botLoc.getBlockZ(),
                            targetLoc.getBlockX(), targetLoc.getBlockY(), targetLoc.getBlockZ(),
                            opts);

                    pathRef[0] = newPath;
                    wpIdx[0]   = (newPath != null && newPath.size() > 1) ? 1 : 0;
                    stuckFor[0] = 0;
                }

                // в”Җв”Җ Fallback: direct walk when no A* path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                List<BotPathfinder.Move> path = pathRef[0];
                if (path == null || path.isEmpty() || wpIdx[0] >= path.size()) {
                    walkToward(botPlayer, targetLoc, distToTarget);
                    return;
                }

                BotPathfinder.Move wp = path.get(wpIdx[0]);
                double wpCX = wp.x() + 0.5, wpCZ = wp.z() + 0.5;

                // в”Җв”Җ BREAK action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.BREAK) {
                    if (!isBreaking[0]) {
                        Location breakTarget = findBreakTarget(botLoc, wp);
                        if (breakTarget != null) {
                            isBreaking[0] = true;
                            breakLeft[0]  = BREAK_TICKS;
                            breakLoc[0]   = breakTarget;
                        } else {
                            // Can't find block to break вҖ” recalc
                            recalcIn[0] = 0;
                            return;
                        }
                    }
                    // Suppress stuck detection while mining
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    botPlayer.setSprinting(false);
                    // Face the block
                    Location blk = breakLoc[0];
                    if (blk != null) {
                        double bdx = blk.getX() - botLoc.getX();
                        double bdz = blk.getZ() - botLoc.getZ();
                        double bdy = blk.getY() - botLoc.getY();
                        float bYaw   = (float) Math.toDegrees(Math.atan2(-bdx, bdz));
                        float bPitch = (float) -Math.toDegrees(Math.atan2(bdy,
                                Math.sqrt(bdx * bdx + bdz * bdz)));
                        botPlayer.setRotation(bYaw, bPitch);
                        NmsPlayerSpawner.setHeadYaw(botPlayer, bYaw);
                    }
                    if (--breakLeft[0] <= 0) {
                        if (breakLoc[0] != null) {
                            breakLoc[0].getBlock().breakNaturally();
                            breakLoc[0] = null;
                        }
                        isBreaking[0] = false;
                        recalcIn[0]   = 0;  // recalc so new path avoids the now-open space
                        stuckFor[0]   = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ();
                    return;
                }

                // в”Җв”Җ PLACE action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.PLACE) {
                    if (!isPlacing[0]) {
                        isPlacing[0] = true;
                        placeLeft[0] = PLACE_TICKS;
                    }
                    // Suppress stuck detection while placing
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    botPlayer.setSprinting(false);
                    // Look down at gap
                    double pdx = (wp.x() + 0.5) - botLoc.getX();
                    double pdz = (wp.z() + 0.5) - botLoc.getZ();
                    float pYaw = (float) Math.toDegrees(Math.atan2(-pdx, pdz));
                    botPlayer.setRotation(pYaw, 70f);  // look steeply down
                    NmsPlayerSpawner.setHeadYaw(botPlayer, pYaw);

                    if (--placeLeft[0] <= 0) {
                        Block gapBlock = botPlayer.getWorld().getBlockAt(wp.x(), wp.y() - 1, wp.z());
                        if (gapBlock.isPassable()) {
                            Material mat = resolvePlaceMaterial();
                            gapBlock.setType(mat);
                        }
                        isPlacing[0] = false;
                        recalcIn[0]  = 0;  // recalc so new path uses the placed block as floor
                        stuckFor[0]  = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ();
                    return;
                }

                // в”Җв”Җ Waypoint advance в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                boolean wpYClose = Math.abs(botLoc.getY() - wp.y()) < 1.2;

                if (wpXZDist < WP_ARRIVE_XZ && wpYClose) {
                    wpIdx[0]++;
                    if (wpIdx[0] >= path.size()) {
                        recalcIn[0] = 0;
                        return;
                    }
                    wp    = path.get(wpIdx[0]);
                    wpCX  = wp.x() + 0.5;
                    wpCZ  = wp.z() + 0.5;
                    wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                }

                // в”Җв”Җ Face the waypoint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double dx = wpCX - botLoc.getX(), dz = wpCZ - botLoc.getZ();
                float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
                botPlayer.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);

                // в”Җв”Җ Walk / sprint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                botPlayer.setSprinting(distToTarget > SPRINT_DIST
                        || wp.type() == BotPathfinder.MoveType.PARKOUR);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);

                // в”Җв”Җ Jump / parkour в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (!botPlayer.isInWater() && !botPlayer.isInLava()) {
                    if (wp.y() > botLoc.getBlockY()) {
                        // Ascend вҖ” step-up jump
                        manager.requestNavJump(botUuid);
                    } else if (wp.type() == BotPathfinder.MoveType.PARKOUR
                            && wpXZDist >= 1.0 && wpXZDist <= 3.5) {
                        // Parkour вҖ” jump when within sprint range of the landing block.
                        // Combined with sprint=true above, this carries the bot across gaps.
                        // If the jump is missed, stuck detection recalculates.
                        manager.requestNavJump(botUuid);
                    }
                }

                // в”Җв”Җ Stuck detection (suppressed during break/place) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double moved = xzDistRaw(botLoc.getX(), botLoc.getZ(), prevX[0], prevZ[0]);
                if (moved < STUCK_THRESHOLD) {
                    if (++stuckFor[0] >= STUCK_TICKS) {
                        if (!botPlayer.isInWater() && !botPlayer.isInLava()) {
                            manager.requestNavJump(botUuid);
                        }
                        recalcIn[0] = 0;
                        stuckFor[0] = 0;
                    }
                } else {
                    stuckFor[0] = 0;
                }

                prevX[0] = botLoc.getX();
                prevZ[0] = botLoc.getZ();
            }

            // в”Җв”Җ Inner helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

            private void cleanup(@Nullable Player botPlayer) {
                manager.clearNavJump(botUuid);
                manager.unlockNavigation(botUuid);  // Re-enable head-AI
                isBreaking[0] = false; breakLoc[0] = null;
                isPlacing[0]  = false;
                if (botPlayer != null) {
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    NmsPlayerSpawner.setJumping(botPlayer, false);
                    botPlayer.setSprinting(false);
                }
                cancel();
                navTasks.remove(botUuid);
            }

            private void walkToward(Player botPlayer, Location targetLoc, double dist) {
                Location bl = botPlayer.getLocation();
                float yaw = (float) Math.toDegrees(
                        Math.atan2(-(targetLoc.getX() - bl.getX()), targetLoc.getZ() - bl.getZ()));
                botPlayer.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);
                botPlayer.setSprinting(dist > SPRINT_DIST);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);
            }

        }.runTaskTimer(plugin, 0L, 1L);

        navTasks.put(botUuid, task);
    }

    // в”Җв”Җ Patrol state machine в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Starts an indefinite patrol loop through the given waypoints.
     * The bot walks waypoint[0] вҶ’ waypoint[1] вҶ’ вҖҰ вҶ’ waypoint[N-1] вҶ’ waypoint[0] вҶ’ вҖҰ
     * using A* pathfinding between each stop.  The task runs until
     * {@link #cancelNavigation(UUID)} is called (e.g. by a new command or bot removal).
     *
     * <p>A snapshot copy of {@code waypoints} is taken at start time so
     * adding/removing entries from the source list mid-patrol has no effect
     * on the running patrol вҖ” issue a new {@code /fpp move <bot>} to pick
     * up changes.
     */
    @SuppressWarnings("unchecked")
    private void startPatrol(@NotNull Player bot, @NotNull List<Location> waypoints) {
        final UUID botUuid  = bot.getUniqueId();
        final List<Location> wps = new ArrayList<>(waypoints); // immutable snapshot

        // Lock bot for navigation вҖ” disables head-AI so it doesn't look at players
        manager.lockForNavigation(botUuid);

        // в”Җв”Җ Mutable patrol state в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final int[]    wpSetIdx = {0};                   // index into wps[]
        final List<BotPathfinder.Move>[] pathRef = new List[]{null};
        final int[]    wpIdx    = {0};
        final int[]    recalcIn = {0};
        final int[]    stuckFor = {0};
        final double[] prevX    = {bot.getLocation().getX()};
        final double[] prevZ    = {bot.getLocation().getZ()};
        final int[]    failedRecalcs = {0};  // Track consecutive failed pathfinds

        // в”Җв”Җ Action state: BREAK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final boolean[]  isBreaking = {false};
        final int[]      breakLeft  = {0};
        final Location[] breakLoc   = {null};

        // в”Җв”Җ Action state: PLACE в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final boolean[] isPlacing = {false};
        final int[]     placeLeft = {0};

        BukkitTask task = new BukkitRunnable() {
            @Override
            public void run() {
                Player botPlayer = Bukkit.getPlayer(botUuid);
                if (botPlayer == null || !botPlayer.isOnline()) { cleanup(null); return; }

                Location botLoc = botPlayer.getLocation();
                Location dest   = wps.get(wpSetIdx[0]);

                // Cancel patrol if bot is in different world (e.g., teleported away)
                if (!botLoc.getWorld().equals(dest.getWorld())) {
                    cleanup(botPlayer);
                    return;
                }

                double distToDest = xzDist(botLoc, dest);

                // в”Җв”Җ Arrived at current waypoint вҶ’ advance to next в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (distToDest <= PATROL_ARRIVE_DIST) {
                    wpSetIdx[0] = (wpSetIdx[0] + 1) % wps.size();
                    pathRef[0]    = null;
                    wpIdx[0]      = 0;
                    recalcIn[0]   = 0;
                    stuckFor[0]   = 0;
                    isBreaking[0] = false; breakLoc[0] = null;
                    isPlacing[0]  = false;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    return;
                }

                // в”Җв”Җ Path recalculation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                boolean pathExhausted = (pathRef[0] == null || wpIdx[0] >= pathRef[0].size());
                boolean heartbeat     = (--recalcIn[0] <= 0);

                if (pathExhausted || heartbeat) {
                    recalcIn[0]   = RECALC_INTERVAL;
                    isBreaking[0] = false; breakLoc[0] = null;
                    isPlacing[0]  = false;

                    BotPathfinder.PathOptions opts = new BotPathfinder.PathOptions(
                            Config.pathfindingParkour(),
                            Config.pathfindingBreakBlocks(),
                            Config.pathfindingPlaceBlocks());

                    List<BotPathfinder.Move> newPath = BotPathfinder.findPathMoves(
                            botLoc.getWorld(),
                            botLoc.getBlockX(), botLoc.getBlockY(), botLoc.getBlockZ(),
                            dest.getBlockX(),   dest.getBlockY(),   dest.getBlockZ(),
                            opts);

                    if (newPath == null) {
                        failedRecalcs[0]++;
                        // Skip unreachable waypoints after 10 failed attempts
                        if (failedRecalcs[0] >= 10) {
                            wpSetIdx[0] = (wpSetIdx[0] + 1) % wps.size();
                            failedRecalcs[0] = 0;
                            pathRef[0]    = null;
                            wpIdx[0]      = 0;
                            stuckFor[0]   = 0;
                            return;
                        }
                    } else {
                        failedRecalcs[0] = 0;
                    }

                    pathRef[0]  = newPath;
                    wpIdx[0]    = (newPath != null && newPath.size() > 1) ? 1 : 0;
                    stuckFor[0] = 0;
                }

                // в”Җв”Җ Fallback: direct walk when no A* path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                List<BotPathfinder.Move> path = pathRef[0];
                if (path == null || path.isEmpty() || wpIdx[0] >= path.size()) {
                    walkToward(botPlayer, dest, distToDest);
                    return;
                }

                BotPathfinder.Move wp = path.get(wpIdx[0]);
                double wpCX = wp.x() + 0.5, wpCZ = wp.z() + 0.5;

                // в”Җв”Җ BREAK action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.BREAK) {
                    if (!isBreaking[0]) {
                        Location blk = findBreakTarget(botLoc, wp);
                        if (blk != null) {
                            isBreaking[0] = true;
                            breakLeft[0]  = BREAK_TICKS;
                            breakLoc[0]   = blk;
                        } else {
                            recalcIn[0] = 0;
                            return;
                        }
                    }
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    botPlayer.setSprinting(false);
                    Location blk = breakLoc[0];
                    if (blk != null) {
                        double bdx = blk.getX() - botLoc.getX();
                        double bdz = blk.getZ() - botLoc.getZ();
                        double bdy = blk.getY() - botLoc.getY();
                        float bYaw   = (float) Math.toDegrees(Math.atan2(-bdx, bdz));
                        float bPitch = (float) -Math.toDegrees(Math.atan2(bdy,
                                Math.sqrt(bdx * bdx + bdz * bdz)));
                        botPlayer.setRotation(bYaw, bPitch);
                        NmsPlayerSpawner.setHeadYaw(botPlayer, bYaw);
                    }
                    if (--breakLeft[0] <= 0) {
                        if (breakLoc[0] != null) { breakLoc[0].getBlock().breakNaturally(); breakLoc[0] = null; }
                        isBreaking[0] = false;
                        recalcIn[0]   = 0;
                        stuckFor[0]   = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ();
                    return;
                }

                // в”Җв”Җ PLACE action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.PLACE) {
                    if (!isPlacing[0]) { isPlacing[0] = true; placeLeft[0] = PLACE_TICKS; }
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    botPlayer.setSprinting(false);
                    double pdx = (wp.x() + 0.5) - botLoc.getX();
                    double pdz = (wp.z() + 0.5) - botLoc.getZ();
                    float pYaw = (float) Math.toDegrees(Math.atan2(-pdx, pdz));
                    botPlayer.setRotation(pYaw, 70f);
                    NmsPlayerSpawner.setHeadYaw(botPlayer, pYaw);
                    if (--placeLeft[0] <= 0) {
                        Block gapBlock = botPlayer.getWorld().getBlockAt(wp.x(), wp.y() - 1, wp.z());
                        if (gapBlock.isPassable()) gapBlock.setType(resolvePlaceMaterial());
                        isPlacing[0] = false;
                        recalcIn[0]  = 0;
                        stuckFor[0]  = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ();
                    return;
                }

                // в”Җв”Җ Waypoint advance в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                boolean wpYClose = Math.abs(botLoc.getY() - wp.y()) < 1.2;

                if (wpXZDist < WP_ARRIVE_XZ && wpYClose) {
                    wpIdx[0]++;
                    if (wpIdx[0] >= path.size()) { recalcIn[0] = 0; return; }
                    wp       = path.get(wpIdx[0]);
                    wpCX     = wp.x() + 0.5;
                    wpCZ     = wp.z() + 0.5;
                    wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                }

                // в”Җв”Җ Face the waypoint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double dx = wpCX - botLoc.getX(), dz = wpCZ - botLoc.getZ();
                float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
                botPlayer.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);

                // в”Җв”Җ Walk / sprint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                botPlayer.setSprinting(distToDest > SPRINT_DIST
                        || wp.type() == BotPathfinder.MoveType.PARKOUR);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);

                // в”Җв”Җ Jump / parkour в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (!botPlayer.isInWater() && !botPlayer.isInLava()) {
                    if (wp.y() > botLoc.getBlockY()) {
                        manager.requestNavJump(botUuid);
                    } else if (wp.type() == BotPathfinder.MoveType.PARKOUR
                            && wpXZDist >= 1.0 && wpXZDist <= 3.5) {
                        manager.requestNavJump(botUuid);
                    }
                }

                // в”Җв”Җ Stuck detection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double moved = xzDistRaw(botLoc.getX(), botLoc.getZ(), prevX[0], prevZ[0]);
                if (moved < STUCK_THRESHOLD) {
                    if (++stuckFor[0] >= STUCK_TICKS) {
                        if (!botPlayer.isInWater() && !botPlayer.isInLava())
                            manager.requestNavJump(botUuid);
                        recalcIn[0] = 0;
                        stuckFor[0] = 0;
                    }
                } else {
                    stuckFor[0] = 0;
                }

                prevX[0] = botLoc.getX();
                prevZ[0] = botLoc.getZ();
            }

            private void cleanup(@Nullable Player botPlayer) {
                manager.clearNavJump(botUuid);
                manager.unlockNavigation(botUuid);  // Re-enable head-AI
                isBreaking[0] = false; breakLoc[0] = null;
                isPlacing[0]  = false;
                if (botPlayer != null) {
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    NmsPlayerSpawner.setJumping(botPlayer, false);
                    botPlayer.setSprinting(false);
                }
                cancel();
                navTasks.remove(botUuid);
            }

            private void walkToward(Player botPlayer, Location targetLoc, double dist) {
                Location bl = botPlayer.getLocation();
                float yaw = (float) Math.toDegrees(
                        Math.atan2(-(targetLoc.getX() - bl.getX()), targetLoc.getZ() - bl.getZ()));
                botPlayer.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);
                botPlayer.setSprinting(dist > SPRINT_DIST);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);
            }

        }.runTaskTimer(plugin, 0L, 1L);

        navTasks.put(botUuid, task);
    }

    // в”Җв”Җ Break / Place helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final UUID     botUuid      = bot.getUniqueId();
        final Location destSnapshot = dest.clone();

        manager.lockForNavigation(botUuid);

        final List<BotPathfinder.Move>[] pathRef = new List[]{null};
        final int[]      wpIdx     = {0};
        final int[]      recalcIn  = {0};
        final int[]      stuckFor  = {0};
        final double[]   prevX     = {bot.getLocation().getX()};
        final double[]   prevZ     = {bot.getLocation().getZ()};

        final boolean[]  isBreaking = {false};
        final int[]      breakLeft  = {0};
        final Location[] breakLoc   = {null};

        final boolean[]  isPlacing  = {false};
        final int[]      placeLeft  = {0};

        BukkitTask task = new BukkitRunnable() {
            @Override
            public void run() {
                Player botPlayer = Bukkit.getPlayer(botUuid);
                if (botPlayer == null || !botPlayer.isOnline()) { cleanup(null); return; }
                if (destSnapshot.getWorld() == null
                        || !botPlayer.getWorld().equals(destSnapshot.getWorld())) {
                    cleanup(botPlayer); return;
                }

                Location botLoc     = botPlayer.getLocation();
                double   distToDest = xzDist(botLoc, destSnapshot);

                // Arrived вҖ” stop
                if (distToDest <= ARRIVAL_DIST) { cleanup(botPlayer); return; }

                // Path recalculation
                boolean pathExhausted = (pathRef[0] == null || wpIdx[0] >= pathRef[0].size());
                if (pathExhausted || --recalcIn[0] <= 0) {
                    recalcIn[0]   = RECALC_INTERVAL;
                    isBreaking[0] = false; breakLoc[0] = null;
                    isPlacing[0]  = false;
                    BotPathfinder.PathOptions opts = new BotPathfinder.PathOptions(
                            Config.pathfindingParkour(),
                            Config.pathfindingBreakBlocks(),
                            Config.pathfindingPlaceBlocks());
                    List<BotPathfinder.Move> newPath = BotPathfinder.findPathMoves(
                            botLoc.getWorld(),
                            botLoc.getBlockX(), botLoc.getBlockY(), botLoc.getBlockZ(),
                            destSnapshot.getBlockX(), destSnapshot.getBlockY(), destSnapshot.getBlockZ(),
                            opts);
                    pathRef[0]  = newPath;
                    wpIdx[0]    = (newPath != null && newPath.size() > 1) ? 1 : 0;
                    stuckFor[0] = 0;
                }

                List<BotPathfinder.Move> path = pathRef[0];
                if (path == null || path.isEmpty() || wpIdx[0] >= path.size()) {
                    walkToward(botPlayer, destSnapshot, distToDest); return;
                }

                BotPathfinder.Move wp  = path.get(wpIdx[0]);
                double wpCX = wp.x() + 0.5, wpCZ = wp.z() + 0.5;

                // в”Җв”Җ BREAK action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.BREAK) {
                    if (!isBreaking[0]) {
                        Location blk = findBreakTarget(botLoc, wp);
                        if (blk != null) { isBreaking[0] = true; breakLeft[0] = BREAK_TICKS; breakLoc[0] = blk; }
                        else { recalcIn[0] = 0; return; }
                    }
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f); botPlayer.setSprinting(false);
                    Location blk = breakLoc[0];
                    if (blk != null) {
                        double bdx = blk.getX()-botLoc.getX(), bdz = blk.getZ()-botLoc.getZ(),
                               bdy = blk.getY()-botLoc.getY();
                        float bYaw   = (float) Math.toDegrees(Math.atan2(-bdx, bdz));
                        float bPitch = (float) -Math.toDegrees(Math.atan2(bdy, Math.sqrt(bdx*bdx+bdz*bdz)));
                        botPlayer.setRotation(bYaw, bPitch); NmsPlayerSpawner.setHeadYaw(botPlayer, bYaw);
                    }
                    if (--breakLeft[0] <= 0) {
                        if (breakLoc[0] != null) { breakLoc[0].getBlock().breakNaturally(); breakLoc[0] = null; }
                        isBreaking[0] = false; recalcIn[0] = 0; stuckFor[0] = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ(); return;
                }

                // в”Җв”Җ PLACE action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.PLACE) {
                    if (!isPlacing[0]) { isPlacing[0] = true; placeLeft[0] = PLACE_TICKS; }
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f); botPlayer.setSprinting(false);
                    double pdx = (wp.x()+0.5)-botLoc.getX(), pdz = (wp.z()+0.5)-botLoc.getZ();
                    float pYaw = (float) Math.toDegrees(Math.atan2(-pdx, pdz));
                    botPlayer.setRotation(pYaw, 70f); NmsPlayerSpawner.setHeadYaw(botPlayer, pYaw);
                    if (--placeLeft[0] <= 0) {
                        Block gapBlock = botPlayer.getWorld().getBlockAt(wp.x(), wp.y()-1, wp.z());
                        if (gapBlock.isPassable()) gapBlock.setType(resolvePlaceMaterial());
                        isPlacing[0] = false; recalcIn[0] = 0; stuckFor[0] = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ(); return;
                }

                // в”Җв”Җ Waypoint advance в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double  wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                boolean wpYClose = Math.abs(botLoc.getY() - wp.y()) < 1.2;
                if (wpXZDist < WP_ARRIVE_XZ && wpYClose) {
                    wpIdx[0]++;
                    if (wpIdx[0] >= path.size()) { recalcIn[0] = 0; return; }
                    wp       = path.get(wpIdx[0]);
                    wpCX     = wp.x() + 0.5; wpCZ = wp.z() + 0.5;
                    wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                }

                // в”Җв”Җ Face + move в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double dx = wpCX - botLoc.getX(), dz = wpCZ - botLoc.getZ();
                float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
                botPlayer.setRotation(yaw, 0f); NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);
                botPlayer.setSprinting(distToDest > SPRINT_DIST || wp.type() == BotPathfinder.MoveType.PARKOUR);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);

                // в”Җв”Җ Jump в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (!botPlayer.isInWater() && !botPlayer.isInLava()) {
                    if (wp.y() > botLoc.getBlockY()) {
                        manager.requestNavJump(botUuid);
                    } else if (wp.type() == BotPathfinder.MoveType.PARKOUR
                            && wpXZDist >= 1.0 && wpXZDist <= 3.5) {
                        manager.requestNavJump(botUuid);
                    }
                }

                // в”Җв”Җ Stuck detection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double moved = xzDistRaw(botLoc.getX(), botLoc.getZ(), prevX[0], prevZ[0]);
                if (moved < STUCK_THRESHOLD) {
                    if (++stuckFor[0] >= STUCK_TICKS) {
                        if (!botPlayer.isInWater() && !botPlayer.isInLava()) manager.requestNavJump(botUuid);
                        recalcIn[0] = 0; stuckFor[0] = 0;
                    }
                } else { stuckFor[0] = 0; }

                prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ();
            }

            private void cleanup(@Nullable Player botPlayer) {
                manager.clearNavJump(botUuid);
                manager.unlockNavigation(botUuid);
                isBreaking[0] = false; breakLoc[0] = null;
                isPlacing[0]  = false;
                if (botPlayer != null) {
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    NmsPlayerSpawner.setJumping(botPlayer, false);
                    botPlayer.setSprinting(false);
                }
                cancel();
                navTasks.remove(botUuid);
            }

            private void walkToward(Player botPlayer, Location targetLoc, double dist) {
                Location bl = botPlayer.getLocation();
                float yaw = (float) Math.toDegrees(
                        Math.atan2(-(targetLoc.getX()-bl.getX()), targetLoc.getZ()-bl.getZ()));
                botPlayer.setRotation(yaw, 0f); NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);
                botPlayer.setSprinting(dist > SPRINT_DIST);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);
            }

        }.runTaskTimer(plugin, 0L, 1L);

        navTasks.put(botUuid, task);
    }

    // в”Җв”Җ Break / Place helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Finds the first non-passable block in the direct path from bot to the BREAK waypoint.
     * Checks, in order: destination feet, destination head, source head (for ascend-break).
     */
    @Nullable
    private static Location findBreakTarget(Location botLoc, BotPathfinder.Move wp) {
        org.bukkit.World w = botLoc.getWorld();
        int wx = wp.x(), wy = wp.y(), wz = wp.z();

        // Destination feet
        if (!w.getBlockAt(wx, wy, wz).isPassable())
            return new Location(w, wx + 0.5, wy + 0.5, wz + 0.5);

        // Destination head
        if (!w.getBlockAt(wx, wy + 1, wz).isPassable())
            return new Location(w, wx + 0.5, wy + 1.5, wz + 0.5);

        // Source head (ascend-break: can't step up because y+2 is blocked)
        int by = botLoc.getBlockY();
        int bx = botLoc.getBlockX(), bz = botLoc.getBlockZ();
        if (!w.getBlockAt(bx, by + 2, bz).isPassable())
            return new Location(w, bx + 0.5, by + 2.5, bz + 0.5);

        return null;
    }

    /**
     * Returns the material to use when placing a bridge block.
     * Falls back to DIRT if the configured value is invalid.
     */
    private Material resolvePlaceMaterial() {
        String raw = Config.pathfindingPlaceMaterial();
        Material mat = Material.matchMaterial(raw.toUpperCase());
        if (mat != null && mat.isBlock() && mat.isSolid()) return mat;
        return Material.DIRT;
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static double xzDist(Location a, Location b) {
        return xzDistRaw(a.getX(), a.getZ(), b.getX(), b.getZ());
    }

    private static double xzDistRaw(double ax, double az, double bx, double bz) {
        double dx = ax - bx, dz = az - bz;
        return Math.sqrt(dx * dx + dz * dz);
    }

    /**
     * Cancels the active navigation task for a bot and fully releases all navigation state:
     * nav-jump, navigation lock (re-enables head-AI), and movement inputs.
     * Safe to call even when no task is running.
     */
    private void cancelNavigation(@NotNull UUID botUuid) {
        BukkitTask t = navTasks.remove(botUuid);
        if (t != null && !t.isCancelled()) t.cancel();
        // Release navigation lock so head-AI resumes and the bot stops moving.
        manager.clearNavJump(botUuid);
        manager.unlockNavigation(botUuid);
        Player botPlayer = Bukkit.getPlayer(botUuid);
        if (botPlayer != null) {
            NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
            NmsPlayerSpawner.setJumping(botPlayer, false);
            botPlayer.setSprinting(false);
        }
    }

    /** Cancels all active navigation tasks. Called from {@code onDisable}. */
    public void cancelAll() {
        new ArrayList<>(navTasks.keySet()).forEach(this::cancelNavigation);
    }

    /**
     * Cleans up all navigation state for a specific bot.
     * Call this when a bot is despawned/deleted to prevent memory leaks.
     *
     * @param botUuid the bot's UUID
     */
    public void cleanupBot(@NotNull UUID botUuid) {
        cancelNavigation(botUuid);
    }

    // в”Җв”Җ Tab-complete в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        List<String> out = new ArrayList<>();
        if (args.length == 1) {
            String in = args[0].toLowerCase();
            for (FakePlayer fp : manager.getActivePlayers())
                if (fp.getName().toLowerCase().startsWith(in)) out.add(fp.getName());
        } else if (args.length == 2) {
            String in = args[1].toLowerCase();
            // Flag options
            for (String flag : List.of("--wp", "--stop"))
                if (flag.startsWith(in)) out.add(flag);
            // Online player names (for player-follow mode)
            for (Player p : Bukkit.getOnlinePlayers())
                if (p.getName().toLowerCase().startsWith(in)) out.add(p.getName());
        } else if (args.length == 3 && args[1].equalsIgnoreCase("--wp")) {
            // Suggest known waypoint names
            if (waypointStore != null) {
                String in = args[2].toLowerCase();
                for (String name : waypointStore.getNames())
                    if (name.startsWith(in)) out.add(name);
            }
        }
        return out;
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotPathfinder;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.fakeplayer.NmsPlayerSpawner;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.Material;
import org.bukkit.block.Block;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;
import org.bukkit.scheduler.BukkitRunnable;
import org.bukkit.scheduler.BukkitTask;
import org.jetbrains.annotations.NotNull;
import org.jetbrains.annotations.Nullable;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Navigates a bot to an online player using an A* grid pathfinder,
 * OR patrols a bot through a user-defined list of waypoints in a loop.
 *
 * <h3>Player-follow mode</h3>
 * {@code /fpp move <bot> <player>} вҖ” navigates continuously toward the player.
 * Recalculates path when target moves &gt;{@value #RECALC_DIST} blocks or every
 * {@value #RECALC_INTERVAL} ticks.
 *
 * <h3>Waypoint patrol mode</h3>
 * <ol>
 *   <li>Create a named route with {@code /fpp wp add <route>} (run multiple times
 *       to build a list of positions).</li>
 *   <li>{@code /fpp move <bot> --wp <route>} вҖ” start the patrol loop (bot visits
 *       position 1 вҶ’ 2 вҶ’ вҖҰ вҶ’ N вҶ’ 1 вҶ’ вҖҰ, forever).</li>
 *   <li>{@code /fpp move <bot> --stop} вҖ” stop navigation.</li>
 * </ol>
 *
 * <h3>Navigation loop (1-tick interval)</h3>
 * <ol>
 *   <li>Handles WALK/ASCEND/DESCEND normally (face + forward + conditional jump).</li>
 *   <li>Handles PARKOUR: sprint + request jump when 1вҖ“3.5 blocks from landing.</li>
 *   <li>Handles BREAK: stop, face block, wait {@value #BREAK_TICKS} ticks, break it.</li>
 *   <li>Handles PLACE: stop, wait {@value #PLACE_TICKS} ticks, place bridge block.</li>
 *   <li>Stuck detection ({@value #STUCK_TICKS} ticks) forces jump + recalc.
 *       Suppressed while breaking or placing.</li>
 *   <li>Falls back to direct face-and-walk when no path is found.</li>
 * </ol>
 */
public final class MoveCommand implements FppCommand {

    // в”Җв”Җ Tuning constants в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static final double ARRIVAL_DIST        = 2.0;
    /** Radius within which the bot considers itself "at" a patrol waypoint. */
    private static final double PATROL_ARRIVE_DIST  = 1.5;
    private static final double SPRINT_DIST         = 8.0;
    private static final double WP_ARRIVE_XZ        = 0.65;
    private static final double RECALC_DIST         = 3.5;
    private static final int    RECALC_INTERVAL     = 60;
    private static final int    STUCK_TICKS         = 8;
    private static final double STUCK_THRESHOLD     = 0.04;

    /**
     * Ticks a bot spends "mining" a blocking block before it disappears.
     * This is a fixed bot-behaviour wait (not physics-accurate hardness),
     * chosen so that navigation feels snappy (~0.75 s) without being jarring.
     */
    private static final int BREAK_TICKS = 15;

    /**
     * Ticks a bot waits before placing a bridge block.
     * Short pause to animate the "look-down-and-place" gesture.
     */
    private static final int PLACE_TICKS = 5;

    // в”Җв”Җ Fields в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;
    private final Map<UUID, BukkitTask> navTasks     = new ConcurrentHashMap<>();
    /**
     * Global named waypoint route registry.  Injected via {@link #setWaypointStore(WaypointStore)}.
     * Used by the {@code --wp <name>} flag.
     */
    private WaypointStore waypointStore;

    public MoveCommand(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
    }

    /** Injects the global waypoint store so {@code --wp <name>} can look up destinations. */
    public void setWaypointStore(WaypointStore store) {
        this.waypointStore = store;
    }

    // в”Җв”Җ FppCommand в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override public String getName()        { return "move"; }
    @Override public String getUsage()       { return "<bot> <player>  |  <bot> --wp <route>  |  <bot> --stop"; }
    @Override public String getDescription() { return "Navigate a bot to a player or patrol a named waypoint route in a loop."; }
    @Override public String getPermission()  { return Perm.MOVE; }
    @Override public boolean canUse(CommandSender sender) { return Perm.has(sender, Perm.MOVE); }

    // в”Җв”Җ execute в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(Lang.get("move-usage"));
            return true;
        }

        FakePlayer fp = manager.getByName(args[0]);
        if (fp == null) {
            sender.sendMessage(Lang.get("move-bot-not-found", "name", args[0]));
            return true;
        }

        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("move-bot-not-online", "name", args[0]));
            return true;
        }

        // в”Җв”Җ Flag sub-commands (--wp / --stop) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (args.length >= 2 && args[1].startsWith("--")) {
            String flag = args[1].toLowerCase();

            if (flag.equals("--stop")) {
                if (!navTasks.containsKey(bot.getUniqueId())) {
                    sender.sendMessage(Lang.get("move-not-navigating", "name", fp.getDisplayName()));
                } else {
                    cancelNavigation(bot.getUniqueId()); // releases lock, clears jump, stops movement
                    sender.sendMessage(Lang.get("move-stopped", "name", fp.getDisplayName()));
                }
                return true;
            }

            if (flag.equals("--wp")) {
                if (waypointStore == null || args.length < 3) {
                    sender.sendMessage(Lang.get("move-wp-usage"));
                    return true;
                }
                String wpName = args[2];
                List<Location> route = waypointStore.getRoute(wpName);
                if (route == null || route.isEmpty()) {
                    sender.sendMessage(Lang.get("move-wp-not-found", "name", wpName));
                    return true;
                }
                // Verify at least the first waypoint is in the same world
                Location first = route.get(0);
                if (first.getWorld() == null || !first.getWorld().equals(bot.getWorld())) {
                    sender.sendMessage(Lang.get("move-wp-different-world",
                            "name", fp.getDisplayName(), "waypoint", wpName));
                    return true;
                }
                cancelNavigation(bot.getUniqueId());
                startPatrol(bot, route);
                sender.sendMessage(Lang.get("move-wp-started",
                        "name", fp.getDisplayName(), "waypoint", wpName,
                        "count", String.valueOf(route.size())));
                return true;
            }

            // Unknown flag вҖ” fall through to usage
            sender.sendMessage(Lang.get("move-usage"));
            return true;
        }

        // в”Җв”Җ Player-follow mode: /fpp move <bot> <player> в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (args.length >= 2) {
            Player target = Bukkit.getPlayer(args[1]);  // Case-insensitive lookup
            if (target == null) {
                sender.sendMessage(Lang.get("player-not-found", "player", args[1]));
                return true;
            }

            if (!bot.getWorld().equals(target.getWorld())) {
                sender.sendMessage(Lang.get("move-different-world",
                        "name", fp.getDisplayName(), "player", target.getName()));
                return true;
            }

            cancelNavigation(bot.getUniqueId());
            startNavigation(bot, target);

            sender.sendMessage(Lang.get("move-navigating",
                    "name", fp.getDisplayName(), "player", target.getName()));
            return true;
        }

        // в”Җв”Җ No second arg вҖ” show usage в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        sender.sendMessage(Lang.get("move-usage"));
        return true;
    }

    // в”Җв”Җ Navigation state machine в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @SuppressWarnings("unchecked")
    private void startNavigation(@NotNull Player bot, @NotNull Player target) {
        final UUID botUuid    = bot.getUniqueId();
        final UUID targetUuid = target.getUniqueId();

        // Lock bot for navigation вҖ” disables head-AI so it doesn't look at players
        manager.lockForNavigation(botUuid);

        // в”Җв”Җ Mutable navigation state в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final List<BotPathfinder.Move>[] pathRef  = new List[]{null};
        final int[]      wpIdx     = {0};
        final Location[] lastCalc  = {target.getLocation().clone()};
        final int[]      recalcIn  = {0};
        final int[]      stuckFor  = {0};
        final double[]   prevX     = {bot.getLocation().getX()};
        final double[]   prevZ     = {bot.getLocation().getZ()};

        // в”Җв”Җ Action state: BREAK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final boolean[]  isBreaking  = {false};
        final int[]      breakLeft   = {0};
        final Location[] breakLoc    = {null};

        // в”Җв”Җ Action state: PLACE в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final boolean[]  isPlacing   = {false};
        final int[]      placeLeft   = {0};

        BukkitTask task = new BukkitRunnable() {
            @Override
            public void run() {
                Player botPlayer    = Bukkit.getPlayer(botUuid);
                Player targetPlayer = Bukkit.getPlayer(targetUuid);

                if (botPlayer == null || !botPlayer.isOnline()) { cleanup(null); return; }
                if (targetPlayer == null || !targetPlayer.isOnline()) { cleanup(botPlayer); return; }

                Location botLoc    = botPlayer.getLocation();
                Location targetLoc = targetPlayer.getLocation();

                if (!botLoc.getWorld().equals(targetLoc.getWorld())) { cleanup(botPlayer); return; }

                // в”Җв”Җ Final arrival в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double distToTarget = xzDist(botLoc, targetLoc);
                if (distToTarget <= ARRIVAL_DIST) { cleanup(botPlayer); return; }

                // в”Җв”Җ Path recalculation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                boolean targetMoved   = lastCalc[0].distanceSquared(targetLoc) > RECALC_DIST * RECALC_DIST;
                boolean pathExhausted = (pathRef[0] == null || wpIdx[0] >= pathRef[0].size());
                boolean heartbeat     = (--recalcIn[0] <= 0);

                if (targetMoved || pathExhausted || heartbeat) {
                    recalcIn[0] = RECALC_INTERVAL;
                    lastCalc[0] = targetLoc.clone();

                    // Reset action states when a new path is computed
                    isBreaking[0] = false; breakLoc[0] = null;
                    isPlacing[0]  = false;

                    BotPathfinder.PathOptions opts = new BotPathfinder.PathOptions(
                            Config.pathfindingParkour(),
                            Config.pathfindingBreakBlocks(),
                            Config.pathfindingPlaceBlocks());

                    List<BotPathfinder.Move> newPath = BotPathfinder.findPathMoves(
                            botLoc.getWorld(),
                            botLoc.getBlockX(), botLoc.getBlockY(), botLoc.getBlockZ(),
                            targetLoc.getBlockX(), targetLoc.getBlockY(), targetLoc.getBlockZ(),
                            opts);

                    pathRef[0] = newPath;
                    wpIdx[0]   = (newPath != null && newPath.size() > 1) ? 1 : 0;
                    stuckFor[0] = 0;
                }

                // в”Җв”Җ Fallback: direct walk when no A* path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                List<BotPathfinder.Move> path = pathRef[0];
                if (path == null || path.isEmpty() || wpIdx[0] >= path.size()) {
                    walkToward(botPlayer, targetLoc, distToTarget);
                    return;
                }

                BotPathfinder.Move wp = path.get(wpIdx[0]);
                double wpCX = wp.x() + 0.5, wpCZ = wp.z() + 0.5;

                // в”Җв”Җ BREAK action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.BREAK) {
                    if (!isBreaking[0]) {
                        Location breakTarget = findBreakTarget(botLoc, wp);
                        if (breakTarget != null) {
                            isBreaking[0] = true;
                            breakLeft[0]  = BREAK_TICKS;
                            breakLoc[0]   = breakTarget;
                        } else {
                            // Can't find block to break вҖ” recalc
                            recalcIn[0] = 0;
                            return;
                        }
                    }
                    // Suppress stuck detection while mining
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    botPlayer.setSprinting(false);
                    // Face the block
                    Location blk = breakLoc[0];
                    if (blk != null) {
                        double bdx = blk.getX() - botLoc.getX();
                        double bdz = blk.getZ() - botLoc.getZ();
                        double bdy = blk.getY() - botLoc.getY();
                        float bYaw   = (float) Math.toDegrees(Math.atan2(-bdx, bdz));
                        float bPitch = (float) -Math.toDegrees(Math.atan2(bdy,
                                Math.sqrt(bdx * bdx + bdz * bdz)));
                        botPlayer.setRotation(bYaw, bPitch);
                        NmsPlayerSpawner.setHeadYaw(botPlayer, bYaw);
                    }
                    if (--breakLeft[0] <= 0) {
                        if (breakLoc[0] != null) {
                            breakLoc[0].getBlock().breakNaturally();
                            breakLoc[0] = null;
                        }
                        isBreaking[0] = false;
                        recalcIn[0]   = 0;  // recalc so new path avoids the now-open space
                        stuckFor[0]   = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ();
                    return;
                }

                // в”Җв”Җ PLACE action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.PLACE) {
                    if (!isPlacing[0]) {
                        isPlacing[0] = true;
                        placeLeft[0] = PLACE_TICKS;
                    }
                    // Suppress stuck detection while placing
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    botPlayer.setSprinting(false);
                    // Look down at gap
                    double pdx = (wp.x() + 0.5) - botLoc.getX();
                    double pdz = (wp.z() + 0.5) - botLoc.getZ();
                    float pYaw = (float) Math.toDegrees(Math.atan2(-pdx, pdz));
                    botPlayer.setRotation(pYaw, 70f);  // look steeply down
                    NmsPlayerSpawner.setHeadYaw(botPlayer, pYaw);

                    if (--placeLeft[0] <= 0) {
                        Block gapBlock = botPlayer.getWorld().getBlockAt(wp.x(), wp.y() - 1, wp.z());
                        if (gapBlock.isPassable()) {
                            Material mat = resolvePlaceMaterial();
                            gapBlock.setType(mat);
                        }
                        isPlacing[0] = false;
                        recalcIn[0]  = 0;  // recalc so new path uses the placed block as floor
                        stuckFor[0]  = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ();
                    return;
                }

                // в”Җв”Җ Waypoint advance в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                boolean wpYClose = Math.abs(botLoc.getY() - wp.y()) < 1.2;

                if (wpXZDist < WP_ARRIVE_XZ && wpYClose) {
                    wpIdx[0]++;
                    if (wpIdx[0] >= path.size()) {
                        recalcIn[0] = 0;
                        return;
                    }
                    wp    = path.get(wpIdx[0]);
                    wpCX  = wp.x() + 0.5;
                    wpCZ  = wp.z() + 0.5;
                    wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                }

                // в”Җв”Җ Face the waypoint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double dx = wpCX - botLoc.getX(), dz = wpCZ - botLoc.getZ();
                float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
                botPlayer.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);

                // в”Җв”Җ Walk / sprint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                botPlayer.setSprinting(distToTarget > SPRINT_DIST
                        || wp.type() == BotPathfinder.MoveType.PARKOUR);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);

                // в”Җв”Җ Jump / parkour в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (!botPlayer.isInWater() && !botPlayer.isInLava()) {
                    if (wp.y() > botLoc.getBlockY()) {
                        // Ascend вҖ” step-up jump
                        manager.requestNavJump(botUuid);
                    } else if (wp.type() == BotPathfinder.MoveType.PARKOUR
                            && wpXZDist >= 1.0 && wpXZDist <= 3.5) {
                        // Parkour вҖ” jump when within sprint range of the landing block.
                        // Combined with sprint=true above, this carries the bot across gaps.
                        // If the jump is missed, stuck detection recalculates.
                        manager.requestNavJump(botUuid);
                    }
                }

                // в”Җв”Җ Stuck detection (suppressed during break/place) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double moved = xzDistRaw(botLoc.getX(), botLoc.getZ(), prevX[0], prevZ[0]);
                if (moved < STUCK_THRESHOLD) {
                    if (++stuckFor[0] >= STUCK_TICKS) {
                        if (!botPlayer.isInWater() && !botPlayer.isInLava()) {
                            manager.requestNavJump(botUuid);
                        }
                        recalcIn[0] = 0;
                        stuckFor[0] = 0;
                    }
                } else {
                    stuckFor[0] = 0;
                }

                prevX[0] = botLoc.getX();
                prevZ[0] = botLoc.getZ();
            }

            // в”Җв”Җ Inner helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

            private void cleanup(@Nullable Player botPlayer) {
                manager.clearNavJump(botUuid);
                manager.unlockNavigation(botUuid);  // Re-enable head-AI
                isBreaking[0] = false; breakLoc[0] = null;
                isPlacing[0]  = false;
                if (botPlayer != null) {
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    NmsPlayerSpawner.setJumping(botPlayer, false);
                    botPlayer.setSprinting(false);
                }
                cancel();
                navTasks.remove(botUuid);
            }

            private void walkToward(Player botPlayer, Location targetLoc, double dist) {
                Location bl = botPlayer.getLocation();
                float yaw = (float) Math.toDegrees(
                        Math.atan2(-(targetLoc.getX() - bl.getX()), targetLoc.getZ() - bl.getZ()));
                botPlayer.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);
                botPlayer.setSprinting(dist > SPRINT_DIST);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);
            }

        }.runTaskTimer(plugin, 0L, 1L);

        navTasks.put(botUuid, task);
    }

    // в”Җв”Җ Patrol state machine в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Starts an indefinite patrol loop through the given waypoints.
     * The bot walks waypoint[0] вҶ’ waypoint[1] вҶ’ вҖҰ вҶ’ waypoint[N-1] вҶ’ waypoint[0] вҶ’ вҖҰ
     * using A* pathfinding between each stop.  The task runs until
     * {@link #cancelNavigation(UUID)} is called (e.g. by a new command or bot removal).
     *
     * <p>A snapshot copy of {@code waypoints} is taken at start time so
     * adding/removing entries from the source list mid-patrol has no effect
     * on the running patrol вҖ” issue a new {@code /fpp move <bot>} to pick
     * up changes.
     */
    @SuppressWarnings("unchecked")
    private void startPatrol(@NotNull Player bot, @NotNull List<Location> waypoints) {
        final UUID botUuid  = bot.getUniqueId();
        final List<Location> wps = new ArrayList<>(waypoints); // immutable snapshot

        // Lock bot for navigation вҖ” disables head-AI so it doesn't look at players
        manager.lockForNavigation(botUuid);

        // в”Җв”Җ Mutable patrol state в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final int[]    wpSetIdx = {0};                   // index into wps[]
        final List<BotPathfinder.Move>[] pathRef = new List[]{null};
        final int[]    wpIdx    = {0};
        final int[]    recalcIn = {0};
        final int[]    stuckFor = {0};
        final double[] prevX    = {bot.getLocation().getX()};
        final double[] prevZ    = {bot.getLocation().getZ()};
        final int[]    failedRecalcs = {0};  // Track consecutive failed pathfinds

        // в”Җв”Җ Action state: BREAK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final boolean[]  isBreaking = {false};
        final int[]      breakLeft  = {0};
        final Location[] breakLoc   = {null};

        // в”Җв”Җ Action state: PLACE в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        final boolean[] isPlacing = {false};
        final int[]     placeLeft = {0};

        BukkitTask task = new BukkitRunnable() {
            @Override
            public void run() {
                Player botPlayer = Bukkit.getPlayer(botUuid);
                if (botPlayer == null || !botPlayer.isOnline()) { cleanup(null); return; }

                Location botLoc = botPlayer.getLocation();
                Location dest   = wps.get(wpSetIdx[0]);

                // Cancel patrol if bot is in different world (e.g., teleported away)
                if (!botLoc.getWorld().equals(dest.getWorld())) {
                    cleanup(botPlayer);
                    return;
                }

                double distToDest = xzDist(botLoc, dest);

                // в”Җв”Җ Arrived at current waypoint вҶ’ advance to next в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (distToDest <= PATROL_ARRIVE_DIST) {
                    wpSetIdx[0] = (wpSetIdx[0] + 1) % wps.size();
                    pathRef[0]    = null;
                    wpIdx[0]      = 0;
                    recalcIn[0]   = 0;
                    stuckFor[0]   = 0;
                    isBreaking[0] = false; breakLoc[0] = null;
                    isPlacing[0]  = false;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    return;
                }

                // в”Җв”Җ Path recalculation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                boolean pathExhausted = (pathRef[0] == null || wpIdx[0] >= pathRef[0].size());
                boolean heartbeat     = (--recalcIn[0] <= 0);

                if (pathExhausted || heartbeat) {
                    recalcIn[0]   = RECALC_INTERVAL;
                    isBreaking[0] = false; breakLoc[0] = null;
                    isPlacing[0]  = false;

                    BotPathfinder.PathOptions opts = new BotPathfinder.PathOptions(
                            Config.pathfindingParkour(),
                            Config.pathfindingBreakBlocks(),
                            Config.pathfindingPlaceBlocks());

                    List<BotPathfinder.Move> newPath = BotPathfinder.findPathMoves(
                            botLoc.getWorld(),
                            botLoc.getBlockX(), botLoc.getBlockY(), botLoc.getBlockZ(),
                            dest.getBlockX(),   dest.getBlockY(),   dest.getBlockZ(),
                            opts);

                    if (newPath == null) {
                        failedRecalcs[0]++;
                        // Skip unreachable waypoints after 10 failed attempts
                        if (failedRecalcs[0] >= 10) {
                            wpSetIdx[0] = (wpSetIdx[0] + 1) % wps.size();
                            failedRecalcs[0] = 0;
                            pathRef[0]    = null;
                            wpIdx[0]      = 0;
                            stuckFor[0]   = 0;
                            return;
                        }
                    } else {
                        failedRecalcs[0] = 0;
                    }

                    pathRef[0]  = newPath;
                    wpIdx[0]    = (newPath != null && newPath.size() > 1) ? 1 : 0;
                    stuckFor[0] = 0;
                }

                // в”Җв”Җ Fallback: direct walk when no A* path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                List<BotPathfinder.Move> path = pathRef[0];
                if (path == null || path.isEmpty() || wpIdx[0] >= path.size()) {
                    walkToward(botPlayer, dest, distToDest);
                    return;
                }

                BotPathfinder.Move wp = path.get(wpIdx[0]);
                double wpCX = wp.x() + 0.5, wpCZ = wp.z() + 0.5;

                // в”Җв”Җ BREAK action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.BREAK) {
                    if (!isBreaking[0]) {
                        Location blk = findBreakTarget(botLoc, wp);
                        if (blk != null) {
                            isBreaking[0] = true;
                            breakLeft[0]  = BREAK_TICKS;
                            breakLoc[0]   = blk;
                        } else {
                            recalcIn[0] = 0;
                            return;
                        }
                    }
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    botPlayer.setSprinting(false);
                    Location blk = breakLoc[0];
                    if (blk != null) {
                        double bdx = blk.getX() - botLoc.getX();
                        double bdz = blk.getZ() - botLoc.getZ();
                        double bdy = blk.getY() - botLoc.getY();
                        float bYaw   = (float) Math.toDegrees(Math.atan2(-bdx, bdz));
                        float bPitch = (float) -Math.toDegrees(Math.atan2(bdy,
                                Math.sqrt(bdx * bdx + bdz * bdz)));
                        botPlayer.setRotation(bYaw, bPitch);
                        NmsPlayerSpawner.setHeadYaw(botPlayer, bYaw);
                    }
                    if (--breakLeft[0] <= 0) {
                        if (breakLoc[0] != null) { breakLoc[0].getBlock().breakNaturally(); breakLoc[0] = null; }
                        isBreaking[0] = false;
                        recalcIn[0]   = 0;
                        stuckFor[0]   = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ();
                    return;
                }

                // в”Җв”Җ PLACE action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.PLACE) {
                    if (!isPlacing[0]) { isPlacing[0] = true; placeLeft[0] = PLACE_TICKS; }
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    botPlayer.setSprinting(false);
                    double pdx = (wp.x() + 0.5) - botLoc.getX();
                    double pdz = (wp.z() + 0.5) - botLoc.getZ();
                    float pYaw = (float) Math.toDegrees(Math.atan2(-pdx, pdz));
                    botPlayer.setRotation(pYaw, 70f);
                    NmsPlayerSpawner.setHeadYaw(botPlayer, pYaw);
                    if (--placeLeft[0] <= 0) {
                        Block gapBlock = botPlayer.getWorld().getBlockAt(wp.x(), wp.y() - 1, wp.z());
                        if (gapBlock.isPassable()) gapBlock.setType(resolvePlaceMaterial());
                        isPlacing[0] = false;
                        recalcIn[0]  = 0;
                        stuckFor[0]  = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ();
                    return;
                }

                // в”Җв”Җ Waypoint advance в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                boolean wpYClose = Math.abs(botLoc.getY() - wp.y()) < 1.2;

                if (wpXZDist < WP_ARRIVE_XZ && wpYClose) {
                    wpIdx[0]++;
                    if (wpIdx[0] >= path.size()) { recalcIn[0] = 0; return; }
                    wp       = path.get(wpIdx[0]);
                    wpCX     = wp.x() + 0.5;
                    wpCZ     = wp.z() + 0.5;
                    wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                }

                // в”Җв”Җ Face the waypoint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double dx = wpCX - botLoc.getX(), dz = wpCZ - botLoc.getZ();
                float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
                botPlayer.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);

                // в”Җв”Җ Walk / sprint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                botPlayer.setSprinting(distToDest > SPRINT_DIST
                        || wp.type() == BotPathfinder.MoveType.PARKOUR);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);

                // в”Җв”Җ Jump / parkour в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (!botPlayer.isInWater() && !botPlayer.isInLava()) {
                    if (wp.y() > botLoc.getBlockY()) {
                        manager.requestNavJump(botUuid);
                    } else if (wp.type() == BotPathfinder.MoveType.PARKOUR
                            && wpXZDist >= 1.0 && wpXZDist <= 3.5) {
                        manager.requestNavJump(botUuid);
                    }
                }

                // в”Җв”Җ Stuck detection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double moved = xzDistRaw(botLoc.getX(), botLoc.getZ(), prevX[0], prevZ[0]);
                if (moved < STUCK_THRESHOLD) {
                    if (++stuckFor[0] >= STUCK_TICKS) {
                        if (!botPlayer.isInWater() && !botPlayer.isInLava())
                            manager.requestNavJump(botUuid);
                        recalcIn[0] = 0;
                        stuckFor[0] = 0;
                    }
                } else {
                    stuckFor[0] = 0;
                }

                prevX[0] = botLoc.getX();
                prevZ[0] = botLoc.getZ();
            }

            private void cleanup(@Nullable Player botPlayer) {
                manager.clearNavJump(botUuid);
                manager.unlockNavigation(botUuid);  // Re-enable head-AI
                isBreaking[0] = false; breakLoc[0] = null;
                isPlacing[0]  = false;
                if (botPlayer != null) {
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    NmsPlayerSpawner.setJumping(botPlayer, false);
                    botPlayer.setSprinting(false);
                }
                cancel();
                navTasks.remove(botUuid);
            }

            private void walkToward(Player botPlayer, Location targetLoc, double dist) {
                Location bl = botPlayer.getLocation();
                float yaw = (float) Math.toDegrees(
                        Math.atan2(-(targetLoc.getX() - bl.getX()), targetLoc.getZ() - bl.getZ()));
                botPlayer.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);
                botPlayer.setSprinting(dist > SPRINT_DIST);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);
            }

        }.runTaskTimer(plugin, 0L, 1L);

        navTasks.put(botUuid, task);
    }

    // в”Җв”Җ Break / Place helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Finds the first non-passable block in the direct path from bot to the BREAK waypoint.

        manager.lockForNavigation(botUuid);

        final List<BotPathfinder.Move>[] pathRef = new List[]{null};
        final int[]      wpIdx     = {0};
        final int[]      recalcIn  = {0};
        final int[]      stuckFor  = {0};
        final double[]   prevX     = {bot.getLocation().getX()};
        final double[]   prevZ     = {bot.getLocation().getZ()};

        final boolean[]  isBreaking = {false};
        final int[]      breakLeft  = {0};
        final Location[] breakLoc   = {null};

        final boolean[]  isPlacing  = {false};
        final int[]      placeLeft  = {0};

        BukkitTask task = new BukkitRunnable() {
            @Override
            public void run() {
                Player botPlayer = Bukkit.getPlayer(botUuid);
                if (botPlayer == null || !botPlayer.isOnline()) { cleanup(null); return; }
                if (destSnapshot.getWorld() == null
                        || !botPlayer.getWorld().equals(destSnapshot.getWorld())) {
                    cleanup(botPlayer); return;
                }

                Location botLoc     = botPlayer.getLocation();
                double   distToDest = xzDist(botLoc, destSnapshot);

                // Arrived вҖ” stop
                if (distToDest <= ARRIVAL_DIST) { cleanup(botPlayer); return; }

                // Path recalculation
                boolean pathExhausted = (pathRef[0] == null || wpIdx[0] >= pathRef[0].size());
                if (pathExhausted || --recalcIn[0] <= 0) {
                    recalcIn[0]   = RECALC_INTERVAL;
                    isBreaking[0] = false; breakLoc[0] = null;
                    isPlacing[0]  = false;
                    BotPathfinder.PathOptions opts = new BotPathfinder.PathOptions(
                            Config.pathfindingParkour(),
                            Config.pathfindingBreakBlocks(),
                            Config.pathfindingPlaceBlocks());
                    List<BotPathfinder.Move> newPath = BotPathfinder.findPathMoves(
                            botLoc.getWorld(),
                            botLoc.getBlockX(), botLoc.getBlockY(), botLoc.getBlockZ(),
                            destSnapshot.getBlockX(), destSnapshot.getBlockY(), destSnapshot.getBlockZ(),
                            opts);
                    pathRef[0]  = newPath;
                    wpIdx[0]    = (newPath != null && newPath.size() > 1) ? 1 : 0;
                    stuckFor[0] = 0;
                }

                List<BotPathfinder.Move> path = pathRef[0];
                if (path == null || path.isEmpty() || wpIdx[0] >= path.size()) {
                    walkToward(botPlayer, destSnapshot, distToDest); return;
                }

                BotPathfinder.Move wp  = path.get(wpIdx[0]);
                double wpCX = wp.x() + 0.5, wpCZ = wp.z() + 0.5;

                // в”Җв”Җ BREAK action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.BREAK) {
                    if (!isBreaking[0]) {
                        Location blk = findBreakTarget(botLoc, wp);
                        if (blk != null) { isBreaking[0] = true; breakLeft[0] = BREAK_TICKS; breakLoc[0] = blk; }
                        else { recalcIn[0] = 0; return; }
                    }
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f); botPlayer.setSprinting(false);
                    Location blk = breakLoc[0];
                    if (blk != null) {
                        double bdx = blk.getX()-botLoc.getX(), bdz = blk.getZ()-botLoc.getZ(),
                               bdy = blk.getY()-botLoc.getY();
                        float bYaw   = (float) Math.toDegrees(Math.atan2(-bdx, bdz));
                        float bPitch = (float) -Math.toDegrees(Math.atan2(bdy, Math.sqrt(bdx*bdx+bdz*bdz)));
                        botPlayer.setRotation(bYaw, bPitch); NmsPlayerSpawner.setHeadYaw(botPlayer, bYaw);
                    }
                    if (--breakLeft[0] <= 0) {
                        if (breakLoc[0] != null) { breakLoc[0].getBlock().breakNaturally(); breakLoc[0] = null; }
                        isBreaking[0] = false; recalcIn[0] = 0; stuckFor[0] = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ(); return;
                }

                // в”Җв”Җ PLACE action в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (wp.type() == BotPathfinder.MoveType.PLACE) {
                    if (!isPlacing[0]) { isPlacing[0] = true; placeLeft[0] = PLACE_TICKS; }
                    stuckFor[0] = 0;
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f); botPlayer.setSprinting(false);
                    double pdx = (wp.x()+0.5)-botLoc.getX(), pdz = (wp.z()+0.5)-botLoc.getZ();
                    float pYaw = (float) Math.toDegrees(Math.atan2(-pdx, pdz));
                    botPlayer.setRotation(pYaw, 70f); NmsPlayerSpawner.setHeadYaw(botPlayer, pYaw);
                    if (--placeLeft[0] <= 0) {
                        Block gapBlock = botPlayer.getWorld().getBlockAt(wp.x(), wp.y()-1, wp.z());
                        if (gapBlock.isPassable()) gapBlock.setType(resolvePlaceMaterial());
                        isPlacing[0] = false; recalcIn[0] = 0; stuckFor[0] = 0;
                    }
                    prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ(); return;
                }

                // в”Җв”Җ Waypoint advance в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double  wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                boolean wpYClose = Math.abs(botLoc.getY() - wp.y()) < 1.2;
                if (wpXZDist < WP_ARRIVE_XZ && wpYClose) {
                    wpIdx[0]++;
                    if (wpIdx[0] >= path.size()) { recalcIn[0] = 0; return; }
                    wp       = path.get(wpIdx[0]);
                    wpCX     = wp.x() + 0.5; wpCZ = wp.z() + 0.5;
                    wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                }

                // в”Җв”Җ Face + move в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double dx = wpCX - botLoc.getX(), dz = wpCZ - botLoc.getZ();
                float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
                botPlayer.setRotation(yaw, 0f); NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);
                botPlayer.setSprinting(distToDest > SPRINT_DIST || wp.type() == BotPathfinder.MoveType.PARKOUR);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);

                // в”Җв”Җ Jump в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (!botPlayer.isInWater() && !botPlayer.isInLava()) {
                    if (wp.y() > botLoc.getBlockY()) {
                        manager.requestNavJump(botUuid);
                    } else if (wp.type() == BotPathfinder.MoveType.PARKOUR
                            && wpXZDist >= 1.0 && wpXZDist <= 3.5) {
                        manager.requestNavJump(botUuid);
                    }
                }

                // в”Җв”Җ Stuck detection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double moved = xzDistRaw(botLoc.getX(), botLoc.getZ(), prevX[0], prevZ[0]);
                if (moved < STUCK_THRESHOLD) {
                    if (++stuckFor[0] >= STUCK_TICKS) {
                        if (!botPlayer.isInWater() && !botPlayer.isInLava()) manager.requestNavJump(botUuid);
                        recalcIn[0] = 0; stuckFor[0] = 0;
                    }
                } else { stuckFor[0] = 0; }

                prevX[0] = botLoc.getX(); prevZ[0] = botLoc.getZ();
            }

            private void cleanup(@Nullable Player botPlayer) {
                manager.clearNavJump(botUuid);
                manager.unlockNavigation(botUuid);
                isBreaking[0] = false; breakLoc[0] = null;
                isPlacing[0]  = false;
                if (botPlayer != null) {
                    NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
                    NmsPlayerSpawner.setJumping(botPlayer, false);
                    botPlayer.setSprinting(false);
                }
                cancel();
                navTasks.remove(botUuid);
            }

            private void walkToward(Player botPlayer, Location targetLoc, double dist) {
                Location bl = botPlayer.getLocation();
                float yaw = (float) Math.toDegrees(
                        Math.atan2(-(targetLoc.getX()-bl.getX()), targetLoc.getZ()-bl.getZ()));
                botPlayer.setRotation(yaw, 0f); NmsPlayerSpawner.setHeadYaw(botPlayer, yaw);
                botPlayer.setSprinting(dist > SPRINT_DIST);
                NmsPlayerSpawner.setMovementForward(botPlayer, 1.0f);
            }

        }.runTaskTimer(plugin, 0L, 1L);

        navTasks.put(botUuid, task);
    }

    // в”Җв”Җ Break / Place helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Finds the first non-passable block in the direct path from bot to the BREAK waypoint.
     * Checks, in order: destination feet, destination head, source head (for ascend-break).
     */
    @Nullable
    private static Location findBreakTarget(Location botLoc, BotPathfinder.Move wp) {
        org.bukkit.World w = botLoc.getWorld();
        int wx = wp.x(), wy = wp.y(), wz = wp.z();

        // Destination feet
        if (!w.getBlockAt(wx, wy, wz).isPassable())
            return new Location(w, wx + 0.5, wy + 0.5, wz + 0.5);

        // Destination head
        if (!w.getBlockAt(wx, wy + 1, wz).isPassable())
            return new Location(w, wx + 0.5, wy + 1.5, wz + 0.5);

        // Source head (ascend-break: can't step up because y+2 is blocked)
        int by = botLoc.getBlockY();
        int bx = botLoc.getBlockX(), bz = botLoc.getBlockZ();
        if (!w.getBlockAt(bx, by + 2, bz).isPassable())
            return new Location(w, bx + 0.5, by + 2.5, bz + 0.5);

        return null;
    }

    /**
     * Returns the material to use when placing a bridge block.
     * Falls back to DIRT if the configured value is invalid.
     */
    private Material resolvePlaceMaterial() {
        String raw = Config.pathfindingPlaceMaterial();
        Material mat = Material.matchMaterial(raw.toUpperCase());
        if (mat != null && mat.isBlock() && mat.isSolid()) return mat;
        return Material.DIRT;
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static double xzDist(Location a, Location b) {
        return xzDistRaw(a.getX(), a.getZ(), b.getX(), b.getZ());
    }

    private static double xzDistRaw(double ax, double az, double bx, double bz) {
        double dx = ax - bx, dz = az - bz;
        return Math.sqrt(dx * dx + dz * dz);
    }

    /**
     * Cancels the active navigation task for a bot and fully releases all navigation state:
     * nav-jump, navigation lock (re-enables head-AI), and movement inputs.
     * Safe to call even when no task is running.
     */
    private void cancelNavigation(@NotNull UUID botUuid) {
        BukkitTask t = navTasks.remove(botUuid);
        if (t != null && !t.isCancelled()) t.cancel();
        // Release navigation lock so head-AI resumes and the bot stops moving.
        manager.clearNavJump(botUuid);
        manager.unlockNavigation(botUuid);
        Player botPlayer = Bukkit.getPlayer(botUuid);
        if (botPlayer != null) {
            NmsPlayerSpawner.setMovementForward(botPlayer, 0f);
            NmsPlayerSpawner.setJumping(botPlayer, false);
            botPlayer.setSprinting(false);
        }
    }

    /** Cancels all active navigation tasks. Called from {@code onDisable}. */
    public void cancelAll() {
        new ArrayList<>(navTasks.keySet()).forEach(this::cancelNavigation);
    }

    /**
     * Cleans up all navigation state for a specific bot.
     * Call this when a bot is despawned/deleted to prevent memory leaks.
     *
     * @param botUuid the bot's UUID
     */
    public void cleanupBot(@NotNull UUID botUuid) {
        cancelNavigation(botUuid);
    }

    // в”Җв”Җ Tab-complete в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        List<String> out = new ArrayList<>();
        if (args.length == 1) {
            String in = args[0].toLowerCase();
            for (FakePlayer fp : manager.getActivePlayers())
                if (fp.getName().toLowerCase().startsWith(in)) out.add(fp.getName());
        } else if (args.length == 2) {
            String in = args[1].toLowerCase();
            // Flag options
            for (String flag : List.of("--wp", "--stop"))
                if (flag.startsWith(in)) out.add(flag);
            // Online player names (for player-follow mode)
            for (Player p : Bukkit.getOnlinePlayers())
                if (p.getName().toLowerCase().startsWith(in)) out.add(p.getName());
        } else if (args.length == 3 && args[1].equalsIgnoreCase("--wp")) {
            // Suggest known waypoint names
            if (waypointStore != null) {
                String in = args[2].toLowerCase();
                for (String name : waypointStore.getNames())
                    if (name.startsWith(in)) out.add(name);
            }
        }
        return out;
    }
}

package me.bill.fakePlayerPlugin.fakeplayer;

import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.util.FppLogger;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.entity.Player;
import org.bukkit.plugin.Plugin;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.nio.charset.StandardCharsets;
import java.util.UUID;

/**
 * NMS-based fake player spawner using reflection (version-independent).
 * Creates real NMS ServerPlayer entities that appear as genuine players.
 *
 * <p><b>Architecture:</b> Uses reflection to access NMS classes without direct imports,
 * making it compatible across Paper versions. Creates a true {@code ServerPlayer} instance
 * that bypasses Mojang authentication.
 *
 * <p><b>Auth bypass:</b> The player is created directly in JVM memory without a TCP connection,
 * so the Mojang session server handshake is never triggered.
 */
public final class NmsPlayerSpawner {

    private static boolean initialized = false;
    private static boolean failed = false;

    // Cached classes
    private static Class<?> minecraftServerClass;
    private static Class<?> serverLevelClass;
    private static Class<?> serverPlayerClass;
    private static Class<?> gameProfileClass;
    private static Class<?> clientInformationClass;
    private static Class<?> commonListenerCookieClass;
    private static Class<?> connectionClass;
    private static Class<?> serverGamePacketListenerClass;
    private static Class<?> chatVisibilityClass;
    private static Class<?> humanoidArmClass;
    private static Class<?> particleStatusClass;
    private static Class<?> playerListClass;

    // Cached methods
    private static Method getServerMethod;
    private static Method getHandleMethod;
    private static Method craftPlayerGetHandleMethod; // CraftPlayer.getHandle() вҶ’ NMS ServerPlayer
    private static Method getPlayerListMethod;
    private static Method placeNewPlayerMethod;
    private static Method setPosMethod;

    // Cached constructors  
    private static Constructor<?> gameProfileConstructor;
    private static Constructor<?> serverPlayerConstructor;
    private static Constructor<?> clientInformationConstructor;
    private static Constructor<?> commonListenerCookieConstructor;
    private static Constructor<?> serverGamePacketListenerConstructor;

    // Cached enum values
    private static Object chatVisibilityHidden;
    private static Object humanoidArmRight;
    private static Object particleStatusAll;

    private NmsPlayerSpawner() {}

    /**
     * Initialize NMS reflection. Safe to call multiple times.
     */
    private static synchronized void init() {
        if (initialized || failed) return;

        try {
            // Get CraftBukkit version (or detect Mojang-mapped Paper)
            String packageName = Bukkit.getServer().getClass().getPackage().getName();
            String version = packageName.substring(packageName.lastIndexOf('.') + 1);

            // On Mojang-mapped Paper, classes are in org.bukkit.craftbukkit directly (no version)
            String craftBukkitPackage = "org.bukkit.craftbukkit";
            if (!version.equals("craftbukkit")) {
                // Legacy/Spigot: org.bukkit.craftbukkit.v1_XX_RX
                craftBukkitPackage += "." + version;
            }

            FppLogger.debug("Detected CraftBukkit package: " + craftBukkitPackage);

            // Load CraftBukkit classes
            Class<?> craftServerClass = Class.forName(craftBukkitPackage + ".CraftServer");
            Class<?> craftWorldClass = Class.forName(craftBukkitPackage + ".CraftWorld");

            // Get NMS class loader
            ClassLoader nmsLoader = craftServerClass.getClassLoader();

            // Try Mojang-mapped names first, fall back to Spigot names
            // Load critical classes first (these determine Mojang vs Spigot)
            try {
                serverPlayerClass = nmsLoader.loadClass("net.minecraft.server.level.ServerPlayer");
                // If ServerPlayer loads, we're on Mojang mappings
                minecraftServerClass = nmsLoader.loadClass("net.minecraft.server.MinecraftServer");
                serverLevelClass = nmsLoader.loadClass("net.minecraft.server.level.ServerLevel");
                FppLogger.debug("Using Mojang-mapped NMS classes");
            } catch (ClassNotFoundException e) {
                // Fall back to Spigot-mapped names
                FppLogger.info("Mojang mappings not found, trying Spigot mappings...");
                minecraftServerClass = nmsLoader.loadClass("net.minecraft.server.MinecraftServer");
                serverLevelClass = nmsLoader.loadClass("net.minecraft.server.level.WorldServer");
                serverPlayerClass = nmsLoader.loadClass("net.minecraft.server.level.EntityPlayer");
                FppLogger.debug("Loaded Spigot-mapped NMS classes");
            }

            // Load optional classes individually (don't fail init if any are missing)
            try {
                clientInformationClass = nmsLoader.loadClass("net.minecraft.server.level.ClientInformation");
                FppLogger.debug("вң“ Loaded ClientInformation class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("вң— ClientInformation class not found: " + e.getMessage());
            }

            try {
                chatVisibilityClass = nmsLoader.loadClass("net.minecraft.world.entity.player.ChatVisiblity");  // Note: typo in MC code
                FppLogger.debug("вң“ Loaded ChatVisiblity class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("вң— ChatVisiblity class not found: " + e.getMessage());
            }

            try {
                humanoidArmClass = nmsLoader.loadClass("net.minecraft.world.entity.HumanoidArm");
                FppLogger.debug("вң“ Loaded HumanoidArm class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("вң— HumanoidArm class not found: " + e.getMessage());
            }

            // Try multiple possible locations for ParticleStatus
            String[] particleStatusPaths = {
                "net.minecraft.world.level.GameRules$ParticleStatus",
                "net.minecraft.world.entity.player.ParticleStatus",
                "net.minecraft.core.particles.ParticleStatus",
                "net.minecraft.server.level.ParticleStatus"
            };

            for (String path : particleStatusPaths) {
                try {
                    particleStatusClass = nmsLoader.loadClass(path);
                    FppLogger.debug("вң“ Loaded ParticleStatus class from: " + path);
                    break;
                } catch (ClassNotFoundException e) {
                    FppLogger.debug("вң— ParticleStatus not found at: " + path);
                }
            }

            if (particleStatusClass == null) {
                FppLogger.debug("вң— ParticleStatus class not found in any known location");
            }

            // Load other optional classes (currently unused but may be needed for future features)
            try {
                commonListenerCookieClass = nmsLoader.loadClass("net.minecraft.server.network.CommonListenerCookie");
                connectionClass = nmsLoader.loadClass("net.minecraft.network.Connection");
                serverGamePacketListenerClass = nmsLoader.loadClass("net.minecraft.server.network.ServerGamePacketListenerImpl");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("Some optional network classes not available: " + e.getMessage());
            }

            // Load authlib (should be on classpath)
            gameProfileClass = Class.forName("com.mojang.authlib.GameProfile");

            // Cache methods
            getServerMethod = craftServerClass.getMethod("getServer");
            getHandleMethod = craftWorldClass.getMethod("getHandle");
            getPlayerListMethod = minecraftServerClass.getMethod("getPlayerList");

            // Find setPos method (various signatures across versions)
            for (Method m : serverPlayerClass.getMethods()) {
                if (m.getName().equals("setPos") && m.getParameterCount() == 3) {
                    Class<?>[] params = m.getParameterTypes();
                    if (params[0] == double.class && params[1] == double.class && params[2] == double.class) {
                        setPosMethod = m;
                        break;
                    }
                }
            }

            // Cache constructors
            gameProfileConstructor = gameProfileClass.getConstructor(UUID.class, String.class);

            // Cache CraftPlayer.getHandle() for setPosition() use
            Class<?> craftPlayerClass = Class.forName(craftBukkitPackage + ".entity.CraftPlayer");
            craftPlayerGetHandleMethod = craftPlayerClass.getMethod("getHandle");
            craftPlayerGetHandleMethod.setAccessible(true);

            initialized = true;
            FppLogger.info("NMS reflection initialized successfully");

        } catch (Exception e) {
            failed = true;
            FppLogger.error("Failed to initialize NMS reflection: " + e.getMessage());
            e.printStackTrace();
        }
    }

    /**
     * Check if NMS spawning is available.
     */
    public static boolean isAvailable() {
        if (!initialized && !failed) init();
        return initialized;
    }

    /**
     * Spawn a fake NMS ServerPlayer at the given location.
     *
     * <p><b>IMPORTANT:</b> This method creates the ServerPlayer with the bot's REAL name
     * (e.g., "BotName"), not the packet profile name (e.g., "{00_BotName").
     * The packet profile name with the sorting prefix is only used in tab-list packets
     * sent via {@code PacketHelper}, not in the actual NMS entity.
     *
     * @param name     Bot name (REAL name, not packet profile name)
     * @param world    World to spawn in
     * @param x        X coordinate
     * @param y        Y coordinate
     * @param z        Z coordinate
     * @return         Bukkit Player wrapper, or null if spawn failed
     */
    public static Player spawnFakePlayer(String name, World world, double x, double y, double z) {
        if (!isAvailable()) {
            FppLogger.warn("NMS spawning not available, cannot spawn " + name);
            return null;
        }

        try {
            // Create deterministic UUID (offline mode formula)
            UUID uuid = UUID.nameUUIDFromBytes(
                ("OfflinePlayer:" + name).getBytes(StandardCharsets.UTF_8)
            );

            // Create GameProfile
            Object gameProfile = gameProfileConstructor.newInstance(uuid, name);

            // Get MinecraftServer
            Object craftServer = Bukkit.getServer();
            Object minecraftServer = getServerMethod.invoke(craftServer);

            // Get ServerLevel
            Object craftWorld = world;
            Object serverLevel = getHandleMethod.invoke(craftWorld);

            // Create ClientInformation (if available)
            Object clientInfo = null;
            if (clientInformationClass != null) {
                clientInfo = createClientInformation();
            }

            // Create ServerPlayer
            // Constructor signature varies by version, try multiple approaches
            Object serverPlayer = createServerPlayer(minecraftServer, serverLevel, gameProfile, clientInfo);

            if (serverPlayer == null) {
                FppLogger.warn("Failed to create ServerPlayer for " + name);
                return null;
            }

            // Set position BEFORE adding to world
            if (setPosMethod != null) {
                setPosMethod.invoke(serverPlayer, x, y, z);
            }

            // CRITICAL: set up a fake network connection BEFORE adding to world.
            // ServerPlayer.tick() immediately calls this.connection.tickClientLoadTimeout(),
            // so connection must be non-null or the server crashes on the next tick.
            setupFakeConnection(minecraftServer, serverPlayer, gameProfile, clientInfo);

            // Add the ServerPlayer to the world via PlayerList.placeNewPlayer(),
            // which properly registers the player, fires join events, and sends
            // spawn packets to nearby players so they can see the bot.
            boolean addedViaPlayerList = false;
            try {
                Object playerList = getPlayerListMethod.invoke(minecraftServer);
                // placeNewPlayer(Connection, ServerPlayer, CommonListenerCookie)
                // The Connection is already set inside setupFakeConnection;
                // retrieve it from the player's connection field.
                Object sgpl = getConnectionField(serverPlayer);
                if (sgpl != null && commonListenerCookieClass != null) {
                    // Extract the Connection from the ServerGamePacketListenerImpl
                    Object conn = getConnectionFromSgpl(sgpl);
                    Object cookie = createCookieDynamic(gameProfile, clientInfo);
                    if (conn != null && cookie != null) {
                        Method placeMethod = findMethod(playerList.getClass(), "placeNewPlayer", 3);
                        if (placeMethod != null) {
                            placeMethod.setAccessible(true);
                            placeMethod.invoke(playerList, conn, serverPlayer, cookie);
                            addedViaPlayerList = true;
                            FppLogger.debug("Added ServerPlayer via PlayerList.placeNewPlayer()");
                        }
                    }
                }
            } catch (Exception e) {
                FppLogger.debug("placeNewPlayer failed (" + e.getMessage() + "), trying addNewPlayer fallback");
            }

            // Fallback: add directly to the ServerLevel entity list
            if (!addedViaPlayerList) {
                try {
                    Method addMethod = findMethod(serverLevel.getClass(), "addNewPlayer", 1);
                    if (addMethod != null) {
                        addMethod.setAccessible(true);
                        addMethod.invoke(serverLevel, serverPlayer);
                        FppLogger.debug("Added ServerPlayer via ServerLevel.addNewPlayer()");
                    }
                } catch (Exception e) {
                    FppLogger.debug("addNewPlayer also failed: " + e.getMessage());
                }
            }

            // Restore position after placeNewPlayer (it may have teleported to spawn)
            if (setPosMethod != null) {
                setPosMethod.invoke(serverPlayer, x, y, z);
            }

            // Get Bukkit wrapper
            Method getBukkitEntityMethod = serverPlayerClass.getMethod("getBukkitEntity");
            Object bukkitEntity = getBukkitEntityMethod.invoke(serverPlayer);

            if (bukkitEntity instanceof Player) {
                Player result = (Player) bukkitEntity;

                // placeNewPlayer() may have reset the game mode to the server default
                // (often CREATIVE or ADVENTURE on test servers).  Force SURVIVAL so:
                //  вҖў Mobs can target the bot (spectator/creative players are ignored)
                //  вҖў Drowning works (creative players are immune)
                //  вҖў Fall damage fires (creative players take no fall damage)
                //  вҖў All other survival-specific mechanics work correctly
                result.setGameMode(org.bukkit.GameMode.SURVIVAL);

                FppLogger.info("NMS ServerPlayer spawned: " + name + " (UUID: " + result.getUniqueId() + ")");
                return result;
            }

            return null;

        } catch (Exception e) {
            FppLogger.error("Failed to spawn fake player " + name + ": " + e.getMessage());
            e.printStackTrace();
            return null;
        }
    }

    private static Object createClientInformation() {
        try {
            // Verify critical classes are loaded
            if (chatVisibilityClass == null || humanoidArmClass == null) {
                FppLogger.warn("Required classes not loaded for ClientInformation");
                return null;
            }

            if (clientInformationConstructor == null) {
                // Find the 9-parameter constructor and extract the actual ParticleStatus class
                Constructor<?>[] constructors = clientInformationClass.getConstructors();
                for (Constructor<?> ctor : constructors) {
                    if (ctor.getParameterCount() == 9) {
                        Class<?>[] params = ctor.getParameterTypes();
                        particleStatusClass = params[8]; // 9th parameter (ParticleStatus)

                        // Get the constructor with the discovered class
                        clientInformationConstructor = clientInformationClass.getConstructor(
                            String.class, int.class, chatVisibilityClass, boolean.class,
                            int.class, humanoidArmClass, boolean.class, boolean.class,
                            particleStatusClass
                        );

                        // Cache enum values
                        chatVisibilityHidden = chatVisibilityClass.getEnumConstants()[2]; // HIDDEN
                        humanoidArmRight = humanoidArmClass.getEnumConstants()[1]; // RIGHT
                        particleStatusAll = particleStatusClass.getEnumConstants()[0]; // ALL

                        FppLogger.debug("ClientInformation constructor cached (ParticleStatus: " + particleStatusClass.getSimpleName() + ")");
                        break;
                    }
                }

                if (clientInformationConstructor == null) {
                    FppLogger.warn("Could not find 9-parameter ClientInformation constructor");
                    return null;
                }
            }

            return clientInformationConstructor.newInstance(
                "en", 2, chatVisibilityHidden, true, 0, humanoidArmRight, false, false, particleStatusAll
            );
        } catch (Exception e) {
            FppLogger.warn("Failed to create ClientInformation: " + e.getMessage());
            return null;
        }
    }

    private static Object createServerPlayer(Object minecraftServer, Object serverLevel, 
                                             Object gameProfile, Object clientInfo) {
        try {
            // Try modern constructor (1.19+): ServerPlayer(MinecraftServer, ServerLevel, GameProfile, ClientInformation)
            if (clientInfo != null) {
                try {
                    serverPlayerConstructor = serverPlayerClass.getConstructor(
                        minecraftServerClass, serverLevelClass, gameProfileClass, clientInformationClass
                    );
                    return serverPlayerConstructor.newInstance(minecraftServer, serverLevel, gameProfile, clientInfo);
                } catch (NoSuchMethodException e) {
                    FppLogger.debug("4-arg ServerPlayer constructor not found, trying 3-arg");
                }
            }

            // Try older constructor: ServerPlayer(MinecraftServer, ServerLevel, GameProfile)
            try {
                serverPlayerConstructor = serverPlayerClass.getConstructor(
                    minecraftServerClass, serverLevelClass, gameProfileClass
                );
                return serverPlayerConstructor.newInstance(minecraftServer, serverLevel, gameProfile);
            } catch (NoSuchMethodException e) {
                FppLogger.warn("No compatible ServerPlayer constructor found");
            }

            return null;

        } catch (Exception e) {
            FppLogger.error("Failed to create ServerPlayer instance: " + e.getMessage());
            return null;
        }
    }

    /**
     * Creates a fake network connection backed by a Netty {@link io.netty.channel.embedded.EmbeddedChannel}
     * and wires it into a new {@code ServerGamePacketListenerImpl} assigned to {@code serverPlayer.connection}.
     *
     * <p><b>Why EmbeddedChannel?</b>  {@code EmbeddedChannel} is always open ({@code isOpen()} == {@code true}),
     * so {@code Connection.isConnected()} returns {@code true} and the server never removes the bot on a
     * perceived connection loss.  Any packets "sent" to the channel are stored in Netty's outbound
     * buffer without triggering encoder exceptions вҖ” no real network I/O occurs.
     *
     * <p><b>Dummy socket address:</b>  {@code Connection.handleDisconnection()} calls
     * {@code this.address.getAddress()} and NPEs if address is {@code null}.  We inject a dummy
     * {@code InetSocketAddress} to prevent this crash when the bot is kicked.
     * 
     * <p><b>Null Promise Fix:</b> Overrides Connection methods to handle null promises gracefully.
     */
    private static void setupFakeConnection(Object minecraftServer, Object serverPlayer,
                                            Object gameProfile, Object clientInfo) {
        if (connectionClass == null || commonListenerCookieClass == null
                || serverGamePacketListenerClass == null) {
            FppLogger.debug("Network classes not loaded вҖ” skipping fake connection setup");
            return;
        }
        try {
            ClassLoader nmsLoader = minecraftServerClass.getClassLoader();

            // 1. Create EmbeddedChannel - simple, no handlers needed
            Class<?> embeddedChannelClass = Class.forName("io.netty.channel.embedded.EmbeddedChannel");
            Constructor<?> embeddedChannelConstructor = embeddedChannelClass.getDeclaredConstructor();
            Object embeddedChannel = embeddedChannelConstructor.newInstance();

            // 2. PacketFlow.SERVERBOUND
            Class<?> packetFlowClass = nmsLoader.loadClass("net.minecraft.network.protocol.PacketFlow");
            Object serverbound = packetFlowClass.getEnumConstants()[0]; // SERVERBOUND

            // 3. Create Connection subclass that handles null promises gracefully
            Constructor<?> connCtor = connectionClass.getDeclaredConstructor(packetFlowClass);
            connCtor.setAccessible(true);
            Object conn = createNullSafeConnection(connCtor, serverbound, embeddedChannel);

            // 4.5. Inject a dummy InetSocketAddress so Connection.handleDisconnection()
            // does not NPE when the bot is kicked.
            for (Field f : getAllDeclaredFields(connectionClass)) {
                if (java.net.SocketAddress.class.isAssignableFrom(f.getType())) {
                    try {
                        f.setAccessible(true);
                        if (f.get(conn) == null) {
                            f.set(conn, new java.net.InetSocketAddress("127.0.0.1", 25565));
                            FppLogger.debug("Injected dummy InetSocketAddress into Connection." + f.getName());
                        }
                    } catch (Exception ignored) {}
                    break;
                }
            }

            // 5. CommonListenerCookie
            Object cookie = createCookieDynamic(gameProfile, clientInfo);
            if (cookie == null) {
                FppLogger.warn("Could not create CommonListenerCookie вҖ” fake connection incomplete");
                return;
            }

            // 6. ServerGamePacketListenerImpl(MinecraftServer, Connection, ServerPlayer, CommonListenerCookie)
            //    Its constructor sets player.connection = this automatically.
            for (Constructor<?> c : serverGamePacketListenerClass.getDeclaredConstructors()) {
                if (c.getParameterCount() == 4) {
                    c.setAccessible(true);
                    c.newInstance(minecraftServer, conn, serverPlayer, cookie);
                    FppLogger.debug("ServerGamePacketListenerImpl created; connection set on ServerPlayer");
                    return;
                }
            }
            FppLogger.warn("Could not find 4-arg ServerGamePacketListenerImpl constructor");

        } catch (Exception e) {
            FppLogger.warn("setupFakeConnection failed: " + e.getClass().getSimpleName() + ": " + e.getMessage());
        }
    }

    /**
     * Creates a Connection object that handles null promises gracefully to prevent Netty NPEs.
     */
    private static Object createNullSafeConnection(Constructor<?> connCtor, Object serverbound, Object embeddedChannel) throws Exception {
        // Create the Connection instance 
        Object conn = connCtor.newInstance(serverbound);

        // Inject EmbeddedChannel into the Connection's channel field
        for (Field f : getAllDeclaredFields(connectionClass)) {
            if (f.getType().getSimpleName().equals("Channel")) {
                f.setAccessible(true);
                f.set(conn, embeddedChannel);
                FppLogger.debug("Injected EmbeddedChannel into Connection." + f.getName());
                break;
            }
        }

        // Instead of proxy, let's override specific methods by wrapping the connection
        // First, let's try to override the problematic send/flush methods directly using reflection
        try {
            // Override the doSendPacket method to be a no-op
            Method doSendPacketMethod = findMethodInClass(connectionClass, "doSendPacket");
            if (doSendPacketMethod != null) {
                // We can't easily override methods without bytecode manipulation, 
                // so let's try a different approach - modify the channel itself
                FppLogger.debug("Found doSendPacket method, will rely on channel modification");
            }
        } catch (Exception e) {
            Config.debug("Could not find doSendPacket method: " + e.getMessage());
        }

        return conn;
    }

    /**
     * Find a method in a class or its superclasses by name.
     */
    private static Method findMethodInClass(Class<?> clazz, String methodName) {
        Class<?> current = clazz;
        while (current != null && current != Object.class) {
            for (Method method : current.getDeclaredMethods()) {
                if (method.getName().equals(methodName)) {
                    return method;
                }
            }
            current = current.getSuperclass();
        }
        return null;
    }

    /** Dynamically creates a {@code CommonListenerCookie} by iterating its constructors. */
    private static Object createCookieDynamic(Object gameProfile, Object clientInfo) {
        try {
            Constructor<?>[] ctors = commonListenerCookieClass.getDeclaredConstructors();

            // Log available constructors on first attempt (debug aids)
            FppLogger.info("CommonListenerCookie constructors (" + ctors.length + "):");
            for (Constructor<?> c : ctors) {
                StringBuilder sb = new StringBuilder("  [" + c.getParameterCount() + "] ");
                for (Class<?> p : c.getParameterTypes()) sb.append(p.getSimpleName()).append(", ");
                FppLogger.info(sb.toString());
            }

            for (Constructor<?> c : ctors) {
                c.setAccessible(true);
                Class<?>[] p = c.getParameterTypes();
                // Skip synthetic constructors added by the compiler (e.g. for records)
                if (p.length > 0 && p[p.length - 1].getSimpleName().contains("DefaultConstructorMarker")) continue;
                try {
                    switch (p.length) {
                        case 1 -> { return c.newInstance(gameProfile); }
                        case 2 -> { return c.newInstance(gameProfile, 0); }
                        case 3 -> { return c.newInstance(gameProfile, 0, clientInfo); }
                        case 4 -> { return c.newInstance(gameProfile, 0, clientInfo, false); }
                        case 5 -> { return c.newInstance(gameProfile, 0, clientInfo, false, false); }
                        case 7 -> {
                            // Paper 1.21.11+: (GameProfile, int, ClientInformation, boolean, String, Set, KeepAlive)
                            // Pass null for String (server address) and KeepAlive; empty Set for server cookies.
                            return c.newInstance(gameProfile, 0, clientInfo, false,
                                    null, java.util.Collections.emptySet(), null);
                        }
                    }
                } catch (Exception e) {
                    FppLogger.info("  вҶ’ [" + p.length + "-arg] failed: " + e.getClass().getSimpleName() + ": " + e.getMessage());
                }
            }
        } catch (Exception e) {
            FppLogger.debug("createCookieDynamic failed: " + e.getMessage());
        }
        FppLogger.warn("createCookieDynamic: no constructor worked for CommonListenerCookie");
        return null;
    }

    /** Returns the value of {@code serverPlayer.connection} (the ServerGamePacketListenerImpl). */
    private static Object getConnectionField(Object serverPlayer) {
        try {
            for (Field f : getAllDeclaredFields(serverPlayerClass)) {
                if (serverGamePacketListenerClass.isAssignableFrom(f.getType())) {
                    f.setAccessible(true);
                    return f.get(serverPlayer);
                }
            }
        } catch (Exception ignored) {}
        return null;
    }

    /** Returns the {@code Connection} object held inside a {@code ServerGamePacketListenerImpl}. */
    private static Object getConnectionFromSgpl(Object sgpl) {
        try {
            for (Field f : getAllDeclaredFields(sgpl.getClass())) {
                if (connectionClass.isAssignableFrom(f.getType())) {
                    f.setAccessible(true);
                    return f.get(sgpl);
                }
            }
        } catch (Exception ignored) {}
        return null;
    }

    /** Finds a method on a class (or its supers) by name and parameter count. */
    private static Method findMethod(Class<?> clazz, String name, int paramCount) {
        Class<?> cur = clazz;
        while (cur != null && cur != Object.class) {
            for (Method m : cur.getDeclaredMethods()) {
                if (m.getName().equals(name) && m.getParameterCount() == paramCount) {
                    m.setAccessible(true);
                    return m;
                }
            }
            cur = cur.getSuperclass();
        }
        return null;
    }

    /** Collects all declared fields from a class and all its superclasses. */
    private static java.util.List<Field> getAllDeclaredFields(Class<?> clazz) {
        java.util.List<Field> fields = new java.util.ArrayList<>();
        Class<?> cur = clazz;
        while (cur != null && cur != Object.class) {
            for (Field f : cur.getDeclaredFields()) fields.add(f);
            cur = cur.getSuperclass();
        }
        return fields;
    }

    /**
     * Directly sets the NMS entity's position via {@code Entity.setPos(x, y, z)}.
     *
     * <p>This bypasses client-authoritative movement вҖ” the entity's server-side
     * coordinates are updated immediately, and the entity tracker then broadcasts
     * the position change to all nearby players on its next update cycle.
     *
     * <p>Used by the manual physics loop in {@code BotCollisionListener} to move
     * NMS fake-player bots that have a fake (EmbeddedChannel) connection that
     * discards all outgoing packets, including velocity and position packets.
     */
    public static void setPosition(Player bot, double x, double y, double z) {
        if (!initialized || setPosMethod == null || craftPlayerGetHandleMethod == null) return;
        try {
            Object nmsPlayer = craftPlayerGetHandleMethod.invoke(bot);
            setPosMethod.invoke(nmsPlayer, x, y, z);
        } catch (Exception e) {
            FppLogger.debug("NmsPlayerSpawner.setPosition failed: " + e.getMessage());
        }
    }

    /**
     * Remove a fake player from the server.
     */
    public static void removeFakePlayer(Player player) {
        if (player == null) return;

        try {
            // Simply disconnect/remove the player
            player.kick(net.kyori.adventure.text.Component.empty());
        } catch (Exception e) {
            FppLogger.error("Failed to remove fake player: " + e.getMessage());
        }
    }
}

package me.bill.fakePlayerPlugin.fakeplayer;

import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.util.FppLogger;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.entity.Player;
import org.bukkit.plugin.Plugin;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.nio.charset.StandardCharsets;
import java.util.UUID;

/**
 * NMS-based fake player spawner using reflection (version-independent).
 * Creates real NMS ServerPlayer entities that appear as genuine players.
 *
 * <p><b>Architecture:</b> Uses reflection to access NMS classes without direct imports,
 * making it compatible across Paper versions. Creates a true {@code ServerPlayer} instance
 * that bypasses Mojang authentication.
 *
 * <p><b>Auth bypass:</b> The player is created directly in JVM memory without a TCP connection,
 * so the Mojang session server handshake is never triggered.
 */
public final class NmsPlayerSpawner {

    private static boolean initialized = false;
    private static boolean failed = false;

    // Cached classes
    private static Class<?> minecraftServerClass;
    private static Class<?> serverLevelClass;
    private static Class<?> serverPlayerClass;
    private static Class<?> gameProfileClass;
    private static Class<?> clientInformationClass;
    private static Class<?> commonListenerCookieClass;
    private static Class<?> connectionClass;
    private static Class<?> serverGamePacketListenerClass;
    private static Class<?> chatVisibilityClass;
    private static Class<?> humanoidArmClass;
    private static Class<?> particleStatusClass;
    private static Class<?> playerListClass;

    // Cached methods
    private static Method getServerMethod;
    private static Method getHandleMethod;
    private static Method craftPlayerGetHandleMethod; // CraftPlayer.getHandle() вҶ’ NMS ServerPlayer
    private static Method getPlayerListMethod;
    private static Method placeNewPlayerMethod;
    private static Method setPosMethod;

    // Cached constructors  
    private static Constructor<?> gameProfileConstructor;
    private static Constructor<?> serverPlayerConstructor;
    private static Constructor<?> clientInformationConstructor;
    private static Constructor<?> commonListenerCookieConstructor;
    private static Constructor<?> serverGamePacketListenerConstructor;

    // Cached enum values
    private static Object chatVisibilityHidden;
    private static Object humanoidArmRight;
    private static Object particleStatusAll;

    private NmsPlayerSpawner() {}

    /**
     * Initialize NMS reflection. Safe to call multiple times.
     */
    private static synchronized void init() {
        if (initialized || failed) return;

        try {
            // Get CraftBukkit version (or detect Mojang-mapped Paper)
            String packageName = Bukkit.getServer().getClass().getPackage().getName();
            String version = packageName.substring(packageName.lastIndexOf('.') + 1);

            // On Mojang-mapped Paper, classes are in org.bukkit.craftbukkit directly (no version)
            String craftBukkitPackage = "org.bukkit.craftbukkit";
            if (!version.equals("craftbukkit")) {
                // Legacy/Spigot: org.bukkit.craftbukkit.v1_XX_RX
                craftBukkitPackage += "." + version;
            }

            FppLogger.debug("Detected CraftBukkit package: " + craftBukkitPackage);

            // Load CraftBukkit classes
            Class<?> craftServerClass = Class.forName(craftBukkitPackage + ".CraftServer");
            Class<?> craftWorldClass = Class.forName(craftBukkitPackage + ".CraftWorld");

            // Get NMS class loader
            ClassLoader nmsLoader = craftServerClass.getClassLoader();

            // Try Mojang-mapped names first, fall back to Spigot names
            // Load critical classes first (these determine Mojang vs Spigot)
            try {
                serverPlayerClass = nmsLoader.loadClass("net.minecraft.server.level.ServerPlayer");
                // If ServerPlayer loads, we're on Mojang mappings
                minecraftServerClass = nmsLoader.loadClass("net.minecraft.server.MinecraftServer");
                serverLevelClass = nmsLoader.loadClass("net.minecraft.server.level.ServerLevel");
                FppLogger.debug("Using Mojang-mapped NMS classes");
            } catch (ClassNotFoundException e) {
                // Fall back to Spigot-mapped names
                FppLogger.info("Mojang mappings not found, trying Spigot mappings...");
                minecraftServerClass = nmsLoader.loadClass("net.minecraft.server.MinecraftServer");
                serverLevelClass = nmsLoader.loadClass("net.minecraft.server.level.WorldServer");
                serverPlayerClass = nmsLoader.loadClass("net.minecraft.server.level.EntityPlayer");
                FppLogger.debug("Loaded Spigot-mapped NMS classes");
            }

            // Load optional classes individually (don't fail init if any are missing)
            try {
                clientInformationClass = nmsLoader.loadClass("net.minecraft.server.level.ClientInformation");
                FppLogger.debug("вң“ Loaded ClientInformation class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("вң— ClientInformation class not found: " + e.getMessage());
            }

            try {
                chatVisibilityClass = nmsLoader.loadClass("net.minecraft.world.entity.player.ChatVisiblity");  // Note: typo in MC code
                FppLogger.debug("вң“ Loaded ChatVisiblity class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("вң— ChatVisiblity class not found: " + e.getMessage());
            }

            try {
                humanoidArmClass = nmsLoader.loadClass("net.minecraft.world.entity.HumanoidArm");
                FppLogger.debug("вң“ Loaded HumanoidArm class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("вң— HumanoidArm class not found: " + e.getMessage());
            }

            // Try multiple possible locations for ParticleStatus
            String[] particleStatusPaths = {
                "net.minecraft.world.level.GameRules$ParticleStatus",
                "net.minecraft.world.entity.player.ParticleStatus",
                "net.minecraft.core.particles.ParticleStatus",
                "net.minecraft.server.level.ParticleStatus"
            };

            for (String path : particleStatusPaths) {
                try {
                    particleStatusClass = nmsLoader.loadClass(path);
                    FppLogger.debug("вң“ Loaded ParticleStatus class from: " + path);
                    break;
                } catch (ClassNotFoundException e) {
                    FppLogger.debug("вң— ParticleStatus not found at: " + path);
                }
            }

            if (particleStatusClass == null) {
                FppLogger.debug("вң— ParticleStatus class not found in any known location");
            }

            // Load other optional classes (currently unused but may be needed for future features)
            try {
                commonListenerCookieClass = nmsLoader.loadClass("net.minecraft.server.network.CommonListenerCookie");
                connectionClass = nmsLoader.loadClass("net.minecraft.network.Connection");
                serverGamePacketListenerClass = nmsLoader.loadClass("net.minecraft.server.network.ServerGamePacketListenerImpl");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("Some optional network classes not available: " + e.getMessage());
            }

            // Load authlib (should be on classpath)
            gameProfileClass = Class.forName("com.mojang.authlib.GameProfile");

            // Cache methods
            getServerMethod = craftServerClass.getMethod("getServer");
            getHandleMethod = craftWorldClass.getMethod("getHandle");
            getPlayerListMethod = minecraftServerClass.getMethod("getPlayerList");

            // Find setPos method (various signatures across versions)
            for (Method m : serverPlayerClass.getMethods()) {
                if (m.getName().equals("setPos") && m.getParameterCount() == 3) {
                    Class<?>[] params = m.getParameterTypes();
                    if (params[0] == double.class && params[1] == double.class && params[2] == double.class) {
                        setPosMethod = m;
                        break;
                    }
                }
            }

            // Cache constructors
            gameProfileConstructor = gameProfileClass.getConstructor(UUID.class, String.class);

            // Cache CraftPlayer.getHandle() for setPosition() use
            Class<?> craftPlayerClass = Class.forName(craftBukkitPackage + ".entity.CraftPlayer");
            craftPlayerGetHandleMethod = craftPlayerClass.getMethod("getHandle");
            craftPlayerGetHandleMethod.setAccessible(true);

            initialized = true;
            FppLogger.info("NMS reflection initialized successfully");

        } catch (Exception e) {
            failed = true;
            FppLogger.error("Failed to initialize NMS reflection: " + e.getMessage());
            e.printStackTrace();
        }
    }

    /**
     * Check if NMS spawning is available.
     */
    public static boolean isAvailable() {
        if (!initialized && !failed) init();
        return initialized;
    }

    /**
     * Spawn a fake NMS ServerPlayer at the given location.
     *
     * <p><b>IMPORTANT:</b> This method creates the ServerPlayer with the bot's REAL name
     * (e.g., "BotName"), not the packet profile name (e.g., "{00_BotName").
     * The packet profile name with the sorting prefix is only used in tab-list packets
     * sent via {@code PacketHelper}, not in the actual NMS entity.
     *
     * @param name     Bot name (REAL name, not packet profile name)
     * @param world    World to spawn in
     * @param x        X coordinate
     * @param y        Y coordinate
     * @param z        Z coordinate
     * @return         Bukkit Player wrapper, or null if spawn failed
     */
    public static Player spawnFakePlayer(String name, World world, double x, double y, double z) {
        if (!isAvailable()) {
            FppLogger.warn("NMS spawning not available, cannot spawn " + name);
            return null;
        }

        try {
            // Create deterministic UUID (offline mode formula)
            UUID uuid = UUID.nameUUIDFromBytes(
                ("OfflinePlayer:" + name).getBytes(StandardCharsets.UTF_8)
            );

            // Create GameProfile
            Object gameProfile = gameProfileConstructor.newInstance(uuid, name);

            // Get MinecraftServer
            Object craftServer = Bukkit.getServer();
            Object minecraftServer = getServerMethod.invoke(craftServer);

            // Get ServerLevel
            Object craftWorld = world;
            Object serverLevel = getHandleMethod.invoke(craftWorld);

            // Create ClientInformation (if available)
            Object clientInfo = null;
            if (clientInformationClass != null) {
                clientInfo = createClientInformation();
            }

            // Create ServerPlayer
            // Constructor signature varies by version, try multiple approaches
            Object serverPlayer = createServerPlayer(minecraftServer, serverLevel, gameProfile, clientInfo);

            if (serverPlayer == null) {
                FppLogger.warn("Failed to create ServerPlayer for " + name);
                return null;
            }

            // Set position BEFORE adding to world
            if (setPosMethod != null) {
                setPosMethod.invoke(serverPlayer, x, y, z);
            }

            // CRITICAL: set up a fake network connection BEFORE adding to world.
            // ServerPlayer.tick() immediately calls this.connection.tickClientLoadTimeout(),
            // so connection must be non-null or the server crashes on the next tick.
            setupFakeConnection(minecraftServer, serverPlayer, gameProfile, clientInfo);

            // Add the ServerPlayer to the world via PlayerList.placeNewPlayer(),
            // which properly registers the player, fires join events, and sends
            // spawn packets to nearby players so they can see the bot.
            boolean addedViaPlayerList = false;
            try {
                Object playerList = getPlayerListMethod.invoke(minecraftServer);
                // placeNewPlayer(Connection, ServerPlayer, CommonListenerCookie)
                // The Connection is already set inside setupFakeConnection;
                // retrieve it from the player's connection field.
                Object sgpl = getConnectionField(serverPlayer);
                if (sgpl != null && commonListenerCookieClass != null) {
                    // Extract the Connection from the ServerGamePacketListenerImpl
                    Object conn = getConnectionFromSgpl(sgpl);
                    Object cookie = createCookieDynamic(gameProfile, clientInfo);
                    if (conn != null && cookie != null) {
                        Method placeMethod = findMethod(playerList.getClass(), "placeNewPlayer", 3);
                        if (placeMethod != null) {
                            placeMethod.setAccessible(true);
                            placeMethod.invoke(playerList, conn, serverPlayer, cookie);
                            addedViaPlayerList = true;
                            FppLogger.debug("Added ServerPlayer via PlayerList.placeNewPlayer()");
                        }
                    }
                }
            } catch (Exception e) {
                FppLogger.debug("placeNewPlayer failed (" + e.getMessage() + "), trying addNewPlayer fallback");
            }

            // Fallback: add directly to the ServerLevel entity list
            if (!addedViaPlayerList) {
                try {
                    Method addMethod = findMethod(serverLevel.getClass(), "addNewPlayer", 1);
                    if (addMethod != null) {
                        addMethod.setAccessible(true);
                        addMethod.invoke(serverLevel, serverPlayer);
                        FppLogger.debug("Added ServerPlayer via ServerLevel.addNewPlayer()");
                    }
                } catch (Exception e) {
                    FppLogger.debug("addNewPlayer also failed: " + e.getMessage());
                }
            }

            // Restore position after placeNewPlayer (it may have teleported to spawn)
            if (setPosMethod != null) {
                setPosMethod.invoke(serverPlayer, x, y, z);
            }

            // Get Bukkit wrapper
            Method getBukkitEntityMethod = serverPlayerClass.getMethod("getBukkitEntity");
            Object bukkitEntity = getBukkitEntityMethod.invoke(serverPlayer);

            if (bukkitEntity instanceof Player) {
                Player result = (Player) bukkitEntity;

                // placeNewPlayer() may have reset the game mode to the server default
                // (often CREATIVE or ADVENTURE on test servers).  Force SURVIVAL so:
                //  вҖў Mobs can target the bot (spectator/creative players are ignored)
                //  вҖў Drowning works (creative players are immune)
                //  вҖў Fall damage fires (creative players take no fall damage)
                //  вҖў All other survival-specific mechanics work correctly
                result.setGameMode(org.bukkit.GameMode.SURVIVAL);

                FppLogger.info("NMS ServerPlayer spawned: " + name + " (UUID: " + result.getUniqueId() + ")");
                return result;
            }

            return null;

        } catch (Exception e) {
            FppLogger.error("Failed to spawn fake player " + name + ": " + e.getMessage());
            e.printStackTrace();
            return null;
        }
    }

    private static Object createClientInformation() {
        try {
            // Verify critical classes are loaded
            if (chatVisibilityClass == null || humanoidArmClass == null) {
                FppLogger.warn("Required classes not loaded for ClientInformation");
                return null;
            }

            if (clientInformationConstructor == null) {
                // Find the 9-parameter constructor and extract the actual ParticleStatus class
                Constructor<?>[] constructors = clientInformationClass.getConstructors();
                for (Constructor<?> ctor : constructors) {
                    if (ctor.getParameterCount() == 9) {
                        Class<?>[] params = ctor.getParameterTypes();
                        particleStatusClass = params[8]; // 9th parameter (ParticleStatus)

                        // Get the constructor with the discovered class
                        clientInformationConstructor = clientInformationClass.getConstructor(
                            String.class, int.class, chatVisibilityClass, boolean.class,
                            int.class, humanoidArmClass, boolean.class, boolean.class,
                            particleStatusClass
                        );

                        // Cache enum values
                        chatVisibilityHidden = chatVisibilityClass.getEnumConstants()[2]; // HIDDEN
                        humanoidArmRight = humanoidArmClass.getEnumConstants()[1]; // RIGHT
                        particleStatusAll = particleStatusClass.getEnumConstants()[0]; // ALL

                        FppLogger.debug("ClientInformation constructor cached (ParticleStatus: " + particleStatusClass.getSimpleName() + ")");
                        break;
                    }
                }

                if (clientInformationConstructor == null) {
                    FppLogger.warn("Could not find 9-parameter ClientInformation constructor");
                    return null;
                }
            }

            return clientInformationConstructor.newInstance(
                "en", 2, chatVisibilityHidden, true, 0, humanoidArmRight, false, false, particleStatusAll
            );
        } catch (Exception e) {
            FppLogger.warn("Failed to create ClientInformation: " + e.getMessage());
            return null;
        }
    }

    private static Object createServerPlayer(Object minecraftServer, Object serverLevel, 
                                             Object gameProfile, Object clientInfo) {
        try {
            // Try modern constructor (1.19+): ServerPlayer(MinecraftServer, ServerLevel, GameProfile, ClientInformation)
            if (clientInfo != null) {
                try {
                    serverPlayerConstructor = serverPlayerClass.getConstructor(
                        minecraftServerClass, serverLevelClass, gameProfileClass, clientInformationClass
                    );
                    return serverPlayerConstructor.newInstance(minecraftServer, serverLevel, gameProfile, clientInfo);
                } catch (NoSuchMethodException e) {
                    FppLogger.debug("4-arg ServerPlayer constructor not found, trying 3-arg");
                }
            }

            // Try older constructor: ServerPlayer(MinecraftServer, ServerLevel, GameProfile)
            try {
                serverPlayerConstructor = serverPlayerClass.getConstructor(
                    minecraftServerClass, serverLevelClass, gameProfileClass
                );
                return serverPlayerConstructor.newInstance(minecraftServer, serverLevel, gameProfile);
            } catch (NoSuchMethodException e) {
                FppLogger.warn("No compatible ServerPlayer constructor found");
            }

            return null;

        } catch (Exception e) {
            FppLogger.error("Failed to create ServerPlayer instance: " + e.getMessage());
            return null;
        }
    }

    /**
     * Creates a fake network connection backed by a Netty {@link io.netty.channel.embedded.EmbeddedChannel}
     * and wires it into a new {@code ServerGamePacketListenerImpl} assigned to {@code serverPlayer.connection}.
     *
     * <p><b>Why EmbeddedChannel?</b>  {@code EmbeddedChannel} is always open ({@code isOpen()} == {@code true}),
     * so {@code Connection.isConnected()} returns {@code true} and the server never removes the bot on a
     * perceived connection loss.  Any packets "sent" to the channel are stored in Netty's outbound
     * buffer without triggering encoder exceptions вҖ” no real network I/O occurs.
     *
     * <p><b>Dummy socket address:</b>  {@code Connection.handleDisconnection()} calls
     * {@code this.address.getAddress()} and NPEs if address is {@code null}.  We inject a dummy
     * {@code InetSocketAddress} to prevent this crash when the bot is kicked.
     * 
     * <p><b>Null Promise Fix:</b> Overrides Connection methods to handle null promises gracefully.
     */
    private static void setupFakeConnection(Object minecraftServer, Object serverPlayer,
                                            Object gameProfile, Object clientInfo) {
        if (connectionClass == null || commonListenerCookieClass == null
                || serverGamePacketListenerClass == null) {
            FppLogger.debug("Network classes not loaded вҖ” skipping fake connection setup");
            return;
        }
        try {
            ClassLoader nmsLoader = minecraftServerClass.getClassLoader();

            // 1. Create custom EmbeddedChannel that handles null promises safely
            Class<?> embeddedChannelClass = Class.forName("io.netty.channel.embedded.EmbeddedChannel");
            Class<?> channelHandlerClass = Class.forName("io.netty.channel.ChannelHandler");
            Class<?> channelPromiseClass = Class.forName("io.netty.channel.ChannelPromise");
            Class<?> channelInboundHandlerAdapterClass = Class.forName("io.netty.channel.ChannelInboundHandlerAdapter");

            // Create a handler that creates dummy promises when needed
            Object customHandler = java.lang.reflect.Proxy.newProxyInstance(
                nmsLoader,
                new Class<?>[]{channelHandlerClass},
                (proxy, method, args) -> {
                    // For any method that might receive null promises, we'll just ignore and return
                    Config.debug("Custom channel handler called: " + method.getName());
                    return null;
                }
            );

            Constructor<?> embeddedChannelConstructor;
            Object embeddedChannel;

            try {
                // Try to create EmbeddedChannel with our custom handler
                embeddedChannelConstructor = embeddedChannelClass.getConstructor(channelHandlerClass.arrayType());
                embeddedChannel = embeddedChannelConstructor.newInstance((Object)new Object[]{customHandler});
                FppLogger.debug("Created EmbeddedChannel with custom handler");
            } catch (Exception e) {
                // Fallback to default constructor if that doesn't work
                embeddedChannelConstructor = embeddedChannelClass.getDeclaredConstructor();
                embeddedChannel = embeddedChannelConstructor.newInstance();
                FppLogger.debug("Created EmbeddedChannel with default constructor");
            }

            // Override the channel's writeAndFlush and flush methods to handle null promises
            try {
                // Wrap the channel in a proxy that handles null promise issues
                embeddedChannel = createNullSafeChannel(embeddedChannel, embeddedChannelClass);
            } catch (Exception e) {
                Config.debug("Could not wrap channel for null safety: " + e.getMessage());
            }

            // 2. PacketFlow.SERVERBOUND
            Class<?> packetFlowClass = nmsLoader.loadClass("net.minecraft.network.protocol.PacketFlow");
            Object serverbound = packetFlowClass.getEnumConstants()[0]; // SERVERBOUND

            // 3. Create Connection subclass that handles null promises gracefully
            Constructor<?> connCtor = connectionClass.getDeclaredConstructor(packetFlowClass);
            connCtor.setAccessible(true);
            Object conn = createNullSafeConnection(connCtor, serverbound, embeddedChannel);

            // 4.5. Inject a dummy InetSocketAddress so Connection.handleDisconnection()
            // does not NPE when the bot is kicked.
            for (Field f : getAllDeclaredFields(connectionClass)) {
                if (java.net.SocketAddress.class.isAssignableFrom(f.getType())) {
                    try {
                        f.setAccessible(true);
                        if (f.get(conn) == null) {
                            f.set(conn, new java.net.InetSocketAddress("127.0.0.1", 25565));
                            FppLogger.debug("Injected dummy InetSocketAddress into Connection." + f.getName());
                        }
                    } catch (Exception ignored) {}
                    break;
                }
            }

            // 5. CommonListenerCookie
            Object cookie = createCookieDynamic(gameProfile, clientInfo);
            if (cookie == null) {
                FppLogger.warn("Could not create CommonListenerCookie вҖ” fake connection incomplete");
                return;
            }

            // 6. ServerGamePacketListenerImpl(MinecraftServer, Connection, ServerPlayer, CommonListenerCookie)
            //    Its constructor sets player.connection = this automatically.
            for (Constructor<?> c : serverGamePacketListenerClass.getDeclaredConstructors()) {
                if (c.getParameterCount() == 4) {
                    c.setAccessible(true);
                    c.newInstance(minecraftServer, conn, serverPlayer, cookie);
                    FppLogger.debug("ServerGamePacketListenerImpl created; connection set on ServerPlayer");
                    return;
                }
            }
            FppLogger.warn("Could not find 4-arg ServerGamePacketListenerImpl constructor");

        } catch (Exception e) {
            FppLogger.warn("setupFakeConnection failed: " + e.getClass().getSimpleName() + ": " + e.getMessage());
        }
    }

    /**
     * Creates a Connection object that handles null promises gracefully to prevent Netty NPEs.
     */
    private static Object createNullSafeConnection(Constructor<?> connCtor, Object serverbound, Object embeddedChannel) throws Exception {
        // Create the Connection instance 
        Object conn = connCtor.newInstance(serverbound);

        // Inject EmbeddedChannel into the Connection's channel field
        for (Field f : getAllDeclaredFields(connectionClass)) {
            if (f.getType().getSimpleName().equals("Channel")) {
                f.setAccessible(true);
                f.set(conn, embeddedChannel);
                FppLogger.debug("Injected EmbeddedChannel into Connection." + f.getName());
                break;
            }
        }

        // Instead of proxy, let's override specific methods by wrapping the connection
        // First, let's try to override the problematic send/flush methods directly using reflection
        try {
            // Override the doSendPacket method to be a no-op
            Method doSendPacketMethod = findMethodInClass(connectionClass, "doSendPacket");
            if (doSendPacketMethod != null) {
                // We can't easily override methods without bytecode manipulation, 
                // so let's try a different approach - modify the channel itself
                FppLogger.debug("Found doSendPacket method, will rely on channel modification");
            }
        } catch (Exception e) {
            Config.debug("Could not find doSendPacket method: " + e.getMessage());
        }

        return conn;
    }

    /**
     * Find a method in a class or its superclasses by name.
     */
    private static Method findMethodInClass(Class<?> clazz, String methodName) {
        Class<?> current = clazz;
        while (current != null && current != Object.class) {
            for (Method method : current.getDeclaredMethods()) {
                if (method.getName().equals(methodName)) {
                    return method;
                }
            }
            current = current.getSuperclass();
        }
        return null;
    }

    /** Dynamically creates a {@code CommonListenerCookie} by iterating its constructors. */
    private static Object createCookieDynamic(Object gameProfile, Object clientInfo) {
        try {
            Constructor<?>[] ctors = commonListenerCookieClass.getDeclaredConstructors();

            // Log available constructors on first attempt (debug aids)
            FppLogger.info("CommonListenerCookie constructors (" + ctors.length + "):");
            for (Constructor<?> c : ctors) {
                StringBuilder sb = new StringBuilder("  [" + c.getParameterCount() + "] ");
                for (Class<?> p : c.getParameterTypes()) sb.append(p.getSimpleName()).append(", ");
                FppLogger.info(sb.toString());
            }

            for (Constructor<?> c : ctors) {
                c.setAccessible(true);
                Class<?>[] p = c.getParameterTypes();
                // Skip synthetic constructors added by the compiler (e.g. for records)
                if (p.length > 0 && p[p.length - 1].getSimpleName().contains("DefaultConstructorMarker")) continue;
                try {
                    switch (p.length) {
                        case 1 -> { return c.newInstance(gameProfile); }
                        case 2 -> { return c.newInstance(gameProfile, 0); }
                        case 3 -> { return c.newInstance(gameProfile, 0, clientInfo); }
                        case 4 -> { return c.newInstance(gameProfile, 0, clientInfo, false); }
                        case 5 -> { return c.newInstance(gameProfile, 0, clientInfo, false, false); }
                        case 7 -> {
                            // Paper 1.21.11+: (GameProfile, int, ClientInformation, boolean, String, Set, KeepAlive)
                            // Pass null for String (server address) and KeepAlive; empty Set for server cookies.
                            return c.newInstance(gameProfile, 0, clientInfo, false,
                                    null, java.util.Collections.emptySet(), null);
                        }
                    }
                } catch (Exception e) {
                    FppLogger.info("  вҶ’ [" + p.length + "-arg] failed: " + e.getClass().getSimpleName() + ": " + e.getMessage());
                }
            }
        } catch (Exception e) {
            FppLogger.debug("createCookieDynamic failed: " + e.getMessage());
        }
        FppLogger.warn("createCookieDynamic: no constructor worked for CommonListenerCookie");
        return null;
    }

    /** Returns the value of {@code serverPlayer.connection} (the ServerGamePacketListenerImpl). */
    private static Object getConnectionField(Object serverPlayer) {
        try {
            for (Field f : getAllDeclaredFields(serverPlayerClass)) {
                if (serverGamePacketListenerClass.isAssignableFrom(f.getType())) {
                    f.setAccessible(true);
                    return f.get(serverPlayer);
                }
            }
        } catch (Exception ignored) {}
        return null;
    }

    /** Returns the {@code Connection} object held inside a {@code ServerGamePacketListenerImpl}. */
    private static Object getConnectionFromSgpl(Object sgpl) {
        try {
            for (Field f : getAllDeclaredFields(sgpl.getClass())) {
                if (connectionClass.isAssignableFrom(f.getType())) {
                    f.setAccessible(true);
                    return f.get(sgpl);
                }
            }
        } catch (Exception ignored) {}
        return null;
    }

    /** Finds a method on a class (or its supers) by name and parameter count. */
    private static Method findMethod(Class<?> clazz, String name, int paramCount) {
        Class<?> cur = clazz;
        while (cur != null && cur != Object.class) {
            for (Method m : cur.getDeclaredMethods()) {
                if (m.getName().equals(name) && m.getParameterCount() == paramCount) {
                    m.setAccessible(true);
                    return m;
                }
            }
            cur = cur.getSuperclass();
        }
        return null;
    }

    /** Collects all declared fields from a class and all its superclasses. */
    private static java.util.List<Field> getAllDeclaredFields(Class<?> clazz) {
        java.util.List<Field> fields = new java.util.ArrayList<>();
        Class<?> cur = clazz;
        while (cur != null && cur != Object.class) {
            for (Field f : cur.getDeclaredFields()) fields.add(f);
            cur = cur.getSuperclass();
        }
        return fields;
    }

    /**
     * Directly sets the NMS entity's position via {@code Entity.setPos(x, y, z)}.
     *
     * <p>This bypasses client-authoritative movement вҖ” the entity's server-side
     * coordinates are updated immediately, and the entity tracker then broadcasts
     * the position change to all nearby players on its next update cycle.
     *
     * <p>Used by the manual physics loop in {@code BotCollisionListener} to move
     * NMS fake-player bots that have a fake (EmbeddedChannel) connection that
     * discards all outgoing packets, including velocity and position packets.
     */
    public static void setPosition(Player bot, double x, double y, double z) {
        if (!initialized || setPosMethod == null || craftPlayerGetHandleMethod == null) return;
        try {
            Object nmsPlayer = craftPlayerGetHandleMethod.invoke(bot);
            setPosMethod.invoke(nmsPlayer, x, y, z);
        } catch (Exception e) {
            FppLogger.debug("NmsPlayerSpawner.setPosition failed: " + e.getMessage());
        }
    }

    /**
     * Remove a fake player from the server.
     */
    public static void removeFakePlayer(Player player) {
        if (player == null) return;

        try {
            // Simply disconnect/remove the player
            player.kick(net.kyori.adventure.text.Component.empty());
        } catch (Exception e) {
            FppLogger.error("Failed to remove fake player: " + e.getMessage());
        }
    }
}

package me.bill.fakePlayerPlugin.fakeplayer;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.database.DatabaseManager;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import me.bill.fakePlayerPlugin.util.FppLogger;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.configuration.ConfigurationSection;
import org.bukkit.entity.Player;

import java.time.*;
import java.time.format.DateTimeParseException;
import java.time.temporal.ChronoUnit;
import java.util.*;
import java.util.concurrent.ThreadLocalRandom;

/**
 * Manages the peak-hours bot pool scheduling system.
 *
 * <h3>How it works</h3>
 * <p>A 60-second repeating tick reads the current server clock, resolves which
 * configured time window is active, computes a target fraction of the total bot
 * pool that should be online, and then gradually <em>sleeps</em> (quietly
 * removes) or <em>wakes</em> (respawns) bots to match that fraction.
 *
 * <p>Transitions are staggered over {@code peak-hours.stagger-seconds} so bots
 * join and leave naturally instead of all at once.
 *
 * <h3>Dynamic swap integration</h3>
 * <ul>
 *   <li>The total pool always includes bots temporarily offline via
 *       {@link BotSwapAI} session rotation, so short swap absences don't
 *       confuse the peak-hours math.</li>
 *   <li>{@code swap.enabled} must be {@code true} before peak-hours can be
 *       activated.  If swap is disabled while peaks is running, the tick
 *       silently pauses and wakes any sleeping bots so none are permanently lost.</li>
 * </ul>
 *
 * <h3>Config keys (peak-hours.*)</h3>
 * <ul>
 *   <li>{@code enabled}            вҖ” master toggle (requires swap.enabled: true)</li>
 *   <li>{@code timezone}           вҖ” java.time.ZoneId string</li>
 *   <li>{@code stagger-seconds}    вҖ” spread joins/leaves across this many seconds</li>
 *   <li>{@code schedule}           вҖ” list of {@code {start, end, fraction}} maps</li>
 *   <li>{@code day-overrides}      вҖ” per-DayOfWeek schedule overrides</li>
 *   <li>{@code min-online}         вҖ” absolute floor: never fewer than this many bots online</li>
 *   <li>{@code notify-transitions} вҖ” broadcast window changes to admins with fpp.peaks</li>
 * </ul>
 */
public final class PeakHoursManager {

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;

    /** Bots put to sleep by peak-hours вҖ” FIFO so the oldest sleep first. */
    private final Deque<SleepingBot> sleepingBots = new ArrayDeque<>();

    /** Bukkit task ID of the periodic tick, or {@code -1} when not running. */
    private int tickTaskId = -1;

    /**
     * Prevents stacked adjustments: {@code true} while staggered actions are pending.
     * Cleared by the last staggered action's completion callback.
     */
    private volatile boolean adjusting = false;

    /**
     * Last fraction applied during a tick. Used to detect window transitions.
     * {@code -1.0} = no tick has run yet (forces a "transition" on first tick).
     */
    private double lastFraction = -1.0;

    // в”Җв”Җ Constructor в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    public PeakHoursManager(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
    }

    // в”Җв”Җ Lifecycle в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Starts the 60-second periodic tick.
     * Safe to call multiple times вҖ” does nothing if already started.
     */
    public void start() {
        if (tickTaskId != -1) return;
        tickTaskId = Bukkit.getScheduler()
                .runTaskTimer(plugin, this::tick, 40L, 1200L)
                .getTaskId();
        Config.debugChat("[PeakHours] Scheduler started (60-second tick).");
    }

    /**
     * Stops the periodic tick and immediately wakes all sleeping bots so
     * persistence can capture the full pool before the plugin shuts down.
     */
    public void shutdown() {
        stopTick();
        wakeAll();
        Config.debugChat("[PeakHours] Shutdown complete вҖ” all sleeping bots woken.");
    }

    /**
     * Hot-reload: cancels the current scheduler, wakes all sleeping bots
     * (config may have changed), resets transition state, then restarts
     * if peak-hours is still enabled in the new config.
     * Called automatically from {@code /fpp reload}.
     */
    public void reload() {
        stopTick();
        adjusting    = false;
        lastFraction = -1.0;
        if (!sleepingBots.isEmpty()) {
            int count = sleepingBots.size();
            wakeAll();
            Config.debugChat("[PeakHours] Reload: woke " + count + " sleeping bot(s) for re-evaluation.");
        }
        if (Config.peakHoursEnabled() && Config.swapEnabled()) {
            start();
            // Run an immediate tick so the new config takes effect within 1 s
            Bukkit.getScheduler().runTaskLater(plugin, this::tick, 20L);
        }
    }

    // в”Җв”Җ Core tick в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private void tick() {
        if (!Config.peakHoursEnabled()) return;

        // Guard: swap must be active for peaks to manage the bot pool safely
        if (!Config.swapEnabled()) {
            if (!sleepingBots.isEmpty()) {
                FppLogger.warn("[PeakHours] Swap disabled while " + sleepingBots.size()
                        + " bot(s) sleeping вҖ” waking all to prevent data loss.");
                wakeAll();
            }
            Config.debugChat("[PeakHours] Swap is off вҖ” tick paused.");
            return;
        }

        if (adjusting) {
            Config.debugChat("[PeakHours] Tick skipped вҖ” previous stagger still in-flight.");
            return;
        }

        double fraction    = computeTargetFraction();
        int    onlineAFK   = countOnlineAFKBots();
        int    sleeping    = sleepingBots.size();

        // Include bots BotSwapAI temporarily removed (they will rejoin on their own).
        // Without this, routine swap absences look like pool shrinkage.
        BotSwapAI swapAI     = manager.getBotSwapAI();
        int       swappedOut = (swapAI != null) ? swapAI.getSwappedOutCount() : 0;
        int       total      = onlineAFK + sleeping + swappedOut;

        if (total == 0) return;

        // Apply min-online floor so the server never feels completely empty
        int minOnline = Math.max(0, Config.peakHoursMinOnline());
        int target    = (int) Math.round(fraction * total);
        target = Math.max(minOnline, Math.min(total, target));

        // Detect and optionally announce window transitions
        checkAndAnnounceTransition(fraction);

        // Compare target against "effectively online" (currently online + returning-soon bots)
        int effectivelyOnline = onlineAFK + swappedOut;
        int toSleep = Math.max(0, effectivelyOnline - target);
        int toWake  = Math.max(0, target - effectivelyOnline);
        toSleep = Math.min(toSleep, onlineAFK); // can only sleep actually-online bots
        toWake  = Math.min(toWake,  sleeping);  // can only wake bots we put to sleep

        if (toSleep == 0 && toWake == 0) {
            Config.debugChat("[PeakHours] OK вҖ” fraction=" + String.format("%.0f%%", fraction * 100)
                    + " online=" + onlineAFK + " swapping=" + swappedOut
                    + " sleeping=" + sleeping + " total=" + total + " target=" + target + ".");
            return;
        }

        int stagger = Math.max(1, Config.peakHoursStaggerSeconds());
        Config.debugChat("[PeakHours] Adjusting вҖ” fraction=" + String.format("%.0f%%", fraction * 100)
                + " online=" + onlineAFK + " swapping=" + swappedOut
                + " sleeping=" + sleeping + " total=" + total
                + " target=" + target + " toSleep=" + toSleep + " toWake=" + toWake);

        adjusting = true;

        if (toSleep > 0) {
            List<FakePlayer> candidates = pickSleepCandidates(toSleep);
            List<Runnable>   actions    = new ArrayList<>(candidates.size());
            for (FakePlayer fp : candidates) {
                actions.add(() -> putToSleep(fp));
            }
            scheduleStaggered(actions, stagger, () -> adjusting = false);
        } else {
            List<Runnable> actions = new ArrayList<>(toWake);
            for (int i = 0; i < toWake; i++) {
                actions.add(this::wakeBotFromQueue);
            }
            scheduleStaggered(actions, stagger, () -> adjusting = false);
        }
    }

    // в”Җв”Җ Sleep / wake в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Internal: put a single bot to sleep. */
    private void putToSleep(FakePlayer fp) {
        if (fp == null) return;
        if (manager.getByUuid(fp.getUuid()) == null) {
            Config.debugChat("[PeakHours] putToSleep: '" + fp.getName() + "' already gone.");
            return;
        }
        // Cancel swap session so BotSwapAI does not independently rejoin this bot
        BotSwapAI swapAI = manager.getBotSwapAI();
        if (swapAI != null) swapAI.cancel(fp.getUuid());

        Location loc  = fp.getLiveLocation();
        String   name = fp.getName();
        sleepingBots.addLast(new SleepingBot(name, loc));
        manager.delete(name);
        Config.debugChat("[PeakHours] '" + name + "' вҶ’ sleep (pool: " + sleepingBots.size() + ").");
    }

    /**
     * Manually puts an active AFK bot to sleep by name.
     * @return {@code true} if the bot was found and queued; {@code false} otherwise.
     */
    public boolean putBotToSleepByName(String name) {
        FakePlayer fp = manager.getByName(name);
        if (fp == null || fp.getBotType() == BotType.PVP) return false;
        putToSleep(fp);
        return true;
    }

    /** Internal: pop the oldest sleeping bot and respawn it. */
    private void wakeBotFromQueue() {
        SleepingBot sb = sleepingBots.pollFirst();
        if (sb != null) wakeEntry(sb);
    }

    /**
     * Wakes a sleeping bot by name.
     * @return {@code true} if found and woken; {@code false} if not in the sleeping pool.
     */
    public boolean wakeBotByName(String name) {
        SleepingBot target = null;
        for (SleepingBot sb : sleepingBots) {
            if (sb.name().equalsIgnoreCase(name)) { target = sb; break; }
        }
        if (target == null) return false;
        sleepingBots.remove(target);
        wakeEntry(target);
        return true;
    }

    /** Shared respawn logic for a {@link SleepingBot} entry. */
    private void wakeEntry(SleepingBot sb) {
        if (sb.loc() == null || sb.loc().getWorld() == null) {
            FppLogger.warn("[PeakHours] Sleeping bot '" + sb.name()
                    + "' had no valid location вҖ” discarded.");
            return;
        }
        String customName = null;
        if (Config.swapSameNameOnRejoin() && !manager.isNameUsed(sb.name())) {
            customName = sb.name();
        }
        int result = manager.spawn(sb.loc(), 1, null, customName, true);
        Config.debugChat("[PeakHours] '" + sb.name()
                + "' вҶ’ wake (result=" + result + ", pool: " + sleepingBots.size() + ").");
    }

    /**
     * Immediately wakes every sleeping bot.
     * Used on shutdown, reload, and when disabling peak-hours.
     */
    public void wakeAll() {
        int count = sleepingBots.size();
        while (!sleepingBots.isEmpty()) wakeBotFromQueue();
        if (count > 0) Config.debugChat("[PeakHours] wakeAll() вҖ” woke " + count + " bot(s).");
    }

    // в”Җв”Җ Force check в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Triggers an immediate peak-hours evaluation, bypassing the 60-second interval.
     * Also clears any stalled {@code adjusting} lock so a stuck previous cycle
     * cannot prevent the force-check from running.
     */
    public void forceCheck() {
        if (adjusting) {
            Config.debugChat("[PeakHours] forceCheck: clearing stalled adjusting flag.");
            adjusting = false;
        }
        tick();
    }

    // в”Җв”Җ Stagger helper в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Distributes {@code actions} evenly across {@code staggerSeconds} with
     * small random jitter on each delay so joins/leaves look organic.
     * Calls {@code onDone} after the last action fires.
     */
    private void scheduleStaggered(List<Runnable> actions, int staggerSeconds, Runnable onDone) {
        if (actions.isEmpty()) {
            adjusting = false;
            if (onDone != null) onDone.run();
            return;
        }
        int  n          = actions.size();
        long totalTicks = (long) staggerSeconds * 20L;

        for (int i = 0; i < n; i++) {
            final int     idx    = i;
            final Runnable action = actions.get(i);
            long base   = n == 1 ? 20L : (long)(((double) idx / (n - 1)) * totalTicks) + 20L;
            long jitter = ThreadLocalRandom.current().nextInt(9) - 4L; // Вұ4 ticks
            long delay  = Math.max(20L, base + jitter);
            Bukkit.getScheduler().runTaskLater(plugin, () -> {
                action.run();
                if (idx == n - 1 && onDone != null) onDone.run();
            }, delay);
        }
    }

    // в”Җв”Җ Transition tracking в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private void checkAndAnnounceTransition(double newFraction) {
        if (lastFraction >= 0.0 && Math.abs(newFraction - lastFraction) > 0.001) {
            String label = String.format("%.0f%%", newFraction * 100);
            String window = getCurrentWindowLabel();
            Config.debugChat("[PeakHours] Transition вҶ’ " + window + " (" + label + ").");
            if (Config.peakHoursNotifyTransitions()) {
                for (Player p : Bukkit.getOnlinePlayers()) {
                    if (Perm.has(p, Perm.PEAKS)) {
                        p.sendMessage(Lang.get("peaks-transition",
                                "window",   window,
                                "fraction", label));
                    }
                }
            }
        }
        lastFraction = newFraction;
    }

    // в”Җв”Җ Time window resolution в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Computes the target fraction for the current time.
     * Returns {@code 1.0} when no window matches (all bots online).
     */
    public double computeTargetFraction() {
        ZoneId zone = safeZone();
        LocalDateTime now  = LocalDateTime.now(zone);
        LocalTime     time = now.toLocalTime();
        DayOfWeek     dow  = now.getDayOfWeek();

        for (Map<?, ?> window : resolveSchedule(dow)) {
            String startStr = objectToString(window.get("start"));
            String endStr   = objectToString(window.get("end"));
            double frac;
            try { frac = Double.parseDouble(objectToString(window.get("fraction"))); }
            catch (NumberFormatException e) { continue; }
            try {
                LocalTime start = LocalTime.parse(startStr);
                LocalTime end   = LocalTime.parse(endStr);
                if (timeInWindow(time, start, end)) return Math.max(0.0, Math.min(1.0, frac));
            } catch (DateTimeParseException ignored) {}
        }
        return 1.0;
    }

    /**
     * Returns the fraction of the next scheduled window, or {@code -1.0} if none.
     */
    public double getNextWindowFraction() {
        ZoneId zone = safeZone();
        LocalDateTime now  = LocalDateTime.now(zone);
        LocalTime     time = now.toLocalTime();
        DayOfWeek     dow  = now.getDayOfWeek();

        List<Map<?, ?>> schedule = resolveSchedule(dow);
        long shortest = Long.MAX_VALUE;
        double nextFrac = -1.0;
        for (Map<?, ?> window : schedule) {
            try {
                LocalTime wStart = LocalTime.parse(objectToString(window.get("start")));
                long secs = time.until(wStart, ChronoUnit.SECONDS);
                if (secs <= 0) secs += 86400L;
                if (secs > 0 && secs < shortest) {
                    shortest = secs;
                    nextFrac = Double.parseDouble(objectToString(window.get("fraction")));
                    nextFrac = Math.max(0.0, Math.min(1.0, nextFrac));
                }
            } catch (Exception ignored) {}
        }
        return nextFrac;
    }

    private List<Map<?, ?>> resolveSchedule(DayOfWeek dow) {
        ConfigurationSection overrides = Config.peakHoursDayOverrides();
        if (overrides != null) {
            String dayKey = dow.name();
            if (overrides.contains(dayKey)) {
                List<Map<?, ?>> daySchedule = overrides.getMapList(dayKey);
                if (!daySchedule.isEmpty()) return daySchedule;
            }
        }
        return Config.peakHoursSchedule();
    }

    private static boolean timeInWindow(LocalTime time, LocalTime start, LocalTime end) {
        if (!end.isBefore(start)) {
            return !time.isBefore(start) && time.isBefore(end);
        } else {
            return !time.isBefore(start) || time.isBefore(end);
        }
    }

    // в”Җв”Җ Bot selection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private int countOnlineAFKBots() {
        int c = 0;
        for (FakePlayer fp : manager.getActivePlayers()) {
            if (fp.getBotType() == BotType.AFK) c++;
        }
        return c;
    }

    private List<FakePlayer> pickSleepCandidates(int limit) {
        List<FakePlayer> list = new ArrayList<>();
        for (FakePlayer fp : manager.getActivePlayers()) {
            if (fp.getBotType() == BotType.AFK) list.add(fp);
        }
        Collections.shuffle(list, ThreadLocalRandom.current());
        return list.subList(0, Math.min(limit, list.size()));
    }

    // в”Җв”Җ Diagnostics в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    public int     getSleepingCount() { return sleepingBots.size(); }
    public boolean isRunning()        { return tickTaskId != -1; }

    /** Returns online AFK + sleeping + BotSwapAI swapped-out (matches tick() denominator). */
    public int getTotalPool() {
        BotSwapAI s = manager.getBotSwapAI();
        return countOnlineAFKBots() + sleepingBots.size() + (s != null ? s.getSwappedOutCount() : 0);
    }

    public List<String> getSleepingNames() {
        List<String> names = new ArrayList<>(sleepingBots.size());
        for (SleepingBot sb : sleepingBots) names.add(sb.name());
        return Collections.unmodifiableList(names);
    }

    /** Returns an immutable snapshot of all sleeping entries (oldest first). */
    public List<SleepingBot> getSleepingEntries() { return List.copyOf(sleepingBots); }

    public boolean isSleeping(String name) {
        for (SleepingBot sb : sleepingBots) {
            if (sb.name().equalsIgnoreCase(name)) return true;
        }
        return false;
    }

    public String getCurrentWindowLabel() {
        ZoneId zone = safeZone();
        LocalDateTime now  = LocalDateTime.now(zone);
        LocalTime     time = now.toLocalTime();
        DayOfWeek     dow  = now.getDayOfWeek();
        for (Map<?, ?> window : resolveSchedule(dow)) {
            String s = objectToString(window.get("start"));
            String e = objectToString(window.get("end"));
            try {
                if (timeInWindow(time, LocalTime.parse(s), LocalTime.parse(e))) return s + "вҖ“" + e;
            } catch (DateTimeParseException ignored) {}
        }
        return "none";
    }

    public long getSecondsToNextWindow() {
        ZoneId zone = safeZone();
        LocalDateTime now  = LocalDateTime.now(zone);
        LocalTime     time = now.toLocalTime();
        DayOfWeek     dow  = now.getDayOfWeek();
        List<Map<?, ?>> schedule = resolveSchedule(dow);
        if (schedule.isEmpty()) return -1;
        long shortest = Long.MAX_VALUE;
        for (Map<?, ?> window : schedule) {
            try {
                LocalTime wStart = LocalTime.parse(objectToString(window.get("start")));
                long secs = time.until(wStart, ChronoUnit.SECONDS);
                if (secs <= 0) secs += 86400L;
                if (secs > 0 && secs < shortest) shortest = secs;
            } catch (DateTimeParseException ignored) {}
        }
        return shortest == Long.MAX_VALUE ? -1 : shortest;
    }

    // в”Җв”Җ Private helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private void stopTick() {
        if (tickTaskId != -1) {
            Bukkit.getScheduler().cancelTask(tickTaskId);
            tickTaskId = -1;
        }
    }

    private ZoneId safeZone() {
        try { return ZoneId.of(Config.peakHoursTimezone()); }
        catch (Exception e) { return ZoneId.of("UTC"); }
    }

    private static String objectToString(Object o) { return o == null ? "" : String.valueOf(o); }

    // в”Җв”Җ Data record в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Immutable snapshot of a bot sleeping in the peak-hours pool. */
    public record SleepingBot(String name, Location loc) {}
}

package me.bill.fakePlayerPlugin.fakeplayer;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.database.DatabaseManager;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import me.bill.fakePlayerPlugin.util.FppLogger;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.configuration.ConfigurationSection;
import org.bukkit.entity.Player;

import java.time.*;
import java.time.format.DateTimeParseException;
import java.time.temporal.ChronoUnit;
import java.util.*;
import java.util.concurrent.ThreadLocalRandom;

/**
 * Manages the peak-hours bot pool scheduling system.
 *
 * <h3>How it works</h3>
 * <p>A 60-second repeating tick reads the current server clock, resolves which
 * configured time window is active, computes a target fraction of the total bot
 * pool that should be online, and then gradually <em>sleeps</em> (quietly
 * removes) or <em>wakes</em> (respawns) bots to match that fraction.
 *
 * <p>Transitions are staggered over {@code peak-hours.stagger-seconds} so bots
 * join and leave naturally instead of all at once.
 *
 * <h3>Dynamic swap integration</h3>
 * <ul>
 *   <li>The total pool always includes bots temporarily offline via
 *       {@link BotSwapAI} session rotation, so short swap absences don't
 *       confuse the peak-hours math.</li>
 *   <li>{@code swap.enabled} must be {@code true} before peak-hours can be
 *       activated.  If swap is disabled while peaks is running, the tick
 *       silently pauses and wakes any sleeping bots so none are permanently lost.</li>
 * </ul>
 *
 * <h3>Config keys (peak-hours.*)</h3>
 * <ul>
 *   <li>{@code enabled}            вҖ” master toggle (requires swap.enabled: true)</li>
 *   <li>{@code timezone}           вҖ” java.time.ZoneId string</li>
 *   <li>{@code stagger-seconds}    вҖ” spread joins/leaves across this many seconds</li>
 *   <li>{@code schedule}           вҖ” list of {@code {start, end, fraction}} maps</li>
 *   <li>{@code day-overrides}      вҖ” per-DayOfWeek schedule overrides</li>
 *   <li>{@code min-online}         вҖ” absolute floor: never fewer than this many bots online</li>
 *   <li>{@code notify-transitions} вҖ” broadcast window changes to admins with fpp.peaks</li>
 * </ul>
 */
public final class PeakHoursManager {

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;

    /** Optional database manager for crash-safe sleeping-bot persistence. May be {@code null}. */
    private DatabaseManager db = null;

    /** Bots put to sleep by peak-hours вҖ” FIFO so the oldest sleep first. */
    private final Deque<SleepingBot> sleepingBots = new ArrayDeque<>();

    /** Bukkit task ID of the periodic tick, or {@code -1} when not running. */
    private int tickTaskId = -1;

    /**
     * Prevents stacked adjustments: {@code true} while staggered actions are pending.
     * Cleared by the last staggered action's completion callback.
     */
    private volatile boolean adjusting = false;

    /**
     * Last fraction applied during a tick. Used to detect window transitions.
     * {@code -1.0} = no tick has run yet (forces a "transition" on first tick).
     */
    private double lastFraction = -1.0;

    // в”Җв”Җ Constructor в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    public PeakHoursManager(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
    }

    /**
     * Injects the database manager so sleeping-bot state is persisted crash-safely.
     * Call immediately after construction, before {@link #start()}.
     */
    public void setDatabaseManager(DatabaseManager db) { this.db = db; }

    // в”Җв”Җ Lifecycle в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Starts the 60-second periodic tick.
     * Safe to call multiple times вҖ” does nothing if already started.
     */
    public void start() {
        if (tickTaskId != -1) return;
        tickTaskId = Bukkit.getScheduler()
                .runTaskTimer(plugin, this::tick, 40L, 1200L)
                .getTaskId();
        Config.debugChat("[PeakHours] Scheduler started (60-second tick).");
    }

    /**
     * Stops the periodic tick and immediately wakes all sleeping bots so
     * persistence can capture the full pool before the plugin shuts down.
     */
    public void shutdown() {
        stopTick();
        wakeAll();
        Config.debugChat("[PeakHours] Shutdown complete вҖ” all sleeping bots woken.");
    }

    /**
     * Hot-reload: cancels the current scheduler, wakes all sleeping bots
     * (config may have changed), resets transition state, then restarts
     * if peak-hours is still enabled in the new config.
     * Called automatically from {@code /fpp reload}.
     */
    public void reload() {
        stopTick();
        adjusting    = false;
        lastFraction = -1.0;
        if (!sleepingBots.isEmpty()) {
            int count = sleepingBots.size();
            wakeAll();
            Config.debugChat("[PeakHours] Reload: woke " + count + " sleeping bot(s) for re-evaluation.");
        }
        if (Config.peakHoursEnabled() && Config.swapEnabled()) {
            start();
            // Run an immediate tick so the new config takes effect within 1 s
            Bukkit.getScheduler().runTaskLater(plugin, this::tick, 20L);
        }
    }

    // в”Җв”Җ Core tick в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private void tick() {
        if (!Config.peakHoursEnabled()) return;

        // Guard: swap must be active for peaks to manage the bot pool safely
        if (!Config.swapEnabled()) {
            if (!sleepingBots.isEmpty()) {
                FppLogger.warn("[PeakHours] Swap disabled while " + sleepingBots.size()
                        + " bot(s) sleeping вҖ” waking all to prevent data loss.");
                wakeAll();
            }
            Config.debugChat("[PeakHours] Swap is off вҖ” tick paused.");
            return;
        }

        if (adjusting) {
            Config.debugChat("[PeakHours] Tick skipped вҖ” previous stagger still in-flight.");
            return;
        }

        double fraction    = computeTargetFraction();
        int    onlineAFK   = countOnlineAFKBots();
        int    sleeping    = sleepingBots.size();

        // Include bots BotSwapAI temporarily removed (they will rejoin on their own).
        // Without this, routine swap absences look like pool shrinkage.
        BotSwapAI swapAI     = manager.getBotSwapAI();
        int       swappedOut = (swapAI != null) ? swapAI.getSwappedOutCount() : 0;
        int       total      = onlineAFK + sleeping + swappedOut;

        if (total == 0) return;

        // Apply min-online floor so the server never feels completely empty
        int minOnline = Math.max(0, Config.peakHoursMinOnline());
        int target    = (int) Math.round(fraction * total);
        target = Math.max(minOnline, Math.min(total, target));

        // Detect and optionally announce window transitions
        checkAndAnnounceTransition(fraction);

        // Compare target against "effectively online" (currently online + returning-soon bots)
        int effectivelyOnline = onlineAFK + swappedOut;
        int toSleep = Math.max(0, effectivelyOnline - target);
        int toWake  = Math.max(0, target - effectivelyOnline);
        toSleep = Math.min(toSleep, onlineAFK); // can only sleep actually-online bots
        toWake  = Math.min(toWake,  sleeping);  // can only wake bots we put to sleep

        if (toSleep == 0 && toWake == 0) {
            Config.debugChat("[PeakHours] OK вҖ” fraction=" + String.format("%.0f%%", fraction * 100)
                    + " online=" + onlineAFK + " swapping=" + swappedOut
                    + " sleeping=" + sleeping + " total=" + total + " target=" + target + ".");
            return;
        }

        int stagger = Math.max(1, Config.peakHoursStaggerSeconds());
        Config.debugChat("[PeakHours] Adjusting вҖ” fraction=" + String.format("%.0f%%", fraction * 100)
                + " online=" + onlineAFK + " swapping=" + swappedOut
                + " sleeping=" + sleeping + " total=" + total
                + " target=" + target + " toSleep=" + toSleep + " toWake=" + toWake);

        adjusting = true;

        if (toSleep > 0) {
            List<FakePlayer> candidates = pickSleepCandidates(toSleep);
            List<Runnable>   actions    = new ArrayList<>(candidates.size());
            for (FakePlayer fp : candidates) {
                actions.add(() -> putToSleep(fp));
            }
            scheduleStaggered(actions, stagger, () -> adjusting = false);
        } else {
            List<Runnable> actions = new ArrayList<>(toWake);
            for (int i = 0; i < toWake; i++) {
                actions.add(this::wakeBotFromQueue);
            }
            scheduleStaggered(actions, stagger, () -> adjusting = false);
        }
    }

    // в”Җв”Җ Sleep / wake в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Internal: put a single bot to sleep. */
    private void putToSleep(FakePlayer fp) {
        if (fp == null) return;
        if (manager.getByUuid(fp.getUuid()) == null) {
            Config.debugChat("[PeakHours] putToSleep: '" + fp.getName() + "' already gone.");
            return;
        }
        // Cancel swap session so BotSwapAI does not independently rejoin this bot
        BotSwapAI swapAI = manager.getBotSwapAI();
        if (swapAI != null) swapAI.cancel(fp.getUuid());

        Location loc  = fp.getLiveLocation();
        String   name = fp.getName();
        sleepingBots.addLast(new SleepingBot(name, loc));
        manager.delete(name);
        Config.debugChat("[PeakHours] '" + name + "' вҶ’ sleep (pool: " + sleepingBots.size() + ").");
    }

    /**
     * Manually puts an active AFK bot to sleep by name.
     * @return {@code true} if the bot was found and queued; {@code false} otherwise.
     */
    public boolean putBotToSleepByName(String name) {
        FakePlayer fp = manager.getByName(name);
        if (fp == null || fp.getBotType() == BotType.PVP) return false;
        putToSleep(fp);
        return true;
    }

    /** Internal: pop the oldest sleeping bot and respawn it. */
    private void wakeBotFromQueue() {
        SleepingBot sb = sleepingBots.pollFirst();
        if (sb != null) wakeEntry(sb);
    }

    /**
     * Wakes a sleeping bot by name.
     * @return {@code true} if found and woken; {@code false} if not in the sleeping pool.
     */
    public boolean wakeBotByName(String name) {
        SleepingBot target = null;
        for (SleepingBot sb : sleepingBots) {
            if (sb.name().equalsIgnoreCase(name)) { target = sb; break; }
        }
        if (target == null) return false;
        sleepingBots.remove(target);
        wakeEntry(target);
        return true;
    }

    /** Shared respawn logic for a {@link SleepingBot} entry. */
    private void wakeEntry(SleepingBot sb) {
        if (sb.loc() == null || sb.loc().getWorld() == null) {
            FppLogger.warn("[PeakHours] Sleeping bot '" + sb.name()
                    + "' had no valid location вҖ” discarded.");
            return;
        }
        String customName = null;
        if (Config.swapSameNameOnRejoin() && !manager.isNameUsed(sb.name())) {
            customName = sb.name();
        }
        int result = manager.spawn(sb.loc(), 1, null, customName, true);
        Config.debugChat("[PeakHours] '" + sb.name()
                + "' вҶ’ wake (result=" + result + ", pool: " + sleepingBots.size() + ").");
    }

    /**
     * Immediately wakes every sleeping bot.
     * Used on shutdown, reload, and when disabling peak-hours.
     */
    public void wakeAll() {
        int count = sleepingBots.size();
        while (!sleepingBots.isEmpty()) wakeBotFromQueue();
        if (count > 0) Config.debugChat("[PeakHours] wakeAll() вҖ” woke " + count + " bot(s).");
    }

    // в”Җв”Җ Force check в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Triggers an immediate peak-hours evaluation, bypassing the 60-second interval.
     * Also clears any stalled {@code adjusting} lock so a stuck previous cycle
     * cannot prevent the force-check from running.
     */
    public void forceCheck() {
        if (adjusting) {
            Config.debugChat("[PeakHours] forceCheck: clearing stalled adjusting flag.");
            adjusting = false;
        }
        tick();
    }

    // в”Җв”Җ Stagger helper в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Distributes {@code actions} evenly across {@code staggerSeconds} with
     * small random jitter on each delay so joins/leaves look organic.
     * Calls {@code onDone} after the last action fires.
     */
    private void scheduleStaggered(List<Runnable> actions, int staggerSeconds, Runnable onDone) {
        if (actions.isEmpty()) {
            adjusting = false;
            if (onDone != null) onDone.run();
            return;
        }
        int  n          = actions.size();
        long totalTicks = (long) staggerSeconds * 20L;

        for (int i = 0; i < n; i++) {
            final int     idx    = i;
            final Runnable action = actions.get(i);
            long base   = n == 1 ? 20L : (long)(((double) idx / (n - 1)) * totalTicks) + 20L;
            long jitter = ThreadLocalRandom.current().nextInt(9) - 4L; // Вұ4 ticks
            long delay  = Math.max(20L, base + jitter);
            Bukkit.getScheduler().runTaskLater(plugin, () -> {
                action.run();
                if (idx == n - 1 && onDone != null) onDone.run();
            }, delay);
        }
    }

    // в”Җв”Җ Transition tracking в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private void checkAndAnnounceTransition(double newFraction) {
        if (lastFraction >= 0.0 && Math.abs(newFraction - lastFraction) > 0.001) {
            String label = String.format("%.0f%%", newFraction * 100);
            String window = getCurrentWindowLabel();
            Config.debugChat("[PeakHours] Transition вҶ’ " + window + " (" + label + ").");
            if (Config.peakHoursNotifyTransitions()) {
                for (Player p : Bukkit.getOnlinePlayers()) {
                    if (Perm.has(p, Perm.PEAKS)) {
                        p.sendMessage(Lang.get("peaks-transition",
                                "window",   window,
                                "fraction", label));
                    }
                }
            }
        }
        lastFraction = newFraction;
    }

    // в”Җв”Җ Time window resolution в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Computes the target fraction for the current time.
     * Returns {@code 1.0} when no window matches (all bots online).
     */
    public double computeTargetFraction() {
        ZoneId zone = safeZone();
        LocalDateTime now  = LocalDateTime.now(zone);
        LocalTime     time = now.toLocalTime();
        DayOfWeek     dow  = now.getDayOfWeek();

        for (Map<?, ?> window : resolveSchedule(dow)) {
            String startStr = objectToString(window.get("start"));
            String endStr   = objectToString(window.get("end"));
            double frac;
            try { frac = Double.parseDouble(objectToString(window.get("fraction"))); }
            catch (NumberFormatException e) { continue; }
            try {
                LocalTime start = LocalTime.parse(startStr);
                LocalTime end   = LocalTime.parse(endStr);
                if (timeInWindow(time, start, end)) return Math.max(0.0, Math.min(1.0, frac));
            } catch (DateTimeParseException ignored) {}
        }
        return 1.0;
    }

    /**
     * Returns the fraction of the next scheduled window, or {@code -1.0} if none.
     */
    public double getNextWindowFraction() {
        ZoneId zone = safeZone();
        LocalDateTime now  = LocalDateTime.now(zone);
        LocalTime     time = now.toLocalTime();
        DayOfWeek     dow  = now.getDayOfWeek();

        List<Map<?, ?>> schedule = resolveSchedule(dow);
        long shortest = Long.MAX_VALUE;
        double nextFrac = -1.0;
        for (Map<?, ?> window : schedule) {
            try {
                LocalTime wStart = LocalTime.parse(objectToString(window.get("start")));
                long secs = time.until(wStart, ChronoUnit.SECONDS);
                if (secs <= 0) secs += 86400L;
                if (secs > 0 && secs < shortest) {
                    shortest = secs;
                    nextFrac = Double.parseDouble(objectToString(window.get("fraction")));
                    nextFrac = Math.max(0.0, Math.min(1.0, nextFrac));
                }
            } catch (Exception ignored) {}
        }
        return nextFrac;
    }

    private List<Map<?, ?>> resolveSchedule(DayOfWeek dow) {
        ConfigurationSection overrides = Config.peakHoursDayOverrides();
        if (overrides != null) {
            String dayKey = dow.name();
            if (overrides.contains(dayKey)) {
                List<Map<?, ?>> daySchedule = overrides.getMapList(dayKey);
                if (!daySchedule.isEmpty()) return daySchedule;
            }
        }
        return Config.peakHoursSchedule();
    }

    private static boolean timeInWindow(LocalTime time, LocalTime start, LocalTime end) {
        if (!end.isBefore(start)) {
            return !time.isBefore(start) && time.isBefore(end);
        } else {
            return !time.isBefore(start) || time.isBefore(end);
        }
    }

    // в”Җв”Җ Bot selection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private int countOnlineAFKBots() {
        int c = 0;
        for (FakePlayer fp : manager.getActivePlayers()) {
            if (fp.getBotType() == BotType.AFK) c++;
        }
        return c;
    }

    private List<FakePlayer> pickSleepCandidates(int limit) {
        List<FakePlayer> list = new ArrayList<>();
        for (FakePlayer fp : manager.getActivePlayers()) {
            if (fp.getBotType() == BotType.AFK) list.add(fp);
        }
        Collections.shuffle(list, ThreadLocalRandom.current());
        return list.subList(0, Math.min(limit, list.size()));
    }

    // в”Җв”Җ Diagnostics в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    public int     getSleepingCount() { return sleepingBots.size(); }
    public boolean isRunning()        { return tickTaskId != -1; }

    /** Returns online AFK + sleeping + BotSwapAI swapped-out (matches tick() denominator). */
    public int getTotalPool() {
        BotSwapAI s = manager.getBotSwapAI();
        return countOnlineAFKBots() + sleepingBots.size() + (s != null ? s.getSwappedOutCount() : 0);
    }

    public List<String> getSleepingNames() {
        List<String> names = new ArrayList<>(sleepingBots.size());
        for (SleepingBot sb : sleepingBots) names.add(sb.name());
        return Collections.unmodifiableList(names);
    }

    /** Returns an immutable snapshot of all sleeping entries (oldest first). */
    public List<SleepingBot> getSleepingEntries() { return List.copyOf(sleepingBots); }

    public boolean isSleeping(String name) {
        for (SleepingBot sb : sleepingBots) {
            if (sb.name().equalsIgnoreCase(name)) return true;
        }
        return false;
    }

    public String getCurrentWindowLabel() {
        ZoneId zone = safeZone();
        LocalDateTime now  = LocalDateTime.now(zone);
        LocalTime     time = now.toLocalTime();
        DayOfWeek     dow  = now.getDayOfWeek();
        for (Map<?, ?> window : resolveSchedule(dow)) {
            String s = objectToString(window.get("start"));
            String e = objectToString(window.get("end"));
            try {
                if (timeInWindow(time, LocalTime.parse(s), LocalTime.parse(e))) return s + "вҖ“" + e;
            } catch (DateTimeParseException ignored) {}
        }
        return "none";
    }

    public long getSecondsToNextWindow() {
        ZoneId zone = safeZone();
        LocalDateTime now  = LocalDateTime.now(zone);
        LocalTime     time = now.toLocalTime();
        DayOfWeek     dow  = now.getDayOfWeek();
        List<Map<?, ?>> schedule = resolveSchedule(dow);
        if (schedule.isEmpty()) return -1;
        long shortest = Long.MAX_VALUE;
        for (Map<?, ?> window : schedule) {
            try {
                LocalTime wStart = LocalTime.parse(objectToString(window.get("start")));
                long secs = time.until(wStart, ChronoUnit.SECONDS);
                if (secs <= 0) secs += 86400L;
                if (secs > 0 && secs < shortest) shortest = secs;
            } catch (DateTimeParseException ignored) {}
        }
        return shortest == Long.MAX_VALUE ? -1 : shortest;
    }

    // в”Җв”Җ Private helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private void stopTick() {
        if (tickTaskId != -1) {
            Bukkit.getScheduler().cancelTask(tickTaskId);
            tickTaskId = -1;
        }
    }

    private ZoneId safeZone() {
        try { return ZoneId.of(Config.peakHoursTimezone()); }
        catch (Exception e) { return ZoneId.of("UTC"); }
    }

    private static String objectToString(Object o) { return o == null ? "" : String.valueOf(o); }

    // в”Җв”Җ Data record в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Immutable snapshot of a bot sleeping in the peak-hours pool. */
    public record SleepingBot(String name, Location loc) {}
}

