        Material  mat   = isNext ? Material.LIME_STAINED_GLASS_PANE : Material.MAGENTA_STAINED_GLASS_PANE;
        String    label = isNext ? "вҶ’  ЙҙбҙҮxбҙӣ бҙҳбҙҖЙўбҙҮ" : "вҶҗ  бҙҳКҖбҙҮбҙ  бҙҳбҙҖЙўбҙҮ";
