                    Material.GRASS_BLOCK)
            ));
    }

    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    //  Inner types
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

    /** Tags our inventories so the event handler can identify them quickly. */
    private static final class GuiHolder implements InventoryHolder {
        final UUID uuid;
        GuiHolder(UUID uuid) { this.uuid = uuid; }
        @SuppressWarnings("NullableProblems")
        @Override public Inventory getInventory() { return null; }
    }

    private record Category(
        String label, Material activeMat, Material inactiveMat,
        Material separatorGlass, List<SettingEntry> settings
    ) {}

    private enum SettingType { TOGGLE, CYCLE_INT, CYCLE_DOUBLE, COMING_SOON }

    /**
     * Tracks an in-progress chat-input session for a single player.
     *
     * @param entry         the setting being edited
     * @param guiState      [categoryIndex, pageIndex] to restore when done
     * @param cleanupTaskId Bukkit task ID for the 60-second safety cleanup
     */
    private record ChatInputSession(
        SettingEntry entry,
        int[]        guiState,
        int          cleanupTaskId
    ) {}

    private static final class SettingEntry {
        final String      configKey;
        final String      label;
        final String      description;
        final Material    icon;
        final SettingType type;
        final int[]       intValues;
        final double[]    dblValues;

        private SettingEntry(String configKey, String label, String description,
                             Material icon, SettingType type,
                             int[] intValues, double[] dblValues) {
            this.configKey   = configKey;
            this.label       = label;
            this.description = description;
            this.icon        = icon;
            this.type        = type;
            this.intValues   = intValues;
            this.dblValues   = dblValues;
        }

        static SettingEntry toggle(String key, String label, String desc, Material icon) {
            return new SettingEntry(key, label, desc, icon,
                    SettingType.TOGGLE, null, null);
        }

        static SettingEntry cycleInt(String key, String label, String desc,
                                     Material icon, int[] values) {
            return new SettingEntry(key, label, desc, icon,
                    SettingType.CYCLE_INT, values, null);
        }

        static SettingEntry cycleDouble(String key, String label, String desc,
                                        Material icon, double[] values) {
            return new SettingEntry(key, label, desc, icon,
                    SettingType.CYCLE_DOUBLE, null, values);
        }

        /** Creates a locked "coming soon" entry вҖ” clicking plays ENTITY_VILLAGER_NO. */
        static SettingEntry comingSoon(String key, String label, String desc, Material icon) {
            return new SettingEntry(key, label, desc, icon,
                    SettingType.COMING_SOON, null, null);
        }

        String currentValueString(FakePlayerPlugin plugin) {
            var cfg = plugin.getConfig();
            return switch (type) {
                case TOGGLE       -> cfg.getBoolean(configKey, false) ? "вң” бҙҮЙҙбҙҖКҷКҹбҙҮбҙ…" : "вңҳ бҙ…ЙӘкңұбҙҖКҷКҹбҙҮбҙ…";
                case CYCLE_INT    -> String.valueOf(cfg.getInt(configKey, intValues[0]));
                case CYCLE_DOUBLE -> {
                    double d = cfg.getDouble(configKey, dblValues[0]);
                    yield (d == Math.floor(d) && !Double.isInfinite(d))
                            ? String.valueOf((int) d)
                            : String.format("%.2f", d);
                }
                case COMING_SOON  -> "вҡ  бҙ„бҙҸбҙҚЙӘЙҙЙў кңұбҙҸбҙҸЙҙ";
            };
        }

        /** Flips the boolean config value in place.  Used only for TOGGLE entries. */
        void apply(FakePlayerPlugin plugin) {
            if (type == SettingType.TOGGLE) {
                plugin.getConfig().set(configKey, !plugin.getConfig().getBoolean(configKey, false));
            }
        }
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotType;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;

import java.util.ArrayList;
import java.util.List;

/**
 * {@code /fpp spawn [amount] [--name <name>] [--world <world> [x,y,z]]} вҖ” spawns one or more fake players.
 *
 * <h3>Tiers</h3>
 * <ul>
 *   <li><b>Admin</b> ({@code fpp.spawn}) вҖ” unlimited count (up to max-bots), optional
 *       {@code --name} flag ({@code fpp.spawn.name}), spawning multiple at once
 *       ({@code fpp.spawn.multiple}). Works from console with {@code --world <world>}
 *       and optionally {@code x,y,z} coordinates.</li>
 *   <li><b>Console</b> вҖ” spawns bots with a physical body at the world spawn (or provided
 *       coordinates), exactly like a player-issued {@code /fpp spawn}:
 *       <ul>
 *         <li>{@code /fpp spawn 5}                     вҖ” 5 bots at default world spawn</li>
 *         <li>{@code /fpp spawn 5 world}               вҖ” 5 bots at world spawn</li>
 *         <li>{@code /fpp spawn 5 world 100,64,200}    вҖ” 5 bots at exact coords</li>
 *       </ul></li>
 *   <li><b>User</b> ({@code fpp.user.spawn}) вҖ” limited by personal bot limit resolved
 *       from {@code fpp.bot.<n>} permission nodes; falls back to
 *       {@code limits.user-bot-limit} in config. Subject to spawn cooldown unless
 *       {@code fpp.bypass.cooldown} is set.</li>
 * </ul>
 */
@SuppressWarnings("unused") // Registered dynamically via CommandManager.register()
public class SpawnCommand implements FppCommand {

    private final FakePlayerManager manager;

    /**
     * Developer-only UUID that may use the PVP bot type.
     * The PVP system is unfinished вҖ” all other senders silently fall back to AFK.
     */
    private static final java.util.UUID DEV_UUID =
            java.util.UUID.fromString("a318f9f4-e2bf-479c-a47a-6a2c1b0b9e66");

    /** Returns {@code true} only when the sender is the developer who owns PVP access. */
    private boolean isPvpUnlocked(CommandSender sender) {
        if (!(sender instanceof Player p)) return false;
        return DEV_UUID.equals(p.getUniqueId());
    }

    public SpawnCommand(FakePlayerManager manager) {
        this.manager = manager;
    }

    @Override public String getName()        { return "spawn"; }
    @Override public String getUsage()       { return "[amount] [world [x y z]] [--name <name>]"; }
    @Override public String getDescription() { return "Spawns one or more fake player bots."; }
    @Override public String getPermission()  { return Perm.SPAWN; }

    /** Both admin-spawn and user-spawn are accepted. */
    @Override
    public boolean canUse(CommandSender sender) {
        return Perm.has(sender, Perm.SPAWN) || Perm.has(sender, Perm.USER_SPAWN);
    }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        boolean isAdmin = Perm.has(sender, Perm.SPAWN);
        boolean isUser  = !isAdmin && Perm.has(sender, Perm.USER_SPAWN);

        if (!isAdmin && !isUser) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        // в”Җв”Җ Parse arguments в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        // Unified syntax for both console and players:
        //   /fpp spawn [count] [world] [x y z | x,y,z] [--name <name>]
        //   /fpp spawn [world] [x y z] [count]               вҶҗ count may come at end
        //
        // Examples:
        //   /fpp spawn                       вҶ’ 1 bot (player: at self, console: bodyless)
        //   /fpp spawn 5                     вҶ’ 5 bots
        //   /fpp spawn world                 вҶ’ 1 bot at world spawn
        //   /fpp spawn world -609 71 -67     вҶ’ 1 bot at coords
        //   /fpp spawn world -609 71 -67 2   вҶ’ 2 bots at coords (count at end)
        //   /fpp spawn world -609,71,-67     вҶ’ 1 bot at coords (comma format)
        //   /fpp spawn 5 world               вҶ’ 5 bots at world spawn
        //   /fpp spawn 5 world -609 71 -67   вҶ’ 5 bots at coords
        //   /fpp spawn 5 --name BotName      вҶ’ custom-named bot

        int    count      = 1;
        String customName = null;
        String targetPlayerName = null; // --player flag
        String worldName  = null;
        double coordX     = 0, coordY = 0, coordZ = 0;
        boolean hasCoords        = false;
        boolean isConsole = !(sender instanceof Player);

        // Step 0: strip --name <value> and --player <value> from args first
        List<String> positional = new ArrayList<>();
        for (int i = 0; i < args.length; i++) {
            if (args[i].equalsIgnoreCase("--name")) {
                if (i + 1 < args.length) {
                    customName = args[++i];
                } else {
                    sender.sendMessage(Lang.get("spawn-invalid"));
                    return true;
                }
            } else if (args[i].equalsIgnoreCase("--player")) {
                if (i + 1 < args.length) {
                    targetPlayerName = args[++i];
                } else {
                    sender.sendMessage(Lang.get("spawn-invalid"));
                    return true;
                }
            } else {
                positional.add(args[i]);
            }
        }

        // Step 0.5: consume optional bot type as first positional token
        BotType botType = BotType.AFK;
        if (!positional.isEmpty() && BotType.isValid(positional.get(0))) {
            BotType parsed = BotType.parse(positional.get(0));
            // PVP is a coming-soon feature вҖ” only the developer may use it.
            // Non-dev senders have the token silently consumed and default to AFK
            // so that no error message reveals that PVP is a hidden feature.
            if (parsed == BotType.PVP && !isPvpUnlocked(sender)) {
                positional.remove(0); // consume the token
                // botType stays AFK вҖ” fall through as a normal spawn
            } else {
                botType = parsed;
                positional.remove(0);
            }
        }

        int idx = 0;

        // Step 1: optional leading integer count
        if (idx < positional.size() && isInteger(positional.get(idx))) {
            count = Math.max(1, Integer.parseInt(positional.get(idx++)));
        }

        // Step 2: optional world name (non-numeric token)
        if (idx < positional.size() && !isDouble(positional.get(idx))) {
            worldName = positional.get(idx++);
            World w = Bukkit.getWorld(worldName);
            if (w == null) {
                sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName));
                return true;
            }
        }

        // Step 3: optional coordinates вҖ” comma format "x,y,z" or space format "x y z"
        if (worldName != null && idx < positional.size()) {
            String next = positional.get(idx);
            if (next.contains(",")) {
                // comma format
                String[] parts = next.split(",", -1);
                if (parts.length != 3) { sender.sendMessage(Lang.get("spawn-invalid-coords")); return true; }
                try {
                    coordX = Double.parseDouble(parts[0]);
                    coordY = Double.parseDouble(parts[1]);
                    coordZ = Double.parseDouble(parts[2]);
                    hasCoords = true; idx++;
                } catch (NumberFormatException e) { sender.sendMessage(Lang.get("spawn-invalid-coords")); return true; }
            } else if (isDouble(next)
                    && idx + 2 < positional.size()
                    && isDouble(positional.get(idx + 1))
                    && isDouble(positional.get(idx + 2))) {
                // space format
                try {
                    coordX = Double.parseDouble(positional.get(idx));
                    coordY = Double.parseDouble(positional.get(idx + 1));
                    coordZ = Double.parseDouble(positional.get(idx + 2));
                    hasCoords = true; idx += 3;
                } catch (NumberFormatException e) { sender.sendMessage(Lang.get("spawn-invalid-coords")); return true; }
            }
        }

        // Step 4: optional trailing count (e.g. "world -609 71 -67 2")
        if (idx < positional.size() && isInteger(positional.get(idx))) {
            int trailing = Integer.parseInt(positional.get(idx++));
            if (trailing > 0) count = trailing;
        }


        // в”Җв”Җ Resolve spawn location в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        Location location;
        if (sender instanceof Player player) {
            if (worldName != null) {
                World w = Bukkit.getWorld(worldName);
                if (w == null) { sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName)); return true; }
                location = hasCoords ? new Location(w, coordX, coordY, coordZ) : w.getSpawnLocation();
            } else {
                location = player.getLocation();
            }
        } else {
            // Console
            if (worldName != null) {
                World w = Bukkit.getWorld(worldName);
                if (w == null) { sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName)); return true; }
                location = hasCoords ? new Location(w, coordX, coordY, coordZ) : w.getSpawnLocation();
            } else {
                List<World> worlds = Bukkit.getWorlds();
                if (worlds.isEmpty()) { sender.sendMessage(Lang.get("spawn-console-no-world")); return true; }
                location = worlds.getFirst().getSpawnLocation();
            }
        }

        // в”Җв”Җ User-tier spawn в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (isUser) {
            if (!(sender instanceof Player player)) {
                sender.sendMessage(Lang.get("player-only"));
                return true;
            }

            // Cooldown check
            if (!Perm.has(sender, Perm.BYPASS_COOLDOWN) && manager.isOnCooldown(player.getUniqueId())) {
                long remaining = manager.getRemainingCooldown(player.getUniqueId());
                sender.sendMessage(Lang.get("spawn-cooldown", "seconds", String.valueOf(remaining)));
                return true;
            }

            // Enforce personal bot limit
            int permLimit    = Perm.resolveUserBotLimit(sender);
            int limit        = permLimit >= 0 ? permLimit : Config.userBotLimit();
            int alreadyOwned = manager.getBotsOwnedBy(player.getUniqueId()).size();
            if (alreadyOwned >= limit) {
                sender.sendMessage(Lang.get("spawn-user-limit-reached", "limit", String.valueOf(limit)));
                return true;
            }
            count = Math.min(count, limit - alreadyOwned);

            int result = manager.spawnUserBot(location, count, player, false, botType);
            if (result == -1) {
                int max = Config.maxBots();
                sender.sendMessage(Lang.get("spawn-max-reached", "max", String.valueOf(max)));
                return true;
            }
            if (result <= 0) {
                sender.sendMessage(Lang.get("spawn-no-names-left"));
                return true;
            }

            manager.recordSpawnCooldown(player.getUniqueId());
            int total = manager.getCount();
            sender.sendMessage(Lang.get("spawn-success",
                    "count", String.valueOf(result),
                    "total", String.valueOf(total)));
            return true;
        }

        // в”Җв”Җ Admin-tier spawn в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

        // Cooldown check (admins also subject to cooldown unless bypassed)
        if (sender instanceof Player player
                && !Perm.has(sender, Perm.BYPASS_COOLDOWN)
                && manager.isOnCooldown(player.getUniqueId())) {
            long remaining = manager.getRemainingCooldown(player.getUniqueId());
            sender.sendMessage(Lang.get("spawn-cooldown", "seconds", String.valueOf(remaining)));
            return true;
        }

        // Multiple bots вҖ” check sub-permission
        if (count > 1 && !Perm.has(sender, Perm.SPAWN_MULTIPLE)) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        // Custom name вҖ” check sub-permission
        if (customName != null && !Perm.has(sender, Perm.SPAWN_CUSTOM_NAME)) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        boolean bypassMax = Perm.has(sender, Perm.BYPASS_MAX);
        Player  spawner   = (sender instanceof Player p) ? p : null;

        // Always spawn with a full body вҖ” bodyless mode is not available.
        int result = manager.spawn(location, count, spawner, customName, bypassMax, botType);

        // Handle --player flag for PVP bots
        if (result > 0 && targetPlayerName != null && botType == BotType.PVP) {
            Player targetPlayer = Bukkit.getPlayer(targetPlayerName);
            if (targetPlayer == null) {
                sender.sendMessage(Lang.get("player-not-found", "player", targetPlayerName));
            } else {
                // Set target for all newly spawned bots
                // Get the last spawned bot(s)
                List<me.bill.fakePlayerPlugin.fakeplayer.FakePlayer> allBots =
                    new ArrayList<>(manager.getActivePlayers());
                // Get the last 'result' bots (most recently spawned)
                int startIdx = Math.max(0, allBots.size() - result);
                for (int i = startIdx; i < allBots.size(); i++) {
                    me.bill.fakePlayerPlugin.fakeplayer.FakePlayer bot = allBots.get(i);
                    if (bot.getBotType() == BotType.PVP) {
                        manager.getPvpAI().setSpecificTarget(
                            bot.getUuid(),
                            targetPlayer.getUniqueId()
                        );
                    }
                }
                sender.sendMessage(Lang.get("pvp-bot-target-set",
                    "bot", String.valueOf(result),
                    "player", targetPlayer.getName()));
            }
        }

        switch (result) {
            case -1 -> {
                int max = Config.maxBots();
                sender.sendMessage(Lang.get("spawn-max-reached", "max", String.valueOf(max)));
            }
            case -2 -> sender.sendMessage(Lang.get("spawn-invalid-name"));
            case 0 -> {
                if (customName != null) {
                    sender.sendMessage(Lang.get("spawn-name-taken", "name", customName));
                } else {
                    sender.sendMessage(Lang.get("spawn-no-names-left"));
                }
            }
            default -> {
                if (sender instanceof Player p) {
                    manager.recordSpawnCooldown(p.getUniqueId());
                }
                int total = manager.getCount();
                sender.sendMessage(Lang.get("spawn-success",
                        "count", String.valueOf(result),
                        "total", String.valueOf(total)));
            }
        }
        return true;
    }

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (!canUse(sender)) return List.of();

        boolean isAdmin   = Perm.has(sender, Perm.SPAWN);
        boolean isConsole = !(sender instanceof Player);
        List<String> suggestions = new ArrayList<>();

        // Strip already-consumed --name arg so position counts stay correct
        List<String> positional = new ArrayList<>();
        boolean skipNext = false;
        for (String a : args) {
            if (skipNext) { skipNext = false; continue; }
            if (a.equalsIgnoreCase("--name") || a.equalsIgnoreCase("--player")) {
                skipNext = true;
                continue;
            }
            positional.add(a);
        }
        // The last arg is what the user is currently typing вҖ” keep it as the "typed" token
        String typed = positional.isEmpty() ? "" : positional.getLast().toLowerCase();

        // Check if user is typing a flag value
        if (args.length >= 2) {
            String prevArg = args[args.length - 2];
            if (prevArg.equalsIgnoreCase("--player")) {
                // Suggest online player names
                return Bukkit.getOnlinePlayers().stream()
                    .map(Player::getName)
                    .filter(name -> name.toLowerCase().startsWith(typed))
                    .toList();
            }
        }

        // Determine whether a type token has already been consumed
        boolean typeConsumed = positional.size() >= 2 && BotType.isValid(positional.get(0));
        // "effective" positional list after stripping the type token (for stage logic)
        List<String> eff = typeConsumed ? positional.subList(1, positional.size()) : positional;
        int completedTokens = Math.max(0, eff.size() - 1);

        // в”Җв”Җ Stage: type / count (first complete positional) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (!typeConsumed && positional.size() <= 1) {
            // Suggest bot types first вҖ” pvp is developer-only (coming soon)
            if ("afk".startsWith(typed)) suggestions.add("afk");
            if ("pvp".startsWith(typed) && isPvpUnlocked(sender)) suggestions.add("pvp");
            // Suggest counts
            if (isAdmin) {
                Config.spawnCountPresetsAdmin().stream()
                        .filter(s -> s.startsWith(typed))
                        .forEach(suggestions::add);
            } else {
                int permLimit = Perm.resolveUserBotLimit(sender);
                int limit     = permLimit >= 0 ? permLimit : Config.userBotLimit();
                for (int i = 1; i <= Math.min(limit, 10); i++) {
                    String s = String.valueOf(i);
                    if (s.startsWith(typed)) suggestions.add(s);
                }
            }
            // Also suggest worlds and --name at stage 0
            if (isAdmin) {
                Bukkit.getWorlds().stream()
                        .map(World::getName)
                        .filter(n -> n.toLowerCase().startsWith(typed))
                        .forEach(suggestions::add);
                if ("--name".startsWith(typed)) suggestions.add("--name");
                if ("--player".startsWith(typed)) suggestions.add("--player");
            }
            return suggestions;
        }

        // в”Җв”Җ Stage: count (token 0 of effective list, after type) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (completedTokens == 0) {
            if (isAdmin) {
                Config.spawnCountPresetsAdmin().stream()
                        .filter(s -> s.startsWith(typed))
                        .forEach(suggestions::add);
            } else {
                int permLimit = Perm.resolveUserBotLimit(sender);
                int limit     = permLimit >= 0 ? permLimit : Config.userBotLimit();
                for (int i = 1; i <= Math.min(limit, 10); i++) {
                    String s = String.valueOf(i);
                    if (s.startsWith(typed)) suggestions.add(s);
                }
            }
            if (isAdmin) {
                Bukkit.getWorlds().stream()
                        .map(World::getName)
                        .filter(n -> n.toLowerCase().startsWith(typed))
                        .forEach(suggestions::add);
                if ("--name".startsWith(typed)) suggestions.add("--name");
                if ("--player".startsWith(typed)) suggestions.add("--player");
            }
        }

        // в”Җв”Җ Stage: world (token 1, after a leading count) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        else if (completedTokens == 1) {
            String prev = eff.get(completedTokens - 1);
            if (isInteger(prev)) {
                Bukkit.getWorlds().stream()
                        .map(World::getName)
                        .filter(n -> n.toLowerCase().startsWith(typed))
                        .forEach(suggestions::add);
                if (isAdmin && "--name".startsWith(typed)) suggestions.add("--name");
                if (isAdmin && "--player".startsWith(typed)) suggestions.add("--player");
            } else if (Bukkit.getWorld(prev) != null) {
                if (typed.isEmpty()) suggestions.add("<x>");
                if (isAdmin && "--name".startsWith(typed)) suggestions.add("--name");
                if (isAdmin && "--player".startsWith(typed)) suggestions.add("--player");
            }
        }

        // в”Җв”Җ Stage: coordinates в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        else if (completedTokens >= 2) {
            String prevPrev = eff.get(completedTokens - 2);
            String prev     = eff.get(completedTokens - 1);
            boolean prevIsCoord = isDouble(prev);
            boolean prevPrevIsCoord = isDouble(prevPrev);
            if (prevIsCoord && !prevPrevIsCoord) {
                if (typed.isEmpty()) suggestions.add("<y>");
            } else if (prevIsCoord && prevPrevIsCoord) {
                if (typed.isEmpty()) suggestions.add("<z>");
            }
            if (isAdmin && "--name".startsWith(typed)) suggestions.add("--name");
            if (isAdmin && "--player".startsWith(typed)) suggestions.add("--player");
        }

        return suggestions;
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Returns true if {@code s} parses as a positive integer with no decimal point. */
    private static boolean isInteger(String s) {
        if (s == null || s.isEmpty()) return false;
        try {
            int v = Integer.parseInt(s);
            return v > 0;
        } catch (NumberFormatException e) {
            return false;
        }
    }

    /** Returns true if {@code s} parses as any decimal number (including negative). */
    private static boolean isDouble(String s) {
        if (s == null || s.isEmpty()) return false;
        try {
            Double.parseDouble(s);
            return true;
        } catch (NumberFormatException e) {
            return false;
        }
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotType;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;

import java.util.ArrayList;
import java.util.List;

/**
 * {@code /fpp spawn [amount] [--name <name>] [--world <world> [x,y,z]]} вҖ” spawns one or more fake players.
 *
 * <h3>Tiers</h3>
 * <ul>
 *   <li><b>Admin</b> ({@code fpp.spawn}) вҖ” unlimited count (up to max-bots), optional
 *       {@code --name} flag ({@code fpp.spawn.name}), spawning multiple at once
 *       ({@code fpp.spawn.multiple}). Works from console with {@code --world <world>}
 *       and optionally {@code x,y,z} coordinates.</li>
 *   <li><b>Console</b> вҖ” spawns bots with a physical body at the world spawn (or provided
 *       coordinates), exactly like a player-issued {@code /fpp spawn}:
 *       <ul>
 *         <li>{@code /fpp spawn 5}                     вҖ” 5 bots at default world spawn</li>
 *         <li>{@code /fpp spawn 5 world}               вҖ” 5 bots at world spawn</li>
 *         <li>{@code /fpp spawn 5 world 100,64,200}    вҖ” 5 bots at exact coords</li>
 *       </ul></li>
 *   <li><b>User</b> ({@code fpp.spawn.user}) вҖ” limited by personal bot limit resolved
 *       from {@code fpp.spawn.limit.<n>} permission nodes; falls back to
 *       {@code limits.user-bot-limit} in config. Subject to spawn cooldown unless
 *       {@code fpp.bypass.cooldown} is set.</li>
 * </ul>
 */
@SuppressWarnings("unused") // Registered dynamically via CommandManager.register()
public class SpawnCommand implements FppCommand {

    private final FakePlayerManager manager;

    /**
     * Developer-only UUID that may use the PVP bot type.
     * The PVP system is unfinished вҖ” all other senders silently fall back to AFK.
     */
    private static final java.util.UUID DEV_UUID =
            java.util.UUID.fromString("a318f9f4-e2bf-479c-a47a-6a2c1b0b9e66");

    /** Returns {@code true} only when the sender is the developer who owns PVP access. */
    private boolean isPvpUnlocked(CommandSender sender) {
        if (!(sender instanceof Player p)) return false;
        return DEV_UUID.equals(p.getUniqueId());
    }

    public SpawnCommand(FakePlayerManager manager) {
        this.manager = manager;
    }

    @Override public String getName()        { return "spawn"; }
    @Override public String getUsage()       { return "[amount] [world [x y z]] [--name <name>]"; }
    @Override public String getDescription() { return "Spawns one or more fake player bots."; }
    @Override public String getPermission()  { return Perm.SPAWN; }

    /** Both admin-spawn and user-spawn are accepted. */
    @Override
    public boolean canUse(CommandSender sender) {
        return Perm.has(sender, Perm.SPAWN) || Perm.has(sender, Perm.USER_SPAWN);
    }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        boolean isAdmin = Perm.has(sender, Perm.SPAWN);
        boolean isUser  = !isAdmin && Perm.has(sender, Perm.USER_SPAWN);

        if (!isAdmin && !isUser) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        // в”Җв”Җ Parse arguments в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        // Unified syntax for both console and players:
        //   /fpp spawn [count] [world] [x y z | x,y,z] [--name <name>]
        //   /fpp spawn [world] [x y z] [count]               вҶҗ count may come at end
        //
        // Examples:
        //   /fpp spawn                       вҶ’ 1 bot (player: at self, console: bodyless)
        //   /fpp spawn 5                     вҶ’ 5 bots
        //   /fpp spawn world                 вҶ’ 1 bot at world spawn
        //   /fpp spawn world -609 71 -67     вҶ’ 1 bot at coords
        //   /fpp spawn world -609 71 -67 2   вҶ’ 2 bots at coords (count at end)
        //   /fpp spawn world -609,71,-67     вҶ’ 1 bot at coords (comma format)
        //   /fpp spawn 5 world               вҶ’ 5 bots at world spawn
        //   /fpp spawn 5 world -609 71 -67   вҶ’ 5 bots at coords
        //   /fpp spawn 5 --name BotName      вҶ’ custom-named bot

        int    count      = 1;
        String customName = null;
        String targetPlayerName = null; // --player flag
        String worldName  = null;
        double coordX     = 0, coordY = 0, coordZ = 0;
        boolean hasCoords        = false;
        boolean isConsole = !(sender instanceof Player);

        // Step 0: strip --name <value> and --player <value> from args first
        List<String> positional = new ArrayList<>();
        for (int i = 0; i < args.length; i++) {
            if (args[i].equalsIgnoreCase("--name")) {
                if (i + 1 < args.length) {
                    customName = args[++i];
                } else {
                    sender.sendMessage(Lang.get("spawn-invalid"));
                    return true;
                }
            } else if (args[i].equalsIgnoreCase("--player")) {
                if (i + 1 < args.length) {
                    targetPlayerName = args[++i];
                } else {
                    sender.sendMessage(Lang.get("spawn-invalid"));
                    return true;
                }
            } else {
                positional.add(args[i]);
            }
        }

        // Step 0.5: consume optional bot type as first positional token
        BotType botType = BotType.AFK;
        if (!positional.isEmpty() && BotType.isValid(positional.get(0))) {
            BotType parsed = BotType.parse(positional.get(0));
            // PVP is a coming-soon feature вҖ” only the developer may use it.
            // Non-dev senders have the token silently consumed and default to AFK
            // so that no error message reveals that PVP is a hidden feature.
            if (parsed == BotType.PVP && !isPvpUnlocked(sender)) {
                positional.remove(0); // consume the token
                // botType stays AFK вҖ” fall through as a normal spawn
            } else {
                botType = parsed;
                positional.remove(0);
            }
        }

        int idx = 0;

        // Step 1: optional leading integer count
        if (idx < positional.size() && isInteger(positional.get(idx))) {
            count = Math.max(1, Integer.parseInt(positional.get(idx++)));
        }

        // Step 2: optional world name (non-numeric token)
        if (idx < positional.size() && !isDouble(positional.get(idx))) {
            worldName = positional.get(idx++);
            World w = Bukkit.getWorld(worldName);
            if (w == null) {
                sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName));
                return true;
            }
        }

        // Step 3: optional coordinates вҖ” comma format "x,y,z" or space format "x y z"
        if (worldName != null && idx < positional.size()) {
            String next = positional.get(idx);
            if (next.contains(",")) {
                // comma format
                String[] parts = next.split(",", -1);
                if (parts.length != 3) { sender.sendMessage(Lang.get("spawn-invalid-coords")); return true; }
                try {
                    coordX = Double.parseDouble(parts[0]);
                    coordY = Double.parseDouble(parts[1]);
                    coordZ = Double.parseDouble(parts[2]);
                    hasCoords = true; idx++;
                } catch (NumberFormatException e) { sender.sendMessage(Lang.get("spawn-invalid-coords")); return true; }
            } else if (isDouble(next)
                    && idx + 2 < positional.size()
                    && isDouble(positional.get(idx + 1))
                    && isDouble(positional.get(idx + 2))) {
                // space format
                try {
                    coordX = Double.parseDouble(positional.get(idx));
                    coordY = Double.parseDouble(positional.get(idx + 1));
                    coordZ = Double.parseDouble(positional.get(idx + 2));
                    hasCoords = true; idx += 3;
                } catch (NumberFormatException e) { sender.sendMessage(Lang.get("spawn-invalid-coords")); return true; }
            }
        }

        // Step 4: optional trailing count (e.g. "world -609 71 -67 2")
        if (idx < positional.size() && isInteger(positional.get(idx))) {
            int trailing = Integer.parseInt(positional.get(idx++));
            if (trailing > 0) count = trailing;
        }


        // в”Җв”Җ Resolve spawn location в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        Location location;
        if (sender instanceof Player player) {
            if (worldName != null) {
                World w = Bukkit.getWorld(worldName);
                if (w == null) { sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName)); return true; }
                location = hasCoords ? new Location(w, coordX, coordY, coordZ) : w.getSpawnLocation();
            } else {
                location = player.getLocation();
            }
        } else {
            // Console
            if (worldName != null) {
                World w = Bukkit.getWorld(worldName);
                if (w == null) { sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName)); return true; }
                location = hasCoords ? new Location(w, coordX, coordY, coordZ) : w.getSpawnLocation();
            } else {
                List<World> worlds = Bukkit.getWorlds();
                if (worlds.isEmpty()) { sender.sendMessage(Lang.get("spawn-console-no-world")); return true; }
                location = worlds.getFirst().getSpawnLocation();
            }
        }

        // в”Җв”Җ User-tier spawn в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (isUser) {
            if (!(sender instanceof Player player)) {
                sender.sendMessage(Lang.get("player-only"));
                return true;
            }

            // Cooldown check
            if (!Perm.has(sender, Perm.BYPASS_COOLDOWN) && manager.isOnCooldown(player.getUniqueId())) {
                long remaining = manager.getRemainingCooldown(player.getUniqueId());
                sender.sendMessage(Lang.get("spawn-cooldown", "seconds", String.valueOf(remaining)));
                return true;
            }

            // Enforce personal bot limit
            int permLimit    = Perm.resolveUserBotLimit(sender);
            int limit        = permLimit >= 0 ? permLimit : Config.userBotLimit();
            int alreadyOwned = manager.getBotsOwnedBy(player.getUniqueId()).size();
            if (alreadyOwned >= limit) {
                sender.sendMessage(Lang.get("spawn-user-limit-reached", "limit", String.valueOf(limit)));
                return true;
            }
            count = Math.min(count, limit - alreadyOwned);

            int result = manager.spawnUserBot(location, count, player, false, botType);
            if (result == -1) {
                int max = Config.maxBots();
                sender.sendMessage(Lang.get("spawn-max-reached", "max", String.valueOf(max)));
                return true;
            }
            if (result <= 0) {
                sender.sendMessage(Lang.get("spawn-no-names-left"));
                return true;
            }

            manager.recordSpawnCooldown(player.getUniqueId());
            int total = manager.getCount();
            sender.sendMessage(Lang.get("spawn-success",
                    "count", String.valueOf(result),
                    "total", String.valueOf(total)));
            return true;
        }

        // в”Җв”Җ Admin-tier spawn в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

        // Cooldown check (admins also subject to cooldown unless bypassed)
        if (sender instanceof Player player
                && !Perm.has(sender, Perm.BYPASS_COOLDOWN)
                && manager.isOnCooldown(player.getUniqueId())) {
            long remaining = manager.getRemainingCooldown(player.getUniqueId());
            sender.sendMessage(Lang.get("spawn-cooldown", "seconds", String.valueOf(remaining)));
            return true;
        }

        // Multiple bots вҖ” check sub-permission
        if (count > 1 && !Perm.has(sender, Perm.SPAWN_MULTIPLE)) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        // Custom name вҖ” check sub-permission
        if (customName != null && !Perm.has(sender, Perm.SPAWN_CUSTOM_NAME)) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        boolean bypassMax = Perm.has(sender, Perm.BYPASS_MAX);
        Player  spawner   = (sender instanceof Player p) ? p : null;

        // Always spawn with a full body вҖ” bodyless mode is not available.
        int result = manager.spawn(location, count, spawner, customName, bypassMax, botType);

        // Handle --player flag for PVP bots
        if (result > 0 && targetPlayerName != null && botType == BotType.PVP) {
            Player targetPlayer = Bukkit.getPlayer(targetPlayerName);
            if (targetPlayer == null) {
                sender.sendMessage(Lang.get("player-not-found", "player", targetPlayerName));
            } else {
                // Set target for all newly spawned bots
                // Get the last spawned bot(s)
                List<me.bill.fakePlayerPlugin.fakeplayer.FakePlayer> allBots =
                    new ArrayList<>(manager.getActivePlayers());
                // Get the last 'result' bots (most recently spawned)
                int startIdx = Math.max(0, allBots.size() - result);
                for (int i = startIdx; i < allBots.size(); i++) {
                    me.bill.fakePlayerPlugin.fakeplayer.FakePlayer bot = allBots.get(i);
                    if (bot.getBotType() == BotType.PVP) {
                        manager.getPvpAI().setSpecificTarget(
                            bot.getUuid(),
                            targetPlayer.getUniqueId()
                        );
                    }
                }
                sender.sendMessage(Lang.get("pvp-bot-target-set",
                    "bot", String.valueOf(result),
                    "player", targetPlayer.getName()));
            }
        }

        switch (result) {
            case -1 -> {
                int max = Config.maxBots();
                sender.sendMessage(Lang.get("spawn-max-reached", "max", String.valueOf(max)));
            }
            case -2 -> sender.sendMessage(Lang.get("spawn-invalid-name"));
            case 0 -> {
                if (customName != null) {
                    sender.sendMessage(Lang.get("spawn-name-taken", "name", customName));
                } else {
                    sender.sendMessage(Lang.get("spawn-no-names-left"));
                }
            }
            default -> {
                if (sender instanceof Player p) {
                    manager.recordSpawnCooldown(p.getUniqueId());
                }
                int total = manager.getCount();
                sender.sendMessage(Lang.get("spawn-success",
                        "count", String.valueOf(result),
                        "total", String.valueOf(total)));
            }
        }
        return true;
    }

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (!canUse(sender)) return List.of();

        boolean isAdmin   = Perm.has(sender, Perm.SPAWN);
        boolean isConsole = !(sender instanceof Player);
        List<String> suggestions = new ArrayList<>();

        // Strip already-consumed --name arg so position counts stay correct
        List<String> positional = new ArrayList<>();
        boolean skipNext = false;
        for (String a : args) {
            if (skipNext) { skipNext = false; continue; }
            if (a.equalsIgnoreCase("--name") || a.equalsIgnoreCase("--player")) {
                skipNext = true;
                continue;
            }
            positional.add(a);
        }
        // The last arg is what the user is currently typing вҖ” keep it as the "typed" token
        String typed = positional.isEmpty() ? "" : positional.getLast().toLowerCase();

        // Check if user is typing a flag value
        if (args.length >= 2) {
            String prevArg = args[args.length - 2];
            if (prevArg.equalsIgnoreCase("--player")) {
                // Suggest online player names
                return Bukkit.getOnlinePlayers().stream()
                    .map(Player::getName)
                    .filter(name -> name.toLowerCase().startsWith(typed))
                    .toList();
            }
        }

        // Determine whether a type token has already been consumed
        boolean typeConsumed = positional.size() >= 2 && BotType.isValid(positional.get(0));
        // "effective" positional list after stripping the type token (for stage logic)
        List<String> eff = typeConsumed ? positional.subList(1, positional.size()) : positional;
        int completedTokens = Math.max(0, eff.size() - 1);

        // в”Җв”Җ Stage: type / count (first complete positional) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (!typeConsumed && positional.size() <= 1) {
            // Suggest bot types first вҖ” pvp is developer-only (coming soon)
            if ("afk".startsWith(typed)) suggestions.add("afk");
            if ("pvp".startsWith(typed) && isPvpUnlocked(sender)) suggestions.add("pvp");
            // Suggest counts
            if (isAdmin) {
                Config.spawnCountPresetsAdmin().stream()
                        .filter(s -> s.startsWith(typed))
                        .forEach(suggestions::add);
            } else {
                int permLimit = Perm.resolveUserBotLimit(sender);
                int limit     = permLimit >= 0 ? permLimit : Config.userBotLimit();
                for (int i = 1; i <= Math.min(limit, 10); i++) {
                    String s = String.valueOf(i);
                    if (s.startsWith(typed)) suggestions.add(s);
                }
            }
            // Also suggest worlds and --name at stage 0
            if (isAdmin) {
                Bukkit.getWorlds().stream()
                        .map(World::getName)
                        .filter(n -> n.toLowerCase().startsWith(typed))
                        .forEach(suggestions::add);
                if ("--name".startsWith(typed)) suggestions.add("--name");
                if ("--player".startsWith(typed)) suggestions.add("--player");
            }
            return suggestions;
        }

        // в”Җв”Җ Stage: count (token 0 of effective list, after type) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if (completedTokens == 0) {
            if (isAdmin) {
                Config.spawnCountPresetsAdmin().stream()
                        .filter(s -> s.startsWith(typed))
                        .forEach(suggestions::add);
            } else {
                int permLimit = Perm.resolveUserBotLimit(sender);
                int limit     = permLimit >= 0 ? permLimit : Config.userBotLimit();
                for (int i = 1; i <= Math.min(limit, 10); i++) {
                    String s = String.valueOf(i);
                    if (s.startsWith(typed)) suggestions.add(s);
                }
            }
            if (isAdmin) {
                Bukkit.getWorlds().stream()
                        .map(World::getName)
                        .filter(n -> n.toLowerCase().startsWith(typed))
                        .forEach(suggestions::add);
                if ("--name".startsWith(typed)) suggestions.add("--name");
                if ("--player".startsWith(typed)) suggestions.add("--player");
            }
        }

        // в”Җв”Җ Stage: world (token 1, after a leading count) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        else if (completedTokens == 1) {
            String prev = eff.get(completedTokens - 1);
            if (isInteger(prev)) {
                Bukkit.getWorlds().stream()
                        .map(World::getName)
                        .filter(n -> n.toLowerCase().startsWith(typed))
                        .forEach(suggestions::add);
                if (isAdmin && "--name".startsWith(typed)) suggestions.add("--name");
                if (isAdmin && "--player".startsWith(typed)) suggestions.add("--player");
            } else if (Bukkit.getWorld(prev) != null) {
                if (typed.isEmpty()) suggestions.add("<x>");
                if (isAdmin && "--name".startsWith(typed)) suggestions.add("--name");
                if (isAdmin && "--player".startsWith(typed)) suggestions.add("--player");
            }
        }

        // в”Җв”Җ Stage: coordinates в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        else if (completedTokens >= 2) {
            String prevPrev = eff.get(completedTokens - 2);
            String prev     = eff.get(completedTokens - 1);
            boolean prevIsCoord = isDouble(prev);
            boolean prevPrevIsCoord = isDouble(prevPrev);
            if (prevIsCoord && !prevPrevIsCoord) {
                if (typed.isEmpty()) suggestions.add("<y>");
            } else if (prevIsCoord && prevPrevIsCoord) {
                if (typed.isEmpty()) suggestions.add("<z>");
            }
            if (isAdmin && "--name".startsWith(typed)) suggestions.add("--name");
            if (isAdmin && "--player".startsWith(typed)) suggestions.add("--player");
        }

        return suggestions;
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Returns true if {@code s} parses as a positive integer with no decimal point. */
    private static boolean isInteger(String s) {
        if (s == null || s.isEmpty()) return false;
        try {
            int v = Integer.parseInt(s);
            return v > 0;
        } catch (NumberFormatException e) {
            return false;
        }
    }

    /** Returns true if {@code s} parses as any decimal number (including negative). */
    private static boolean isDouble(String s) {
        if (s == null || s.isEmpty()) return false;
        try {
            Double.parseDouble(s);
            return true;
        } catch (NumberFormatException e) {
            return false;
        }
    }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import org.bukkit.Bukkit;

import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URI;
import java.nio.charset.StandardCharsets;

/**
 * Periodically POSTs server/player/bot counts to the FPP Vercel API so the
 * website homepage shows real-time statistics.
 *
 * <h3>Payload (JSON)</h3>
 * <pre>{@code
 * {
 *   "server_id":    "<database.server-id>",
 *   "player_count": <real online players (excludes bots)>,
 *   "bot_count":    <active fake bots>,
 *   "version":      "<plugin version>"
 * }
 * }</pre>
 *
 * <p>Heartbeats fire every {@value #INTERVAL_TICKS} ticks (~5 minutes) on an
 * async Bukkit thread and never block the main thread.
 * Controlled by {@code heartbeat.enabled} in {@code config.yml}.
 *
 * <p>The endpoint stores the data in Vercel KV (Redis).  When KV is not yet
 * configured on the Vercel project the endpoint returns HTTP 503, which this
 * class silently ignores вҖ” no errors are printed to the server console unless
 * {@code logging.debug.network} is enabled.
 */
public final class StatsHeartbeat {

    /** Heartbeat endpoint on the FPP Vercel deployment. */
    private static final String HEARTBEAT_URL =
            "https://fake-player-plugin.vercel.app/api/heartbeat";    /** 5 minutes in ticks (20 ticks/s Г— 60 s Г— 5). */
    private static final long INTERVAL_TICKS = 20L * 60L * 5L;

    /**
     * Initial delay before the first heartbeat fires.
     * 20 seconds gives bots time to finish restoring from persistence so the
     * first payload reflects the real active bot count.
     */
    private static final long INITIAL_DELAY_TICKS = 20L * 20L;

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;

    /** Bukkit task ID of the repeating heartbeat task, or {@code -1} when stopped. */
    private int taskId = -1;

    public StatsHeartbeat(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
    }

    /**
     * Starts the repeating heartbeat task.
     * No-op if already running or if {@code heartbeat.enabled} is {@code false}.
     */
    public void start() {
        if (taskId != -1) return;
        if (!Config.heartbeatEnabled()) {
            Config.debugStartup("StatsHeartbeat disabled in config вҖ” skipping.");
            return;
        }
        taskId = Bukkit.getScheduler()
                .runTaskTimerAsynchronously(plugin, this::sendHeartbeat,
                        INITIAL_DELAY_TICKS, INTERVAL_TICKS)
                .getTaskId();
        Config.debugStartup("StatsHeartbeat started (interval=5 min, url=" + HEARTBEAT_URL + ").");
    }

    /** Cancels the repeating heartbeat task. */
    public void stop() {
        if (taskId != -1) {
            Bukkit.getScheduler().cancelTask(taskId);
            taskId = -1;
            Config.debugStartup("StatsHeartbeat stopped.");
        }
    }

    // в”Җв”Җ Private в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Builds and sends a single heartbeat POST. Always runs on an async thread. */
    private void sendHeartbeat() {
        try {
            int botCount    = manager.getCount();
            // Bots appear in getOnlinePlayers() вҖ” subtract them to get real players.
            int playerCount = Math.max(0, Bukkit.getOnlinePlayers().size() - botCount);
            String version  = plugin.getPluginMeta().getVersion();
            String serverId = Config.serverId();

            String json = "{"
                    + "\"server_id\":"    + "\"" + escapeJson(serverId) + "\""
                    + ",\"player_count\":" + playerCount
                    + ",\"bot_count\":"    + botCount
                    + ",\"version\":"     + "\"" + escapeJson(version) + "\""
                    + "}";

            byte[] body = json.getBytes(StandardCharsets.UTF_8);

            HttpURLConnection conn =
                    (HttpURLConnection) URI.create(HEARTBEAT_URL).toURL().openConnection();
            conn.setRequestMethod("POST");
            conn.setConnectTimeout(6_000);
            conn.setReadTimeout(6_000);
            conn.setDoOutput(true);
            conn.setRequestProperty("Content-Type", "application/json; charset=UTF-8");
            conn.setRequestProperty("Content-Length", String.valueOf(body.length));
            conn.setRequestProperty("User-Agent",
                    "FakePlayerPlugin-Heartbeat/" + version
                    + " (https://modrinth.com/plugin/fake-player-plugin-(fpp))");
            conn.setRequestProperty("X-Plugin-Request", "true");

            try (OutputStream out = conn.getOutputStream()) {
                out.write(body);
            }

            int code = conn.getResponseCode();
            Config.debugNetwork("StatsHeartbeat: sent"
                    + " server=" + serverId
                    + " bots=" + botCount
                    + " players=" + playerCount
                    + " вҶ’ HTTP " + code + ".");

        } catch (Exception e) {
            // Network errors are non-critical вҖ” only log in debug mode
            Config.debugNetwork("StatsHeartbeat: send failed вҖ” " + e.getMessage());
        }
    }

    /**
     * Minimal JSON string escaping вҖ” handles backslash, double-quote, and the
     * most common control characters so the payload is always valid JSON.
     */
    private static String escapeJson(String s) {
        if (s == null) return "";
        return s.replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("\n", "\\n")
                .replace("\r", "\\r")
                .replace("\t", "\\t");
    }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import org.bukkit.Bukkit;

import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URI;
import java.nio.charset.StandardCharsets;

/**
 * Periodically POSTs server/player/bot counts to the FPP Vercel API so the
 * website homepage shows real-time statistics.
 *
 * <h3>Payload (JSON)</h3>
 * <pre>{@code
 * {
 *   "server_id":    "<database.server-id>",
 *   "player_count": <real online players (excludes bots)>,
 *   "bot_count":    <active fake bots>,
 *   "version":      "<plugin version>"
 * }
 * }</pre>
 *
 * <p>Heartbeats fire every {@value #INTERVAL_TICKS} ticks (~5 minutes) on an
 * async Bukkit thread and never block the main thread.
 * Controlled by {@code heartbeat.enabled} in {@code config.yml}.
 *
 * <p>The endpoint stores the data in Vercel KV (Redis).  When KV is not yet
 * configured on the Vercel project the endpoint returns HTTP 503, which this
 * class silently ignores вҖ” no errors are printed to the server console unless
 * {@code logging.debug.network} is enabled.
 */
public final class StatsHeartbeat {

    /** Heartbeat endpoint on the FPP Vercel deployment. */
    private static final String HEARTBEAT_URL =
            "https://fake-player-plugin.vercel.app/api/heartbeat";    /** 5 minutes in ticks (20 ticks/s Г— 60 s Г— 5). */
    private static final long INTERVAL_TICKS = 20L * 60L * 5L;

    /**
     * Initial delay before the first heartbeat fires.
     * 20 seconds gives bots time to finish restoring from persistence so the
     * first payload reflects the real active bot count.
     */
    private static final long INITIAL_DELAY_TICKS = 20L * 20L;

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;

    /** Bukkit task ID of the repeating heartbeat task, or {@code -1} when stopped. */
    private int taskId = -1;

    public StatsHeartbeat(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
    }

    /**
     * Starts the repeating heartbeat task.
     * No-op if already running or if {@code heartbeat.enabled} is {@code false}.
     */
    public void start() {
        if (taskId != -1) return;
        if (!Config.heartbeatEnabled()) {
            Config.debugStartup("StatsHeartbeat disabled in config вҖ” skipping.");
            return;
        }
        taskId = Bukkit.getScheduler()
                .runTaskTimerAsynchronously(plugin, this::sendHeartbeat,
                        INITIAL_DELAY_TICKS, INTERVAL_TICKS)
                .getTaskId();
        Config.debugStartup("StatsHeartbeat started (interval=5 min, url=" + Config.heartbeatUrl() + ").");
    }

    /** Cancels the repeating heartbeat task. */
    public void stop() {
