        if (args.length == 2 && args[0].equalsIgnoreCase("now")) {
            String pfx = args[1].toLowerCase();
            return manager.getActiveNames().stream()
                    .filter(n -> n.toLowerCase().startsWith(pfx))
                    .collect(Collectors.toList());
        }
        return List.of();
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotPathfinder;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.fakeplayer.NmsPlayerSpawner;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import net.minecraft.core.Direction;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.InteractionHand;
import net.minecraft.world.entity.decoration.ItemFrame;
import net.minecraft.world.level.ClipContext;
import net.minecraft.world.phys.AABB;
import net.minecraft.world.phys.BlockHitResult;
import net.minecraft.world.phys.EntityHitResult;
import net.minecraft.world.phys.HitResult;
import net.minecraft.world.phys.Vec3;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.command.CommandSender;
import org.bukkit.craftbukkit.entity.CraftPlayer;
import org.bukkit.entity.Player;
import org.bukkit.scheduler.BukkitRunnable;
import org.bukkit.scheduler.BukkitTask;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Two-phase use command - mirrors the structure of {@link MineCommand}.
 *
 * <h3>Phase 1 - Navigation</h3>
 * The bot walks/sprints to the sender's exact position using A* pathfinding.
 * Normal physics, knockback, and pushable are all active during this phase.
 *
 * <h3>Phase 2 - Right-click loop</h3>
 * Once the bot arrives (XZ вүӨ {@value #ARRIVAL_DIST}) it is snapped to the exact
 * spot, its position is locked via {@code FakePlayerManager.lockForMining()},
 * head-AI is suppressed, and the right-click loop begins.
 *
 * <p>On each tick the bot's look-direction is raycast (4.5 survival / 5 creative).
 * Three interaction paths are attempted per hand:
 * <ol>
 *   <li><b>Block</b> - {@code gameMode.useItemOn()}</li>
 *   <li><b>Entity</b> - {@code interactAt()} + {@code interactOn()}</li>
 *   <li><b>Air / item</b> - {@code gameMode.useItem()}</li>
 * </ol>
 * A 3-tick freeze is applied after each successful action.
 *
 * <p>Usage:
 * <ul>
 *   <li>{@code /fpp use <bot>}      - walk to your spot, right-click continuously.</li>
 *   <li>{@code /fpp use <bot> once} - walk to your spot, right-click once, stop.</li>
 *   <li>{@code /fpp use <bot> stop} - stop navigating / stop right-clicking.</li>
 *   <li>{@code /fpp use stop}       - stop all bots.</li>
 * </ul>
 *
 * <p>Permission: {@link Perm#USE_CMD} ({@code fpp.useitem}), default {@code op}.
 */
public final class UseCommand implements FppCommand {

    // в”Җв”Җ Tuning constants (mirrors MoveCommand / MineCommand) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private static final double ARRIVAL_DIST    = 1.2;
    private static final double SPRINT_DIST     = 6.0;
    private static final double WP_ARRIVE_XZ    = 0.65;
    private static final int    RECALC_INTERVAL = 60;
    private static final int    STUCK_TICKS     = 8;
    private static final double STUCK_THRESHOLD = 0.04;

    // в”Җв”Җ Fields в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;

    /** Phase-1 navigation tasks (walking to the use spot). */
    private final Map<UUID, BukkitTask> navTasks  = new ConcurrentHashMap<>();
    /** Phase-2 right-click task IDs. */
    private final Map<UUID, Integer>    useTasks  = new ConcurrentHashMap<>();
    /** Active use lock locations per bot (populated at lock-and-use start). */
    private final Map<UUID, Location>   activeUseLocations = new ConcurrentHashMap<>();
    /** Whether the active use task is once-only per bot. */
    private final Map<UUID, Boolean>    activeUseOnceFlags  = new ConcurrentHashMap<>();

    public UseCommand(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
    }

    // в”Җв”Җ FppCommand в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override public String getName()        { return "use"; }
    @Override public String getUsage()       { return "<bot> [once|stop]  |  stop"; }
    @Override public String getDescription() { return "Walk a bot to your position then right-click what it's looking at."; }
    @Override public String getPermission()  { return Perm.USE_CMD; }
    @Override public boolean canUse(CommandSender sender) { return Perm.has(sender, Perm.USE_CMD); }

    // в”Җв”Җ execute в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(Lang.get("use-usage"));
            return true;
        }

        // /fpp use stop - stop all bots
        if (args[0].equalsIgnoreCase("stop") && args.length == 1) {
            stopAll();
            sender.sendMessage(Lang.get("use-stopped-all"));
            return true;
        }

        String botName = args[0];
        FakePlayer fp = manager.getByName(botName);
        if (fp == null) {
            sender.sendMessage(Lang.get("use-not-found", "name", botName));
            return true;
        }

        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("use-bot-offline", "name", fp.getDisplayName()));
            return true;
        }

        // /fpp use <bot> stop
        if (args.length >= 2 && args[1].equalsIgnoreCase("stop")) {
            cancelAll(fp.getUuid());
            sender.sendMessage(Lang.get("use-stopped", "name", fp.getDisplayName()));
            return true;
        }

        // /fpp use <bot> [once]
        boolean once = args.length >= 2 && args[1].equalsIgnoreCase("once");

        // Destination = sender's location (player) or bot's current location (console)
        Location dest = (sender instanceof Player sp)
                ? sp.getLocation().clone()
                : bot.getLocation().clone();

        // Cancel any existing nav/use for this bot
        cancelAll(fp.getUuid());

        double xzDist = xzDist(bot.getLocation(), dest);
        if (xzDist <= ARRIVAL_DIST) {
            // Already close enough - lock and start right-clicking immediately
            lockAndStartUsing(fp, once, dest);
            sender.sendMessage(once
                    ? Lang.get("use-started-once", "name", fp.getDisplayName())
                    : Lang.get("use-started",      "name", fp.getDisplayName()));
        } else {
            // Walk to the destination first
            startNavigation(fp, once, dest);
            sender.sendMessage(Lang.get("use-walking", "name", fp.getDisplayName()));
        }
        return true;
    }

    // в”Җв”Җ Tab-complete в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (!canUse(sender)) return List.of();

        if (args.length == 1) {
            String prefix = args[0].toLowerCase();
            List<String> out = new ArrayList<>();
            if ("stop".startsWith(prefix)) out.add("stop");
            for (FakePlayer fp : manager.getActivePlayers())
                if (fp.getName().toLowerCase().startsWith(prefix)) out.add(fp.getName());
            return out;
        }

        if (args.length == 2 && !args[0].equalsIgnoreCase("stop")) {
            String prefix = args[1].toLowerCase();
            List<String> out = new ArrayList<>();
            if ("once".startsWith(prefix)) out.add("once");
            if ("stop".startsWith(prefix)) out.add("stop");
            return out;
        }

        return List.of();
    }

    // в”Җв”Җ Phase 1: navigation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @SuppressWarnings("unchecked")
    private void startNavigation(FakePlayer fp, boolean once, Location dest) {
        final UUID uuid = fp.getUuid();

        final List<BotPathfinder.Move>[] pathRef = new List[]{null};
        final int[]    wpIdx    = {0};
        final int[]    recalcIn = {0};
        final int[]    stuckFor = {0};
        final double[] prevX    = {fp.getPlayer().getLocation().getX()};
        final double[] prevZ    = {fp.getPlayer().getLocation().getZ()};

        BukkitTask task = new BukkitRunnable() {
            @Override
            public void run() {
                Player bot = Bukkit.getPlayer(uuid);
                if (bot == null || !bot.isOnline()) { cleanup(null); return; }

                Location botLoc = bot.getLocation();
                double dist = xzDist(botLoc, dest);

                // в”Җв”Җ Arrived в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (dist <= ARRIVAL_DIST) {
                    cleanup(bot);
                    lockAndStartUsing(fp, once, dest);
                    return;
                }

                // в”Җв”Җ Path recalculation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                boolean exhausted = (pathRef[0] == null || wpIdx[0] >= pathRef[0].size());
                boolean heartbeat = (--recalcIn[0] <= 0);

                if (exhausted || heartbeat) {
                    recalcIn[0] = RECALC_INTERVAL;
                    BotPathfinder.PathOptions opts = new BotPathfinder.PathOptions(
                            Config.pathfindingParkour(),
                            Config.pathfindingBreakBlocks(),
                            Config.pathfindingPlaceBlocks());
                    List<BotPathfinder.Move> newPath = BotPathfinder.findPathMoves(
                            botLoc.getWorld(),
                            botLoc.getBlockX(), botLoc.getBlockY(), botLoc.getBlockZ(),
                            dest.getBlockX(),   dest.getBlockY(),   dest.getBlockZ(),
                            opts);
                    pathRef[0]  = newPath;
                    wpIdx[0]    = (newPath != null && newPath.size() > 1) ? 1 : 0;
                    stuckFor[0] = 0;
                }

                // в”Җв”Җ Fallback: direct walk в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                List<BotPathfinder.Move> path = pathRef[0];
                if (path == null || path.isEmpty() || wpIdx[0] >= path.size()) {
                    walkToward(bot, dest, dist);
                    return;
                }

                BotPathfinder.Move wp = path.get(wpIdx[0]);
                double wpCX = wp.x() + 0.5, wpCZ = wp.z() + 0.5;

                // в”Җв”Җ Waypoint advance в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                boolean wpYClose = Math.abs(botLoc.getY() - wp.y()) < 1.2;
                if (wpXZDist < WP_ARRIVE_XZ && wpYClose) {
                    wpIdx[0]++;
                    if (wpIdx[0] >= path.size()) { recalcIn[0] = 0; return; }
                    wp       = path.get(wpIdx[0]);
                    wpCX     = wp.x() + 0.5;
                    wpCZ     = wp.z() + 0.5;
                    wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                }

                // в”Җв”Җ Face waypoint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double dx = wpCX - botLoc.getX(), dz = wpCZ - botLoc.getZ();
                float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
                bot.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(bot, yaw);

                // в”Җв”Җ Walk / sprint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                bot.setSprinting(dist > SPRINT_DIST || wp.type() == BotPathfinder.MoveType.PARKOUR);
                NmsPlayerSpawner.setMovementForward(bot, 1.0f);

                // в”Җв”Җ Jump в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (!bot.isInWater() && !bot.isInLava()) {
                    if (wp.y() > botLoc.getBlockY()) {
                        manager.requestNavJump(uuid);
                    } else if (wp.type() == BotPathfinder.MoveType.PARKOUR
                            && wpXZDist >= 1.0 && wpXZDist <= 3.5) {
                        manager.requestNavJump(uuid);
                    }
                }

                // в”Җв”Җ Stuck detection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double moved = xzDistRaw(botLoc.getX(), botLoc.getZ(), prevX[0], prevZ[0]);
                if (moved < STUCK_THRESHOLD) {
                    if (++stuckFor[0] >= STUCK_TICKS) {
                        if (!bot.isInWater() && !bot.isInLava()) manager.requestNavJump(uuid);
                        recalcIn[0] = 0;
                        stuckFor[0] = 0;
                    }
                } else {
                    stuckFor[0] = 0;
                }
                prevX[0] = botLoc.getX();
                prevZ[0] = botLoc.getZ();
            }

            private void cleanup(Player bot) {
                manager.clearNavJump(uuid);
                if (bot != null) {
                    NmsPlayerSpawner.setMovementForward(bot, 0f);
                    NmsPlayerSpawner.setJumping(bot, false);
                    bot.setSprinting(false);
                }
                cancel();
                navTasks.remove(uuid);
            }

            private void walkToward(Player bot, Location dest, double dist) {
                Location bl = bot.getLocation();
                float yaw = (float) Math.toDegrees(
                        Math.atan2(-(dest.getX() - bl.getX()), dest.getZ() - bl.getZ()));
                bot.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(bot, yaw);
                bot.setSprinting(dist > SPRINT_DIST);
                NmsPlayerSpawner.setMovementForward(bot, 1.0f);
            }

        }.runTaskTimer(plugin, 0L, 1L);

        navTasks.put(uuid, task);
    }

    // в”Җв”Җ Phase 2: lock + right-click loop в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Called once the bot has arrived at the use destination.
     * Snaps to the exact position, locks position + head-AI, and starts the
     * 1-tick right-click loop.
     */
    private void lockAndStartUsing(FakePlayer fp, boolean once, Location lockLoc) {
        UUID uuid = fp.getUuid();
        Player bot = fp.getPlayer();
        if (bot == null) return;

        // Final snap to exact position (bot is вүӨ ARRIVAL_DIST away - imperceptible)
        bot.teleport(lockLoc);

        // Lock position + suppress head-AI in the manager's tick loop
        manager.lockForMining(uuid, lockLoc);

        // Record active use state for persistence
        activeUseLocations.put(uuid, lockLoc.clone());
        activeUseOnceFlags.put(uuid, once);

        // Per-task freeze counter
        final int[] freeze = {0};

        int taskId = Bukkit.getScheduler().runTaskTimer(plugin, () -> {
            Player b = fp.getPlayer();
            if (b == null || !b.isOnline()) { stopUsing(uuid); return; }

            if (freeze[0] > 0) { freeze[0]--; return; }

            ServerPlayer nms = ((CraftPlayer) b).getHandle();

            // If bot is actively holding/using an item (bow, eating), wait
            if (nms.isUsingItem()) {
                if (once) stopUsing(uuid);
                return;
            }

            HitResult hit = rayTrace(nms);
            if (hit == null || hit.getType() == HitResult.Type.MISS) return;

            boolean acted = false;

            for (InteractionHand hand : InteractionHand.values()) {

                // в”Җв”Җ Block interaction в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (hit.getType() == HitResult.Type.BLOCK) {
                    BlockHitResult blockHit = (BlockHitResult) hit;
                    var pos  = blockHit.getBlockPos();
                    Direction side = blockHit.getDirection();

                    if (pos.getY() < nms.level().getMaxY() - (side == Direction.UP ? 1 : 0)
                            && nms.level().mayInteract(nms, pos)) {
                        nms.resetLastActionTime();
                        var result = nms.gameMode.useItemOn(
                                nms, nms.level(), nms.getItemInHand(hand), hand, blockHit);
                        if (result.consumesAction()) {
                            nms.swing(hand);
                            freeze[0] = 3;
                            acted = true;
                            break;
                        }
                    }

                // в”Җв”Җ Entity interaction в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                } else if (hit.getType() == HitResult.Type.ENTITY) {
                    EntityHitResult entityHit = (EntityHitResult) hit;
                    var entity = entityHit.getEntity();

                    boolean handWasEmpty   = nms.getItemInHand(hand).isEmpty();
                    boolean itemFrameEmpty = (entity instanceof ItemFrame ife)
                            && ife.getItem().isEmpty();
                    Vec3 relPos = entityHit.getLocation().subtract(
                            entity.getX(), entity.getY(), entity.getZ());

                    nms.resetLastActionTime();

                    if (entity.interactAt(nms, relPos, hand).consumesAction()) {
                        freeze[0] = 3; acted = true; break;
                    }
                    if (nms.interactOn(entity, hand).consumesAction()
                            && !(handWasEmpty && itemFrameEmpty)) {
                        freeze[0] = 3; acted = true; break;
                    }
                }

                // в”Җв”Җ Item use in air (bow, food, ender pearl, etc.) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (nms.gameMode.useItem(nms, nms.level(), nms.getItemInHand(hand), hand)
                        .consumesAction()) {
                    nms.resetLastActionTime();
                    freeze[0] = 3; acted = true; break;
                }
            }

            if (once && acted) stopUsing(uuid);

        }, 0L, 1L).getTaskId();

        useTasks.put(uuid, taskId);
    }

    // в”Җв”Җ Stop helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Cancels both the navigation task AND the right-click task, releases the
     * position lock and any held item.
     */
    private void cancelAll(UUID botUuid) {
        BukkitTask t = navTasks.remove(botUuid);
        if (t != null && !t.isCancelled()) t.cancel();
        manager.clearNavJump(botUuid);

        stopUsing(botUuid);

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp != null) {
            Player bot = fp.getPlayer();
            if (bot != null && bot.isOnline()) {
                NmsPlayerSpawner.setMovementForward(bot, 0f);
                NmsPlayerSpawner.setJumping(bot, false);
                bot.setSprinting(false);
            }
        }
    }

    /** Stops only the right-click phase (task + lock + item release). */
    public void stopUsing(UUID botUuid) {
        Integer taskId = useTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);

        manager.unlockMining(botUuid);   // reuses the same mining lock mechanism

        // Clear persistence tracking
        activeUseLocations.remove(botUuid);
        activeUseOnceFlags.remove(botUuid);

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp != null) {
            Player bot = fp.getPlayer();
            if (bot != null && bot.isOnline())
                ((CraftPlayer) bot).getHandle().releaseUsingItem();
        }
    }

    /** Stops all bots (navigation + right-clicking). */
    public void stopAll() {
        new HashSet<>(navTasks.keySet()).forEach(this::cancelAll);
        new HashSet<>(useTasks.keySet()).forEach(this::cancelAll);
    }

    /** Returns {@code true} if the bot is currently navigating to the use spot. */
    public boolean isNavigating(UUID botUuid) { return navTasks.containsKey(botUuid); }

    /** Returns {@code true} if the bot is actively right-clicking. */
    public boolean isUsing(UUID botUuid)      { return useTasks.containsKey(botUuid); }

    // в”Җв”Җ Persistence API в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Returns the active use lock location for the given bot,
     * or {@code null} when the bot is not in use mode.
     */
    @org.jetbrains.annotations.Nullable
    public Location getActiveUseLocation(UUID botUuid) {
        return activeUseLocations.get(botUuid);
    }

    /**
     * Returns {@code true} if the bot's active use task is once-only.
     */
    public boolean isActiveUseOnce(UUID botUuid) {
        Boolean v = activeUseOnceFlags.get(botUuid);
        return v != null && v;
    }

    /**
     * Resumes a right-click use loop for a bot restored from persistence.
     * Navigates to the location if not already close enough.
     */
    public void resumeUsing(FakePlayer fp, boolean once, Location loc) {
        if (fp == null || loc == null) return;
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) return;
        cancelAll(fp.getUuid());
        double dx = bot.getLocation().getX() - loc.getX();
        double dz = bot.getLocation().getZ() - loc.getZ();
        double xzDist = Math.sqrt(dx * dx + dz * dz);
        if (xzDist <= ARRIVAL_DIST) {
            lockAndStartUsing(fp, once, loc);
        } else {
            startNavigation(fp, once, loc);
        }
    }

    // в”Җв”Җ NMS raytracer в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Combined block + entity raycast from the bot's eye position.
     * Reach: 4.5 blocks (survival) / 5 blocks (creative).
     * Entity takes priority when closer than the hit block face.
     */
    @SuppressWarnings("resource")
    private static HitResult rayTrace(ServerPlayer player) {
        double reach   = player.gameMode.isCreative() ? 5.0 : 4.5;
        Vec3 eyePos    = player.getEyePosition(1.0f);
        Vec3 viewVec   = player.getViewVector(1.0f);
        Vec3 endPos    = eyePos.add(viewVec.x * reach, viewVec.y * reach, viewVec.z * reach);

        BlockHitResult blockHit;
        try {
            blockHit = player.level().clip(new ClipContext(
                    eyePos, endPos,
                    ClipContext.Block.OUTLINE, ClipContext.Fluid.NONE, player));
        } catch (Exception e) {
            return null;
        }

        double maxSqDist = reach * reach;
        if (blockHit.getType() != HitResult.Type.MISS)
            maxSqDist = blockHit.getLocation().distanceToSqr(eyePos);

        AABB searchBox = player.getBoundingBox().expandTowards(viewVec.scale(reach)).inflate(1.0);

        EntityHitResult entityHit    = null;
        double          entityDistSq = maxSqDist;

        for (var entity : player.level().getEntities(player, searchBox,
                e -> !e.isSpectator() && e.isPickable())) {
            AABB entityBox = entity.getBoundingBox().inflate(entity.getPickRadius());
            var  hitOpt    = entityBox.clip(eyePos, endPos);
            if (entityBox.contains(eyePos)) {
                if (entityDistSq >= 0) {
                    entityHit    = new EntityHitResult(entity, hitOpt.orElse(eyePos));
                    entityDistSq = 0;
                }
            } else if (hitOpt.isPresent()) {
                double d = eyePos.distanceToSqr(hitOpt.get());
                if (d < entityDistSq || entityDistSq == 0) {
                    entityHit    = new EntityHitResult(entity, hitOpt.get());
                    entityDistSq = d;
                }
            }
        }

        return entityHit != null ? entityHit : blockHit;
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static double xzDist(Location a, Location b) {
        return xzDistRaw(a.getX(), a.getZ(), b.getX(), b.getZ());
    }

    private static double xzDistRaw(double ax, double az, double bx, double bz) {
        double dx = ax - bx, dz = az - bz;
        return Math.sqrt(dx * dx + dz * dz);
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotPathfinder;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.fakeplayer.NmsPlayerSpawner;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import net.minecraft.core.Direction;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.InteractionHand;
import net.minecraft.world.entity.decoration.ItemFrame;
import net.minecraft.world.level.ClipContext;
import net.minecraft.world.phys.AABB;
import net.minecraft.world.phys.BlockHitResult;
import net.minecraft.world.phys.EntityHitResult;
import net.minecraft.world.phys.HitResult;
import net.minecraft.world.phys.Vec3;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.command.CommandSender;
import org.bukkit.craftbukkit.entity.CraftPlayer;
import org.bukkit.entity.Player;
import org.bukkit.scheduler.BukkitRunnable;
import org.bukkit.scheduler.BukkitTask;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Two-phase use command - mirrors the structure of {@link MineCommand}.
 *
 * <h3>Phase 1 - Navigation</h3>
 * The bot walks/sprints to the sender's exact position using A* pathfinding.
 * Normal physics, knockback, and pushable are all active during this phase.
 *
 * <h3>Phase 2 - Right-click loop</h3>
 * Once the bot arrives (XZ вүӨ {@value #ARRIVAL_DIST}) it is snapped to the exact
 * spot, its position is locked via {@code FakePlayerManager.lockForMining()},
 * head-AI is suppressed, and the right-click loop begins.
 *
 * <p>On each tick the bot's look-direction is raycast (4.5 survival / 5 creative).
 * Three interaction paths are attempted per hand:
 * <ol>
 *   <li><b>Block</b> - {@code gameMode.useItemOn()}</li>
 *   <li><b>Entity</b> - {@code interactAt()} + {@code interactOn()}</li>
 *   <li><b>Air / item</b> - {@code gameMode.useItem()}</li>
 * </ol>
 * A 3-tick freeze is applied after each successful action.
 *
 * <p>Usage:
 * <ul>
 *   <li>{@code /fpp use <bot>}      - walk to your spot, right-click continuously.</li>
 *   <li>{@code /fpp use <bot> once} - walk to your spot, right-click once, stop.</li>
 *   <li>{@code /fpp use <bot> stop} - stop navigating / stop right-clicking.</li>
 *   <li>{@code /fpp use stop}       - stop all bots.</li>
 * </ul>
 *
 * <p>Permission: {@link Perm#USE_CMD} ({@code fpp.useitem}), default {@code op}.
 */
public final class UseCommand implements FppCommand {

    // в”Җв”Җ Tuning constants (mirrors MoveCommand / MineCommand) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private static final double ARRIVAL_DIST    = 1.2;
    private static final double SPRINT_DIST     = 6.0;
    private static final double WP_ARRIVE_XZ    = 0.65;
    private static final int    RECALC_INTERVAL = 60;
    private static final int    STUCK_TICKS     = 8;
    private static final double STUCK_THRESHOLD = 0.04;

    // в”Җв”Җ Fields в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;

    /** Phase-1 navigation tasks (walking to the use spot). */
    private final Map<UUID, BukkitTask> navTasks  = new ConcurrentHashMap<>();
    /** Phase-2 right-click task IDs. */
    private final Map<UUID, Integer>    useTasks  = new ConcurrentHashMap<>();
    /** Active use lock locations per bot (populated at lock-and-use start). */
    private final Map<UUID, Location>   activeUseLocations = new ConcurrentHashMap<>();
    /** Whether the active use task is once-only per bot. */
    private final Map<UUID, Boolean>    activeUseOnceFlags  = new ConcurrentHashMap<>();

    public UseCommand(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
    }

    // в”Җв”Җ FppCommand в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override public String getName()        { return "use"; }
    @Override public String getUsage()       { return "<bot> [once|stop]  |  stop"; }
    @Override public String getDescription() { return "Walk a bot to your position then right-click what it's looking at."; }
    @Override public String getPermission()  { return Perm.USE_CMD; }
    @Override public boolean canUse(CommandSender sender) { return Perm.has(sender, Perm.USE_CMD); }

    // в”Җв”Җ execute в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(Lang.get("use-usage"));
            return true;
        }

        // /fpp use stop - stop all bots
        if (args[0].equalsIgnoreCase("stop") && args.length == 1) {
            stopAll();
            sender.sendMessage(Lang.get("use-stopped-all"));
            return true;
        }

        String botName = args[0];
        FakePlayer fp = manager.getByName(botName);
        if (fp == null) {
            sender.sendMessage(Lang.get("use-not-found", "name", botName));
            return true;
        }

        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("use-bot-offline", "name", fp.getDisplayName()));
            return true;
        }

        // /fpp use <bot> stop
        if (args.length >= 2 && args[1].equalsIgnoreCase("stop")) {
            cancelAll(fp.getUuid());
            sender.sendMessage(Lang.get("use-stopped", "name", fp.getDisplayName()));
            return true;
        }

        // /fpp use <bot> [once]
        boolean once = args.length >= 2 && args[1].equalsIgnoreCase("once");

        // Destination = sender's location (player) or bot's current location (console)
        Location dest = (sender instanceof Player sp)
                ? sp.getLocation().clone()
                : bot.getLocation().clone();

        // Cancel any existing nav/use for this bot
        cancelAll(fp.getUuid());

        double xzDist = xzDist(bot.getLocation(), dest);
        if (xzDist <= ARRIVAL_DIST) {
            // Already close enough - lock and start right-clicking immediately
            lockAndStartUsing(fp, once, dest);
            sender.sendMessage(once
                    ? Lang.get("use-started-once", "name", fp.getDisplayName())
                    : Lang.get("use-started",      "name", fp.getDisplayName()));
        } else {
            // Walk to the destination first
            startNavigation(fp, once, dest);
            sender.sendMessage(Lang.get("use-walking", "name", fp.getDisplayName()));
        }
        return true;
    }

    // в”Җв”Җ Tab-complete в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (!canUse(sender)) return List.of();

        if (args.length == 1) {
            String prefix = args[0].toLowerCase();
            List<String> out = new ArrayList<>();
            if ("stop".startsWith(prefix)) out.add("stop");
            for (FakePlayer fp : manager.getActivePlayers())
                if (fp.getName().toLowerCase().startsWith(prefix)) out.add(fp.getName());
            return out;
        }

        if (args.length == 2 && !args[0].equalsIgnoreCase("stop")) {
            String prefix = args[1].toLowerCase();
            List<String> out = new ArrayList<>();
            if ("once".startsWith(prefix)) out.add("once");
            if ("stop".startsWith(prefix)) out.add("stop");
            return out;
        }

        return List.of();
    }

    // в”Җв”Җ Phase 1: navigation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    @SuppressWarnings("unchecked")
    private void startNavigation(FakePlayer fp, boolean once, Location dest) {
        final UUID uuid = fp.getUuid();

        final List<BotPathfinder.Move>[] pathRef = new List[]{null};
        final int[]    wpIdx    = {0};
        final int[]    recalcIn = {0};
        final int[]    stuckFor = {0};
        final double[] prevX    = {fp.getPlayer().getLocation().getX()};
        final double[] prevZ    = {fp.getPlayer().getLocation().getZ()};

        BukkitTask task = new BukkitRunnable() {
            @Override
            public void run() {
                Player bot = Bukkit.getPlayer(uuid);
                if (bot == null || !bot.isOnline()) { cleanup(null); return; }

                Location botLoc = bot.getLocation();
                double dist = xzDist(botLoc, dest);

                // в”Җв”Җ Arrived в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (dist <= ARRIVAL_DIST) {
                    cleanup(bot);
                    lockAndStartUsing(fp, once, dest);
                    return;
                }

                // в”Җв”Җ Path recalculation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                boolean exhausted = (pathRef[0] == null || wpIdx[0] >= pathRef[0].size());
                boolean heartbeat = (--recalcIn[0] <= 0);

                if (exhausted || heartbeat) {
                    recalcIn[0] = RECALC_INTERVAL;
                    BotPathfinder.PathOptions opts = new BotPathfinder.PathOptions(
                            Config.pathfindingParkour(),
                            Config.pathfindingBreakBlocks(),
                            Config.pathfindingPlaceBlocks());
                    List<BotPathfinder.Move> newPath = BotPathfinder.findPathMoves(
                            botLoc.getWorld(),
                            botLoc.getBlockX(), botLoc.getBlockY(), botLoc.getBlockZ(),
                            dest.getBlockX(),   dest.getBlockY(),   dest.getBlockZ(),
                            opts);
                    pathRef[0]  = newPath;
                    wpIdx[0]    = (newPath != null && newPath.size() > 1) ? 1 : 0;
                    stuckFor[0] = 0;
                }

                // в”Җв”Җ Fallback: direct walk в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                List<BotPathfinder.Move> path = pathRef[0];
                if (path == null || path.isEmpty() || wpIdx[0] >= path.size()) {
                    walkToward(bot, dest, dist);
                    return;
                }

                BotPathfinder.Move wp = path.get(wpIdx[0]);
                double wpCX = wp.x() + 0.5, wpCZ = wp.z() + 0.5;

                // в”Җв”Җ Waypoint advance в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                boolean wpYClose = Math.abs(botLoc.getY() - wp.y()) < 1.2;
                if (wpXZDist < WP_ARRIVE_XZ && wpYClose) {
                    wpIdx[0]++;
                    if (wpIdx[0] >= path.size()) { recalcIn[0] = 0; return; }
                    wp       = path.get(wpIdx[0]);
                    wpCX     = wp.x() + 0.5;
                    wpCZ     = wp.z() + 0.5;
                    wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                }

                // в”Җв”Җ Face waypoint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double dx = wpCX - botLoc.getX(), dz = wpCZ - botLoc.getZ();
                float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
                bot.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(bot, yaw);

                // в”Җв”Җ Walk / sprint в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                bot.setSprinting(dist > SPRINT_DIST || wp.type() == BotPathfinder.MoveType.PARKOUR);
                NmsPlayerSpawner.setMovementForward(bot, 1.0f);

                // в”Җв”Җ Jump в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (!bot.isInWater() && !bot.isInLava()) {
                    if (wp.y() > botLoc.getBlockY()) {
                        manager.requestNavJump(uuid);
                    } else if (wp.type() == BotPathfinder.MoveType.PARKOUR
                            && wpXZDist >= 1.0 && wpXZDist <= 3.5) {
                        manager.requestNavJump(uuid);
                    }
                }

                // в”Җв”Җ Stuck detection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                double moved = xzDistRaw(botLoc.getX(), botLoc.getZ(), prevX[0], prevZ[0]);
                if (moved < STUCK_THRESHOLD) {
                    if (++stuckFor[0] >= STUCK_TICKS) {
                        if (!bot.isInWater() && !bot.isInLava()) manager.requestNavJump(uuid);
                        recalcIn[0] = 0;
                        stuckFor[0] = 0;
                    }
                } else {
                    stuckFor[0] = 0;
                }
                prevX[0] = botLoc.getX();
                prevZ[0] = botLoc.getZ();
            }

            private void cleanup(Player bot) {
                manager.clearNavJump(uuid);
                if (bot != null) {
                    NmsPlayerSpawner.setMovementForward(bot, 0f);
                    NmsPlayerSpawner.setJumping(bot, false);
                    bot.setSprinting(false);
                }
                cancel();
                navTasks.remove(uuid);
            }

            private void walkToward(Player bot, Location dest, double dist) {
                Location bl = bot.getLocation();
                float yaw = (float) Math.toDegrees(
                        Math.atan2(-(dest.getX() - bl.getX()), dest.getZ() - bl.getZ()));
                bot.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(bot, yaw);
                bot.setSprinting(dist > SPRINT_DIST);
                NmsPlayerSpawner.setMovementForward(bot, 1.0f);
            }

        }.runTaskTimer(plugin, 0L, 1L);

        navTasks.put(uuid, task);
    }

    // в”Җв”Җ Phase 2: lock + right-click loop в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Called once the bot has arrived at the use destination.
     * Snaps to the exact position, locks position + head-AI, and starts the
     * 1-tick right-click loop.
     */
    private void lockAndStartUsing(FakePlayer fp, boolean once, Location lockLoc) {
        UUID uuid = fp.getUuid();
        Player bot = fp.getPlayer();
        if (bot == null) return;

        // Final snap to exact position (bot is вүӨ ARRIVAL_DIST away - imperceptible)
        bot.teleport(lockLoc);

        // Lock position + suppress head-AI in the manager's tick loop
        manager.lockForMining(uuid, lockLoc);

        // Record active use state for persistence
        activeUseLocations.put(uuid, lockLoc.clone());
        activeUseOnceFlags.put(uuid, once);

        // Per-task freeze counter
        final int[] freeze = {0};

        int taskId = Bukkit.getScheduler().runTaskTimer(plugin, () -> {
            Player b = fp.getPlayer();
            if (b == null || !b.isOnline()) { stopUsing(uuid); return; }

            if (freeze[0] > 0) { freeze[0]--; return; }

            ServerPlayer nms = ((CraftPlayer) b).getHandle();

            // If bot is actively holding/using an item (bow, eating), wait
            if (nms.isUsingItem()) {
                if (once) stopUsing(uuid);
                return;
            }

            HitResult hit = rayTrace(nms);
            if (hit == null || hit.getType() == HitResult.Type.MISS) return;

            boolean acted = false;

            for (InteractionHand hand : InteractionHand.values()) {

                // в”Җв”Җ Block interaction в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (hit.getType() == HitResult.Type.BLOCK) {
                    BlockHitResult blockHit = (BlockHitResult) hit;
                    var pos  = blockHit.getBlockPos();
                    Direction side = blockHit.getDirection();

                    if (pos.getY() < nms.level().getMaxY() - (side == Direction.UP ? 1 : 0)
                            && nms.level().mayInteract(nms, pos)) {
                        nms.resetLastActionTime();
                        var result = nms.gameMode.useItemOn(
                                nms, nms.level(), nms.getItemInHand(hand), hand, blockHit);
                        if (result.consumesAction()) {
                            nms.swing(hand);
                            freeze[0] = 3;
                            acted = true;
                            break;
                        }
                    }

                // в”Җв”Җ Entity interaction в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                } else if (hit.getType() == HitResult.Type.ENTITY) {
                    EntityHitResult entityHit = (EntityHitResult) hit;
                    var entity = entityHit.getEntity();

                    boolean handWasEmpty   = nms.getItemInHand(hand).isEmpty();
                    boolean itemFrameEmpty = (entity instanceof ItemFrame ife)
                            && ife.getItem().isEmpty();
                    Vec3 relPos = entityHit.getLocation().subtract(
                            entity.getX(), entity.getY(), entity.getZ());

                    nms.resetLastActionTime();

                    if (entity.interactAt(nms, relPos, hand).consumesAction()) {
                        freeze[0] = 3; acted = true; break;
                    }
                    if (nms.interactOn(entity, hand).consumesAction()
                            && !(handWasEmpty && itemFrameEmpty)) {
                        freeze[0] = 3; acted = true; break;
                    }
                }

                // в”Җв”Җ Item use in air (bow, food, ender pearl, etc.) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                if (nms.gameMode.useItem(nms, nms.level(), nms.getItemInHand(hand), hand)
                        .consumesAction()) {
                    nms.resetLastActionTime();
                    freeze[0] = 3; acted = true; break;
                }
            }

            if (once && acted) stopUsing(uuid);

        }, 0L, 1L).getTaskId();

        useTasks.put(uuid, taskId);
    }

    // в”Җв”Җ Stop helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Cancels both the navigation task AND the right-click task, releases the
     * position lock and any held item.
     */
    private void cancelAll(UUID botUuid) {
        BukkitTask t = navTasks.remove(botUuid);
        if (t != null && !t.isCancelled()) t.cancel();
        manager.clearNavJump(botUuid);

        stopUsing(botUuid);

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp != null) {
            Player bot = fp.getPlayer();
            if (bot != null && bot.isOnline()) {
                NmsPlayerSpawner.setMovementForward(bot, 0f);
                NmsPlayerSpawner.setJumping(bot, false);
                bot.setSprinting(false);
            }
        }
    }

    /** Stops only the right-click phase (task + lock + item release). */
    public void stopUsing(UUID botUuid) {
        Integer taskId = useTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);

        manager.unlockMining(botUuid);   // reuses the same mining lock mechanism

        // Clear persistence tracking
        activeUseLocations.remove(botUuid);
        activeUseOnceFlags.remove(botUuid);

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp != null) {
            Player bot = fp.getPlayer();
            if (bot != null && bot.isOnline())
                ((CraftPlayer) bot).getHandle().releaseUsingItem();
        }
    }

    /** Stops all bots (navigation + right-clicking). */
    public void stopAll() {
        new HashSet<>(navTasks.keySet()).forEach(this::cancelAll);
        new HashSet<>(useTasks.keySet()).forEach(this::cancelAll);
    }

    /** Returns {@code true} if the bot is currently navigating to the use spot. */
    public boolean isNavigating(UUID botUuid) { return navTasks.containsKey(botUuid); }

    /** Returns {@code true} if the bot is actively right-clicking. */
    public boolean isUsing(UUID botUuid)      { return useTasks.containsKey(botUuid); }

    // в”Җв”Җ Persistence API в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Returns the active use lock location for the given bot,
     * or {@code null} when the bot is not in use mode.
     */
    @org.jetbrains.annotations.Nullable
    public Location getActiveUseLocation(UUID botUuid) {
        return activeUseLocations.get(botUuid);
    }

    /**
     * Returns {@code true} if the bot's active use task is once-only.
     */
    public boolean isActiveUseOnce(UUID botUuid) {
        Boolean v = activeUseOnceFlags.get(botUuid);
        return v != null && v;
    }

    /**
     * Resumes a right-click use loop for a bot restored from persistence.
     * Navigates to the location if not already close enough.
     */
    public void resumeUsing(FakePlayer fp, boolean once, Location loc) {
        if (fp == null || loc == null) return;
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) return;
        cancelAll(fp.getUuid());
        double dx = bot.getLocation().getX() - loc.getX();
        double dz = bot.getLocation().getZ() - loc.getZ();
        double xzDist = Math.sqrt(dx * dx + dz * dz);
        if (xzDist <= ARRIVAL_DIST) {
            lockAndStartUsing(fp, once, loc);
        } else {
            startNavigation(fp, once, loc);
        }
    }

    // в”Җв”Җ NMS raytracer в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Combined block + entity raycast from the bot's eye position.
     * Reach: 4.5 blocks (survival) / 5 blocks (creative).
     * Entity takes priority when closer than the hit block face.
     */
    @SuppressWarnings("resource")
    private static HitResult rayTrace(ServerPlayer player) {
        double reach   = player.gameMode.isCreative() ? 5.0 : 4.5;
        Vec3 eyePos    = player.getEyePosition(1.0f);
        Vec3 viewVec   = player.getViewVector(1.0f);
        Vec3 endPos    = eyePos.add(viewVec.x * reach, viewVec.y * reach, viewVec.z * reach);

        BlockHitResult blockHit;
        try {
            blockHit = player.level().clip(new ClipContext(
                    eyePos, endPos,
                    ClipContext.Block.OUTLINE, ClipContext.Fluid.NONE, player));
        } catch (Exception e) {
            return null;
        }

        double maxSqDist = reach * reach;
        if (blockHit.getType() != HitResult.Type.MISS)
            maxSqDist = blockHit.getLocation().distanceToSqr(eyePos);

        AABB searchBox = player.getBoundingBox().expandTowards(viewVec.scale(reach)).inflate(1.0);

        EntityHitResult entityHit    = null;
        double          entityDistSq = maxSqDist;

        for (var entity : player.level().getEntities(player, searchBox,
                e -> !e.isSpectator() && e.isPickable())) {
            AABB entityBox = entity.getBoundingBox().inflate(entity.getPickRadius());
            var  hitOpt    = entityBox.clip(eyePos, endPos);
            if (entityBox.contains(eyePos)) {
                if (entityDistSq >= 0) {
                    entityHit    = new EntityHitResult(entity, hitOpt.orElse(eyePos));
                    entityDistSq = 0;
                }
            } else if (hitOpt.isPresent()) {
                double d = eyePos.distanceToSqr(hitOpt.get());
                if (d < entityDistSq || entityDistSq == 0) {
                    entityHit    = new EntityHitResult(entity, hitOpt.get());
                    entityDistSq = d;
                }
            }
        }

        if (entityHit != null) return (HitResult) entityHit;
        return (HitResult) blockHit;
    }

    // в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private static double xzDist(Location a, Location b) {
        return xzDistRaw(a.getX(), a.getZ(), b.getX(), b.getZ());
    }

    private static double xzDistRaw(double ax, double az, double bx, double bz) {
        double dx = ax - bx, dz = az - bz;
        return Math.sqrt(dx * dx + dz * dz);
    }
}

package me.bill.fakePlayerPlugin.command;

import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.configuration.file.YamlConfiguration;
import org.bukkit.plugin.java.JavaPlugin;

import java.io.File;
import java.io.IOException;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Thread-safe registry of named global waypoints, persisted to
 * {@code plugins/FakePlayerPlugin/data/waypoints.yml}.
 *
 * <p>Names are stored and looked-up case-insensitively (lowercased keys).
 * Saves are synchronous and triggered on every mutation.
 *
 * <p>Lifecycle: call {@link #load()} once during plugin startup, then
 * {@link #add}/{@link #remove} as needed вҖ” each mutation auto-saves.
 */
public final class WaypointStore {

    private final JavaPlugin plugin;
    private final Map<String, Location> waypoints = new ConcurrentHashMap<>();
    private File file;

    public WaypointStore(JavaPlugin plugin) {
        this.plugin = plugin;
    }

    // в”Җв”Җ Load / Save в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Loads all waypoints from {@code data/waypoints.yml}. */
    public void load() {
        file = new File(plugin.getDataFolder(), "data/waypoints.yml");
        if (!file.exists()) return;

        YamlConfiguration yaml = YamlConfiguration.loadConfiguration(file);
        int loaded = 0;
        for (String key : yaml.getKeys(false)) {
            String worldName = yaml.getString(key + ".world", "world");
            double x     = yaml.getDouble(key + ".x");
            double y     = yaml.getDouble(key + ".y");
            double z     = yaml.getDouble(key + ".z");
            float  yaw   = (float) yaml.getDouble(key + ".yaw");
            float  pitch = (float) yaml.getDouble(key + ".pitch");

            World w = Bukkit.getWorld(worldName != null ? worldName : "world");
            if (w != null) {
                waypoints.put(key.toLowerCase(), new Location(w, x, y, z, yaw, pitch));
                loaded++;
            }
        }
        if (loaded > 0) {
            plugin.getLogger().info("[FPP] Loaded " + loaded + " waypoint(s) from waypoints.yml");
        }
    }

    /** Saves all waypoints to disk. Called automatically on every mutation. */
    public void save() {
        if (file == null) {
            file = new File(plugin.getDataFolder(), "data/waypoints.yml");
        }
        file.getParentFile().mkdirs();

        YamlConfiguration yaml = new YamlConfiguration();
        for (Map.Entry<String, Location> e : waypoints.entrySet()) {
            String   k   = e.getKey();
            Location loc = e.getValue();
            yaml.set(k + ".world", loc.getWorld() != null ? loc.getWorld().getName() : "world");
            yaml.set(k + ".x",     loc.getX());
            yaml.set(k + ".y",     loc.getY());
            yaml.set(k + ".z",     loc.getZ());
            yaml.set(k + ".yaw",   (double) loc.getYaw());
            yaml.set(k + ".pitch", (double) loc.getPitch());
        }
        try {
            yaml.save(file);
        } catch (IOException ex) {
            plugin.getLogger().warning("[FPP] Could not save waypoints.yml: " + ex.getMessage());
        }
    }

    // в”Җв”Җ CRUD в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Adds (or overwrites) a waypoint with the given name at the given location.
     * Persists to disk immediately.
     */
    public void add(String name, Location loc) {
        waypoints.put(name.toLowerCase(), loc.clone());
        save();
    }

    /**
     * Removes the waypoint with the given name.
     *
     * @return {@code true} if the waypoint existed and was removed
     */
    public boolean remove(String name) {
        boolean removed = waypoints.remove(name.toLowerCase()) != null;
        if (removed) save();
        return removed;
    }

    /**
     * Returns the location of the named waypoint, or {@code null} if not found.
     * Name lookup is case-insensitive.
     */
    public Location get(String name) {
        return waypoints.get(name.toLowerCase());
    }

    /** Returns {@code true} if a waypoint with this name exists. */
    public boolean exists(String name) {
        return waypoints.containsKey(name.toLowerCase());
    }

    /** Returns an unmodifiable sorted set of all waypoint names (lowercase). */
    public Set<String> getNames() {
        return Collections.unmodifiableSet(new TreeSet<>(waypoints.keySet()));
    }

    /** Returns the number of stored waypoints. */
    public int size() {
        return waypoints.size();
    }
}

package me.bill.fakePlayerPlugin.command;

import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.configuration.ConfigurationSection;
import org.bukkit.configuration.file.YamlConfiguration;
import org.bukkit.plugin.java.JavaPlugin;

import java.io.File;
import java.io.IOException;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Thread-safe registry of named waypoint routes, persisted to
 * {@code plugins/FakePlayerPlugin/data/waypoints.yml}.
 *
 * <p>Each route is an ordered list of {@link Location}s that a bot can
 * patrol in a loop via {@code /fpp move <bot> --wp <name>}.
 *
 * <p>Names are stored and looked-up case-insensitively (lowercased keys).
 * Saves are synchronous and triggered on every mutation.
 *
 * <p>Lifecycle: call {@link #load()} once during plugin startup, then
 * use {@link #addPos}/{@link #removePos}/{@link #delete} as needed вҖ” each mutation auto-saves.
 */
public final class WaypointStore {

    private final JavaPlugin plugin;
    /** routeName (lowercase) вҶ’ ordered list of positions */
    private final Map<String, List<Location>> routes = new ConcurrentHashMap<>();
    private File file;

    public WaypointStore(JavaPlugin plugin) {
        this.plugin = plugin;
    }

    // в”Җв”Җ Load / Save в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /** Loads all waypoint routes from {@code data/waypoints.yml}. */
    public void load() {
        file = new File(plugin.getDataFolder(), "data/waypoints.yml");
        if (!file.exists()) return;

        YamlConfiguration yaml = YamlConfiguration.loadConfiguration(file);
        int routeCount = 0, posCount = 0;

        for (String routeName : yaml.getKeys(false)) {
            ConfigurationSection routeSection = yaml.getConfigurationSection(routeName);
            if (routeSection == null) continue;

            List<Location> positions = new ArrayList<>();
            // Positions stored as numbered entries: "0", "1", "2", ...
            int i = 0;
            while (routeSection.contains(String.valueOf(i))) {
                ConfigurationSection pos = routeSection.getConfigurationSection(String.valueOf(i));
                if (pos != null) {
                    String worldName = pos.getString("world", "world");
                    double x     = pos.getDouble("x");
                    double y     = pos.getDouble("y");
                    double z     = pos.getDouble("z");
                    float  yaw   = (float) pos.getDouble("yaw");
                    float  pitch = (float) pos.getDouble("pitch");
                    World w = Bukkit.getWorld(worldName != null ? worldName : "world");
                    if (w != null) {
                        positions.add(new Location(w, x, y, z, yaw, pitch));
                        posCount++;
                    }
                }
                i++;
            }
            if (!positions.isEmpty()) {
                routes.put(routeName.toLowerCase(), positions);
                routeCount++;
            }
        }
        if (routeCount > 0) {
            plugin.getLogger().info("[FPP] Loaded " + routeCount + " waypoint route(s) with "
                    + posCount + " total position(s).");
        }
    }

    /** Saves all routes to disk. Called automatically on every mutation. */
    public void save() {
        if (file == null) {
            file = new File(plugin.getDataFolder(), "data/waypoints.yml");
        }
        file.getParentFile().mkdirs();

        YamlConfiguration yaml = new YamlConfiguration();
        for (Map.Entry<String, List<Location>> e : routes.entrySet()) {
            String routeName = e.getKey();
            List<Location> positions = e.getValue();
            for (int i = 0; i < positions.size(); i++) {
                Location loc = positions.get(i);
                String prefix = routeName + "." + i + ".";
                yaml.set(prefix + "world", loc.getWorld() != null ? loc.getWorld().getName() : "world");
                yaml.set(prefix + "x",     loc.getX());
                yaml.set(prefix + "y",     loc.getY());
                yaml.set(prefix + "z",     loc.getZ());
                yaml.set(prefix + "yaw",   (double) loc.getYaw());
                yaml.set(prefix + "pitch", (double) loc.getPitch());
            }
        }
        try {
            yaml.save(file);
        } catch (IOException ex) {
            plugin.getLogger().warning("[FPP] Could not save waypoints.yml: " + ex.getMessage());
        }
    }

    // в”Җв”Җ CRUD в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Appends a position to the named route. Creates the route if it does not exist.
     *
     * @return the new total position count for this route
     */
    public int addPos(String name, Location loc) {
        List<Location> positions = routes.computeIfAbsent(name.toLowerCase(), k -> new ArrayList<>());
        positions.add(loc.clone());
        save();
        return positions.size();
    }

    /**
     * Removes the position at the given 0-based index from the named route.
     * Auto-deletes the route if it becomes empty.
     *
     * @return {@code true} if removed successfully
     */
    public boolean removePos(String name, int index) {
        List<Location> positions = routes.get(name.toLowerCase());
        if (positions == null || index < 0 || index >= positions.size()) return false;
        positions.remove(index);
        if (positions.isEmpty()) routes.remove(name.toLowerCase());
        save();
        return true;
    }

    /**
     * Deletes the entire named route (all positions).
     *
     * @return {@code true} if the route existed and was deleted
     */
    public boolean delete(String name) {
        boolean removed = routes.remove(name.toLowerCase()) != null;
        if (removed) save();
        return removed;
    }

    /**
     * Clears all positions from the route and removes it.
     *
     * @return {@code true} if the route existed and was cleared
     */
    public boolean clear(String name) {
        List<Location> positions = routes.remove(name.toLowerCase());
        boolean had = positions != null && !positions.isEmpty();
        if (had) save();
        return had;
    }

    /**
     * Returns an unmodifiable snapshot of the positions in the named route,
     * or {@code null} if the route does not exist or is empty.
     * Name lookup is case-insensitive.
     */
    public List<Location> getRoute(String name) {
        List<Location> positions = routes.get(name.toLowerCase());
        if (positions == null || positions.isEmpty()) return null;
        return Collections.unmodifiableList(new ArrayList<>(positions));
    }

    /** Returns {@code true} if a route with this name exists and has at least one position. */
    public boolean exists(String name) {
        List<Location> positions = routes.get(name.toLowerCase());
        return positions != null && !positions.isEmpty();
    }

    /** Returns {@code true} if a route with this name exists (including empty routes). */
    public boolean hasRoute(String name) {
        return routes.containsKey(name.toLowerCase());
    }

    /** Returns an unmodifiable sorted set of all route names (lowercase). */
    public Set<String> getNames() {
        return Collections.unmodifiableSet(new TreeSet<>(routes.keySet()));
    }

    /** Returns the number of stored routes. */
    public int size() {
        return routes.size();
    }

    /** Returns the number of positions in the named route, or 0 if not found. */
    public int getPositionCount(String name) {
        List<Location> positions = routes.get(name.toLowerCase());
        return positions != null ? positions.size() : 0;
    }
}

const express = require("express");
const cors = require("cors");
const fs = require("fs");
const path = require("path");
const yaml = require("js-yaml");
const fetch = require("node-fetch");

const app = express();
const port = process.env.PORT || 3000;

app.use(cors());

// Middleware to check if request is from plugin (for API protection)
function isPluginRequest(req) {
  const userAgent = req.get('User-Agent') || '';
  const pluginHeaders = req.get('X-Plugin-Request') || req.get('X-FPP-Request');

  // Allow requests from Java HTTP clients (plugin) or with plugin headers
  return userAgent.includes('Java') ||
         userAgent.includes('Apache-HttpClient') ||
         pluginHeaders === 'true' ||
         req.ip === '127.0.0.1' ||
         req.ip === '::1';
}

// API protection middleware
function protectAPI(req, res, next) {
  if (isPluginRequest(req)) {
    next();
  } else {
    res.status(403).json({ error: 'API access restricted to plugin requests.' });
  }
}

// в”Җв”Җ API ROUTES (must come BEFORE static middleware) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

// в”Җв”Җ Online stats endpoint (public - no auth required) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Returns the count of servers and users currently using the plugin
app.get('/api/online-stats', async (req, res) => {
  res.json({
    servers: 200,
    users: 630,
    timestamp: new Date().toISOString()
  });
});

// в”Җв”Җ Helper functions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

function findProjectRoot(startDir) {
  if (process.env.PLUGIN_ROOT) return path.resolve(process.env.PLUGIN_ROOT);
  let cur = path.resolve(startDir);
  for (let i = 0; i < 8; i++) {
    const candidateA = path.join(cur, "src", "main", "resources", "plugin.yml");
    const candidateB = path.join(cur, "pom.xml");
    const candidateC = path.join(cur, "target");
    if (
      fs.existsSync(candidateA) ||
      fs.existsSync(candidateB) ||
      fs.existsSync(candidateC)
    )
      return cur;
    const parent = path.dirname(cur);
    if (parent === cur) break;
    cur = parent;
  }
  return path.resolve(__dirname);
}

function safeReadYaml(filePath) {
  try {
    if (!fs.existsSync(filePath)) return null;
    const content = fs.readFileSync(filePath, "utf8");
    return yaml.load(content);
  } catch (e) {
    return { error: String(e) };
  }
}

// Helpers to normalize responses to a minimal public shape
function toSafeString(v) {
  if (v === undefined || v === null) return null;
  if (typeof v === "string") return v;
  if (typeof v === "number" || typeof v === "boolean") return String(v);
  return null; // avoid arrays/objects
}

function mapToMinimal(obj) {
  const fallback = {
    name: null,
    version: null,
    downloadUrl: process.env.PLUGIN_DOWNLOAD_URL || "https://api.fpp.com/",
    notes: null,
  };
  if (!obj || typeof obj !== "object") return fallback;
  const name = toSafeString(obj.name || obj.displayName || obj.title) || null;
  const version =
    toSafeString(
      obj.version || obj.tag_name || obj.latest || obj.version_number
    ) || null;
  const downloadUrl =
    toSafeString(obj.downloadUrl || obj.download_url || obj.website) ||
    process.env.PLUGIN_DOWNLOAD_URL ||
    "https://api.fpp.com/";
  const notes =
    toSafeString(obj.description || obj.notes || obj.body || obj.summary) ||
    null;
  return { name, version, downloadUrl, notes };
}

function findBestObject(result) {
  if (!result || typeof result !== "object") return null;
  if (result.version || result.tag_name || result.name || result.latest)
    return result;
  const keys = [
    "plugin",
    "data",
    "release",
    "manifest",
    "result",
    "package",
    "body",
  ];
  for (const k of keys) {
    if (result[k] && typeof result[k] === "object") {
      const candidate = result[k];
      if (
        candidate.version ||
        candidate.tag_name ||
        candidate.name ||
        candidate.latest
      )
        return candidate;
    }
  }
  for (const k of Object.keys(result)) {
    const v = result[k];
    if (v && typeof v === "object") {
      if (v.version || v.tag_name || v.name || v.latest) return v;
    }
  }
  return null;
}

