{
  "version": 2,
  "builds": [
    { "src": "frontend/api/status.js",       "use": "@vercel/node"   },
    { "src": "frontend/api/check-update.js", "use": "@vercel/node"   },
    { "src": "frontend/api/online-stats.js", "use": "@vercel/node"   },
    { "src": "frontend/api/heartbeat.js",    "use": "@vercel/node"   },
    { "src": "frontend/index.html",          "use": "@vercel/static" },
    { "src": "frontend/wiki.html",           "use": "@vercel/static" },
    { "src": "frontend/legal.html",          "use": "@vercel/static" },
    { "src": "frontend/wiki-styles.css",     "use": "@vercel/static" },
    { "src": "frontend/wiki-script.js",      "use": "@vercel/static" },
    { "src": "frontend/Icon/**",             "use": "@vercel/static" },
    { "src": "frontend/wiki/**",             "use": "@vercel/static" },
    { "src": "frontend/legal/**",            "use": "@vercel/static" }
  ],
  "routes": [
    { "src": "/api/check-update",  "dest": "/frontend/api/check-update.js" },
    { "src": "/api/status",        "dest": "/frontend/api/status.js"       },
    { "src": "/api/online-stats",  "dest": "/frontend/api/online-stats.js" },
    { "src": "/api/heartbeat",     "dest": "/frontend/api/heartbeat.js"    },

    { "src": "/wiki-styles.css",   "dest": "/frontend/wiki-styles.css"     },
    { "src": "/wiki-script.js",    "dest": "/frontend/wiki-script.js"      },
    { "src": "/Icon/(.*)",         "dest": "/frontend/Icon/$1"             },

    { "src": "/wiki/(.+\\.md)",    "dest": "/frontend/wiki/$1"             },

    { "src": "/legal/(.+\\.md)",   "dest": "/frontend/legal/$1"            },
    { "src": "/legal",             "status": 301, "headers": { "Location": "/legal/privacy-policy" } },
    { "src": "/legal/(privacy-policy|terms-of-service|copyright)", "dest": "/frontend/legal.html" },
